// ── Game Log ────────────────────────────────────────────────────────────────

// Entries are "TYPE|VISIBILITY|text" joined by "<NL>" — the GameLog zone value
// must stay single-line to survive the line-based gamestate serialization, and
// the client renderer (GameLayout swuRenderGameLog) splits on "<NL>".
function AddGameLogEntry(string $type, string $text, string $visibility = 'ALL'): void {
    global $gGameLog;
    $entry = $type . '|' . $visibility . '|' . $text;
    if (!isset($gGameLog) || $gGameLog === '' || $gGameLog === '0' || $gGameLog === '-') {
        $gGameLog = $entry;
    } else {
        $gGameLog .= '<NL>' . $entry;
    }
}

function GameLogCardRef(string $cardID): string {
    $title = CardTitle($cardID) ?? $cardID;
    return '[[' . $cardID . '|' . $title . ']]';
}

// ── Zone hooks ──────────────────────────────────────────────────────────────

function TokenCeaseBeforeAdd($player, $CardID, ...$extra) {
    // Tokens cease to exist when they leave play (CR 5.8).
    // TODO: block token CardIDs once token type data is reliable.
    return true;
}

function GroundArenaAfterAdd($player, $CardID, $Status, $Owner, $Damage, $Controller,
                              $TurnEffects, $Subcards, $UniqueID) {}

function SpaceArenaAfterAdd($player, $CardID, $Status, $Owner, $Damage, $Controller,
                             $TurnEffects, $Subcards, $UniqueID) {}

function SWUAddToDiscard(int $player, string $cardID, string $from, string $modifier = '', ?object $sourceObject = null): object {
    global $gTurnNumber;
    $entry = AddDiscard($player, $cardID, $from, intval($gTurnNumber), $modifier);
    OnCardDiscarded($player, $cardID, $entry, $sourceObject);
    return $entry;
}

function OnCardDiscarded(int $player, string $cardID, object $entry, ?object $sourceObject = null): void {
    global $cardDiscardedHandlers;
    $key = $cardID . ':0';
    if (isset($cardDiscardedHandlers[$key])) {
        $cardDiscardedHandlers[$key]($player, $entry, $sourceObject);
    }
}

global $cardDiscardedHandlers;
$cardDiscardedHandlers = $cardDiscardedHandlers ?? [];

// Cards that offer an optional alternate cost (e.g. "discard a [Aspect] card instead").
// Keyed by cardID → true. Checked in ActivateCard and SWUComputeActionsData.
global $hasAlternateCostCards;
$hasAlternateCostCards = ['SOR_199' => true];

function HasTrait(string $cardID, string $trait): bool {
    $raw = CardTrait($cardID);
    if ($raw === null || $raw === '') return false;
    foreach (explode(',', $raw) as $t) {
        if (trim($t) === $trait) return true;
    }
    return false;
}

// Object-aware trait check: honors per-instance trait-suppression markers (NO_TRAIT_<TRAIT>, e.g.
// LOF_033 Nameless Terror stripping the Force trait from enemy units in play this phase). Falls back
// to the static dictionary trait when no marker is present, so routing an existing arena-object read
// through this is behavior-preserving until a suppression marker exists. Pass an in-play UNIT OBJECT
// (or its mzID); bare-CardID / hand / deck / play-time reads should keep calling HasTrait directly.
function _SWUUnitHasTrait($obj, string $trait): bool {
    if (is_string($obj)) $obj = GetZoneObject($obj);
    if ($obj === null || !is_object($obj)) return false;
    $te = $obj->TurnEffects ?? null;
    if (is_array($te) && in_array('NO_TRAIT_' . strtoupper($trait), $te, true)) return false;
    // SEC_054 Exiled from the Force — attached unit loses the Force trait.
    if (strtoupper($trait) === 'FORCE' && _SWUUnitHasUpgrade($obj, 'SEC_054')) return false;
    // SEC_156 Nemik's Manifesto — attached unit GAINS the Rebel trait.
    if (strtoupper($trait) === 'REBEL' && _SWUUnitHasUpgrade($obj, 'SEC_156')) return true;
    // LAW_150 Fulcrum — attached unit GAINS the Rebel trait.
    if (strtoupper($trait) === 'REBEL' && _SWUUnitHasUpgrade($obj, 'LAW_150')) return true;
    // LAW_111 Leia's Disguise — attached unit GAINS the Underworld trait.
    if (strtoupper($trait) === 'UNDERWORLD' && _SWUUnitHasUpgrade($obj, 'LAW_111')) return true;
    // ASH_135 The Darksaber — attached unit GAINS the Mandalorian trait.
    if (strtoupper($trait) === 'MANDALORIAN' && _SWUUnitHasUpgrade($obj, 'ASH_135')) return true;
    // LAW_212 Malakili — "Each friendly Creature unit ... gains the Underworld trait." Granted to any
    // Creature whose controller controls a Malakili in play. (The "Creature you own that isn't in play"
    // half is NOT covered here — those reads go through bare-CardID HasTrait; deferred edge.)
    if (strtoupper($trait) === 'UNDERWORLD' && !HasTrait($obj->CardID ?? '', 'Underworld')
        && HasTrait($obj->CardID ?? '', 'Creature')) {
        $ctrl = intval($obj->Controller ?? 0);
        if ($ctrl > 0) {
            foreach (GetUnitsInPlay($ctrl) as $mu) {
                if (empty($mu->removed) && ($mu->CardID ?? '') === 'LAW_212') return true;
            }
        }
    }
    return HasTrait($obj->CardID ?? '', $trait);
}

function _SWUUnitHasUpgrade(object $unit, string $upgradeCardID): bool {
    if (!is_array($unit->Subcards ?? null)) return false;
    foreach ($unit->Subcards as $sub) {
        $subCardID  = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
        $subRemoved = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
        if (!$subRemoved && $subCardID === $upgradeCardID) return true;
    }
    return false;
}

// True if $player controls a unit in play bearing $upgradeCardID (JTL_260 granted-discount check).
function _SWUControlsUnitBearingUpgrade(int $player, string $upgradeCardID): bool {
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (_SWUUnitHasUpgrade($u, $upgradeCardID)) return true;
    }
    return false;
}

// ── SWU-only virtual properties (not defined in GA code) ────────────────────

function GetExperienceTokenCount($obj) { return 0; }
function GetShieldTokenCount($obj)     { return 0; }
function HandCardCostDifference($obj)  { return null; }

// FieldSelectionMetadata: highlight arena units when they can act (ready, your turn, DQ empty).
// Overrides the GA-template version which calls PrideAmount() — a GA-only function.
if (!function_exists('FieldSelectionMetadata')) {
function FieldSelectionMetadata($obj) {
    $location = $obj->Location ?? '';
    if ($location !== 'GroundArena' && $location !== 'SpaceArena') return json_encode(['highlight' => false]);
    $cardType = CardType($obj->CardID ?? '');
    // Allow "Unit" (all unit types) and "Leader" (deployed leader units in arena).
    if (!PropertyContains($cardType, 'Unit') && !PropertyContains($cardType, 'Leader')) return json_encode(['highlight' => false]);
    $currentPhase = GetCurrentPhase();
    if ($currentPhase !== 'MAIN') return json_encode(['highlight' => false]);
    $turnPlayer = GetTurnPlayer();
    $decisionQueue      = &GetDecisionQueue(1);
    $decisionQueueOther = &GetDecisionQueue(2);
    if (count($decisionQueue) > 0 || count($decisionQueueOther) > 0) return json_encode(['highlight' => false]);
    $controller = isset($obj->Controller) ? intval($obj->Controller) : 0;
    if ($controller !== intval($turnPlayer)) return json_encode(['highlight' => false]);
    if (isset($obj->Status) && intval($obj->Status) !== 1) return json_encode(['highlight' => false]);
    return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
}
}

