function CardActivateAbilityCount($cardID)      { return 0; }

// ── Stubs for GA cost-system functions not present in SWU ──────────────────
// GA uses a "reserve" payment system; SWU uses exhausted resources instead.
// These stubs prevent fatals in GA template code that SWUSim inherits.
function CardCost_reserve($cardID)        { return CardCost($cardID); }
function CardClasses($cardID)             { return ''; }
function CardSubtypes($cardID)            { return ''; }
function GetLinkedCards($obj)             { return []; }
