    'JTL_035' => ['kind' => 'STAT_DEBUFF', 'label' => '-{0}/-{1}'], // Tam Ryvora (granted on-attack arena debuff)
    'SOR_216' => ['kind' => 'STAT_DEBUFF', 'label' => '-{0}/-{1}'], // Disarm
