    'SOR_051' => ['kind' => 'STAT_DEBUFF', 'label' => '-{0}/-{1}'], // (Leia?) -X/-X
    'SOR_028' => ['kind' => 'STAT_DEBUFF', 'label' => '-{0}/-{1}'], // base -4/-0
];

// Parse a TurnEffects entry into ['base','params','duration','raw']. Inline "@duration" wins;
// else the registry default for the base; else "phase".
function SWUParseTurnEffect(string $s): array {
    global $turnEffectRegistry;
    $raw = $s;
    $duration = null;
    $at = strpos($s, '@');
    if ($at !== false) { $duration = substr($s, $at + 1); $s = substr($s, 0, $at); }
    $params = [];
    // Dynamic per-instance values are dash-delimited: "CARDID-p1-p2" (e.g. a -3/-3 debuff is
    // "SOR_051-3-3"). The base CardID/synthetic token never contains a dash, so the first '-'
    // cleanly separates the base from its value params. ('#' is reserved for handler step keys.)
    $dash = strpos($s, '-');
    if ($dash !== false) {
        $payload = substr($s, $dash + 1);
        $params = ($payload === '') ? [] : explode('-', $payload);
        $s = substr($s, 0, $dash);
    }
    $base = $s;
    if ($duration === null) $duration = $turnEffectRegistry[$base]['duration'] ?? SWU_DUR_PHASE;
    return ['base' => $base, 'params' => $params, 'duration' => $duration, 'raw' => $raw];
}

// Build a canonical TurnEffects token. The "@duration" suffix is emitted only when it differs
// from the registry default for $base, keeping tokens short and back-compatible with bare names.
function SWUMakeTurnEffect(string $base, array $params = [], ?string $duration = null): string {
    global $turnEffectRegistry;
    $s = $base;
    if (!empty($params)) $s .= '-' . implode('-', array_map('strval', $params));
    $default = $turnEffectRegistry[$base]['duration'] ?? SWU_DUR_PHASE;
    if ($duration !== null && $duration !== $default) $s .= '@' . $duration;
    return $s;
}

// Registry kind for a base token (null if unregistered).
function SWUEffectKind(string $base): ?string {
    global $turnEffectRegistry;
    return $turnEffectRegistry[$base]['kind'] ?? null;
}

// Parsed, registry-resolved view of every TurnEffect on $obj:
//   [ ['base','kind','value','params','duration','label','sourceCardID','raw'], ... ]
// sourceCardID is the base when it looks like a CardID (SET_NNN / SET_T##), else null.
// Drives both the reader helpers and the Active Effects UI (SWUDescribeActiveEffects).
function SWUParsedTurnEffects($obj): array {
    global $turnEffectRegistry;
    if (is_string($obj)) $obj = GetZoneObject($obj);
    if ($obj === null || empty($obj->TurnEffects)) return [];
    $out = [];
    foreach ($obj->TurnEffects as $te) {
        $p = SWUParseTurnEffect((string)$te);
        $reg = $turnEffectRegistry[$p['base']] ?? null;
        $isCardID = (bool)preg_match('/^[A-Z]{2,5}_(T?\d{2,3})$/', $p['base']);
        $out[] = [
            'base'         => $p['base'],
            'kind'         => $reg['kind']  ?? null,
            'value'        => $reg['value'] ?? null,
            'amount'       => $reg['amount'] ?? null,   // static value-keyword value (CardID-derived); null ⇒ read from params
            'params'       => $p['params'],
            'duration'     => $p['duration'],
            'label'        => $reg['label'] ?? null,
            'sourceCardID' => $isCardID ? $p['base'] : null,
            'raw'          => $p['raw'],
        ];
    }
    return $out;
}

// True if $obj has any TurnEffect that grants keyword $keyword (boolean grant). Resolves both
// the synthetic bare token ("SENTINEL") and a CardID grant token (kind GRANT_KEYWORD, value match).
function SWUHasTurnEffectKeyword($obj, string $keyword): bool {
    foreach (SWUParsedTurnEffects($obj) as $e) {
        if ($e['kind'] === 'GRANT_KEYWORD' && $e['value'] === $keyword) return true;
    }
    return false;
}

// Highest granted value for a value-keyword ($keyword = "RAID"|"RESTORE"|"EXPLOIT"). 0 if none.
// (CR: Raid/Restore use the highest instance; Exploit is summed — callers that need the sum use
// SWUTurnEffectKeywordValueSum.)
function SWUTurnEffectKeywordValue($obj, string $keyword): int {
    $val = 0;
    foreach (SWUParsedTurnEffects($obj) as $e) {
        if ($e['kind'] === 'GRANT_KEYWORD_VALUE' && $e['value'] === $keyword) {
            $amt = $e['amount'] ?? intval($e['params'][0] ?? 0);  // CardID-derived value, else dash param
            $val = max($val, intval($amt));
        }
    }
    return $val;
}

// Sum of granted values for a value-keyword (Exploit stacks additively, CR 16.b).
function SWUTurnEffectKeywordValueSum($obj, string $keyword): int {
    $sum = 0;
    foreach (SWUParsedTurnEffects($obj) as $e) {
        if ($e['kind'] === 'GRANT_KEYWORD_VALUE' && $e['value'] === $keyword) {
            $sum += $e['amount'] ?? intval($e['params'][0] ?? 0);  // CardID-derived value, else dash param
        }
    }
    return $sum;
}

// Net "for this phase" stat bonus on $obj for $stat ('power'|'hp'): STAT_BUFF minus STAT_DEBUFF.
// (Attack-duration STAT_ATK_POWER is NOT included — combat reads that separately.)
function SWUTurnEffectStatBonus($obj, string $stat): int {
    $idx = ($stat === 'hp') ? 1 : 0;
    $net = 0;
    foreach (SWUParsedTurnEffects($obj) as $e) {
        if ($e['kind'] === 'STAT_BUFF')   $net += intval($e['params'][$idx] ?? 0);
        if ($e['kind'] === 'STAT_DEBUFF') $net -= intval($e['params'][$idx] ?? 0);
    }
    return $net;
}

// UI-facing summary of a unit's active TurnEffects for the "Active Effects" popup.
// Returns [['label'=>string, 'duration'=>'attack'|'phase'|'perm', 'sourceCardID'=>string|null], …].
// Only REGISTERED tokens are described; unregistered tokens (internal bookkeeping like SWU_PAID_*,
// the inline-consumed combat one-shots, and dead GA tokens) are skipped so the popup shows only
// meaningful, player-facing effects. {0},{1},… in a registry label interpolate the token #params.
function SWUDescribeActiveEffects($obj): array {
    $out = [];
    foreach (SWUParsedTurnEffects($obj) as $e) {
        if ($e['kind'] === null) continue;                       // unregistered → not shown
        $label = $e['label'] ?? ($e['sourceCardID'] ?? $e['base']);
        if (strpos($label, '{') !== false) {
            foreach ($e['params'] as $i => $p) {
                $label = str_replace('{' . $i . '}', (string)$p, $label);
            }
        }
        $out[] = [
            'label'        => $label,
            'duration'     => $e['duration'],
            'sourceCardID' => $e['sourceCardID'],
        ];
    }
    return $out;
}

// Centralized duration-driven expiry. Drops expiring TurnEffects from every arena unit:
//   $scope 'attack' → drop only attack-duration effects (run at attack end).
//   $scope 'phase'  → drop attack- AND phase-duration effects (run at RegroupPhaseStart).
// 'perm' effects are never dropped (they ride until the unit leaves play). ONLY registry-known
// tokens are affected — unregistered tokens (legacy stat strings still handled by the old
// RegroupPhaseStart predicate during the migration, and dead GA tokens) are left untouched, so
// this can run alongside the legacy predicate without double-handling.
function SWUExpireTurnEffects(string $scope): void {
    global $turnEffectRegistry;
    $dropPhaseToo = ($scope === SWU_DUR_PHASE);
    $shouldDrop = function($te) use ($turnEffectRegistry, $dropPhaseToo): bool {
        $p = SWUParseTurnEffect((string)$te);
        if (!isset($turnEffectRegistry[$p['base']])) return false;   // unregistered → untouched
        if ($p['duration'] === SWU_DUR_ATTACK) return true;          // attack drops in both scopes
        if ($p['duration'] === SWU_DUR_PHASE)  return $dropPhaseToo;  // phase drops only in phase scope
        return false;                                                 // perm never drops
    };
    $keep = fn($e) => !$shouldDrop($e);
    for ($p = 1; $p <= 2; $p++) {
        $g = &GetGroundArena($p);
        for ($i = 0; $i < count($g); $i++) {
            if (!empty($g[$i]->removed)) continue;
            $g[$i]->TurnEffects = array_values(array_filter($g[$i]->TurnEffects ?? [], $keep));
        }
        unset($g);
        $s = &GetSpaceArena($p);
        for ($i = 0; $i < count($s); $i++) {
            if (!empty($s[$i]->removed)) continue;
            $s[$i]->TurnEffects = array_values(array_filter($s[$i]->TurnEffects ?? [], $keep));
        }
        unset($s);
    }
}

// Apply a "for this phase" buff (+$power/+$hp) to the unit at $mzID by tagging it with a
// "{source}-{power}-{hp}" TurnEffect (registry kind STAT_BUFF, phase duration). The base is the
// $source CardID (Active Effects provenance) when it has a registry row; otherwise it falls back
// to the synthetic 'SWUBUFF' base so the stat still applies and still expires even if a source
// row was forgotten. Read by ObjectCurrentPower/HP via SWUTurnEffectStatBonus; expired centrally
// by SWUExpireTurnEffects. Unlike a shrink, a buff never defeats a unit, so no sweep here.
function SWUApplyPhaseBuff(string $mzID, int $power, int $hp, string $source = ''): void {
    global $turnEffectRegistry;
    $base = ($source !== '' && isset($turnEffectRegistry[$source])) ? $source : 'SWUBUFF';
    AddTurnEffect($mzID, "{$base}-{$power}-{$hp}");
}

// "+N power for THIS ATTACK" (Surprise Strike SOR_220, attack-with riders SOR_227/SOR_240).
// Unlike SWUApplyPhaseBuff this is NOT a persistent stat — it's a one-shot combat-damage
// bonus that SWUCombatDamage adds to attack power and REMOVES (mirrors Raid). So the unit's
// ObjectCurrentPower is unchanged before/after; only the dealt damage is boosted. The cards
// are all +N/+0, so power-only. Cleared in RegroupPhaseStart too, in case an attack fizzles.
function SWUAddAttackPowerBonus(string $mzID, int $power): void {
    if ($power <= 0) return;
    AddTurnEffect($mzID, "SWU_ATK_POWER_{$power}");
}

// ── Targeted-effect queue helpers ───────────────────────────────────────────
// Collapse the ubiquitous "choose one target, then run $handler on it" tail:
// 1 target → PASSPARAMETER (auto); 2+ → MZCHOOSE; then CUSTOM $handler (which reads the
// chosen mzID from $lastDecision). No-op on an empty list. $handler may carry args, e.g.
// "GIVE_EXPERIENCE|1". Pass $block to match the surrounding decisions' priority (default 1).
function SWUQueueChooseTarget(int $player, array $targets, string $tooltip, string $handler, int $block = 1): void {
    if (empty($targets)) return;
    if (count($targets) === 1) DecisionQueueController::AddDecision($player, 'PASSPARAMETER', $targets[0], $block);
    else DecisionQueueController::AddDecision($player, 'MZCHOOSE', implode('&', $targets), $block, $tooltip);
    DecisionQueueController::AddDecision($player, 'CUSTOM', $handler, $block);
}

// "You may: choose a target, then run $handler." Emits a single MZMAYCHOOSE — one popup
// where the player picks a target OR declines (the Pass button). On decline the chosen
// value is '-', so $handler must no-op on a '-'/''/PASS lastDecision (all the universal
// effect handlers — DEAL_UNIT_DAMAGE, GIVE_SHIELD, GIVE_EXPERIENCE, HEAL_TARGET,
// EXHAUST_UNIT, BOUNCE_UNIT — already do). This replaces the old YESNO + MAY_CHOOSE
// re-collection chain, saving a click. $handler may carry args ("GIVE_EXPERIENCE|1") —
// no pipe-escaping needed since it's queued as its own CUSTOM decision (like
// SWUQueueChooseTarget). $yesTooltip is retained for call-site readability/compat; the
// $chooseTooltip is the selection-mode prompt. Use SWUQueueChooseTarget for mandatory
// (non-"may") effects.
function SWUQueueMayChooseTarget(int $player, array $targets, string $yesTooltip, string $chooseTooltip, string $handler, int $block = 1): void {
    if (empty($targets)) return;
    DecisionQueueController::AddDecision($player, 'MZMAYCHOOSE', implode('&', $targets), $block, $chooseTooltip);
    DecisionQueueController::AddDecision($player, 'CUSTOM', $handler, $block);
}

// "Choose two (different modes), in any order" modal (SOR_058/107/155/203 — the aspect events).
// Reuses sequential OPTIONCHOOSE — NO new decision type / UI. Queue a mode picker (all remaining
// labels); MODAL_CHOOSE resolves the chosen mode (its own effect decisions go on at block 1) then
// appends the NEXT picker (also block 1) so it runs AFTER the prior mode's effects (block-1 FIFO +
// append-at-end-of-block insertion sequences them). $picksLeft counts modes still to choose.
function SWUQueueModalChoose(int $player, string $cardID, array $labels, int $picksLeft, int $block = 1): void {
    if ($picksLeft <= 0 || count($labels) === 0) return;
    // Each successive picker sits at a HIGHER block so a multi-step mode (whose chained sub-decisions
    // run at block 1) fully resolves before the next pick is offered.
    DecisionQueueController::AddDecision($player, "OPTIONCHOOSE", implode("&", $labels), $block,
        tooltip:"Choose_a_mode");
    DecisionQueueController::AddDecision($player, "CUSTOM",
        "MODAL_CHOOSE|{$cardID}|{$picksLeft}|{$block}|" . implode(",", $labels), $block);
}

// "An opponent chooses one of THEIR units, then $handler runs on it" — the reusable cross-player
// choose pattern (generalizes SOR_167's inline cross-player discard). $caster's opponent picks; the
// targets are the opponent's own units (collected under $playerID=$opponent so myGroundArena/
// mySpaceArena resolve to THEIR arenas). $nonLeader excludes deployed leaders (NonLeaderUnitFilter).
//  - 0 units → no-op.
//  - 1 unit  → the choice is forced, so resolve $handler SYNCHRONOUSLY under the opponent (a
//              cross-player single-target PASSPARAMETER auto-resolve is fragile — cf. SOR_167).
//  - 2+ units → queue an MZCHOOSE answered BY THE OPPONENT + the CUSTOM $handler (which resolves the
//              picked relative mzID under the opponent). Leaves $playerID = opponent on return so the
//              harness's MZCountChoices resolves the relative mzIDs under the opponent (queuing gotcha).
// Because a trigger dispatch (DispatchTrigger) restores $playerID after the closure, the calling card
// must queue this via an intermediate CUSTOM (e.g. OPP_DEFEAT_OWN_UNIT) rather than calling it inline
// from a WhenPlayed/OnAttack closure — the CUSTOM path (ExecuteStaticMethods) does not restore $playerID.
function SWUOpponentChoosesOwnUnit(int $caster, bool $nonLeader, string $tooltip, string $handler): void {
    global $playerID, $customDQHandlers;
    $opp = OtherPlayer($caster);
    $savedPID = $playerID;
    $playerID = $opp;
    $filter = $nonLeader ? NonLeaderUnitFilter : AnyUnitFilter;
    $units = array_values(array_merge(
        ZoneSearch('myGroundArena', $filter),
        ZoneSearch('mySpaceArena',  $filter)
    ));
    if (empty($units)) { $playerID = $savedPID; return; }
    if (count($units) === 1) {
        $hp = explode('|', $handler);
        $hn = array_shift($hp);
        if (isset($customDQHandlers[$hn])) $customDQHandlers[$hn]($opp, $hp, $units[0]);
        $playerID = $savedPID;
        return;
    }
    DecisionQueueController::AddDecision($opp, 'MZCHOOSE', implode('&', $units), 1, tooltip:$tooltip);
    DecisionQueueController::AddDecision($opp, 'CUSTOM', $handler, 1);
    // intentionally leave $playerID = $opp (MZCountChoices resolves the relative mzIDs under it)
}

// "(You may) attack with another [Rebel] unit" — the post-attack follow-up shared by Leia's leader
// action / deployed OnAttackEnd (SOR_009) and Rebel Assault (SOR_103). Collects eligible READY
// units (optionally Rebel-only), excluding $excludeUID (the "another" clause = the just-attacked
// unit). Queues a mandatory MZCHOOSE or an optional MZMAYCHOOSE, then CUSTOM CHAINED_ATTACK|{bonus},
// which applies a one-shot +{bonus}/+0 ("for this attack") and begins the attack. Fizzles (no-op)
// if no eligible unit. Caller must already be in a post-combat trigger context (OnAttackEnd or the
// ChainedAttack trigger) so SWUAfterAction stays deferred until this second attack resolves.
// $constraint (optional): "space"/"ground" restricts the chained attacker by current arena; any other
// non-empty value is treated as a required trait (e.g. "Vehicle"). $rebelOnly is the legacy Rebel filter.
// JTL_247 — true if $obj has a (non-captive) Pilot subcard attached.
function _SWUHasPilotOnIt($obj): bool {
    if (!is_array($obj->Subcards ?? null)) return false;
    foreach ($obj->Subcards as $sub) {
        $cap = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
        $rem = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
        $pil = is_array($sub) ? !empty($sub['IsPilot'])   : !empty($sub->IsPilot);
        $scid = is_array($sub) ? ($sub['CardID'] ?? '')   : ($sub->CardID ?? '');
        if (!$cap && !$rem && ($pil || ($scid !== '' && HasTrait($scid, 'Pilot')))) return true;
    }
    return false;
}

// JTL_141 IG-88 — true if any enemy unit (an opponent of $obj's controller) is damaged.
function _SWUEnemyUnitDamaged($obj): bool {
    $opp = OtherPlayer(intval($obj->Controller ?? 0));
    if ($opp <= 0) return false;
    foreach (array_merge(GetGroundArena($opp), GetSpaceArena($opp)) as $u) {
        if (empty($u->removed) && intval($u->Damage) > 0) return true;
    }
    return false;
}

// JTL_093 Nien Nunb — count friendly Pilots ("Pilot unit and upgrade") the controller controls, excluding
// the unit at $excludeUid. If $excludeOneUpgrade, subtract one (the JTL_093 pilot upgrade counting itself).
function _SWUCountFriendlyPilots(int $controller, int $excludeUid, bool $excludeOneUpgrade): int {
    $count = 0;
    foreach (GetUnitsInPlay($controller) as $u) {
        if (intval($u->UniqueID ?? 0) !== $excludeUid && HasTrait($u->CardID ?? '', 'Pilot')) $count++;
        foreach (GetUpgradesOnUnit($u) as $up) {
            if (HasTrait($up->CardID ?? '', 'Pilot')) $count++;
        }
    }
    if ($excludeOneUpgrade) $count = max(0, $count - 1);
    return $count;
}

function SWUQueueAnotherAttack(int $player, bool $rebelOnly, bool $mayDecline, int $bonus, int $excludeUID, string $constraint = ''): void {
    global $playerID;
    $playerID = $player;
    $units = array_values(array_filter(array_merge(
        ZoneSearch('myGroundArena', AnyUnitFilter),
        ZoneSearch('mySpaceArena',  AnyUnitFilter)
    ), function($mz) use ($rebelOnly, $excludeUID, $constraint) {
        $o = GetZoneObject($mz);
        if ($o === null || intval($o->Status) !== 1) return false;
        if (intval($o->UniqueID ?? 0) === $excludeUID) return false;
        if ($rebelOnly && !HasTrait($o->CardID, 'Rebel')) return false;
        $loc = $o->Location ?? '';
        if ($constraint === 'space'  && $loc !== 'SpaceArena')  return false;
        if ($constraint === 'ground' && $loc !== 'GroundArena') return false;
        // SEC_006 Colonel Yularen — cost-capped chain: "costlt:N" = cost < N (leader, "less than it"),
        // "costle:N" = cost ≤ N (deployed, "costs 4 or less").
        if (strpos($constraint, 'costlt:') === 0) {
            if (intval(CardCost($o->CardID)) >= intval(substr($constraint, 7))) return false;
        } elseif (strpos($constraint, 'costle:') === 0) {
            if (intval(CardCost($o->CardID)) >  intval(substr($constraint, 7))) return false;
        } elseif ($constraint !== '' && $constraint !== 'space' && $constraint !== 'ground'
            && !HasTrait($o->CardID, $constraint)) return false;
        return true;
    }));
    if (empty($units)) return;
    $handler = "CHAINED_ATTACK|{$bonus}";
    if ($mayDecline) {
        SWUQueueMayChooseTarget($player, $units, 'Attack_with_another_unit', 'Choose_another_unit_to_attack_with', $handler);
    } else {
        SWUQueueChooseTarget($player, $units, 'Attack_with_another_unit', $handler);
    }
}

// SEC_103 Mon Mothma — offer the next "you may attack with another unit (even if exhausted)". The loop
// var SWU_MONMOTHMA_LOOP holds the CSV of UIDs to exclude (Mon Mothma + every unit that already attacked
// this When Played). Offers a MAY-choose over the remaining OTHER friendly units in BOTH arenas,
// regardless of ready/exhausted status; an empty pool clears the loop var (the loop ends). Re-fired after
// each attack resolves (via the SWU_TRIGGER_RESUME stack-empty branch). Units can't attack bases here —
// MONMOTHMA_ATTACK calls BeginSWUAttack with noBases=true.
function _SWUMonMothmaOffer(int $player): void {
    global $playerID; $playerID = $player;
    $loop = GetSWUVar('SWU_MONMOTHMA_LOOP', '');
    if ($loop === '') return;
    $excl = array_values(array_filter(explode(',', $loop), fn($x) => $x !== ''));
    $units = [];
    foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
        $arr = GetZone($zone);
        for ($i = 0; $i < count($arr); $i++) {
            $u = $arr[$i];
            if ($u === null || !empty($u->removed)) continue;
            if (in_array(strval(intval($u->UniqueID ?? 0)), $excl, true)) continue;
            $units[] = "{$zone}-{$i}";
        }
    }
    if (empty($units)) { SetSWUVar('SWU_MONMOTHMA_LOOP', ''); return; }   // no more eligible units → stop
    SWUQueueMayChooseTarget($player, $units, 'Attack_with_another_unit_even_if_exhausted',
        'Choose_a_unit_to_attack_with', 'MONMOTHMA_ATTACK');
}

// Field-presence "other friendly {trait} units get +1/+1" buff. Returns +1 (to
// either stat) for each OTHER unit the controller has with CardID $sourceCardID,
// when $obj itself has trait $trait. "Other" excludes $obj by UniqueID, so the
// commander never buffs itself and two commanders buff each other. (SOR_230
// General Veers / Imperial, SOR_242 General Dodonna / Rebel.)
// LAW_150 Fulcrum — the wearer grants "+2/+2 to each OTHER friendly Rebel unit." Returns the total
// +stat for $obj: +2 per OTHER friendly unit wearing LAW_150, but only if $obj is a Rebel (granted
// Rebel via _SWUUnitHasTrait counts too). Added to both ObjectCurrentPower and ObjectCurrentHP.
// Count the DISTINCT keywords on $obj (ASH_100 Gallius Rax "2 or more different keywords").
function _SWUCountDistinctKeywords($obj): int {
    if ($obj === null) return 0;
    $n = 0;
    foreach (['Sentinel', 'Ambush', 'Overwhelm', 'Grit', 'Saboteur', 'Shielded', 'Bounty', 'Hidden', 'Smuggle', 'Plot', 'Piloting', 'Support'] as $kw) {
        $fn = "HasKeyword_{$kw}";
        if (function_exists($fn) && $fn($obj)) $n++;
    }
    foreach (['Raid', 'Restore', 'Exploit'] as $vkw) {
        $fn = "GetKeyword_{$vkw}_Value";
        if (function_exists($fn)) { $v = $fn($obj); if ($v !== null && intval($v) > 0) $n++; }
    }
    return $n;
}

// ASH_100 Gallius Rax — "Other friendly units with 2+ different keywords get +2/+2." +2 for $obj if its
// controller controls another Gallius Rax and $obj has ≥2 distinct keywords.
function _SWUAsh100Bonus($obj): int {
    if ($obj === null) return 0;
    $ctrl = intval($obj->Controller ?? 0);
    if ($ctrl <= 0) return 0;
    $selfUid = intval($obj->UniqueID ?? 0);
    $hasOther = false;
    foreach (GetUnitsInPlay($ctrl) as $u) {
        if (empty($u->removed) && ($u->CardID ?? '') === 'ASH_100' && intval($u->UniqueID ?? 0) !== $selfUid) { $hasOther = true; break; }
    }
    if (!$hasOther) return 0;
    return _SWUCountDistinctKeywords($obj) >= 2 ? 2 : 0;
}

function _SWULaw150Bonus($obj): int {
    $controller = intval($obj->Controller ?? $obj->Owner ?? 0);
    if ($controller <= 0) return 0;
    if (!_SWUUnitHasTrait($obj, 'Rebel')) return 0;
    $n = 0;
    foreach (GetUnitsInPlay($controller) as $fu) {
        if (empty($fu->removed) && !LostAbilities($fu)
            && intval($fu->UniqueID ?? -1) !== intval($obj->UniqueID ?? -2)
            && _SWUUnitHasUpgrade($fu, 'LAW_150')) $n++;
    }
    return 2 * $n;
}

function SWUTraitCommanderBonus($obj, string $sourceCardID, string $trait): int {
    $controller = intval($obj->Controller ?? $obj->Owner ?? 0);
    if ($controller <= 0) return 0;
    if (!HasTrait($obj->CardID, $trait)) return 0;
    $bonus = 0;
    foreach (array_merge(GetGroundArena($controller) ?? [], GetSpaceArena($controller) ?? []) as $u) {
        if (!empty($u->removed)) continue;
        if (($u->CardID ?? '') !== $sourceCardID) continue;
        if (intval($u->UniqueID ?? -1) === intval($obj->UniqueID ?? -2)) continue; // not self
        if (LostAbilities($u)) continue; // a source that lost its abilities no longer grants the bonus
        $bonus += 1;
    }
    return $bonus;
}

// LOF_237 The Son — "While the Force is with you, each friendly unit gets +2/+0." Power-only field
// passive; gated on the controller currently controlling their Force token. Applies to EVERY friendly
// unit including The Son itself (so, unlike SWUTraitCommanderBonus, no self-exclusion). Stacks per copy.
function _SWUTheSonBonus($obj): int {
    $controller = intval($obj->Controller ?? $obj->Owner ?? 0);
    if ($controller <= 0) return 0;
    if (!PlayerHasTheForce($controller)) return 0;
    $bonus = 0;
    foreach (array_merge(GetGroundArena($controller) ?? [], GetSpaceArena($controller) ?? []) as $u) {
        if (!empty($u->removed)) continue;
        if (($u->CardID ?? '') !== 'LOF_237') continue;
        if (LostAbilities($u)) continue; // a Son that lost its abilities stops granting
        $bonus += 2;
    }
    return $bonus;
}

// LOF_191 BD-1 — "Choose another friendly unit. While this unit is in play, the chosen unit gets +1/+0 and
// gains Saboteur." True if $obj is the chosen target of any LOF_191 still in play (the link is the global
// effect SWU_LOF191_{sourceUID}_{targetUID}; once BD-1 leaves play the loop finds no source, ending the buff).
function _SWULof191HasBuff($obj): bool {
    if ($obj === null) return false;
    $player = intval($obj->Controller ?? $obj->Owner ?? 0);
    if ($player <= 0) return false;
    $tgtUID = intval($obj->UniqueID ?? -1);
    foreach (array_merge(GetGroundArena($player) ?? [], GetSpaceArena($player) ?? []) as $u) {
        if (!empty($u->removed) || ($u->CardID ?? '') !== 'LOF_191' || LostAbilities($u)) continue;
        if (GlobalEffectCount($player, 'SWU_LOF191_' . intval($u->UniqueID ?? -1) . '_' . $tgtUID) > 0) return true;
    }
    return false;
}

// True if $player controls a Force unit OR a Force upgrade (on any of their units). (LOF_060.)
function _SWUControlsForceUnitOrUpgrade(int $player): bool {
    foreach (GetUnitsInPlay($player) as $u) {
        if (!empty($u->removed)) continue;
        if (_SWUUnitHasTrait($u, 'Force')) return true;
        foreach (GetUpgradesOnUnit($u) as $up) {
            if (_SWUUnitHasTrait($up, 'Force')) return true;
        }
    }
    return false;
}

// True if $player controls a deployed leader (i.e. a leader unit is in play).
function SWUControlsLeaderUnit(int $player): bool {
    foreach (GetLeader($player) as $l) {
        if (!empty($l->removed)) continue;
        if (!empty($l->Deployed)) return true;
    }
    return false;
}

// True if $player has the specific leader $cardID deployed (its leader-unit side in play).
// Used for deployed-leader passives (e.g. SOR_018 Jyn Erso's defender debuff).
function _SWULeaderDeployed(int $player, string $cardID): bool {
    foreach (GetLeader($player) as $l) {
        if (!empty($l->removed)) continue;
        if (($l->CardID ?? '') === $cardID && !empty($l->Deployed)) return true;
    }
    return false;
}

// Number of SHD_037 (Supreme Leader Snoke) controlled by $obj's opponent.
// Only non-leader units are affected by Snoke's passive; leaders/leader units return 0.
function SWUEnemySnokeCount($obj): int {
    if (IsLeaderUnit($obj)) return 0;
    $controller = intval($obj->Controller ?? $obj->Owner ?? 0);
    if ($controller <= 0) return 0;
    $opp = GetOpponent($controller);
    $count = 0;
    foreach (array_merge(GetGroundArena($opp) ?? [], GetSpaceArena($opp) ?? []) as $u) {
        if (!empty($u->removed)) continue;
        if (($u->CardID ?? '') === 'SHD_037' && !LostAbilities($u)) $count++;
    }
    return $count;
}

// Apply a "for this phase" shrink (–$power/–$hp) to the unit at $mzID, then run a
// state-based defeat check: a shrink lowers HP directly (it is NOT damage, so shields
// do not prevent it), and a unit reduced to 0 remaining HP is defeated.
// Caller must have $playerID set so the relative $mzID resolves to the right arena.
function SWUApplyPhaseDebuff(string $mzID, int $power, int $hp, string $source = ''): void {
    global $turnEffectRegistry;
    // "{source}-{power}-{hp}" (registry kind STAT_DEBUFF, phase). CardID base for provenance when
    // registered; synthetic 'SWUDEBUFF' fallback otherwise. params are amounts to SUBTRACT.
    $base = ($source !== '' && isset($turnEffectRegistry[$source])) ? $source : 'SWUDEBUFF';
    AddTurnEffect($mzID, "{$base}-{$power}-{$hp}");
    SWUCheckShrinkDefeats();
}

// SOR_004 Chirrut Îmwe (deployed): "During the action phase, this unit isn't defeated by having
// no remaining HP. (During the regroup phase, if he has no remaining HP, defeat him.)" So the
// deployed Chirrut leader unit is immune to HP-defeat in EVERY phase except the regroup phase —
// the RegroupPhaseStart sweep (SWUCheckShrinkDefeats, which runs while GetCurrentPhase()==='RGS')
// then defeats him if his damage still meets/exceeds his HP. This is HP-defeat only; an effect
// that defeats him directly ("defeat target unit") is unaffected.
function SWUImmuneToHpDefeat($obj): bool {
    if ($obj === null) return false;
    $cid = $obj->CardID ?? '';
    // SOR_004 Chirrut: not defeated by no remaining HP while it's not the regroup phase.
    if ($cid === 'SOR_004' && IsLeaderUnit($obj)) return GetCurrentPhase() !== 'RGS';
    // LOF_043 The Tragedy of Plagueis — a chosen unit "can't be defeated by having no remaining HP" for
    // this phase (NO_HP_DEFEAT turn-effect marker; expires at RegroupPhaseStart).
    if (is_array($obj->TurnEffects ?? null) && in_array('NO_HP_DEFEAT', $obj->TurnEffects, true)) return true;
    return false;
}

// LOF_220 — consume a one-shot "prevent 2 of the next damage" marker on $obj (if present) and return the
// reduced amount. Called at every damage instance (combat + effect) so whichever lands first consumes it.
function _SWUApplyDamagePrevention($obj, int $amount): int {
    if ($obj === null || $amount <= 0) return $amount;
    // LOF_220 one-shot "prevent 2 of the next damage" marker (combat or effect).
    if (is_array($obj->TurnEffects ?? null)) {
        $idx = array_search('PREVENT_DMG_2', $obj->TurnEffects, true);
        if ($idx !== false) { array_splice($obj->TurnEffects, $idx, 1); $amount = max(0, $amount - 2); }
    }
    if ($amount <= 0) return 0;
    $ctrl = intval($obj->Controller ?? 0);
    $uid  = intval($obj->UniqueID ?? 0);
    // SEC_067 Umbaran Mobile Cannon — "the first time this unit would take damage each phase, prevent
    // that damage." Per-unit per-phase flag; cleared at RegroupPhaseStart.
    if (($obj->CardID ?? '') === 'SEC_067' && $ctrl > 0
            && GlobalEffectCount($ctrl, 'SWU_SEC067_USED_' . $uid) <= 0) {
        AddGlobalEffects($ctrl, 'SWU_SEC067_USED_' . $uid);
        return 0;
    }
    // SEC_050 Vigil — "If damage would be dealt to THIS unit by another card, deal that much +1 instead."
    if (($obj->CardID ?? '') === 'SEC_050') {
        $amount += 1;
    } else if ($ctrl > 0) {
        // SEC_050 — "If damage would be dealt to ANOTHER friendly unit, prevent 1 of that damage."
        foreach (GetUnitsInPlay($ctrl) as $u) {
            if (empty($u->removed) && ($u->CardID ?? '') === 'SEC_050' && intval($u->UniqueID ?? 0) !== $uid) {
                $amount = max(0, $amount - 1); break;
            }
        }
    }
    // ASH_150 Deadly Vulnerability — "If attached unit would take damage, it takes twice as much instead."
    // Applied last (after prevention) so it doubles the net damage. Covers combat AND ability paths (both
    // route through this function).
    if ($amount > 0 && _SWUUnitHasUpgrade($obj, 'ASH_150')) $amount *= 2;
    return $amount;
}

// True if $player currently holds the initiative. GetInitiativeCounter() returns 'P1_CLAIMED'/'P2_…'.
function _SWUHasInitiative(int $player): bool {
    return strpos((string)GetInitiativeCounter(), 'P' . $player) === 0;
}

// True if $obj bears at least one non-captive, non-removed upgrade subcard ("upgraded unit").
function _SWUIsUpgraded($obj): bool {
    if ($obj === null || !is_array($obj->Subcards ?? null)) return false;
    foreach ($obj->Subcards as $sub) {
        $isCap = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
        $isRem = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
        if (!$isCap && !$isRem) return true;
    }
    return false;
}

// ── "Can't be X by enemy card abilities" immunity helpers ──────────────────────────────────────────
// Each returns true if $obj currently has the relevant immunity, via: its own CardID, a granted
// attached upgrade, or a controller field-passive. CALL SITES apply these only for ENEMY-sourced
// ability actions (actor ≠ the unit's controller/owner) — these immunities never restrict the
// controller's own abilities, combat, or state-based "no remaining HP" defeat (see SWUImmuneToHpDefeat).
function SWUAvoidsDefeat($obj): bool {
    if ($obj === null) return false;
    $cid = $obj->CardID ?? '';
    if ($cid === 'SHD_187' || $cid === 'JTL_103' || $cid === 'LAW_149') return true;        // self
    if (_SWUUnitHasUpgrade($obj, 'TWI_220')) return true;  // Shadowed Intentions (attached grant)
    if (_SWUUnitHasUpgrade($obj, 'JTL_103')) return true;  // Chewbacca as a Pilot (attached grant)
    return false;
}
function SWUAvoidsBounce($obj): bool {
    if ($obj === null) return false;
    $cid = $obj->CardID ?? '';
    if ($cid === 'JTL_103') return true;                                                     // self
    if (_SWUUnitHasUpgrade($obj, 'TWI_220')) return true;  // Shadowed Intentions
    if (_SWUUnitHasUpgrade($obj, 'JTL_103')) return true;  // Chewbacca as a Pilot
    // LOF_073 Mythosaur: friendly UPGRADED units can't be returned to hand by enemy abilities.
    if (_SWUIsUpgraded($obj) && _SWUCountUnitsWithCardID(intval($obj->Controller ?? 0), 'LOF_073') > 0) return true;
    return false;
}
function SWUAvoidsCapture($obj): bool {
    if ($obj === null) return false;
    if (($obj->CardID ?? '') === 'SHD_187') return true;                                     // self
    if (_SWUUnitHasUpgrade($obj, 'TWI_220')) return true;  // Shadowed Intentions
    return false;
}
function SWUAvoidsAbilityDamage($obj): bool {
    if ($obj === null) return false;
    return ($obj->CardID ?? '') === 'SHD_187';  // "can't be damaged by enemy card abilities"
}
function SWUAvoidsTakeControl($obj): bool {
    if ($obj === null) return false;
    return ($obj->CardID ?? '') === 'LAW_149';  // "Opponents can't take control of this unit."
}
function SWUAvoidsExhaust($obj): bool {
    if ($obj === null) return false;
    // LOF_040 Kylo Ren's Lightsaber: attached FORCE unit can't be exhausted by enemy abilities.
    if (_SWUUnitHasUpgrade($obj, 'LOF_040') && _SWUUnitHasTrait($obj, 'Force')) return true;
    // LOF_073 Mythosaur: friendly UPGRADED units can't be exhausted by enemy abilities.
    if (_SWUIsUpgraded($obj) && _SWUCountUnitsWithCardID(intval($obj->Controller ?? 0), 'LOF_073') > 0) return true;
    return false;
}

// State-based defeat sweep: any unit whose effective HP (after shrinks/Snoke) minus
// its damage is 0 or less is defeated. Re-scans after each defeat because removing a
// unit shifts indices and can change other units' stats (e.g. a defeated Snoke).
function SWUCheckShrinkDefeats(): void {
    global $playerID;
    $saved = $playerID;
    $guard = 0;
    do {
        $defeated = false;
        for ($p = 1; $p <= 2 && !$defeated; $p++) {
            $playerID = $p;
            foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
                foreach (ZoneSearch($zone, AnyUnitFilter) as $mz) {
                    $obj = GetZoneObject($mz);
                    if ($obj === null || !empty($obj->removed)) continue;
                    if (ObjectCurrentHP($obj) - intval($obj->Damage ?? 0) <= 0 && !SWUImmuneToHpDefeat($obj)) {
                        SWUDefeatUnit($p, $mz);
                        $defeated = true;
                        break 2;
                    }
                }
            }
        }
        $guard++;
    } while ($defeated && $guard < 100);
    $playerID = $saved;
    DecisionQueueController::CleanupRemovedCards();
}

// GA initiative helper (note: intentional typo from GA codebase).
// Returns true if the given player holds the initiative counter this round.
function PlayerHasIniative($player) {
    $ic = GetInitiativeCounter();
    return ($ic === "P{$player}_UNCLAIMED" || $ic === "P{$player}_CLAIMED");
}

// Returns the flat array of aspect icons provided by a player's leader + base.
// Each icon appears once per source card that provides it (e.g. two Aggression
// sources → ['Aggression', 'Aggression']). Empty/null aspect entries are ignored.
function PlayerAspects($player): array {
    $aspects = [];
    foreach ([GetLeader($player) ?? [], GetBase($player) ?? []] as $zone) {
        for ($i = 0; $i < count($zone); $i++) {
            if (isset($zone[$i]->removed) && $zone[$i]->removed) continue;
            $raw = CardAspect($zone[$i]->CardID);
            if ($raw === null || $raw === '') continue;
            foreach (explode(',', $raw) as $a) {
                $a = trim($a);
                if ($a !== '') $aspects[] = $a;
            }
        }
    }
    // ASH_135 The Darksaber — "While you are paying costs, the attached unit provides its aspect icons."
    // Add each Darksaber-wearing unit's printed aspects to the player's available cost-payment icons.
    foreach (GetUnitsInPlay($player) as $u) {
        if (empty($u->removed) && _SWUUnitHasUpgrade($u, 'ASH_135')) {
            $raw = CardAspect($u->CardID ?? '');
            if ($raw) foreach (explode(',', $raw) as $a) { $a = trim($a); if ($a !== '') $aspects[] = $a; }
        }
    }
    return $aspects;
}

// True if $player controls a non-removed unit (either arena, incl. leader units) whose printed
// aspects include $aspect. Used by JTL_250 Sabine's Masterpiece (per-aspect On-Attack effects).
function _SWUControlsUnitWithAspect(int $player, string $aspect): bool {
    foreach (array_merge(GetGroundArena($player) ?? [], GetSpaceArena($player) ?? []) as $u) {
        if (!empty($u->removed)) continue;
        $raw = CardAspect($u->CardID ?? '');
        if ($raw === null || $raw === '') continue;
        foreach (explode(',', $raw) as $a) {
            if (trim($a) === $aspect) return true;
        }
    }
    return false;
}

// Returns the aspect penalty cost (in resources) for a player playing a card.
// CR 8.1: +2 per card aspect icon not covered by the player's leader + base.
// Matching is multiset: if card needs 2× Aggression, player needs 2× Aggression.
// SOR_008 Hera Syndulla — true while $player controls the Hera leader (deployed or not; the leader-zone
// entry persists either way). Her passive (both sides) ignores the aspect penalty on Spectre cards.
function _SWUControlsHera(int $player): bool {
    foreach (GetLeader($player) as $l) {
        if ($l !== null && empty($l->removed) && ($l->CardID ?? '') === 'SOR_008') return true;
    }
    return false;
}
// SEC_009 Mon Mothma — both the leader front side and the deployed unit carry the same passive, so the
// player has it while SEC_009 is their leader (undeployed or deployed — the leader-zone entry persists).
function _SWUControlsMonMothma(int $player): bool {
    foreach (GetLeader($player) as $l) {
        if ($l !== null && empty($l->removed) && ($l->CardID ?? '') === 'SEC_009') return true;
    }
    return false;
}
// SEC_008 Bail Organa (deployed) — "When you play a card from your resources: Heal 1 damage from your
// base." Called after a Smuggle or Plot play; heals 1 per controlled SEC_008.
function _SWUSec008HealOnResourcePlay(int $player): void {
    $n = _SWUCountUnitsWithCardID($player, 'SEC_008');
    for ($i = 0; $i < $n; $i++) OnHealBase($player, $player, 1);
}
function SWUAspectPenalty($player, $cardID): int {
    $raw = CardAspect($cardID);
    if ($raw === null || $raw === '') return 0;

    // SOR_008 Hera Syndulla: "Ignore the aspect penalty on SPECTRE cards you play." Single chokepoint,
    // so every play path (hand / discard / affordability glow) is covered.
    if (HasTrait($cardID, 'Spectre') && _SWUControlsHera(intval($player))) return 0;

    // SEC_009 Mon Mothma: "Ignore the aspect penalties on non-Villainy Official units you play."
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false && HasTrait($cardID, 'Official')
            && strpos($raw, 'Villainy') === false && _SWUControlsMonMothma(intval($player))) {
        return 0;
    }

    // ASH_212 Peli Motto: "Ignore the aspect penalties of the first non-unit card you play each phase."
    // The waiver applies until SWU_ASH212_USED is set (locked in by ActivateCard on the first non-unit play).
    if (stripos(CardType($cardID) ?? '', 'Unit') === false
            && GlobalEffectCount(intval($player), 'SWU_ASH212_USED') <= 0
            && _SWUControlsCardInPlay(intval($player), 'ASH_212')) {
        return 0;
    }

    $cardAspects = array_filter(array_map('trim', explode(',', $raw)), fn($a) => $a !== '');
    if (empty($cardAspects)) return 0;

    $provided = PlayerAspects($player);
    $penalty  = 0;
    foreach ($cardAspects as $need) {
        $idx = array_search($need, $provided);
        if ($idx !== false) {
            array_splice($provided, $idx, 1); // consume one matching icon
        } else {
            $penalty += 2;
        }
    }
    return $penalty;
}

// LAW common bases (LAW_020/021/022/024/025/027/028/030) Epic Action: "Play a card from your hand,
// ignoring 1 of its Vigilance, Command, Aggression, or Cunning aspect penalties." Returns the resource
// value waived: 2 if — after matching the player's provided aspects (same greedy match as
// SWUAspectPenalty) — at least one UNMATCHED pip is a battlefield aspect (the player ignores that one
// pip); 0 otherwise (no penalty, or the only unmatched pip is an alignment aspect the base can't waive).
// Callers cap at SWUAspectPenalty so it never over-discounts (e.g. a Hera/Mon-Mothma 0-penalty card).
function _SWUCommonBaseWaivePenalty(int $player, string $cardID): int {
    $raw = CardAspect($cardID);
    if ($raw === null || $raw === '') return 0;
    $cardAspects = array_filter(array_map('trim', explode(',', $raw)), fn($a) => $a !== '');
    if (empty($cardAspects)) return 0;
    $provided    = PlayerAspects($player);
    $battlefield = ['Vigilance', 'Command', 'Aggression', 'Cunning'];
    $unmatched   = [];
    foreach ($cardAspects as $need) {
        $idx = array_search($need, $provided);
        if ($idx !== false) array_splice($provided, $idx, 1);
        else $unmatched[] = $need;
    }
    foreach ($unmatched as $u) {
        if (in_array($u, $battlefield, true)) return 2; // waive exactly one battlefield pip
    }
    return 0;
}

// ── SWU play-cost: single source of truth (M9 conditional cost reduction) ─────
// Per-card play-cost modifiers register a delta closure here:
//   $playCostModifiers[$cardID] = fn($player, $subjectObj): int   (negative = cheaper)
// SWUComputePlayCost consults this registry plus any generated PlayCostModifier
// abilities, so the cost the UI shows (CanAffordActivationReserve) and the cost
// ActivateCard charges can never drift. To add a new cost-reducing card, add a
// closure here — do NOT hand-edit the cost math in ActivateCard/affordability.
$playCostModifiers = [];

// SHD_182 Bravado: costs 2 less if you've defeated an enemy unit this phase.
$playCostModifiers["SHD_182"] = function($player, $subjectObj) {
    return GlobalEffectCount($player, 'SWU_ENEMY_DEFEATED') > 0 ? -2 : 0;
};

// LAW_179 Fear and Dead Men: costs 1 less per card discarded from your hand this phase.
$playCostModifiers["LAW_179"] = function($player, $subjectObj) {
    return -GlobalEffectCount($player, 'SWU_DISCARDED_HAND');
};

// ASH_104 Dathomiri Magicks: "If you control a Force unit, this event costs 1 resource less to play."
$playCostModifiers["ASH_104"] = function($player, $subjectObj) {
    foreach (GetUnitsInPlay(intval($player)) as $u) {
        if (empty($u->removed) && _SWUUnitHasTrait($u, 'Force')) return -1;
    }
    return 0;
};

// LAW_110 Phoenix Squadron Fighters: costs 1 less per friendly damaged unit (counted at play time).
$playCostModifiers["LAW_110"] = function($player, $subjectObj) {
    $n = 0;
    foreach (GetUnitsInPlay($player) as $u) {
        if (empty($u->removed) && intval($u->Damage ?? 0) > 0) $n++;
    }
    return -$n;
};

// SEC_131 Let's Talk: costs 3 less if a friendly unit left play this phase.
$playCostModifiers["SEC_131"] = function($player, $subjectObj) {
    return GlobalEffectCount($player, 'SWU_FRIENDLY_LEFT_PLAY') > 0 ? -3 : 0;
};

// SOR_248 Volunteer Soldier: costs 1 less if you control a Trooper unit.
// (It is still in hand when this runs, so it never counts itself.)
$playCostModifiers["SOR_248"] = function($player, $subjectObj) {
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (HasTrait($u->CardID, 'Trooper')) return -1;
    }
    return 0;
};

// SOR_139 Force Choke: costs 1 less if you control a Force unit. (Force is a TRAIT,
// not an aspect.) The event is in hand/discard when this runs, so it never self-counts.
$playCostModifiers["SOR_139"] = function($player, $subjectObj) {
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (_SWUUnitHasTrait($u, 'Force')) return -1;
    }
    return 0;
};

// LOF_056 Size Matters Not: costs 1 less if you control a Force unit.
$playCostModifiers["LOF_056"] = function($player, $subjectObj) {
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (_SWUUnitHasTrait($u, 'Force')) return -1;
    }
    return 0;
};

// JTL_204 Home One: costs 3 less if an opponent controls 3 or more space units.
$playCostModifiers["JTL_204"] = function($player, $subjectObj) {
    $opp = GetOpponent($player);
    $cnt = 0;
    foreach (GetSpaceArena($opp) as $u) {
        if (empty($u->removed)) $cnt++;
    }
    return $cnt >= 3 ? -3 : 0;
};

// JTL_191 Invincible: costs 1 less if you control a unique Separatist card (unit, upgrade, or leader).
$playCostModifiers["JTL_191"] = function($player, $subjectObj) {
    return _SWUControlsUniqueSeparatist($player) ? -1 : 0;
};

// JTL_101 Red Leader: costs 1 less to play for each friendly Pilot unit and upgrade.
$playCostModifiers["JTL_101"] = function($player, $subjectObj) {
    return -1 * _SWUCountFriendlyPilots($player, 0, false);
};

// True if $player controls a UNIQUE Separatist card — a friendly unit/leader (trait Separatist + unique)
// or an attached Separatist upgrade that is unique.
function _SWUControlsUniqueSeparatist(int $player): bool {
    if ($player <= 0) return false;
    foreach (GetLeader($player) as $l) {
        if (empty($l->removed) && HasTrait($l->CardID ?? '', 'Separatist') && CardUnique($l->CardID ?? '')) return true;
    }
    foreach (GetUnitsInPlay($player) as $u) {
        if (HasTrait($u->CardID ?? '', 'Separatist') && CardUnique($u->CardID ?? '')) return true;
        foreach (GetUpgradesOnUnit($u) as $up) {
            if (HasTrait($up->CardID ?? '', 'Separatist') && CardUnique($up->CardID ?? '')) return true;
        }
    }
    return false;
}

// JTL_138 Decimator of Dissidents: costs 1 less if you dealt indirect damage this phase.
$playCostModifiers["JTL_138"] = function($player, $subjectObj) {
    return GlobalEffectCount($player, 'SWU_DEALT_INDIRECT') > 0 ? -1 : 0;
};

// JTL_163 AT-DP Occupier: costs 1 less for each damaged ground unit (any player's).
$playCostModifiers["JTL_163"] = function($player, $subjectObj) {
    $cnt = 0;
    foreach ([1, 2] as $p) {
        foreach (GetGroundArena($p) as $u) {
            if (empty($u->removed) && intval($u->Damage) > 0) $cnt++;
        }
    }
    return -1 * $cnt;
};

// SEC_122 Vuutun Palaa: costs 1 resource less for each friendly Droid unit in play.
// "Droid" is a TRAIT in SWU (CardSubtypes always returns '' — traits live in $traitData).
// HasTrait checks $traitData. GetField covers both ground and space arenas, and includes
// all unit types (Token Unit, Leader Unit) because AddGroundArena/AddSpaceArena puts
// everything into those arrays regardless of whether it's a token or deployed leader.
// Battle Droid tokens (TWI_T01, trait Separatist,Droid,Trooper) count correctly.
$playCostModifiers["SEC_122"] = function($player, $subjectObj) {
    $count = 0;
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (HasTrait($u->CardID, 'Droid')) $count++;
    }
    return -1 * $count;
};

// Source/field-presence play-cost modifiers: a unit IN PLAY that changes the cost
// of OTHER cards being played. Keyed by the SOURCE card's ID; consulted by
// SWUComputePlayCost for every field object of either player.
//   fn($subjectObj, $subjectPlayer, $sourceObj): int   (positive = more expensive)
$playCostFieldModifiers = [];

// SOR_181 Jabba the Hutt: each TRICK event YOU (Jabba's controller) play costs 1 less.
$playCostFieldModifiers["SOR_181"] = function($subjectObj, $subjectPlayer, $sourceObj) {
    $srcController = intval($sourceObj->Controller ?? 0);
    if ($srcController <= 0 || $srcController !== intval($subjectPlayer)) return 0; // only your own
    if (!HasTrait($subjectObj->CardID, 'Trick')) return 0;
    if (stripos(CardType($subjectObj->CardID) ?? '', 'Event') === false) return 0;
    return -1;
};

// JTL_188 Moff Gideon: after he deals combat damage to an opponent's base (sets SWU_GIDEON_TAX on that
// opponent), each unit that opponent plays this phase costs 1 more. Gated on Gideon being in play.
$playCostFieldModifiers["JTL_188"] = function($subjectObj, $subjectPlayer, $sourceObj) {
    $srcController = intval($sourceObj->Controller ?? 0);
    if ($srcController <= 0 || $srcController === intval($subjectPlayer)) return 0; // only Gideon's opponent
    if (stripos(CardType($subjectObj->CardID) ?? '', 'Unit') === false) return 0;  // units only
    if (GlobalEffectCount(intval($subjectPlayer), 'SWU_GIDEON_TAX') <= 0) return 0;
    return 1;
};

// SOR_034 Del Meeko: each event an opponent plays costs 1 more.
$playCostFieldModifiers["SOR_034"] = function($subjectObj, $subjectPlayer, $sourceObj) {
    $srcController = intval($sourceObj->Controller ?? 0);
    if ($srcController <= 0 || $srcController === intval($subjectPlayer)) return 0; // only opponents
    if (stripos(CardType($subjectObj->CardID) ?? '', 'Event') === false) return 0;
    return 1;
};

// JTL_032 Director Krennic: the FIRST unit you play each round that has a "When Defeated" ability costs
// 1 resource less. Eligibility = source JTL_032 in play, subject is YOUR unit with a WhenDefeated
// ability, and the once-per-round SWU_KRENNIC_USED flag isn't set yet (set in ActivateCard after the
// first such play; cleared at RegroupPhaseStart). The flag-set happens AFTER cost is charged, so the
// first qualifying play still receives the -1 (flag was 0 during cost computation).
$playCostFieldModifiers["JTL_032"] = function($subjectObj, $subjectPlayer, $sourceObj) {
    $srcController = intval($sourceObj->Controller ?? 0);
    if ($srcController <= 0 || $srcController !== intval($subjectPlayer)) return 0; // only your own plays
    if (!HasWhenDefeatedAbility($subjectObj->CardID ?? '')) return 0;
    if (GlobalEffectCount(intval($subjectPlayer), 'SWU_KRENNIC_USED') > 0) return 0; // already used this round
    return -1;
};

// LOF_108 Malakili: the FIRST Creature unit you play each phase costs 1 resource less. Mirrors JTL_032
// (SWU_LOF108_CREATURE_USED set in ActivateCard after the first Creature play; cleared at RegroupPhaseStart;
// the flag-set happens AFTER cost is charged, so the first Creature still receives the -1).
$playCostFieldModifiers["LOF_108"] = function($subjectObj, $subjectPlayer, $sourceObj) {
    $srcController = intval($sourceObj->Controller ?? 0);
    if ($srcController <= 0 || $srcController !== intval($subjectPlayer)) return 0; // only your own plays
    if (!HasTrait($subjectObj->CardID ?? '', 'Creature')) return 0;
    if (stripos(CardType($subjectObj->CardID) ?? '', 'Unit') === false) return 0;  // Creature UNIT
    if (GlobalEffectCount(intval($subjectPlayer), 'SWU_LOF108_CREATURE_USED') > 0) return 0;
    return -1;
};

// True if $player controls Director Krennic (JTL_032) as a unit in either arena.
function _SWUControlsKrennic(int $player): bool {
    if ($player <= 0) return false;
    foreach (GetField($player) as $u) {
        if (empty($u->removed) && ($u->CardID ?? '') === 'JTL_032') return true;
    }
    return false;
}

// LOF_108 Malakili rider — true when a $sourceMzID Creature would deal damage to friendly $targetUnit
// and the shared controller has Malakili (LOF_108) in play, so the damage must be prevented. Source +
// target must share a controller (friendly→friendly); the source must carry the Creature trait.
function _SWULof108PreventsCreatureDamage(string $sourceMzID, $targetUnit): bool {
    $src = GetZoneObject($sourceMzID);
    if ($src === null || !empty($src->removed)) return false;
    if (!HasTrait($src->CardID ?? '', 'Creature')) return false;
    $srcController = intval($src->Controller ?? -1);
    if ($srcController < 0 || $srcController !== intval($targetUnit->Controller ?? -2)) return false;
    foreach (GetField($srcController) as $u) {
        if (empty($u->removed) && ($u->CardID ?? '') === 'LOF_108') return true;
    }
    return false;
}

// JTL_005 Admiral Piett (deployed leader unit): each Capital Ship unit YOU (Piett's controller) play
// costs 2 resources less. Only fires while Piett is in play as a Leader Unit (GetField includes deployed
// leaders), so the leader-side action discount (–1) and this deployed passive never stack.
$playCostFieldModifiers["JTL_005"] = function($subjectObj, $subjectPlayer, $sourceObj) {
    $srcController = intval($sourceObj->Controller ?? 0);
    if ($srcController <= 0 || $srcController !== intval($subjectPlayer)) return 0; // only your own plays
    if (!HasTrait($subjectObj->CardID, 'Capital Ship')) return 0;
    return -2;
};

// A card is "non-[Heroism], non-[Villainy]" (neutral) when its aspect string carries
// neither alignment — used by SOR_056 Bendu's "next neutral card costs 2 less".
function _SWUIsNeutralCard($cardID): bool {
    $asp = CardAspect($cardID) ?? '';
    return stripos($asp, 'Heroism') === false && stripos($asp, 'Villainy') === false;
}

// True if $player controls a unit with the Force trait (SOR_138 / SOR_167 conditional bonuses).
function _SWUControlsForceUnit(int $player): bool {
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (_SWUUnitHasTrait($u, 'Force')) return true;
    }
    return false;
}

// SOR_061 Guardian of the Whills: "the first upgrade you play on this unit each round costs 1 less."
// True if $player controls a Guardian whose per-round upgrade-discount charge is still unused (flag
// SWU_GUARDIAN_UPG_USED_{uid}, set on attach, cleared at ActionPhaseStart). Each Guardian has its own
// charge, so multiple Guardians grant multiple discounts.
function _SWUFirstUpgradeGuardianAvailable(int $player): bool {
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed) || !in_array($u->CardID ?? '', ['SOR_061', 'LOF_058'], true)) continue;
        $uid = intval($u->UniqueID ?? 0);
        if (GlobalEffectCount($player, 'SWU_GUARDIAN_UPG_USED_' . $uid) <= 0) return true;
    }
    return false;
}

// Final cost to play $obj from $player's hand: base cost + aspect penalty + all
// modifiers, floored at 0. The single source of truth for play cost.
//
// $host (optional): when provided at payment time (upgrade path, post-host-selection),
// the SOR_061 Guardian discount is host-specific — −1 only if the chosen host IS a
// controlled SOR_061 with an unused per-round charge. When $host is null (affordability /
// GLOW check), the old best-case logic applies: −1 if ANY Guardian has a spare charge.
function SWUComputePlayCost($player, $obj, $host = null): int {
    if ($obj === null || !isset($obj->CardID)) return 0;
    global $playCostModifiers, $playCostFieldModifiers;
    $cardID = $obj->CardID;
    $cost = intval(CardCost($cardID)) + SWUAspectPenalty($player, $cardID);
    // Subject-keyed modifiers (the card discounts/surcharges itself).
    // SEC_046 Galen Erso — a named card has lost its own cost-modifier ability.
    if (isset($playCostModifiers[$cardID]) && !_SWUGalenSuppressesCard(intval($player), $cardID)) {
        $cost += intval($playCostModifiers[$cardID]($player, $obj));
    }
    // SOR_056 Bendu: one-shot armed "next non-Heroism/non-Villainy card costs 2 less".
    // The charge is consumed in ActivateCard when such a card is actually played.
    if (GlobalEffectCount(intval($player), 'SWU_NEUTRAL_DISCOUNT') > 0 && _SWUIsNeutralCard($cardID)) {
        $cost += -2;
    }
    // JTL_098 Snap Wexley: one-shot armed "next Resistance card you play this phase costs 1 less".
    // Consumed in ActivateCard when such a card is actually played.
    if (GlobalEffectCount(intval($player), 'SWU_SNAP_DISCOUNT') > 0 && HasTrait($cardID, 'Resistance')) {
        $cost += -1;
    }
    // LOF_005 Morgan Elsbeth (deployed) On Attack: one-shot "next unit you play this phase costs 1 less if
    // it shares a keyword with a friendly unit". Charge consumed in ActivateCard on the next unit play.
    if (GlobalEffectCount(intval($player), 'SWU_LOF005_DISCOUNT_NEXT') > 0
            && stripos(CardType($cardID) ?? '', 'Unit') !== false
            && _SWULof005SharesKeywordWithFriendly(intval($player), $cardID)) {
        $cost += -1;
    }
    // SEC_110 GNK Power Droid (On Attack): one-shot armed "the next unit you play this phase costs 1 less".
    // Charge consumed in ActivateCard on the next unit play; cleared at RegroupPhaseStart.
    if (GlobalEffectCount(intval($player), 'SWU_SEC110_DISCOUNT_NEXT') > 0
            && stripos(CardType($cardID) ?? '', 'Unit') !== false) {
        $cost += -1;
    }
    // SEC_261 Inspiring Senator (When Defeated): one-shot armed "the next OFFICIAL unit you play this
    // phase costs 1 less". Consumed in ActivateCard on the next Official unit play; cleared at RGS.
    if (GlobalEffectCount(intval($player), 'SWU_SEC261_OFFICIAL_DISCOUNT') > 0
            && stripos(CardType($cardID) ?? '', 'Unit') !== false && HasTrait($cardID, 'Official')) {
        $cost += -1;
    }
    // SEC_001 Chancellor Palpatine (deployed): "the next card you play using Plot this phase costs 3
    // resources less." "Using Plot" = the card is played FROM the resource zone (a Resources object;
    // a normal hand play of a Plot-keyword card is NOT using Plot). Consumed in ActivateCard when such
    // a card is actually played; cleared at RegroupPhaseStart.
    global $Plot_Cards;
    if (GlobalEffectCount(intval($player), 'SWU_SEC001_PLOT_DISCOUNT') > 0
            && isset($Plot_Cards[$cardID])
            && is_object($obj) && ($obj instanceof Resources)) {
        $cost += -3;
    }
    // JTL_260 Death Star Plans: attached unit grants "the first unit you play each round costs 2 less".
    // Applies while the player controls a unit bearing JTL_260 and hasn't used the discount this round.
    // Consumed in ActivateCard on the first unit play; cleared at RegroupPhaseStart.
    if (strpos(CardType($cardID) ?? '', 'Unit') !== false
            && GlobalEffectCount(intval($player), 'SWU_JTL260_USED') <= 0
            && _SWUControlsUnitBearingUpgrade(intval($player), 'JTL_260')) {
        $cost += -2;
    }
    // LAW_058 Honor-Bound Partisan (When Defeated): one-shot armed "the next unit you play this phase
    // costs 1 less." Consumed in ActivateCard on the next unit play; cleared at RegroupPhaseStart.
    if (GlobalEffectCount(intval($player), 'SWU_LAW058_DISCOUNT_NEXT') > 0
            && stripos(CardType($cardID) ?? '', 'Unit') !== false) {
        $cost += -1;
    }
    // ASH_027 Enoch (When Defeated): "the next unit you play this phase costs 1 less for every 2 damage
    // dealt this way." Count-based charge (1 per discount); consumed in ActivateCard; cleared at RGS.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false) {
        $cost += -GlobalEffectCount(intval($player), 'SWU_ASH027_DISCOUNT_NEXT');
    }
    // SHD_006 Jabba's collected Bounty: "the next unit you play this phase costs N less." Count-based
    // charge (1 per resource of discount, accumulates across collected bounties); consumed on the next
    // unit play in ActivateCard; cleared at RegroupPhaseStart.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false) {
        $cost += -GlobalEffectCount(intval($player), 'SWU_SHD006_DISCOUNT_NEXT');
    }
    // LAW_158 Khetanna: one-shot armed "the next Underworld unit you play this phase costs 1 less."
    // Consumed in ActivateCard on the next Underworld unit play; cleared at RegroupPhaseStart.
    if (GlobalEffectCount(intval($player), 'SWU_LAW158_DISCOUNT_NEXT') > 0
            && stripos(CardType($cardID) ?? '', 'Unit') !== false && HasTrait($cardID, 'Underworld')) {
        $cost += -1;
    }
    // ASH_237 Mouse Droid (When Played): "the next Imperial unit you play this phase costs 1 less."
    if (GlobalEffectCount(intval($player), 'SWU_ASH237_DISCOUNT_NEXT') > 0
            && stripos(CardType($cardID) ?? '', 'Unit') !== false && HasTrait($cardID, 'Imperial')) {
        $cost += -1;
    }
    // LAW_229 The Master Codebreaker: "the first Gambit card you play each round costs 1 resource less."
    // Applies while the player controls LAW_229 and hasn't used the discount this round. Consumed in
    // ActivateCard on the first Gambit play; cleared at RegroupPhaseStart.
    if (HasTrait($cardID, 'Gambit')
            && GlobalEffectCount(intval($player), 'SWU_LAW229_USED') <= 0
            && _SWUCountUnitsWithCardID(intval($player), 'LAW_229') > 0) {
        $cost += -1;
    }
    // SOR_061 Guardian of the Whills: "the first upgrade you play on this unit each round costs 1 less."
    // Two modes:
    //   $host === null  → affordability / GLOW: best-case −1 if any Guardian has a spare charge.
    //   $host !== null  → payment time (post-host selection): −1 only if THIS host is a Guardian
    //                     with an unused charge. No claw-back needed — payment is now exact.
    if (stripos(CardType($cardID) ?? '', 'Upgrade') !== false) {
        if ($host === null) {
            // Best-case affordability check.
            if (_SWUFirstUpgradeGuardianAvailable(intval($player))) {
                $cost += -1;
            }
        } else {
            // Host-specific exact discount.
            $hostUid = intval($host->UniqueID ?? 0);
            if (in_array($host->CardID ?? '', ['SOR_061', 'LOF_058'], true)
                && GlobalEffectCount(intval($player), 'SWU_GUARDIAN_UPG_USED_' . $hostUid) <= 0) {
                $cost += -1;
            }
        }
    }
    // LAW_129 Mastery — "This upgrade costs 1 resource less to play on a non-unique unit." Two modes:
    //   $host === null → best-case affordability: −1 if any friendly non-unique unit exists to host it.
    //   $host !== null → payment time: −1 only if the chosen host is non-unique. (No claw-back needed.)
    if ($cardID === 'LAW_129') {
        if ($host === null) {
            foreach (GetUnitsInPlay(intval($player)) as $hu) {
                if (empty($hu->removed) && !CardUnique($hu->CardID ?? '')) { $cost += -1; break; }
            }
        } elseif (!CardUnique($host->CardID ?? '')) {
            $cost += -1;
        }
    }
    // ASH_262 Faith in the Empire — "costs 1 resource less to play on an Imperial unit." (host-trait, LAW_129 pattern)
    if ($cardID === 'ASH_262') {
        if ($host === null) {
            foreach (GetUnitsInPlay(intval($player)) as $hu) { if (empty($hu->removed) && HasTrait($hu->CardID ?? '', 'Imperial')) { $cost += -1; break; } }
        } elseif (HasTrait($host->CardID ?? '', 'Imperial')) { $cost += -1; }
    }
    // ASH_263 The Way of the Mand'alor — "costs 1 resource less to play on a Mandalorian unit."
    if ($cardID === 'ASH_263') {
        if ($host === null) {
            foreach (GetUnitsInPlay(intval($player)) as $hu) { if (empty($hu->removed) && HasTrait($hu->CardID ?? '', 'Mandalorian')) { $cost += -1; break; } }
        } elseif (HasTrait($host->CardID ?? '', 'Mandalorian')) { $cost += -1; }
    }
    // LAW_009 Hera Syndulla — "While you control 2 or more units, ignore the aspect penalties on Heroism
    // units you play." Passive (works in leader form OR deployed); waive the full aspect penalty.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false
            && strpos(CardAspect($cardID) ?? '', 'Heroism') !== false
            && _SWUControlsTitle(intval($player), ['Hera Syndulla'])) {
        $units = 0;
        foreach (GetUnitsInPlay(intval($player)) as $hu) { if (empty($hu->removed)) $units++; }
        if ($units >= 2) $cost -= SWUAspectPenalty(intval($player), $cardID);
    }
    // SEC_064 Congress of Malastare — "the first upgrade you play each phase costs 1 resource less"
    // (while you control SEC_064). Applies to any upgrade; consumed at ATTACH_UPGRADE on the first play.
    if (stripos(CardType($cardID) ?? '', 'Upgrade') !== false
            && GlobalEffectCount(intval($player), 'SWU_SEC064_USED') <= 0
            && _SWUCountUnitsWithCardID(intval($player), 'SEC_064') > 0) {
        $cost += -1;
    }
    // ASH_075 Pit Droid Team — "The first upgrade you play on another friendly unit each phase costs 1
    // resource less." Mirrors SEC_064 (the on-another-friendly nuance is enforced at the ATTACH consume).
    if (stripos(CardType($cardID) ?? '', 'Upgrade') !== false
            && GlobalEffectCount(intval($player), 'SWU_ASH075_USED') <= 0
            && _SWUCountUnitsWithCardID(intval($player), 'ASH_075') > 0) {
        $cost += -1;
    }
    // Field-presence modifiers (a unit in play changes other cards' costs) +
    // generated PlayCostModifier abilities, over every field object of both players.
    $hasGenerated = function_exists('EvaluatePlayCostModifier');
    if ($hasGenerated) {
        $cost += intval(EvaluatePlayCostModifier($cardID, $player, $obj, $cost, null));
    }
    foreach ([1, 2] as $fp) {
        foreach (GetField($fp) as $fo) {
            // SEC_046 Galen Erso — a named source unit no longer modifies other cards' costs.
            if ($fo === null || !empty($fo->removed) || HasNoAbilities($fo) || LostAbilities($fo)) continue;
            if (isset($playCostFieldModifiers[$fo->CardID])) {
                $cost += intval($playCostFieldModifiers[$fo->CardID]($obj, $player, $fo));
            }
            if ($hasGenerated) {
                $cost += intval(EvaluatePlayCostModifier($fo->CardID, $player, $obj, $cost, $fo));
            }
        }
    }
    return max(0, $cost);
}

// Piloting cost: the bracket cost Y from the card's Piloting keyword, plus the
// off-aspect penalty for the player. Used when a pilot is played/deployed as an
// upgrade. Returns 0 for non-pilots / cards with no Piloting cost.
function SWUComputePilotCost($player, $obj): int {
    if ($obj === null || !isset($obj->CardID)) return 0;
    $cardID = $obj->CardID;
    $base = CardPilotingCost($cardID);
    if ($base === null) return 0;
    // SWU_PILOT_DISCOUNT: a one-shot "next Piloting play costs N less" (JTL_008 Wedge Antilles).
    // Honored here — the single pilot-cost chokepoint used by BOTH affordability
    // (SWUGetPilotValidTargets) AND the charge (_SWUFinalizeUpgradeAttach) — so the two stay
    // consistent. Consumed once in _SWUFinalizeUpgradeAttach after a successful pilot pay.
    $discount = GlobalEffectCount(intval($player), 'SWU_PILOT_DISCOUNT');
    return max(0, intval($base) + SWUAspectPenalty($player, $cardID) - $discount);
}

// Create a unit token ($tokenID) for $player in the token's printed arena (Ground/Space).
// Tokens enter exhausted by default (Status 0); pass $ready=true for "enters ready" effects.
// No WhenPlayed triggers fire for tokens (mirrors the SOR_087 / JTL_100 free-placement pattern).
// Returns the new token's UniqueID (callers may ignore it; used to further tag the token, e.g. grant
// a phase keyword to a just-created Spy — SEC_082).
// Raw single-token creation (the board mutation + per-token side effects: Shielded-on-create, the
// SWU_CREATED_TOKEN flag, the ASH_017 Greef offer). Callers should use SWUCreateUnitToken /
// SWUCreateUnitTokens instead so ASH_094 Moff Jerjerrod's "create twice that number" replacement is
// offered; this raw helper deliberately skips that offer (used for the doubled tokens themselves).
function _SWUCreateOneToken(int $player, string $tokenID, bool $ready = false): int {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $uid    = NextUniqueID();
    $status = $ready ? 1 : 0;
    if (CardTargetArena($tokenID) === 'SpaceArena') {
        $newCard = AddSpaceArena($player, CardID: $tokenID, Status: $status, Owner: $player,
            Damage: 0, Controller: $player, UniqueID: $uid);
    } else {
        $newCard = AddGroundArena($player, CardID: $tokenID, Status: $status, Owner: $player,
            Damage: 0, Controller: $player, UniqueID: $uid);
    }
    // Shielded (e.g. ASH_T01 Mandalorian token, or a Vehicle token while JTL_047 Yularen grants Shielded)
    // applies when the unit enters play, including by being created — give it a Shield token now. Creation
    // is NOT "playing", so other entry triggers (WhenPlayed/Ambush) deliberately don't fire here.
    if ($newCard !== null && empty($newCard->removed) && HasKeyword_Shielded($newCard)) {
        DoGiveShieldToken($player, $newCard->GetMzID());
    }
    AddGlobalEffects(intval($player), 'SWU_CREATED_TOKEN'); // LAW_016 "if you created a token this phase"
    // ASH_017 Greef Karga — "When you play OR create a unit: may exhaust leader → Advantage to that unit."
    // Creation isn't "playing", so queue the offer directly (the play half rides SWUCollectOwnPlayReactions).
    if ($newCard !== null && empty($newCard->removed) && _SWULeaderReadyUndeployed($player, 'ASH_017')) {
        DecisionQueueController::AddDecision($player, "YESNO", "-", 1, tooltip: "Exhaust_Greef_to_give_the_created_unit_an_Advantage_token?");
        DecisionQueueController::AddDecision($player, "CUSTOM", "ASH_017#0|{$uid}", 1);
    }
    $playerID = $savedPID;
    return $uid;
}

// Create ONE token unit for $player, returning its UniqueID. ASH_094 Moff Jerjerrod: if the player
// controls a Jerjerrod, this offers the "defeat Jerjerrod → create twice that number (2) instead"
// replacement after the token is made.
function SWUCreateUnitToken(int $player, string $tokenID, bool $ready = false): int {
    $uid = _SWUCreateOneToken($player, $tokenID, $ready);
    _SWUMaybeOfferJerjerrodDouble($player, $tokenID, 1, $ready);
    return $uid;
}

// Create $count token units of the SAME type for $player (a single "create a number of tokens"
// instruction). Returns the UniqueIDs of the tokens created now. $turnEffect (optional) is applied to each
// created token (e.g. 'CANT_ATTACK_BASES' for JTL_092, 'JTL_130' Sentinel) — it is also carried through
// the Jerjerrod doubling so the doubled tokens get it too. ASH_094 Moff Jerjerrod's doubling is offered
// ONCE for the whole batch (creating $count MORE on accept).
function SWUCreateUnitTokens(int $player, string $tokenID, int $count, bool $ready = false, string $turnEffect = ''): array {
    $uids = [];
    if ($count <= 0) return $uids;
    for ($i = 0; $i < $count; $i++) {
        $uid = _SWUCreateOneToken($player, $tokenID, $ready);
        $uids[] = $uid;
        if ($turnEffect !== '') {
            $mz = SWUFindMzByUID($uid);
            if ($mz !== null) AddTurnEffect($mz, $turnEffect);
        }
    }
    _SWUMaybeOfferJerjerrodDouble($player, $tokenID, $count, $ready, $turnEffect);
    return $uids;
}

// ASH_094 Moff Jerjerrod — "If you would create a number of tokens, you may defeat this unit. If you do,
// create twice that number of tokens instead." The $count tokens were just created; if $player controls a
// Jerjerrod, offer to defeat it and create $count MORE of the same token (net 2×count). Gated on a
// Jerjerrod being in play, so the no-Jerjerrod path is byte-for-byte the old behavior.
function _SWUMaybeOfferJerjerrodDouble(int $player, string $tokenID, int $count, bool $ready, string $turnEffect = ''): void {
    if ($count < 1) return;
    $jUID = 0;
    foreach (GetUnitsInPlay($player) as $u) {
        if (empty($u->removed) && ($u->CardID ?? '') === 'ASH_094') { $jUID = intval($u->UniqueID ?? 0); break; }
    }
    if ($jUID <= 0) return;
    $r = $ready ? 1 : 0;
    DecisionQueueController::AddDecision($player, 'YESNO', '-', 1,
        tooltip: 'Defeat_Moff_Jerjerrod_to_create_twice_as_many_tokens?');
    DecisionQueueController::AddDecision($player, 'CUSTOM', "ASH_094_DOUBLE|{$tokenID}|{$count}|{$r}|{$jUID}|{$turnEffect}", 1);
}

// True if $obj is a valid "Resistance unit OR a unit with a Resistance upgrade on it" target
// (JTL_007 Admiral Holdo). The Resistance trait may be on the unit itself or on any of its
// upgrade subcards (e.g. a Resistance pilot attached to a Vehicle).
function _SWUIsResistanceTarget($obj): bool {
    if ($obj === null || !empty($obj->removed)) return false;
    if (HasTrait($obj->CardID ?? '', 'Resistance')) return true;
    foreach (GetUpgradesOnUnit($obj) as $u) {
        if (HasTrait($u->CardID ?? '', 'Resistance')) return true;
    }
    return false;
}

// SWU affordability: player has enough ready resources to cover the card's
// cost (including aspect penalty and cost modifiers). Overrides the GA version.
function CanAffordActivationReserve($player, $obj) {
    if ($obj === null || !isset($obj->CardID)) return false;
    // SOR_062 Regional Governor: a card named by an opponent is not playable (don't glow it).
    if (SWUCardPlayBlocked(intval($player), $obj->CardID)) return false;
    // SEC_053 etc.: "can't be played from your hand" — this affordability check is hand-only
    // (called solely for Location==Hand cards), so suppress the hand glow.
    if (_SWUCantPlayFromHand($obj->CardID)) return false;
    $cost    = SWUComputePlayCost($player, $obj);
    $cost    = SWUApplyCostHalving(intval($player), $cost); // JTL_105 The Starhawk — affordable at half
    $ready   = 0;
    $res     = GetResources($player);
    for ($i = 0; $i < count($res); $i++) {
        if (isset($res[$i]->removed) && $res[$i]->removed) continue;
        if (SWUIsCreditToken($res[$i]->CardID ?? '')) continue; // Credit tokens aren't resources
        if (intval($res[$i]->Status) === 1) $ready++;
    }
    return $ready >= $cost;
}

// ── Macro ChoiceFunctions ───────────────────────────────────────────────────

function DoDrawCard($player, $amount) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);

    $deck  = GetDeck($player);
    $drawn = [];

    for ($i = 0; $i < intval($amount); $i++) {
        // Top of deck = FIRST non-removed entry (index 0). This matches the rest of the engine's
        // deck-top convention — DoScry, the look-at-top family (SOR_119/152/192), the test harness
        // topCardID, and the deck builder (first WithP1Deck = top) — so a card left or placed on
        // top is the next one drawn. (Previously this drew from the LAST index, the lone outlier.)
        $topIdx = null;
        for ($j = 0; $j < count($deck); $j++) {
            if (!isset($deck[$j]->removed) || !$deck[$j]->removed) { $topIdx = $j; break; }
        }
        if ($topIdx === null) break;

        $newObj = MZMove($player, "myDeck-$topIdx", "myHand");
        if ($newObj !== null) {
            if (function_exists('SWUTelemetryBumpCard')) SWUTelemetryBumpCard($player, $newObj->CardID ?? '', 'drawn');
            $hand = GetHand($player);
            for ($k = count($hand) - 1; $k >= 0; $k--) {
                if (!isset($hand[$k]->removed) || !$hand[$k]->removed) {
                    $drawn[] = "myHand-$k";
                    break;
                }
            }
        }
    }

    $playerID = $savedPID;
    // Per-phase "cards you've drawn this phase" counter (LAW_051 Beilert Valance). Action phase only;
    // cleared at RegroupPhaseStart.
    if (!empty($drawn) && GetCurrentPhase() === 'MAIN') {
        for ($d = 0; $d < count($drawn); $d++) AddGlobalEffects(intval($player), 'SWU_DREW_PHASE');
    }
    // Reactive "when a player draws 1+ cards during the action phase" hook (JTL_111 / SHD_184).
    if (!empty($drawn) && function_exists('_SWUOnPlayerDrew')) _SWUOnPlayerDrew(intval($player), count($drawn));
    // "When you draw THIS card during the action phase" hook (LOF_148 — needs the drawn card identities).
    if (!empty($drawn)) _SWUOnDrawLof148(intval($player), $drawn);
    return empty($drawn) ? "-" : (count($drawn) === 1 ? $drawn[0] : implode("&", $drawn));
}

// True if $player controls a leader OR base with the Aggression aspect (LOF_148's draw condition).
function _SWUControlsAggressionLeaderOrBase(int $player): bool {
    foreach ([GetLeader($player) ?? [], GetBase($player) ?? []] as $zone) {
        foreach ($zone as $c) {
            if (!empty($c->removed)) continue;
            if (strpos(CardAspect($c->CardID ?? '') ?? '', 'Aggression') !== false) return true;
        }
    }
    return false;
}

// LOF_148 — "When you draw this card during the action phase: if you control an Aggression leader or
// base, you may reveal it from your hand. If you do, deal 2 damage to a unit and 2 damage to a base."
function _SWUOnDrawLof148(int $player, array $drawn): void {
    if (GetCurrentPhase() !== 'MAIN') return;                  // action phase only
    if (!_SWUControlsAggressionLeaderOrBase($player)) return;
    global $playerID; $savedPID = $playerID; $playerID = intval($player);
    foreach ($drawn as $mz) {
        $o = GetZoneObject($mz);
        if ($o !== null && empty($o->removed) && ($o->CardID ?? '') === 'LOF_148') {
            DecisionQueueController::AddDecision($player, 'YESNO', '-', 1,
                tooltip: "Reveal_LOF_148_to_deal_2_to_a_unit_and_2_to_a_base?");
            DecisionQueueController::AddDecision($player, 'CUSTOM', "LOF_148#0", 1);
        }
    }
    $playerID = $savedPID;
}

function DoResourceCard($player, $mzID) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $newObj   = MZMove($player, $mzID, "myResources");
    if ($newObj !== null && function_exists('SWUTelemetryBumpCard')) SWUTelemetryBumpCard($player, $newObj->CardID ?? '', 'resourced');
    if ($newObj !== null) SWUKeepCreditTokensLast(intval($player)); // Credit tokens stay at the end
    $playerID = $savedPID;
    return $newObj !== null ? $mzID : "-";
}

function DoDiscardCard($player, $mzID) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $fromHand = (strpos($mzID, 'Hand') !== false);
    $newObj   = MZMove($player, $mzID, "myDiscard");
    if ($fromHand && $newObj !== null && function_exists('SWUTelemetryBumpCard')) SWUTelemetryBumpCard($player, $newObj->CardID ?? '', 'discarded');
    $playerID = $savedPID;
    // Per-phase counter of cards discarded from a player's hand (LAW_179 cost reduction). Cleared at
    // RegroupPhaseStart with the other per-phase flags.
    if ($fromHand && $newObj !== null) AddGlobalEffects(intval($player), 'SWU_DISCARDED_HAND');
    // "Discarded a card from your hand OR deck this phase" (LAW_076). Hand discards count here; deck
    // mills add it in SWUMillTopCard. (Excludes played events — those never route through DoDiscardCard.)
    if ($fromHand && $newObj !== null) AddGlobalEffects(intval($player), 'SWU_DISCARDED_PHASE');
    // SEC_016 Padmé Amidala — "When you discard 1 or more cards from your hand: …" (per-call; a single
    // effect discarding multiple cards over-triggers the deploy side — a rare edge).
    if ($fromHand && $newObj !== null && function_exists('_SWUSec016React')) _SWUSec016React(intval($player));
    return $newObj !== null ? $mzID : "-";
}

// Return the discard entry at $discardMzID (e.g. "myDiscard-2") to the player's
// hand. Used by SOR_101 ("return a unit that costs 2 or less from your discard").
function SWUReturnFromDiscardToHand($player, $discardMzID) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $newObj   = MZMove($player, $discardMzID, "myHand");
    $playerID = $savedPID;
    return $newObj !== null;
}

// Return a card from ANY discard pile to its OWNER's hand (the discard pile's player owns its cards,
// CR 7.5). $discardMzID is relative to $player: "myDiscard-N" → $player's hand; "theirDiscard-N" →
// the opponent's hand (re-resolved from the opponent's "myDiscard" perspective). For "return an
// event from a discard pile to its owner's hand" (SOR_183).
function SWUReturnDiscardCardToOwnerHand(int $player, string $discardMzID): bool {
    $parts = explode('-', $discardMzID);
    $idx   = intval($parts[1] ?? 0);
    if (str_starts_with($discardMzID, 'theirDiscard')) {
        return SWUReturnFromDiscardToHand(GetOpponent($player), "myDiscard-{$idx}");
    }
    return SWUReturnFromDiscardToHand($player, $discardMzID);
}

// Return a resource (at $resourceMzID, relative to $player) to its OWNER's hand. Used by Lando
// (SOR_197) "return up to N friendly resources to their owners' hands". Caller batches removals and
// runs a single CleanupRemovedCards (indices shift per removal).
function SWUReturnResourceToHand(int $player, string $resourceMzID): bool {
    global $playerID;
    $saved = $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($resourceMzID);
    if ($obj === null || !empty($obj->removed)) { $playerID = $saved; return false; }
    // Resource Owner is often 0 (unset, e.g. fixtures / freshly-resourced cards) — default to the
    // controlling player, else AddHand(0) silently drops the returned card (documented zone-Owner gotcha).
    $owner = intval($obj->Owner ?? 0);
    if ($owner <= 0) $owner = intval($player);
    $obj->removed = true;
    AddHand($owner, CardID:$obj->CardID);
    $playerID = $saved;
    return true;
}

function SWUDiscardCards(int $player, int $numCards): void {
    $opponent  = OtherPlayer($player);
    $hand      = GetHand($opponent);
    $handCount = 0;
    foreach ($hand as $card) {
        if (isset($card->removed) && $card->removed) continue;
        $handCount++;
    }
    if ($handCount === 0) return;

    if ($handCount <= $numCards) {
        global $playerID;
        $savedPID = $playerID;
        $playerID = $opponent;
        foreach ($hand as $card) {
            if (isset($card->removed) && $card->removed) continue;
            $card->Remove();
            SWUAddToDiscard($opponent, $card->CardID, 'HAND');
        }
        $playerID = $savedPID;
    } else {
        for ($n = 0; $n < $numCards; $n++) {
            DecisionQueueController::AddDecision($opponent, "MZCHOOSE", "myHand", 1,
                tooltip:"Choose_card_to_discard");
            DecisionQueueController::AddDecision($opponent, "CUSTOM", "DISCARD_FROM_OWN_HAND|{$opponent}", 1);
        }
    }
}

// "$player keeps $keep cards of their choice, discards the rest of their hand" (SOR_174 Smoke and
// Cinders, "each player discards all but 2 of their choice"). Builds the keep-N MZMULTICHOOSE over
// $player's own hand; the follow-up SOR_174 discards every card NOT kept. No-op (no decision)
// when the hand already has ≤ $keep cards. Cleans removed entries FIRST so the spec's mzIDs match the
// compacted indices the resolver will see (the caster's just-played event lingers as a removed entry).
// Leaves $playerID = $player so the harness MZCountChoices resolves the relative mzIDs under $player.
function SWUKeepNDiscardRest(int $player, int $keep, string $tooltip): void {
    global $playerID;
    $playerID = intval($player);
    DecisionQueueController::CleanupRemovedCards();
    $hand = array_values(ZoneSearch("myHand"));
    if (count($hand) <= $keep) return;   // nothing to discard
    DecisionQueueController::AddDecision($player, "MZMULTICHOOSE", "{$keep}|{$keep}|" . implode("&", $hand), 1,
        tooltip:$tooltip);
    DecisionQueueController::AddDecision($player, "CUSTOM", "SOR_174#0|{$player}", 1);
}

// "Look at an opponent's hand" — logs a PRIVATE reveal (visible only to the acting player) of the
// opponent's hand, and returns the opponent's hand cards as MZCHOOSE targets from $player's
// perspective ("theirHand-N"). $filter (optional) restricts which cards are returned as targets
// (e.g. non-unit for SOR_201 Bodhi Rook) — the reveal still lists the WHOLE hand. Used by the
// "look at an opponent's hand [and discard …]" family (SOR_228, SOR_200, SOR_201).
function SWULookAtOpponentHand(int $player, ?callable $filter = null): array {
    global $playerID;
    $savedPID = $playerID; $playerID = intval($player);
    $opp     = OtherPlayer(intval($player));
    $oppHand = GetHand($opp);
    $refs = []; $targets = [];
    foreach ($oppHand as $i => $card) {
        if (!empty($card->removed)) continue;
        $refs[] = GameLogCardRef($card->CardID);
        if ($filter === null || $filter($card->CardID)) $targets[] = "theirHand-$i";
    }
    $msg = 'P' . intval($player) . " looked at P{$opp}'s hand: " . (empty($refs) ? '(empty)' : implode(', ', $refs));
    // For now (2-player) the reveal is visible to both players (effectively public). In a future
    // 4-player Twin Suns format this should be scoped to just the two players involved.
    AddGameLogEntry('REVEAL', $msg, 'ALL');
    $playerID = $savedPID;
    return $targets;
}

// Log a "P looked at an opponent's resources: …" REVEAL entry for the given resource mzIDs (the cards
// the player looked at) — so a "look at an opponent's resources" effect (SEC_242 Elia Kane, LAW_066) is
// scrollable in the game log, like SWULookAtOpponentHand. Visible to both players (2-player simplification).
function SWULogResourceReveal(int $player, array $resMzIDs): void {
    global $playerID;
    $savedPID = $playerID; $playerID = intval($player);
    $opp  = OtherPlayer(intval($player));
    $refs = [];
    foreach ($resMzIDs as $mz) {
        $o = GetZoneObject($mz);
        if ($o !== null && empty($o->removed)) $refs[] = GameLogCardRef($o->CardID ?? '');
    }
    if (!empty($refs)) {
        AddGameLogEntry('REVEAL', 'P' . intval($player) . " looked at P{$opp}'s resources: " . implode(', ', $refs), 'ALL');
    }
    $playerID = $savedPID;
}

// ── Generic resource-reveal shuffler (CR resource-shuffling) ────────────────────
// "Reveal/look at $count of $ownerPlayer's resources." The resource ORDER isn't fixed (a player may
// shuffle their resources), so the engine picks which $count to reveal — ordered for the ACTIVE player's
// benefit, then random among equal-priority cards. Excludes Credit tokens (not resources). Returns the
// chosen mzIDs (in the active player's frame) and logs the reveal. Reusable by SEC_242 Elia Kane,
// SHD_114 Scanning Officer, etc.
//   Priority (descending desirability of being revealed, from the active player's POV):
//     1. READY resources first — so a defeat-and-replace doesn't swap an EXHAUSTED resource for a ready
//        one from the deck (a free resource for the owner). Side effect: this incentivizes keeping your
//        Smuggle/Plot cards exhausted so they aren't the ones revealed/defeated (e.g. vs SHD_114).
//     2. Resources OWNED by the active player first — a defeated one returns to the active player's
//        discard (recur it).
//     3. Random among ties (anti-exploit — the owner can't pre-arrange a known order).
function SWURevealResources(int $activePlayer, int $ownerPlayer, int $count): array {
    global $playerID;
    $saved = $playerID; $playerID = intval($activePlayer);
    $rel = ($ownerPlayer === $activePlayer) ? 'myResources' : 'theirResources';
    $pool = [];
    foreach (ZoneSearch($rel, null) as $mz) {
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        if (SWUIsCreditToken($o->CardID ?? '')) continue;   // Credit tokens aren't resources
        $pool[] = [
            'mz'    => $mz,
            'ready' => (intval($o->Status ?? 0) === 1) ? 1 : 0,
            'own'   => (intval($o->Owner ?? 0) === intval($activePlayer)) ? 1 : 0,
            'rand'  => mt_rand(),
        ];
    }
    usort($pool, function($a, $b) {
        if ($a['ready'] !== $b['ready']) return $b['ready'] - $a['ready']; // ready first
        if ($a['own']   !== $b['own'])   return $b['own']   - $a['own'];   // active-player-owned first
        return $a['rand'] <=> $b['rand'];                                   // random tiebreak
    });
    $chosen = array_slice(array_map(fn($e) => $e['mz'], $pool), 0, max(0, $count));
    SWULogResourceReveal(intval($activePlayer), $chosen);
    $playerID = $saved;
    return $chosen;
}

// Present the opponent's WHOLE hand to $player as an information-only acknowledge popup (card
// images + an OK button), exactly like SOR_228 Viper Probe Droid. No-op on an empty hand.
// The hand is SNAPSHOTTED into the popup param at call time, so the saved state is shown verbatim
// even if a later-resolving decision mutates the hand — call this while the hand is in the state
// you want shown (e.g. BEFORE a pending auto-discard) and the player still sees the saved hand.
// Used when a "look at an opponent's hand" effect would otherwise never surface the hand to the
// player — e.g. SOR_201 Bodhi Rook when the discard auto-resolves (0 or 1 non-unit target, so no
// MZCHOOSE is shown). When an MZCHOOSE *is* shown, it already presents the hand, so don't call this.
function SWUQueueShowOpponentHand(int $player): void {
    global $playerID;
    $savedPID = $playerID; $playerID = intval($player);
    $opp     = OtherPlayer(intval($player));
    $oppHand = GetHand($opp);
    $cards = [];
    foreach ($oppHand as $card) {
        if (empty($card->removed)) $cards[] = '@' . $card->CardID;
    }
    $playerID = $savedPID;
    if (empty($cards)) return;                   // empty hand → nothing to show
    $param = implode('&', $cards) . '&OK';       // "@CardID&@CardID&…&OK" — images then an OK button
    DecisionQueueController::AddDecision($player, "OPTIONCHOOSE", $param, 1, "Opponent's_hand");
    DecisionQueueController::AddDecision($player, "CUSTOM", "ACK", 1);
}

// Present the opponent's WHOLE deck to $player as an information-only acknowledge popup (card images +
// an OK button), the deck counterpart of SWUQueueShowOpponentHand. Used by "search a player's deck"
// effects (e.g. JTL_041 Annihilator) so the searching player actually sees the zone they searched.
// Snapshots the deck into the popup param at call time, so call it while the deck is in the state you
// want shown (e.g. BEFORE a name-hunt discard/shuffle). No-op on an empty deck.
function SWUQueueShowOpponentDeck(int $player): void {
    global $playerID;
    $savedPID = $playerID; $playerID = intval($player);
    $opp     = OtherPlayer(intval($player));
    $oppDeck = GetDeck($opp);
    $cards = [];
    foreach ($oppDeck as $card) {
        if (empty($card->removed)) $cards[] = '@' . $card->CardID;
    }
    $playerID = $savedPID;
    if (empty($cards)) return;                   // empty deck → nothing to show
    $param = implode('&', $cards) . '&OK';       // "@CardID&@CardID&…&OK" — images then an OK button
    DecisionQueueController::AddDecision($player, "OPTIONCHOOSE", $param, 1, "Opponent's_deck");
    DecisionQueueController::AddDecision($player, "CUSTOM", "ACK", 1);
}

// SOR_062 Regional Governor: "While this unit is in play, opponents can't play the named card."
// The named card is stored as a GlobalEffects flag "SWU_NAMEBLOCK|{uid}|{titleNoSpaces}" on the
// Governor's controller (GlobalEffects serialize space-delimited, so the title's spaces are encoded
// to underscores). A play by $player is blocked when an OPPONENT controls a still-in-play unit that
// named this card's title. Stale flags (the naming unit has left play) are removed lazily here, so
// the block ends automatically when the unit leaves — no per-leave-path hook needed.
function _SWUUnitInPlayWithUID(int $player, int $uid): bool {
    if ($uid === 0) return false;
    foreach ([GetGroundArena($player), GetSpaceArena($player)] as $arena) {
        foreach ($arena as $u) {
            if (empty($u->removed) && intval($u->UniqueID ?? 0) === $uid) return true;
        }
    }
    return false;
}

// Cards whose text says "This card can't be played from your hand." — a HAND-only play restriction;
// they may still be played from the resource zone (Plot/Smuggle) or any non-hand source. Gated in
// ActivateCard on the source mzID and in the hand-glow affordability check. Keyed by CardID.
function _SWUCantPlayFromHand(string $cardID): bool {
    static $cards = [
        'SEC_053' => true,   // One in a Million (Plot event)
    ];
    return isset($cards[$cardID]);
}

function SWUCardPlayBlocked(int $player, string $cardID): bool {
    // SEC_145 Confidence in Victory — "Play only as your first action in the action phase."
    if ($cardID === 'SEC_145' && GlobalEffectCount($player, 'SWU_ACTED_PHASE') > 0) return true;
    // SEC_126 Trade Route Taxation — "that opponent can't play events for this phase." The per-phase
    // SWU_EVENT_LOCK flag sits on the blocked player; it blocks only Event-type cards.
    if (GlobalEffectCount($player, 'SWU_EVENT_LOCK') > 0
        && stripos(CardType($cardID) ?? '', 'Event') !== false) return true;
    $titleEnc = str_replace(' ', '_', (string)(CardTitle($cardID) ?? ''));
    if ($titleEnc === '') return false;
    // LAW_243 Transmission Jamming — "Cards with that name can't be played this phase." Phase-duration
    // name-block, set by EITHER player (applies to both); cleared at RegroupPhaseStart.
    foreach ([$player, OtherPlayer($player)] as $pp) {
        if (GlobalEffectCount($pp, "SWU_NAMEBLOCK_PHASE|{$titleEnc}") > 0) return true;
    }
    $opp = OtherPlayer($player);                 // 2-player: the one opponent (Twin Suns: all opponents)
    $ge  = &GetGlobalEffects($opp);
    $prefix  = 'SWU_NAMEBLOCK|';
    $blocked = false;
    for ($i = count($ge) - 1; $i >= 0; $i--) {
        $flag = (string)($ge[$i]->CardID ?? '');
        if (!str_starts_with($flag, $prefix)) continue;
        $parts = explode('|', $flag);            // [SWU_NAMEBLOCK, uid, titleEnc]
        if (!_SWUUnitInPlayWithUID($opp, intval($parts[1] ?? 0))) {
            array_splice($ge, $i, 1);            // naming unit left play → stale flag, drop it
            continue;
        }
        if (($parts[2] ?? '') === $titleEnc) $blocked = true;
    }
    return $blocked;
}

// ASH_208 Sabine Wren — "When 1 or more upgrades attach to this unit (including from Shielded): you may
// exhaust a ground unit." Called from every attach point (DoGiveShieldToken + _SWUFinalizeUpgradeAttach).
// Returns true if it queued the optional exhaust (so the attach finalizer doesn't early-finish the action).
function _SWUAsh208OnUpgradeAttach(int $player, $hostObj): bool {
    if ($hostObj === null || !empty($hostObj->removed) || ($hostObj->CardID ?? '') !== 'ASH_208') return false;
    $ctrl = intval($hostObj->Controller ?? $player);
    global $playerID; $sp = $playerID; $playerID = $ctrl;
    $tg = array_merge(ZoneSearch('myGroundArena', AnyUnitFilter), ZoneSearch('theirGroundArena', AnyUnitFilter));
    if (empty($tg)) { $playerID = $sp; return false; }
    SWUQueueMayChooseTarget($ctrl, $tg, "Exhaust_a_ground_unit?", "Choose_a_ground_unit", "EXHAUST_UNIT");
    $playerID = $sp;
    return true;
}

function DoGiveShieldToken($player, $targetMZ) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $obj = GetZoneObject($targetMZ);
    $playerID = $savedPID;
    if ($obj === null || (isset($obj->removed) && $obj->removed)) return "-";
    if (!is_array($obj->Subcards)) $obj->Subcards = [];
    $obj->Subcards[] = (object)[
        'CardID'      => 'SOR_T02',
        'Owner'       => $player,
        'Controller'  => $player,
        'TurnEffects' => [],
        'IsPilot'     => false,
    ];
    AddGlobalEffects(intval($player), 'SWU_CREATED_TOKEN'); // LAW_016 "if you created a token this phase"
    _SWUAsh208OnUpgradeAttach(intval($player), $obj);   // a Shield is an upgrade attaching (ASH_208)
    return $targetMZ;
}

function DoGiveExperienceToken($player, $targetMZ) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $obj = GetZoneObject($targetMZ);
    $playerID = $savedPID;
    if ($obj === null || (isset($obj->removed) && $obj->removed)) return "-";
    if (!is_array($obj->Subcards)) $obj->Subcards = [];
    $obj->Subcards[] = (object)[
        'CardID'      => 'SOR_T01',
        'Owner'       => $player,
        'Controller'  => $player,
        'TurnEffects' => [],
        'IsPilot'     => false,
    ];
    AddGlobalEffects(intval($player), 'SWU_CREATED_TOKEN'); // LAW_016 "if you created a token this phase"
    return $targetMZ;
}

// Give one Advantage token (ASH_T02 — a +1/+0 Token Upgrade) to a unit. Mirrors DoGiveExperienceToken.
// Consumed (defeated) when the host's attack OR defense ends (see _SWUDefeatAllAdvantageTokens).
function DoGiveAdvantageToken($player, $targetMZ) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $obj = GetZoneObject($targetMZ);
    $playerID = $savedPID;
    if ($obj === null || (isset($obj->removed) && $obj->removed)) return "-";
    if (!is_array($obj->Subcards)) $obj->Subcards = [];
    $obj->Subcards[] = (object)[
        'CardID'      => 'ASH_T02',
        'Owner'       => $player,
        'Controller'  => $player,
        'TurnEffects' => [],
        'IsPilot'     => false,
    ];
    AddGlobalEffects(intval($player), 'SWU_CREATED_TOKEN'); // LAW_016 "if you created a token this phase"
    return $targetMZ;
}

// Defeat ALL Advantage tokens (ASH_T02 subcards) on a unit — the token's "When attached unit's attack
// or defense ends: Defeat this upgrade." Tokens are set aside, not discarded (no WhenDefeated). No-op on
// a non-unit mzID (e.g. a base target). Returns the number removed.
function _SWUDefeatAllAdvantageTokens($targetMZ): int {
    $obj = GetZoneObject($targetMZ);
    if ($obj === null || !empty($obj->removed) || !is_array($obj->Subcards ?? null)) return 0;
    // ASH_149 Eviscerator — "Advantage tokens on friendly units … aren't defeated after combat." Skip the
    // post-combat shed for any unit whose controller has an Eviscerator in play.
    $ctrl149 = intval($obj->Controller ?? 0);
    if ($ctrl149 > 0 && _SWUControlsCardInPlay($ctrl149, 'ASH_149')) return 0;
    $removed = 0;
    foreach ($obj->Subcards as $i => $sub) {
        $cid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
        $rem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
        if (!$rem && $cid === 'ASH_T02') { unset($obj->Subcards[$i]); $removed++; }
    }
    if ($removed > 0) $obj->Subcards = array_values($obj->Subcards);
    return $removed;
}

// Defeat ALL upgrades on a unit (CR 9.3): non-token upgrades → owner's discard; token upgrades (Shield/
// Experience/Advantage) → set aside. Captives are not upgrades and are left intact. Returns count removed.
// Shared "a friendly (real, non-token) upgrade was defeated" observer — called from BOTH upgrade-defeat
// points (SWUDefeatUpgrade for explicit defeats, _SWUDefeatAllUpgradesOn for host-leaves-play). $controller
// is the upgrade's controller; $owner is its owner; $hostObj is the unit it was attached to.
function _SWUOnUpgradeDefeated(int $controller, string $cardID, $hostObj, int $owner): void {
    if ($controller <= 0) return;
    AddGlobalEffects($controller, 'SWU_FRIENDLY_UPGRADE_DEFEATED');   // ASH_039 phase flag
    // ASH_055 Blade of Talzin — "When Defeated: if this upgrade was on a friendly Night unit, return it from
    // your discard pile to your hand." It was just discarded; pull the most recent copy back to hand.
    if ($cardID === 'ASH_055' && $hostObj !== null && _SWUUnitHasTrait($hostObj, 'Night')) {
        $disc = &GetDiscard($owner);
        for ($i = count($disc) - 1; $i >= 0; $i--) {
            if (!empty($disc[$i]->removed)) continue;
            if (($disc[$i]->CardID ?? '') === 'ASH_055') {
                $disc[$i]->removed = true;
                DecisionQueueController::CleanupRemovedCards();
                AddHand($owner, CardID: 'ASH_055');
                break;
            }
        }
    }
    // ASH_161 Zeb Orrelios — "When a friendly upgrade is defeated: deal 1 damage to a base." (Controller's.)
    if (_SWUControlsCardInPlay($controller, 'ASH_161')) {
        global $playerID; $sp = $playerID; $playerID = $controller;
        SWUQueueChooseTarget($controller, ['myBase-0', 'theirBase-0'], "Deal_1_damage_to_a_base", "DEAL_BASE_DAMAGE|1");
        $playerID = $sp;
    }
}

function _SWUDefeatAllUpgradesOn($targetMZ): int {
    $obj = GetZoneObject($targetMZ);
    if ($obj === null || !empty($obj->removed) || !is_array($obj->Subcards ?? null)) return 0;
    $owner = intval($obj->Owner ?? $obj->Controller ?? 0);
    $removed = 0;
    foreach ($obj->Subcards as $i => $sub) {
        $cid       = is_array($sub) ? ($sub['CardID'] ?? '')     : ($sub->CardID ?? '');
        $rem       = is_array($sub) ? !empty($sub['removed'])     : !empty($sub->removed);
        $isCaptive = is_array($sub) ? !empty($sub['IsCaptive'])   : !empty($sub->IsCaptive);
        $subOwner  = is_array($sub) ? intval($sub['Owner'] ?? $owner) : intval($sub->Owner ?? $owner);
        if ($rem || $isCaptive || $cid === '') continue;
        if (strpos(strtolower(CardType($cid) ?? ''), 'token') === false) {
            SWUAddToDiscard($subOwner > 0 ? $subOwner : $owner, $cid, 'PLAY');
            _SWUOnUpgradeDefeated(intval($obj->Controller ?? $owner), $cid, $obj, $subOwner > 0 ? $subOwner : $owner);
        }
        unset($obj->Subcards[$i]); $removed++;
    }
    if ($removed > 0) $obj->Subcards = array_values($obj->Subcards);
    return $removed;
}

// Defeat ONE upgrade subcard of a specific CardID on a unit (CR 9.3): non-token → owner's discard, token
// → set aside. Returns true if one was removed. Used for "defeat this upgrade" (ASH_085 Grav Charge).
function _SWUDefeatNamedUpgrade($obj, string $upgradeCardID): bool {
    if ($obj === null || !empty($obj->removed) || !is_array($obj->Subcards ?? null)) return false;
    $owner = intval($obj->Owner ?? $obj->Controller ?? 0);
    foreach ($obj->Subcards as $i => $sub) {
        $cid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
        $rem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
        if ($rem || $cid !== $upgradeCardID) continue;
        $subOwner = is_array($sub) ? intval($sub['Owner'] ?? $owner) : intval($sub->Owner ?? $owner);
        if (strpos(strtolower(CardType($cid) ?? ''), 'token') === false) {
            SWUAddToDiscard($subOwner > 0 ? $subOwner : $owner, $cid, 'PLAY');
        }
        unset($obj->Subcards[$i]);
        $obj->Subcards = array_values($obj->Subcards);
        return true;
    }
    return false;
}

// Defeat ONE Advantage token (ASH_T02 subcard) on a unit. Returns true if one was removed.
function _SWUDefeatOneAdvantageToken($targetMZ): bool {
    $obj = GetZoneObject($targetMZ);
    if ($obj === null || !empty($obj->removed) || !is_array($obj->Subcards ?? null)) return false;
    foreach ($obj->Subcards as $i => $sub) {
        $cid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
        $rem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
        if (!$rem && $cid === 'ASH_T02') { array_splice($obj->Subcards, $i, 1); return true; }
    }
    return false;
}

// Defeat one Experience token (SOR_T01 subcard) on a unit. Returns true if one was removed.
// Reusable for "defeat an Experience token on it/a unit" (LOF_156 self-attrition, LOF_082 Vaneé).
function SWUDefeatExperienceToken($targetMZ): bool {
    $obj = GetZoneObject($targetMZ);
    if ($obj === null || !empty($obj->removed) || !is_array($obj->Subcards ?? null)) return false;
    foreach ($obj->Subcards as $i => $sub) {
        $cid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
        $rem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
        if (!$rem && $cid === 'SOR_T01') {
            array_splice($obj->Subcards, $i, 1); // tokens are set aside, not discarded
            return true;
        }
    }
    return false;
}

// DoCaptureUnit — ChoiceFunction for the CaptureUnit(capturingMZ, capturedMZ) macro (GameSchema.txt).
// Places the captured unit face-down as a captive subcard under the capturing unit (CR 8.34).
// The captured unit's arena entry is marked removed; its CardID/Owner/Controller are preserved
// in an IsCaptive subcard so RescueUnit can return it later.
// Per CR 8.34.1: defeats the captured unit's non-captive upgrades, fires leave-play reactions
// (Boba SOR_015, SWU_ENEMY_LEFT_PLAY), and offers Bounty to the capturing player.
function DoCaptureUnit($player, $capturingMZ, $capturedMZ) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);

    $captor   = GetZoneObject($capturingMZ);
    $captive  = GetZoneObject($capturedMZ);

    $playerID = $savedPID;

    if ($captor === null || ($captor->removed ?? false)) return "-";
    if ($captive === null || ($captive->removed ?? false)) return "-";

    // "Can't be captured by enemy card abilities" (SHD_187 / TWI_220). Capture is always ability-driven;
    // block when the captor belongs to an opponent of the captive's controller.
    if (intval($player) !== intval($captive->Controller ?? $player) && SWUAvoidsCapture($captive)) return "-";

    // Record the captured unit's identity before we remove it.
    $cardID     = $captive->CardID;
    $owner      = intval($captive->Owner ?? $player);
    $controller = intval($captive->Controller ?? $owner);

    // CR 8.34.1: defeat all non-captive, non-removed upgrades on the captured unit before capture.
    // Tokens are set aside (removed from game); non-tokens go to their owner's discard.
    // Mirrors the upgrade-defeat pattern in SWUBounceUnit.
    if (!empty($captive->Subcards) && is_array($captive->Subcards)) {
        foreach ($captive->Subcards as $sub) {
            $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
            $isRemoved = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
            if ($isCaptive || $isRemoved) continue;
            $subCardID = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
            $subOwner  = is_array($sub) ? intval($sub['Owner'] ?? $owner) : intval($sub->Owner ?? $owner);
            if ($subCardID === '') continue;
            if (strpos(strtolower(CardType($subCardID) ?? ''), 'token') === false) {
                SWUAddToDiscard($subOwner, $subCardID, 'PLAY');
            }
        }
        // Clear all non-captive subcards (upgrades have been defeated above).
        $remaining = [];
        foreach ($captive->Subcards as $sub) {
            $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
            if ($isCaptive) $remaining[] = $sub;
        }
        $captive->Subcards = $remaining;
    }

    // CR 8.34.4: if the unit being captured was itself guarding captured units, rescue those
    // captives first (the unit leaving play triggers rescue of its own captives).
    SWURescueCaptivesOf($captive);

    // Remove the captured unit from its arena zone.
    $captive->removed = true;

    // Attach the captured unit as a captive subcard on the captor.
    if (!is_array($captor->Subcards)) $captor->Subcards = [];
    $captor->Subcards[] = (object)[
        'CardID'      => $cardID,
        'Owner'       => $owner,
        'Controller'  => $controller,
        'TurnEffects' => [],
        'IsPilot'     => false,
        'IsCaptive'   => true,
    ];

    // Fire leave-play reactions and Bounty for the capture.
    CollectCaptureTriggers(intval($player), $controller, $cardID);

    return $capturingMZ;
}

// SEC_195 Arrest — "your base captures an enemy non-leader unit." Bases have no Subcards, so the captive
// can't be attached like a unit-captor's. It's removed from play (mirroring DoCaptureUnit's CR 8.34 steps)
// and recorded in a GlobalEffects flag on the capturing player; _SWURescueBaseCaptives (RegroupPhaseStart)
// returns it to its owner. Returns true on a successful capture.
function _SWUBaseCaptureUnit(int $player, string $capturedMZ): bool {
    global $playerID;
    $savedPID = $playerID; $playerID = intval($player);
    $captive = GetZoneObject($capturedMZ);
    if ($captive === null || !empty($captive->removed)) { $playerID = $savedPID; return false; }
    // "Can't be captured by enemy card abilities" (SHD_187 / TWI_220).
    if (intval($player) !== intval($captive->Controller ?? $player) && SWUAvoidsCapture($captive)) { $playerID = $savedPID; return false; }
    $cardID     = $captive->CardID;
    $owner      = intval($captive->Owner ?? $player);
    $controller = intval($captive->Controller ?? $owner);
    // CR 8.34.1: defeat all non-captive, non-removed upgrades before capture (mirror DoCaptureUnit).
    if (!empty($captive->Subcards) && is_array($captive->Subcards)) {
        foreach ($captive->Subcards as $sub) {
            $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
            $isRemoved = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
            if ($isCaptive || $isRemoved) continue;
            $subCardID = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
            $subOwner  = is_array($sub) ? intval($sub['Owner'] ?? $owner) : intval($sub->Owner ?? $owner);
            if ($subCardID === '') continue;
            if (strpos(strtolower(CardType($subCardID) ?? ''), 'token') === false) SWUAddToDiscard($subOwner, $subCardID, 'PLAY');
        }
    }
    SWURescueCaptivesOf($captive);                 // CR 8.34.4: rescue any units IT was guarding
    $captive->removed = true;
    DecisionQueueController::CleanupRemovedCards();
    AddGlobalEffects(intval($player), 'SWU_BASECAPTIVE|' . $cardID . '|' . $owner);  // base captive store
    CollectCaptureTriggers(intval($player), $controller, $cardID);
    $playerID = $savedPID;
    return true;
}

// Rescue every base captive (SEC_195) to its owner's control, exhausted. Called at RegroupPhaseStart.
function _SWURescueBaseCaptives(): void {
    for ($p = 1; $p <= 2; $p++) {
        $ge = &GetGlobalEffects($p);
        for ($i = count($ge) - 1; $i >= 0; $i--) {
            $flag = (string)($ge[$i]->CardID ?? '');
            if (strpos($flag, 'SWU_BASECAPTIVE|') !== 0) continue;
            $parts  = explode('|', $flag);
            $cardID = $parts[1] ?? ''; $owner = intval($parts[2] ?? 0);
            if ($cardID !== '' && $owner > 0) DoRescueUnit((object)['CardID' => $cardID, 'Owner' => $owner], null);
            array_splice($ge, $i, 1);
        }
    }
}

// SEC_145 Confidence in Victory — at the start of the regroup phase, if the caster is the ONLY player
// who controls units in the chosen arena, they win. Armed via SWU_CONFIDENCE|{caster}|{Ground|Space};
// one-shot (the flag is consumed here).
function _SWUCheckConfidenceWin(): void {
    global $gWinner;
    for ($p = 1; $p <= 2; $p++) {
        $ge = &GetGlobalEffects($p);
        for ($i = count($ge) - 1; $i >= 0; $i--) {
            $flag = (string)($ge[$i]->CardID ?? '');
            if (strpos($flag, 'SWU_CONFIDENCE|') !== 0) continue;
            $parts  = explode('|', $flag);
            $caster = intval($parts[1] ?? 0);
            $arena  = $parts[2] ?? '';
            array_splice($ge, $i, 1);                                  // one-shot regardless of outcome
            if ($caster <= 0 || $arena === '') continue;
            $opp     = OtherPlayer($caster);
            $myArr   = ($arena === 'Space') ? GetSpaceArena($caster) : GetGroundArena($caster);
            $oppArr  = ($arena === 'Space') ? GetSpaceArena($opp)    : GetGroundArena($opp);
            $myCnt = 0;  foreach ($myArr  as $u) { if (empty($u->removed)) $myCnt++; }
            $opCnt = 0;  foreach ($oppArr as $u) { if (empty($u->removed)) $opCnt++; }
            if ($myCnt > 0 && $opCnt === 0) {                          // caster is the only one with units there
                SWUDeclareGameWinner($caster);
                AddGameLogEntry('WIN', 'P' . $caster . ' wins the game (Confidence in Victory).', 'ALL');
            }
        }
    }
}

// CollectCaptureTriggers — fires the leave-play reactions and Bounty that apply when a unit is
// captured. Capture is a non-defeat leave-play event (CR 8.34), so:
//   • Boba Fett SOR_015 and SWU_ENEMY_LEFT_PLAY fire (outside $defeated guard).
//   • Gideon/Krell/Kallus do NOT fire (those are defeat-only).
//   • Bounty (CR 7.6.3) is offered to the CAPTURING player (mirrors the defeat path's activePlayer).
// $capturingPlayer : the player who performed the capture (receives Bounty).
// $capturedController : the controller of the unit that just left play (used for leave-play reaction).
// $capturedCardID : the CardID of the captured unit.
function CollectCaptureTriggers(int $capturingPlayer, int $capturedController, string $capturedCardID): void {
    // Leave-play reactions: Boba Fett trigger + SWU_ENEMY_LEFT_PLAY phase flag.
    // Called with $defeated = false so only the non-defeat reactions fire.
    SWUCollectLeavePlayReactions([['player' => $capturedController, 'cardID' => $capturedCardID]], false);

    // Bounty (CR 7.6.3): offered to the capturing player, mirroring the defeat-path bounty block
    // in CollectWhenDefeatedTriggers where it is offered to the $activePlayer (the defeating player).
    global $Bounty_Cards;
    // SEC_046 Galen Erso — a named captured unit has lost its Bounty (no reward offered).
    if (isset($Bounty_Cards[$capturedCardID]) && !_SWUGalenSuppressesCard(intval($capturedController), $capturedCardID)) {
        DecisionQueueController::AddDecision($capturingPlayer, "YESNO", "-", 1, tooltip:"Collect_bounty?");
        DecisionQueueController::AddDecision($capturingPlayer, "CUSTOM", "SWUCollectBounty|{$capturedCardID}", 1);
    }

    // Flush any AddTrigger'd reactions (e.g. Boba BobaLeftPlay) into the DQ.
    // Uses $capturingPlayer as the active player, mirroring CollectWhenDefeatedTriggers
    // which calls FlushTriggerBag($activePlayer) where $activePlayer is the defeating player.
    FlushTriggerBag($capturingPlayer);
}

// DoRescueUnit — CR 8.34.3: return a single captive subcard to play under its owner's control,
// exhausted. Does NOT trigger WhenPlayed or any "enters play" effects (the unit is not played).
// $captiveSubcard : the captive subcard object (or array) stored on the former host.
// $hostObj        : the host unit object (used only for context; its Subcards are managed by caller).
function DoRescueUnit($captiveSubcard, $hostObj): void {
    global $playerID;
    $savedPID = $playerID;

    $cardID = is_array($captiveSubcard) ? ($captiveSubcard['CardID'] ?? '') : ($captiveSubcard->CardID ?? '');
    $owner  = is_array($captiveSubcard) ? intval($captiveSubcard['Owner'] ?? 0) : intval($captiveSubcard->Owner ?? 0);

    if ($cardID === '' || $owner === 0) {
        $playerID = $savedPID;
        return;
    }

    // Add the rescued unit directly to the arena as the owner/controller, exhausted (Status:0).
    // Status:0 is the exhausted value used in ActivateCard's $entryStatus default path (CR 8.22.f).
    // We use AddGroundArena/AddSpaceArena directly (not SWUBeginPlayCard/ActivateCard) so that
    // no WhenPlayed or "enters play" triggers fire.
    $playerID = $owner;
    $uid = NextUniqueID();
    $targetArena = CardTargetArena($cardID);
    // SEC_018 DJ (deployed) — "Friendly units that are rescued enter play ready." The rescued unit
    // returns to its owner; if that owner controls a deployed SEC_018, it enters ready (Status:1).
    $entryStatus = _SWULeaderDeployed($owner, 'SEC_018') ? 1 : 0;
    if ($targetArena === 'SpaceArena') {
        AddSpaceArena($owner, CardID:$cardID, Status:$entryStatus, Owner:$owner, Damage:0, Controller:$owner, UniqueID:$uid);
    } else {
        AddGroundArena($owner, CardID:$cardID, Status:$entryStatus, Owner:$owner, Damage:0, Controller:$owner, UniqueID:$uid);
    }

    $playerID = $savedPID;
}

// SWURescueCaptivesOf — CR 8.34.4: if $hostObj guards any captured units, rescue all of them
// via DoRescueUnit and clear them from the host. No-op when the host has no captives.
// MUST be called BEFORE the host is marked removed / spliced out of the arena array.
function SWURescueCaptivesOf($hostObj): void {
    if ($hostObj === null || empty($hostObj->Subcards) || !is_array($hostObj->Subcards)) return;

    // Snapshot captives first to avoid reading stale indices after mutation.
    $captives = [];
    foreach ($hostObj->Subcards as $sub) {
        $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
        $isRemoved = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
        if ($isCaptive && !$isRemoved) {
            $captives[] = $sub;
        }
    }

    if (empty($captives)) return;

    // Remove captive subcards from the host before rescuing so they don't double-fire later.
    $remaining = [];
    foreach ($hostObj->Subcards as $sub) {
        $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
        $isRemoved = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
        if (!$isCaptive || $isRemoved) $remaining[] = $sub;
    }
    $hostObj->Subcards = $remaining;

    // Also rescue captives nested on a pilot subcard (a captor that became a Pilot upgrade carries its
    // captive on the subcard's Captives list — JTL move/attach subsystem). If the WHOLE host leaves play
    // while such a pilot is attached, those nested captives must release too.
    foreach ($hostObj->Subcards as $sub) {
        $nested = is_array($sub) ? ($sub['Captives'] ?? null) : ($sub->Captives ?? null);
        if (is_array($nested)) foreach ($nested as $cap) $captives[] = $cap;
    }

    if (empty($captives)) return;

    // Remove captive subcards from the host before rescuing so they don't double-fire later.
    $remaining = [];
    foreach ($hostObj->Subcards as $sub) {
        $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
        $isRemoved = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
        if (!$isCaptive || $isRemoved) {
            // strip any nested captives off a surviving pilot subcard (they're being rescued)
            if (is_array($sub)) unset($sub['Captives']); elseif (isset($sub->Captives)) unset($sub->Captives);
            $remaining[] = $sub;
        }
    }
    $hostObj->Subcards = $remaining;

    // Rescue each captive back to its owner's arena, exhausted.
    foreach ($captives as $captive) {
        DoRescueUnit($captive, $hostObj);
    }
}

// ─── JTL move/attach subsystem (Eject/Corvus/Luke unit/L3-37) ──────────────────
// Move a UNIT in play to become a Pilot upgrade attached to $hostMz. The unit's normal (non-captive)
// upgrades are defeated and its damage is dropped (CR: "it's no longer a unit; defeat all upgrades on it
// and remove all damage"); any CAPTIVES it holds ride along on the pilot subcard's Captives list so the
// captor keeps them tucked. The UniqueID is PRESERVED on the subcard so UID-keyed markers (e.g.
// SWU_PLAYED_UNIT_{uid} → Luke SOR_005's "a unit you played this phase") survive the transition.
function SWUMoveUnitToUpgrade(string $unitMz, string $hostMz, bool $isPilot = true): void {
    global $playerID;
    $unit = GetZoneObject($unitMz);
    $host = GetZoneObject($hostMz);
    if ($unit === null || !empty($unit->removed) || $host === null || !empty($host->removed)) return;

    $cardID     = $unit->CardID;
    $owner      = intval($unit->Owner ?? $playerID);
    $controller = intval($unit->Controller ?? $owner);
    $uid        = intval($unit->UniqueID ?? 0);

    // Snapshot captives; defeat normal upgrades (non-token → owner's discard).
    $captives = [];
    if (is_array($unit->Subcards ?? null)) {
        foreach ($unit->Subcards as $sub) {
            $isCap = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
            $isRem = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
            if ($isRem) continue;
            if ($isCap) { $captives[] = $sub; continue; }
            $scid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
            $sown = is_array($sub) ? intval($sub['Owner'] ?? $owner) : intval($sub->Owner ?? $owner);
            if ($scid !== '' && strpos(strtolower(CardType($scid) ?? ''), 'token') === false) {
                SWUAddToDiscard($sown, $scid, 'PLAY');
            }
        }
    }

    // Remove the unit from its arena (NOT defeated — it becomes an upgrade).
    $unit->removed = true;

    if (!is_array($host->Subcards)) $host->Subcards = [];
    $pilotSub = (object)[
        'CardID'      => $cardID,
        'Owner'       => $owner,
        'Controller'  => $controller,
        'TurnEffects' => [],
        'IsPilot'     => $isPilot,
        'UniqueID'    => $uid,
    ];
    if (!empty($captives)) $pilotSub->Captives = $captives;
    $host->Subcards[] = $pilotSub;

    DecisionQueueController::CleanupRemovedCards();
}

// Move a Pilot UPGRADE (subcard at $subIdx on $hostMz) to become a UNIT in $targetArena (defaults to the
// card's natural arena; Eject/Luke force 'GroundArena'). The UniqueID is PRESERVED (or freshly assigned
// if the pilot was never a unit). Any captives carried on the subcard come back as the new unit's captive
// subcards. Enters exhausted by default. Returns the new unit's owner-relative mzID ('' on failure).
function SWUMoveUpgradeToUnit(string $hostMz, int $subIdx, ?string $targetArena = null, bool $exhaust = true): string {
    $host = GetZoneObject($hostMz);
    if ($host === null || !empty($host->removed) || !is_array($host->Subcards ?? null)) return '';
    if (!isset($host->Subcards[$subIdx])) return '';
    $sub = $host->Subcards[$subIdx];

    $cardID = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
    if ($cardID === '') return '';
    $owner      = is_array($sub) ? intval($sub['Owner'] ?? 0) : intval($sub->Owner ?? 0);
    $controller = is_array($sub) ? intval($sub['Controller'] ?? $owner) : intval($sub->Controller ?? $owner);
    $uid        = is_array($sub) ? intval($sub['UniqueID'] ?? 0) : intval($sub->UniqueID ?? 0);
    if ($uid <= 0) $uid = NextUniqueID();
    $carried    = is_array($sub) ? ($sub['Captives'] ?? []) : ($sub->Captives ?? []);
    $newSubs    = is_array($carried) ? array_values($carried) : [];

    // Remove the pilot subcard from the host.
    array_splice($host->Subcards, $subIdx, 1);

    $arena  = $targetArena ?: CardTargetArena($cardID);
    $status = $exhaust ? 0 : 1; // 0=exhausted, 1=ready
    if ($arena === 'SpaceArena') {
        $newObj = AddSpaceArena($owner, CardID:$cardID, Status:$status, Owner:$owner, Damage:0,
            Controller:$controller, Subcards:$newSubs, UniqueID:$uid);
        $idx = $newObj->mzIndex ?? (count(GetSpaceArena($owner)) - 1);
        return "mySpaceArena-{$idx}";
    }
    $newObj = AddGroundArena($owner, CardID:$cardID, Status:$status, Owner:$owner, Damage:0,
        Controller:$controller, Subcards:$newSubs, UniqueID:$uid);
    $idx = $newObj->mzIndex ?? (count(GetGroundArena($owner)) - 1);
    return "myGroundArena-{$idx}";
}

// Move a UNIT from its current arena into $targetArena ('GroundArena'/'SpaceArena'), staying a unit.
// UniqueID, Owner, Controller, Damage, Status, Subcards and TurnEffects are all preserved (so
// SWU_PLAYED_UNIT_{uid}, attached upgrades and damage carry over). Returns the new owner-relative mzID
// ('' on failure). Used by JTL_096 Blue Leader ("move this unit to the ground arena").
function SWUMoveUnitBetweenArenas(string $unitMz, string $targetArena): string {
    global $playerID;
    $u = GetZoneObject($unitMz);
    if ($u === null || !empty($u->removed)) return '';
    $owner       = intval($u->Owner ?? $playerID);
    $controller  = intval($u->Controller ?? $owner);
    $uid         = intval($u->UniqueID ?? 0);
    if ($uid <= 0) $uid = NextUniqueID();
    $cardID      = $u->CardID;
    $damage      = intval($u->Damage ?? 0);
    $status      = intval($u->Status ?? 0);
    $subs        = is_array($u->Subcards ?? null)    ? array_values($u->Subcards)    : [];
    $turnEffects = is_array($u->TurnEffects ?? null) ? array_values($u->TurnEffects) : [];

    $savedPID = $playerID;
    $playerID = $owner;
    $u->removed = true;
    if ($targetArena === 'SpaceArena') {
        $newObj = AddSpaceArena($owner, CardID:$cardID, Status:$status, Owner:$owner, Damage:$damage,
            Controller:$controller, TurnEffects:$turnEffects, Subcards:$subs, UniqueID:$uid);
    } else {
        $newObj = AddGroundArena($owner, CardID:$cardID, Status:$status, Owner:$owner, Damage:$damage,
            Controller:$controller, TurnEffects:$turnEffects, Subcards:$subs, UniqueID:$uid);
    }
    DecisionQueueController::CleanupRemovedCards();
    // Re-resolve by UID AFTER cleanup so a compacted source arena can't stale the index.
    $newMz = SWUFindMzByUID($uid) ?? '';
    $playerID = $savedPID;
    return $newMz;
}

// Detach the first non-removed upgrade matching $cardID from $hostMz and return it to its owner's hand.
// Used by JTL_197 Anakin ("return this upgrade to its owner's hand").
// SEC_061 Willrow Hood — "While this unit has exactly 1 friendly upgrade on it, that upgrade can't be
// defeated or returned to hand by enemy card abilities." True when the upgrade (controlled by $host's
// controller) is protected from $actor. Only ENEMY abilities are blocked (actor != host controller),
// only FRIENDLY upgrades are protected, and only when the host bears EXACTLY ONE friendly upgrade.
function _SWUWillrowProtectsUpgrade(object $host, int $upgradeController, int $actor): bool {
    if (($host->CardID ?? '') !== 'SEC_061') return false;
    $hostCtrl = intval($host->Controller ?? $host->Owner ?? 0);
    if ($actor === $hostCtrl || $actor <= 0) return false;   // friendly (or unknown) actor — not blocked
    if ($upgradeController !== $hostCtrl)     return false;   // only friendly upgrades are protected
    if (!is_array($host->Subcards ?? null))   return false;
    $friendly = 0;
    foreach ($host->Subcards as $sub) {
        $isCap = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
        $isRem = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
        if ($isCap || $isRem) continue;
        $sc = is_array($sub) ? intval($sub['Controller'] ?? $sub['Owner'] ?? 0)
                             : intval($sub->Controller ?? $sub->Owner ?? 0);
        if ($sc === $hostCtrl) $friendly++;
    }
    return $friendly === 1;
}

// SEC_101 Queen Amidala — "If damage would be dealt to this unit, you may defeat another friendly unit
// that shares a trait with this unit. If you do, prevent that damage." Interactive prevention. These two
// helpers + the AMIDALA_PREVENT_* handlers (CardDQHandlers) implement it; indirect damage modifies Damage
// directly (never through SWUDealDamageToUnit / SWUCombatDamage's unit path) so it's unpreventable for free.
// Friendly trait-sharing units the controller could defeat to prevent (empty = can't prevent).
function _SWUAmidalaPreventTargets(object $amidala): array {
    $ctrl = intval($amidala->Controller ?? 0);
    if ($ctrl <= 0) return [];
    $auid = intval($amidala->UniqueID ?? 0);
    global $playerID; $sv = $playerID; $playerID = $ctrl;
    $out = [];
    foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
        foreach (ZoneSearch($zone, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            if (intval($o->UniqueID ?? 0) === $auid) continue;   // "another" unit
            if (_SWUUnitHasTrait($o, 'Naboo') || _SWUUnitHasTrait($o, 'Official')) $out[] = $mz; // SEC_101 traits
        }
    }
    $playerID = $sv;
    return $out;
}
// Consume a pending combat prevent-marker on $unit (set by the step-1 offer). True ⇒ skip this damage.
function _SWUConsumeAmidalaPrevent($unit): bool {
    if ($unit === null || ($unit->CardID ?? '') !== 'SEC_101') return false;
    $ctrl = intval($unit->Controller ?? 0);
    $uid  = intval($unit->UniqueID ?? 0);
    if ($ctrl <= 0 || GlobalEffectCount($ctrl, 'SWU_AMIDALA_PREVENT_' . $uid) <= 0) return false;
    RemoveGlobalEffect($ctrl, 'SWU_AMIDALA_PREVENT_' . $uid);
    return true;
}

// ASH_062 The Mandalorian — "Shielded. If damage would be dealt to ANOTHER friendly unit, you may defeat
// a Shield token on this unit. If you do, prevent that damage." Interactive prevention powered by a
// friendly ASH_062 that still has a Shield. These two helpers + the ASH062_PREVENT_* handlers + the combat
// arming implement it; indirect damage writes Damage directly (never through SWUDealDamageToUnit /
// SWUCombatDamage's unit path) so it's unpreventable for free, exactly like SEC_101.
// Given a unit about to take damage, return a friendly ASH_062 (a DIFFERENT unit) that has a Shield to
// defeat — the provider that could prevent the damage. null = no prevention available.
function _SWUAsh062Provider($unit): ?object {
    if ($unit === null || !empty($unit->removed)) return null;
    $ctrl = intval($unit->Controller ?? 0);
    if ($ctrl <= 0) return null;
    $uuid = intval($unit->UniqueID ?? 0);
    global $playerID; $sv = $playerID; $playerID = $ctrl;
    $provider = null;
    foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
        foreach (ZoneSearch($zone, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            if (($o->CardID ?? '') !== 'ASH_062') continue;
            if (intval($o->UniqueID ?? 0) === $uuid) continue;   // "ANOTHER friendly unit" — not itself
            if (_SWUCountShieldSubcards($o) <= 0) continue;
            $provider = $o; break 2;
        }
    }
    $playerID = $sv;
    return $provider;
}
// Consume a pending ASH_062 combat prevent-marker on $unit (set when the offer was accepted). The marker
// keys on the PROTECTED unit's UID (not the provider's). True ⇒ skip this combat damage instance.
function _SWUConsumeAsh062Prevent($unit): bool {
    if ($unit === null) return false;
    $ctrl = intval($unit->Controller ?? 0);
    $uid  = intval($unit->UniqueID ?? 0);
    if ($ctrl <= 0 || GlobalEffectCount($ctrl, 'SWU_ASH062_PREVENT_' . $uid) <= 0) return false;
    RemoveGlobalEffect($ctrl, 'SWU_ASH062_PREVENT_' . $uid);
    return true;
}

// ASH_196 Gorian Shard's Corsair — "Damage dealt by friendly Underworld cards is unpreventable." While a
// player controls an in-play ASH_196, damage whose SOURCE is one of that player's Underworld cards bypasses
// Shields AND every prevention/reduction effect (Amidala, The Mandalorian, prevent-2 markers, Cassian).
// $sourceObj = the dealing card: combat → the attacker (or the defender, for counter-damage); ability →
// the source card when threaded. Combat is the signature case (the source is always a unit object).
function _SWUDamageUnpreventable($sourceObj): bool {
    if ($sourceObj === null || !empty($sourceObj->removed)) return false;
    if (!HasTrait($sourceObj->CardID ?? '', 'Underworld')) return false;
    $ctrl = intval($sourceObj->Controller ?? 0);
    if ($ctrl <= 0) return false;
    return _SWUCountActiveUnitsWithCardID($ctrl, 'ASH_196') > 0;
}

function SWUReturnUpgradeToHand(string $hostMz, string $cardID, int $actor = 0): void {
    $host = GetZoneObject($hostMz);
    if ($host === null || !empty($host->removed) || !is_array($host->Subcards ?? null)) return;
    foreach ($host->Subcards as $i => $sub) {
        $scid  = is_array($sub) ? ($sub['CardID'] ?? '')   : ($sub->CardID ?? '');
        $isRem = is_array($sub) ? !empty($sub['removed'])  : !empty($sub->removed);
        if ($isRem || $scid !== $cardID) continue;
        $owner = is_array($sub) ? intval($sub['Owner'] ?? 0) : intval($sub->Owner ?? 0);
        if ($owner <= 0) $owner = intval($host->Controller ?? $host->Owner ?? 1);
        $sctrl = is_array($sub) ? intval($sub['Controller'] ?? $owner) : intval($sub->Controller ?? $owner);
        if (_SWUWillrowProtectsUpgrade($host, $sctrl, $actor)) return;   // SEC_061 protection
        array_splice($host->Subcards, $i, 1);
        AddHand($owner, CardID:$cardID);
        return;
    }
}

// Relocate a Pilot subcard (index $subIdx) from one host to another, intact (UniqueID + carried captives
// preserved). Used by Corvus (JTL_038) when it attaches a Pilot that is ALREADY an upgrade on another
// friendly Vehicle (a pilot upgrade has no upgrades/damage of its own, so it simply moves).
function SWURelocatePilotSubcard(string $fromHostMz, int $subIdx, string $toHostMz): void {
    $from = GetZoneObject($fromHostMz);
    $to   = GetZoneObject($toHostMz);
    if ($from === null || !empty($from->removed) || $to === null || !empty($to->removed)) return;
    if (!is_array($from->Subcards ?? null) || !isset($from->Subcards[$subIdx])) return;
    $sub = $from->Subcards[$subIdx];
    array_splice($from->Subcards, $subIdx, 1);
    if (!is_array($to->Subcards)) $to->Subcards = [];
    $to->Subcards[] = $sub;
}

// Move an existing (non-pilot) upgrade SUBCARD from one host to another. Splices it out of $fromHostMz's
// Subcards and appends to $toHostMz's, intact (TurnEffects/Owner preserved). Optionally re-assigns the
// upgrade's Controller (JTL_056/JTL_242 "take control of an upgrade and attach it to a different unit").
function SWUMoveUpgradeCrossUnit(string $fromHostMz, int $subIdx, string $toHostMz, int $newController = 0): void {
    $from = GetZoneObject($fromHostMz);
    $to   = GetZoneObject($toHostMz);
    if ($from === null || !empty($from->removed) || $to === null || !empty($to->removed)) return;
    if (!is_array($from->Subcards ?? null) || !isset($from->Subcards[$subIdx])) return;
    $sub = $from->Subcards[$subIdx];
    array_splice($from->Subcards, $subIdx, 1);
    if ($newController > 0) {
        if (is_array($sub)) $sub['Controller'] = $newController; else $sub->Controller = $newController;
    }
    if (!is_array($to->Subcards)) $to->Subcards = [];
    $to->Subcards[] = $sub;
}

// Predicate for "move an upgrade" target filtering. Pilots and captives are never movable here.
//   'token'    — only Token Upgrades (Shield SOR_T02 / Experience SOR_T01) (JTL_242).
//   'nonpilot' — any non-Pilot upgrade, real or token (JTL_056 "a non-Pilot upgrade").
function _SWUUpgradeMatchesMoveFilter($sub, string $filter): bool {
    $isRem = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
    $isCap = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
    if ($isRem || $isCap) return false;
    $scid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
    if ($scid === '') return false;
    $isPilot = is_array($sub) ? !empty($sub['IsPilot']) : !empty($sub->IsPilot);
    if ($isPilot || HasTrait($scid, 'Pilot')) return false; // pilots excluded for both filters
    if ($filter === 'token') return strpos(CardType($scid) ?? '', 'Token') !== false;
    return true; // 'nonpilot' = any non-pilot upgrade
}

// Find the (hostMz, subIdx) of the FIRST Pilot subcard on $hostMz, or null. Pilots are detected by the
// IsPilot flag OR the Pilot trait (the test harness leaves IsPilot=false on pre-set upgrades).
function _SWUFindPilotSubcard($host): ?int {
    if ($host === null || !is_array($host->Subcards ?? null)) return null;
    foreach ($host->Subcards as $i => $sub) {
        $isRem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
        if ($isRem) continue;
        $isPilot = is_array($sub) ? !empty($sub['IsPilot']) : !empty($sub->IsPilot);
        $scid    = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
        if ($isPilot || ($scid !== '' && HasTrait($scid, 'Pilot'))) return $i;
    }
    return null;
}

// Controller-relative mzIDs of $controller's pilot-LESS Vehicle units (either arena), excluding $excludeUid.
function _SWUPilotlessFriendlyVehicleMzs(int $controller, int $excludeUid): array {
    global $playerID;
    $saved = $playerID; $playerID = $controller;
    $out = [];
    foreach (['myGroundArena', 'mySpaceArena'] as $z) {
        foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            if (intval($o->UniqueID ?? 0) === $excludeUid) continue;
            if (!HasTrait($o->CardID, 'Vehicle')) continue;
            if (_SWUFindPilotSubcard($o) !== null) continue; // already piloted
            $out[] = $mz;
        }
    }
    $playerID = $saved;
    return $out;
}

// "If this unit would be defeated, you may instead …" replacement descriptor, or null if unavailable.
// JTL_049 L3-37 → attach as a Pilot upgrade onto a friendly pilot-less Vehicle (only if such a Vehicle
// exists). A unit that has lost its abilities can't replace its defeat.
function _SWUUnitDefeatReplacement($obj): ?array {
    if ($obj === null || empty($obj->CardID) || LostAbilities($obj)) return null;
    if ($obj->CardID === 'JTL_049') {
        $ctrl = intval($obj->Controller ?? $obj->Owner ?? 0);
        if (!empty(_SWUPilotlessFriendlyVehicleMzs($ctrl, intval($obj->UniqueID ?? 0)))) {
            return ['kind' => 'unit_to_upgrade'];
        }
    }
    return null;
}

// Pilot-UPGRADE defeat-replacement (JTL_094 Luke): when a host carrying such a pilot leaves play, the
// pilot "would be defeated". Snapshot it into the deferred bag (the host is gone by drain time, so we
// store the data to rebuild the unit) and offer the controller the move at action end. Called BEFORE
// the host is removed, at every host-leave-play site.
function _SWUDeferPilotDefeatReplacements($hostObj): void {
    global $gDeferredReplacements;
    if ($hostObj === null || !is_array($hostObj->Subcards ?? null)) return;
    foreach ($hostObj->Subcards as $sub) {
        $rem  = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
        if ($rem) continue;
        $scid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
        if ($scid !== 'JTL_094') continue; // (generalize to a registry if more such pilots appear)
        $suid = is_array($sub) ? intval($sub['UniqueID'] ?? 0) : intval($sub->UniqueID ?? 0);
        if ($suid <= 0) $suid = NextUniqueID();
        $sown = is_array($sub) ? intval($sub['Owner'] ?? 0) : intval($sub->Owner ?? 0);
        $sctl = is_array($sub) ? intval($sub['Controller'] ?? $sown) : intval($sub->Controller ?? $sown);
        $caps = is_array($sub) ? ($sub['Captives'] ?? []) : ($sub->Captives ?? []);
        $gDeferredReplacements[] = ['kind' => 'upgrade_to_unit', 'uid' => $suid, 'controller' => $sctl,
            'owner' => $sown, 'cardID' => $scid, 'captives' => is_array($caps) ? $caps : []];
    }
}

// Drain the deferred defeat-replacement bag (CR replacement effects). Called at action end (and at
// combat resolution). For each deferred would-be-defeated unit still in play, offer its controller the
// optional replacement; if declined or no valid target remains, the defeat is carried out for real.
function SWUFlushDeferredReplacements(): void {
    global $gDeferredReplacements, $gReplaceSnapshots, $playerID;
    if (empty($gDeferredReplacements)) return;
    $bag = $gDeferredReplacements;
    $gDeferredReplacements = [];
    foreach ($bag as $e) {
        $ctrl = intval($e['controller']);
        $uid  = intval($e['uid']);
        if (($e['kind'] ?? '') === 'upgrade_to_unit') {
            // Pilot UPGRADE → ground unit (JTL_094). Host is already gone; rebuild from the snapshot.
            $gReplaceSnapshots[$uid] = $e;
            DecisionQueueController::AddDecision($ctrl, "YESNO", "-", 1,
                tooltip:"Move_this_Pilot_to_the_ground_arena_as_a_unit_instead_of_defeating_it?");
            DecisionQueueController::AddDecision($ctrl, "CUSTOM", "DEFEAT_REPLACE_UPG|{$ctrl}|{$uid}", 1);
            continue;
        }
        // Unit → pilot upgrade (JTL_049). The unit is still parked in play; re-find by UID.
        $saved = $playerID; $playerID = $ctrl;
        $mz = SWUFindMzByUID($uid);
        $playerID = $saved;
        if ($mz === null) continue; // already gone
        if (empty(_SWUPilotlessFriendlyVehicleMzs($ctrl, $uid))) {
            SWUDefeatUnit($ctrl, $mz, true); // no target → real defeat
            continue;
        }
        DecisionQueueController::AddDecision($ctrl, "YESNO", "-", 1,
            tooltip:"Attach_this_unit_to_a_friendly_Vehicle_instead_of_defeating_it?");
        DecisionQueueController::AddDecision($ctrl, "CUSTOM", "DEFEAT_REPLACE|{$ctrl}|{$uid}", 1);
    }
}

function OnExhaustCard($player, $mzID) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($mzID);
    if ($obj !== null && !$obj->removed) {
        // "Can't be exhausted by enemy card abilities" (LOF_040 / LOF_073). Self-exhaust (attacking,
        // cost payment — actor == controller) is always allowed; only an opponent's exhaust is blocked.
        if (intval($player) === intval($obj->Controller ?? $player) || !SWUAvoidsExhaust($obj)) {
            $obj->Status = 0;
        }
    }
    $playerID = $savedPID;
    return $mzID;
}

// SEC_037 Cantwell Arrestor Cruiser — "that unit can't ready while THIS unit is in play." The lock is
// per-instance (target UID + source UID): stored on the target's controller as SWU_CR37_{tgtUID}_{srcUID}.
// It holds while the source SEC_037 instance is still in play (any arena) and lifts automatically when
// the source leaves — checked at read time, with stale flags pruned lazily. NOT cleared at round start.
function _SWUReadyLockedWhileSourceInPlay(int $controller, int $targetUID): bool {
    if ($targetUID <= 0) return false;
    $zone = &GetGlobalEffects($controller);
    $prefix = 'SWU_CR37_' . $targetUID . '_';
    $locked = false;
    for ($i = count($zone) - 1; $i >= 0; $i--) {
        $f = $zone[$i]->CardID ?? '';
        if (!str_starts_with($f, $prefix)) continue;
        $srcUID = intval(substr($f, strlen($prefix)));
        if ($srcUID > 0 && SWUFindMzByUID($srcUID) !== null) {
            $locked = true;                 // source still in play → lock holds
        } else {
            array_splice($zone, $i, 1);     // source gone → prune the stale lock
        }
    }
    return $locked;
}

function OnReadyCard($player, $mzID) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($mzID);
    if ($obj !== null && !$obj->removed) {
        // LOF_098 — "while in the space arena, she can't ready" by any "Ready a unit" effect.
        if (($obj->CardID ?? '') === 'LOF_098' && strpos((string)$mzID, 'SpaceArena') !== false) {
            $playerID = $savedPID; return $mzID;
        }
        // SOR_186 No Good to Me Dead: a unit flagged "can't ready this round" doesn't ready from any
        // effect this round (the regroup ready step is gated separately in RegroupPhaseStart).
        $uid  = intval($obj->UniqueID ?? 0);
        $ctrl = intval($obj->Controller ?? $player);
        if ($uid > 0 && GlobalEffectCount($ctrl, 'SWU_CANT_READY_' . $uid) > 0) { $playerID = $savedPID; return $mzID; }
        // SEC_037: locked "can't ready while [the source] is in play."
        if ($uid > 0 && _SWUReadyLockedWhileSourceInPlay($ctrl, $uid)) { $playerID = $savedPID; return $mzID; }
        // LAW_077 Shadow of Stygeon Prime: attached unit can't ready (continuous while attached).
        if (_SWUUnitHasUpgrade($obj, 'LAW_077')) { $playerID = $savedPID; return $mzID; }
        $obj->Status = 1;
    }
    $playerID = $savedPID;
    return $mzID;
}

// ── Pregame DQ handlers ─────────────────────────────────────────────────────

$customDQHandlers["MulliganDecision"] = function($player, $parts, $lastDecision) {
    $targetPlayer = isset($parts[0]) ? intval($parts[0]) : intval($player);
    if (strtoupper($lastDecision) !== "YES") return;

    // Shuffle hand back into deck then draw 6 (SWU CR 1.8 setup)
    global $playerID;
    $savedPID = $playerID;
    $playerID = $targetPlayer;

    $hand = GetHand($targetPlayer);
    for ($i = count($hand) - 1; $i >= 0; $i--) {
        if (!isset($hand[$i]->removed) || !$hand[$i]->removed) {
            MZMove($targetPlayer, "myHand-$i", "myDeck");
        }
    }
    $deck = &GetDeck($targetPlayer);
    EngineShuffle($deck, true);

    for ($i = 0; $i < 6; $i++) DoDrawCard($targetPlayer, 1);

    $playerID = $savedPID;
};

$customDQHandlers["ChooseStartingResource"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $hand = GetHand($player);
    $hasCards = false;
    for ($i = 0; $i < count($hand); $i++) {
        if (!isset($hand[$i]->removed) || !$hand[$i]->removed) { $hasCards = true; break; }
    }
    $playerID = $savedPID;
    if (!$hasCards) return;

    // Use zone reference ("myHand") rather than specific indices so the MZCHOOSE
    // remains valid after WriteGamestate rewrites the hand. WriteGamestate strips
    // removed tombstones and resets indices to 0-N; a saved "myHand-6" would point
    // at nothing on the next load, whereas "myHand" always means "any live card".
    DecisionQueueController::AddDecision($player, "MZCHOOSE", "myHand", 40, "Choose_a_card_to_resource");
    DecisionQueueController::AddDecision($player, "CUSTOM", "ApplyStartingResource", 40);
};

$customDQHandlers["ApplyStartingResource"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === "-" || $lastDecision === "" || $lastDecision === "PASS") return;

    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $newResource = MZMove($player, $lastDecision, "myResources");
    // Hand cards don't carry a Status field; Resources must default to 1 (ready).
    if ($newResource !== null) {
        $newResource->Status = 1;
        if (function_exists('SWUTelemetryBumpCard')) SWUTelemetryBumpCard($player, $newResource->CardID ?? '', 'resourced'); // Plan D telemetry
    }
    $playerID = $savedPID;
};

$customDQHandlers["SWURegroupResource"] = function($player, $parts, $lastDecision) {
    if ($lastDecision !== "YES") return;
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $hand = GetHand($player);
    $hasCards = false;
    for ($i = 0; $i < count($hand); $i++) {
        if (!isset($hand[$i]->removed) || !$hand[$i]->removed) { $hasCards = true; break; }
    }
    if ($hasCards) {
        DecisionQueueController::AddDecision($player, "MZCHOOSE", "myHand", 1, tooltip:"Choose_a_card_to_resource");
        DecisionQueueController::AddDecision($player, "CUSTOM", "SWUApplyRegroupResource", 1);
    }
    $playerID = $savedPID;
};

$customDQHandlers["SWUApplyRegroupResource"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === "-" || $lastDecision === "" || $lastDecision === "PASS") return;
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $newResource = MZMove($player, $lastDecision, "myResources");
    if ($newResource !== null) {
        $newResource->Status = 0; // enters exhausted, readied in ReadyPhase
        if (function_exists('SWUTelemetryBumpCard')) SWUTelemetryBumpCard($player, $newResource->CardID ?? '', 'resourced'); // Plan D telemetry
        AddGameLogEntry('RESOURCE', 'P' . intval($player) . ' resourced a card');
    }
    $playerID = $savedPID;
};

// ── Phase handlers ──────────────────────────────────────────────────────────

// These stubs are defined before the GA template code so the guards at the
// GA definitions keep these SWUSim versions. Add real logic here as phases
// are implemented.

function MainPhase() {
    // TODO: consecutive-pass tracking and TurnPlayer swap
}

function DrawPhase() {
    // Draw is a step WITHIN the Regroup phase (not a separate phase in the log) — only the
    // "— Regroup Phase —" banner is emitted (by RegroupPhaseStart).
    // CR 5.4.b: each player draws 2 cards.
    DoDrawCard(1, 2);
    DoDrawCard(2, 2);
}

function ResourcePhase() {
    // Resource is a step WITHIN the Regroup phase (not a separate phase in the log).
    // CR 5.4.c: starting with the active player (initiative holder), each player
    // may resource 1 card from hand. Player selects a card or declines with "-".
    $firstPlayer = intval(GetFirstPlayer());
    $secondPlayer = $firstPlayer === 1 ? 2 : 1;
    DecisionQueueController::AddDecision($firstPlayer,  "MZMAYCHOOSE", "myHand", 1, tooltip:"Resource_up_to_1_card");
    DecisionQueueController::AddDecision($firstPlayer,  "CUSTOM",      "SWUApplyRegroupResource", 1);
    DecisionQueueController::AddDecision($secondPlayer, "MZMAYCHOOSE", "myHand", 1, tooltip:"Resource_up_to_1_card");
    DecisionQueueController::AddDecision($secondPlayer, "CUSTOM",      "SWUApplyRegroupResource", 1);
}

function ReadyPhase() {
    // CR 5.4.d: ready all exhausted cards for both players (units, resources, leader).
    // Leader.EpicActionUsed is NOT reset — that flag persists the whole game.
    for ($p = 1; $p <= 2; $p++) {
        $resources = &GetResources($p);
        for ($i = 0; $i < count($resources); $i++) {
            if (!isset($resources[$i]->removed) || !$resources[$i]->removed) $resources[$i]->Status = 1;
        }
        // SOR_186 No Good to Me Dead: a flagged unit doesn't ready this regroup; consume the flag so
        // it readies next round. (Shared by ground + space arenas.)
        $cantReadyRegroup = function($u) use ($p): bool {
            $uid = intval($u->UniqueID ?? 0);
            if ($uid > 0 && GlobalEffectCount($p, 'SWU_CANT_READY_' . $uid) > 0) {
                SWUClearGlobalEffectsByPrefix($p, 'SWU_CANT_READY_' . $uid);
                return true;
            }
            // JTL_182 Rampart: doesn't ready during regroup unless its power is 4 or more.
            if (($u->CardID ?? '') === 'JTL_182' && ObjectCurrentPower($u) < 4) return true;
            // SEC_037: locked "can't ready while [the source] is in play" (not consumed — lifts when
            // the source leaves play).
            if ($uid > 0 && _SWUReadyLockedWhileSourceInPlay($p, $uid)) return true;
            // LAW_077 Shadow of Stygeon Prime: attached unit can't ready while the upgrade is attached.
            if (_SWUUnitHasUpgrade($u, 'LAW_077')) return true;
            return false;
        };
        $ground = &GetGroundArena($p);
        for ($i = 0; $i < count($ground); $i++) {
            if ((!isset($ground[$i]->removed) || !$ground[$i]->removed) && !$cantReadyRegroup($ground[$i])) $ground[$i]->Status = 1;
        }
        $space = &GetSpaceArena($p);
        for ($i = 0; $i < count($space); $i++) {
            // LOF_098 — "while in the space arena, she can't ready." Blocks the regroup ready here (and
            // any "Ready a unit" effect via OnReadyCard); "enters play ready" is a separate path, unaffected.
            if (($space[$i]->CardID ?? '') === 'LOF_098') continue;
            if ((!isset($space[$i]->removed) || !$space[$i]->removed) && !$cantReadyRegroup($space[$i])) $space[$i]->Status = 1;
        }
        $leader = &GetLeader($p);
        for ($i = 0; $i < count($leader); $i++) {
            if (!isset($leader[$i]->removed) || !$leader[$i]->removed) $leader[$i]->Ready = true;
        }
    }
    // LAW_072 Max Rebo: when a second (additional) regroup phase still follows this round, DON'T advance
    // the round here — the increment happens on the final regroup's ready (so the round counter + the
    // "=== Round N ===" banner fire once per round, not once per regroup phase).
    if (!_SWUNeedsExtraRegroup()) {
        global $gTurnNumber;
        $gTurnNumber = intval($gTurnNumber) + 1;
        AddGameLogEntry('PHASE', '=== Round ' . intval($gTurnNumber) . ' ===');
    }

    // SOR_193 Millennium Falcon — "When you ready cards during the regroup phase:
    // Either pay [1 resource] or return this unit to her owner's hand."
    SWUQueueFalconRegroupTriggers();

    // JTL_192 In Debt to Crimson Dawn — "When attached unit readies: exhaust it unless its controller
    // pays 2 resources." Fires for every host that just readied in the regroup ready step.
    SWUQueueJTL192RegroupTriggers();

    // ASH_088 The Conflict Within — "When this unit readies: you may pay 3 resources. If you don't,
    // exhaust this unit." Same shape as JTL_192 (pay 3 instead of 2).
    SWUQueueASH088RegroupTriggers();
}

// ASH_088 The Conflict Within — queue a "pay 3 or be exhausted" decision for each unit carrying an
// ASH_088 upgrade that readied during the regroup ready step. (Clone of SWUQueueJTL192RegroupTriggers.)
function SWUQueueASH088RegroupTriggers(): void {
    global $playerID;
    $savedPID = $playerID;
    for ($p = 1; $p <= 2; $p++) {
        $playerID = $p;
        foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
            foreach (ZoneSearch($zone, ['Unit']) as $mzID) {
                $obj = GetZoneObject($mzID);
                if ($obj === null || ($obj->removed ?? false)) continue;
                if (!_SWUUnitHasUpgrade($obj, 'ASH_088')) continue;
                DecisionQueueController::AddDecision($p, 'YESNO', '', 1,
                    'Pay_3_resources_to_keep_this_unit_ready?_(No_exhausts_it)');
                DecisionQueueController::AddDecision($p, 'CUSTOM', "ASH_088#0|{$mzID}", 1);
            }
        }
    }
    $playerID = $savedPID;
}

// Queue the SOR_193 Millennium Falcon "ready cards" trigger for every Falcon in
// play, controller's first (active player 1, then 2). Each Falcon's controller is
// asked to pay 1 resource (keep) or bounce it to hand.
function SWUQueueFalconRegroupTriggers(): void {
    global $playerID;
    $savedPID = $playerID;
    for ($p = 1; $p <= 2; $p++) {
        $playerID = $p;
        foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
            foreach (ZoneSearch($zone, ['Unit']) as $mzID) {
                $obj = GetZoneObject($mzID);
                if ($obj === null || ($obj->removed ?? false)) continue;
                if (($obj->CardID ?? '') !== 'SOR_193') continue;
                DecisionQueueController::AddDecision($p, 'YESNO', '', 1,
                    'Pay_1_resource_to_keep_Millennium_Falcon?_(No_returns_her_to_hand)');
                DecisionQueueController::AddDecision($p, 'CUSTOM', "SOR_193#0|{$mzID}", 1);
            }
        }
    }
    $playerID = $savedPID;
}

// JTL_192 In Debt to Crimson Dawn — queue a "pay 2 or be exhausted" decision for each unit carrying a
// JTL_192 upgrade that readied during the regroup ready step. (Modeled on SWUQueueFalconRegroupTriggers.)
function SWUQueueJTL192RegroupTriggers(): void {
    global $playerID;
    $savedPID = $playerID;
    for ($p = 1; $p <= 2; $p++) {
        $playerID = $p;
        foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
            foreach (ZoneSearch($zone, ['Unit']) as $mzID) {
                $obj = GetZoneObject($mzID);
                if ($obj === null || ($obj->removed ?? false)) continue;
                if (!_SWUUnitHasUpgrade($obj, 'JTL_192')) continue;
                DecisionQueueController::AddDecision($p, 'YESNO', '', 1,
                    'Pay_2_resources_to_keep_this_unit_ready?_(No_exhausts_it)');
                DecisionQueueController::AddDecision($p, 'CUSTOM', "JTL_192#0|{$mzID}", 1);
            }
        }
    }
    $playerID = $savedPID;
}

// ─── Pregame setup modifiers (CR 5.2.1 step d) ────────────────────────────────
// Base cards that change how many cards their controller draws in the starting
// hand. Returns a signed delta off the default 6. Shared by CreateGame's
// QueuePregameSetup (production) and the test harness's Option-B builder so both
// honor the same rule. JTL_024/025 (min-deck-size bases) live in ValidateDeck —
// they change deck legality, not the opening draw, so they are NOT listed here.
function SWUStartingHandModifier($baseID): int {
    static $mods = [
        'JTL_021' => -1,  // Colossus: draw 1 fewer card
        'JTL_028' => +3,  // Nabat Village: draw 3 more cards
    ];
    return $mods[$baseID] ?? 0;
}

// Bases whose controller can't take a mulligan.
function SWUBaseSuppressesMulligan($baseID): bool {
    static $set = ['JTL_028' => true]; // Nabat Village
    return isset($set[$baseID]);
}

function SWUClearDiscardModifiers(): void {
    for ($p = 1; $p <= 2; $p++) {
        $discard = &GetDiscard($p);
        for ($i = 0; $i < count($discard); $i++) {
            if (isset($discard[$i]->removed) && $discard[$i]->removed) continue;
            if (!empty($discard[$i]->Modifier)) $discard[$i]->Modifier = '';
        }
    }
}

// LAW regroup-start triggers (fire at the start of the regroup phase, before the next ReadyPhase).
function _SWULawRegroupStartTriggers(): void {
    global $playerID; $saved = $playerID;
    for ($p = 1; $p <= 2; $p++) {
        $playerID = $p;
        // LAW_071 The Max Rebo Band — "When the regroup phase starts: create a Credit token."
        $n071 = _SWUCountActiveUnitsWithCardID($p, 'LAW_071');
        for ($i = 0; $i < $n071; $i++) SWUCreateCreditToken($p, 1);
        // LAW_073 Patient Hunter — "When the regroup phase starts: you may give an Experience token to a
        // non-leader unit; if you do, that unit can't ready during this regroup phase."
        $n073 = _SWUCountActiveUnitsWithCardID($p, 'LAW_073');
        if ($n073 > 0) {
            $targets = [];
            foreach (["myGroundArena", "mySpaceArena", "theirGroundArena", "theirSpaceArena"] as $z) {
                foreach (ZoneSearch($z, NonLeaderUnitFilter) as $mz) {
                    $o = GetZoneObject($mz);
                    if ($o !== null && empty($o->removed)) $targets[] = $mz;
                }
            }
            for ($i = 0; $i < $n073 && !empty($targets); $i++) {
                SWUQueueMayChooseTarget($p, $targets, "Give_an_Experience_token_to_a_non-leader_unit_(it_can't_ready_this_regroup)?", "Choose_a_unit", "LAW_073#0|" . $p);
            }
        }
        // LAW_077 Shadow of Stygeon Prime — granted "When the regroup phase starts: deal 2 damage to
        // your base" (the attached unit's controller's base). Once per attached LAW_077 instance.
        foreach (array_merge(GetGroundArena($p), GetSpaceArena($p)) as $u) {
            if (empty($u->removed) && _SWUUnitHasUpgrade($u, 'LAW_077')) SWUDealDamageToBase(2, $p);
        }
    }
    $playerID = $saved;
}

// ── LAW_072 Max Rebo — "There is an additional regroup phase after the first regroup phase each round." ──
// Each Max Rebo in play adds ONE additional regroup phase — they STACK, so total regroups = 1 + count
// (both players' Max Rebos count). SWU_REGROUP_NUM counts the regroup phases run this round (incremented
// at each RegroupPhaseStart, reset to 0 at ActionPhaseStart).
function _SWUMaxReboCount(): int {
    $n = 0;
    for ($p = 1; $p <= 2; $p++) {
        foreach (GetGroundArena($p) as $u) {
            if (empty($u->removed) && ($u->CardID ?? '') === 'LAW_072') $n++;
        }
    }
    return $n;
}
// True while another regroup is still owed this round: fewer regroups have run (SWU_REGROUP_NUM) than the
// total owed (1 + Max Rebo count), i.e. SWU_REGROUP_NUM <= count. Read by the READY→ transition
// (TurnController) to loop back to RGS, and by ReadyPhase to DEFER the round increment to the final regroup.
function _SWUNeedsExtraRegroup(): bool {
    return intval(GetSWUVar('SWU_REGROUP_NUM', '0')) <= _SWUMaxReboCount();
}

// ASH_227 Heightened Awareness — "Attached unit gains: 'When the regroup phase starts: give an Advantage
// token to this unit.'" Give one Advantage token per ASH_227 upgrade on each in-play unit (both players).
function _SWUAsh227RegroupStart(): void {
    global $playerID; $savedPID = $playerID;
    for ($p = 1; $p <= 2; $p++) {
        $playerID = $p;
        foreach (['myGroundArena', 'mySpaceArena'] as $z) {
            foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                $o = GetZoneObject($mz);
                if ($o === null || !empty($o->removed)) continue;
                $n = 0;
                foreach (GetUpgradesOnUnit($o) as $up) { if (($up->CardID ?? '') === 'ASH_227') $n++; }
                for ($i = 0; $i < $n; $i++) DoGiveAdvantageToken($p, $mz);
            }
        }
    }
    $playerID = $savedPID;
}

// ASH_159 Alphabet Squadron U-Wing — "When the regroup phase starts: give an Advantage token to a unit."
// Each ASH_159 in play lets its controller give 1 Advantage to a unit of their choice.
function _SWUAsh159RegroupStart(): void {
    global $playerID; $savedPID = $playerID;
    for ($p = 1; $p <= 2; $p++) {
        foreach (GetUnitsInPlay($p) as $src) {
            if (empty($src->removed) && ($src->CardID ?? '') === 'ASH_159') {
                $playerID = $p;
                $tg = [];
                foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $z) {
                    foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                        $o = GetZoneObject($mz);
                        if ($o !== null && empty($o->removed)) $tg[] = $mz;
                    }
                }
                if (!empty($tg)) SWUQueueChooseTarget($p, $tg, "Give_an_Advantage_token_to_a_unit", "GIVE_ADVANTAGE|1");
            }
        }
    }
    $playerID = $savedPID;
}

function RegroupPhaseStart(): void {
    AddGameLogEntry('PHASE', '— Regroup Phase —');
    // Telemetry: finalize each seat's per-round counters into a turnResults entry (once per round).
    if (function_exists('SWUTelemetrySnapshotTurn')) { SWUTelemetrySnapshotTurn(1); SWUTelemetrySnapshotTurn(2); }
    SetSWUVar('SWU_REGROUP_NUM', (string)(intval(GetSWUVar('SWU_REGROUP_NUM', '0')) + 1)); // LAW_072: count regroups this round
    ResetUndoDenyCount(1);
    ResetUndoDenyCount(2);
    SWUClearDiscardModifiers();
    SetSWUVar('SWU_LAST_ACTION', '');      // SEC_194 per-action tracking resets each phase
    SetSWUVar('SWU_ACTION_BASEATK', '');
    _SWURescueBaseCaptives();              // SEC_195 Arrest — base captives' owners rescue them now
    _SWUCheckConfidenceWin();              // SEC_145 Confidence in Victory — arena-control win check
    _SWULawRegroupStartTriggers();         // LAW_071 (credit), LAW_073 (Exp + can't-ready) at regroup start
    _SWUAsh227RegroupStart();              // ASH_227 Heightened Awareness — Advantage token to each wearer
    _SWUAsh159RegroupStart();              // ASH_159 Alphabet Squadron U-Wing — Advantage token to a chosen unit

    // LAW_074 Maz Kanata — "At the start of the regroup phase, put that unit on the bottom of your deck
    // (if it is still in play)." Bottom every unit still carrying the SWU_LAW074_BOTTOM marker, to its
    // owner's deck. Drain loop: SWUUnitToBottomOfDeck shifts arena indices, so re-scan after each.
    global $playerID;
    $savedLawPID = $playerID;
    $law074Found = true;
    while ($law074Found) {
        $law074Found = false;
        for ($lp = 1; $lp <= 2; $lp++) {
            $playerID = $lp;
            foreach (['myGroundArena', 'mySpaceArena'] as $lz) {
                foreach (ZoneSearch($lz, AnyUnitFilter) as $lmz) {
                    $lo = GetZoneObject($lmz);
                    if ($lo === null || !empty($lo->removed)) continue;
                    if (in_array('SWU_LAW074_BOTTOM', $lo->TurnEffects ?? [])) {
                        SWUUnitToBottomOfDeck($lp, $lmz); // bottoms to the unit's owner's deck
                        $law074Found = true;
                        break 3;
                    }
                }
            }
        }
    }
    $playerID = $savedLawPID;

    // SOR_219 Sneak Attack — "At the start of the regroup phase, defeat it." Defeat every unit still
    // carrying the SWU_SNEAK_DEFEAT marker (set when it was played by Sneak Attack). Drain loop:
    // SWUDefeatUnit shifts arena indices, so re-scan after each defeat.
    global $playerID;
    $savedSneakPID = $playerID;
    $sneakFound = true;
    while ($sneakFound) {
        $sneakFound = false;
        for ($sp = 1; $sp <= 2; $sp++) {
            $playerID = $sp;
            foreach (['myGroundArena', 'mySpaceArena'] as $szone) {
                foreach (ZoneSearch($szone, AnyUnitFilter) as $smz) {
                    $so = GetZoneObject($smz);
                    if ($so === null || !empty($so->removed)) continue;
                    if (!in_array('SWU_SNEAK_DEFEAT', $so->TurnEffects ?? [])) continue;
                    SWUDefeatUnit($sp, $smz);
                    $sneakFound = true;
                    break 3;
                }
            }
        }
    }
    $playerID = $savedSneakPID;

    // JTL_198 Fireball — "When the regroup phase starts: deal 1 damage to this unit." (one pass; any
    // resulting defeat is handled by the SWUDealDamageToUnit/state-based checks below.)
    for ($rp = 1; $rp <= 2; $rp++) {
        $playerID = $rp;
        foreach (['myGroundArena', 'mySpaceArena'] as $rz) {
            foreach (ZoneSearch($rz, AnyUnitFilter) as $rmz) {
                $ro = GetZoneObject($rmz);
                if ($ro === null || !empty($ro->removed)) continue;
                if (($ro->CardID ?? '') === 'JTL_198') SWUDealDamageToUnit($rmz, 1, $rp);
            }
        }
    }
    $playerID = $savedSneakPID;

    // JTL_216 Contracted Hunter — "When the regroup phase starts: defeat this unit." (drain loop — a
    // defeat shifts arena indices, so re-scan after each.)
    $chFound = true;
    while ($chFound) {
        $chFound = false;
        for ($cp = 1; $cp <= 2; $cp++) {
            $playerID = $cp;
            foreach (['myGroundArena', 'mySpaceArena'] as $cz) {
                foreach (ZoneSearch($cz, AnyUnitFilter) as $cmz) {
                    $co = GetZoneObject($cmz);
                    if ($co === null || !empty($co->removed)) continue;
                    if (($co->CardID ?? '') === 'JTL_216') { SWUDefeatUnit($cp, $cmz); $chFound = true; break 3; }
                }
            }
        }
    }
    $playerID = $savedSneakPID;

    // LOF_019 Vergence Temple — "When the regroup phase starts: If you control a unit with 4 or more
    // remaining HP, the Force is with you." Checked for whichever player's base is Vergence Temple.
    for ($vp = 1; $vp <= 2; $vp++) {
        $vbaseArr = GetBase($vp);
        if (empty($vbaseArr) || ($vbaseArr[0]->CardID ?? '') !== 'LOF_019') continue;
        $playerID = $vp;
        $hasBig = false;
        foreach (['myGroundArena', 'mySpaceArena'] as $vz) {
            foreach (ZoneSearch($vz, AnyUnitFilter) as $vmz) {
                $vo = GetZoneObject($vmz);
                if ($vo === null || !empty($vo->removed)) continue;
                if (intval(ObjectCurrentHP($vo)) - intval($vo->Damage ?? 0) >= 4) { $hasBig = true; break 2; }
            }
        }
        if ($hasBig) TheForceIsWithYou($vp);
    }
    $playerID = $savedSneakPID;

    // LOF_055 Dume — "When the regroup phase starts: give an Experience token to each OTHER friendly
    // non-Vehicle unit." (Loop per Dume so multiple copies each grant.)
    for ($dp = 1; $dp <= 2; $dp++) {
        $playerID = $dp;
        $dumeUIDs = [];
        foreach (['myGroundArena', 'mySpaceArena'] as $dz) {
            foreach (ZoneSearch($dz, AnyUnitFilter) as $dmz) {
                $do = GetZoneObject($dmz);
                if ($do !== null && empty($do->removed) && ($do->CardID ?? '') === 'LOF_055') $dumeUIDs[] = intval($do->UniqueID ?? 0);
            }
        }
        foreach ($dumeUIDs as $dumeUID) {
            foreach (['myGroundArena', 'mySpaceArena'] as $dz) {
                foreach (ZoneSearch($dz, AnyUnitFilter) as $dmz) {
                    $do = GetZoneObject($dmz);
                    if ($do === null || !empty($do->removed)) continue;
                    if (intval($do->UniqueID ?? -1) === $dumeUID) continue;       // "other"
                    if (HasTrait($do->CardID ?? '', 'Vehicle')) continue;         // non-Vehicle
                    DoGiveExperienceToken($dp, $dmz);
                }
            }
        }
    }
    $playerID = $savedSneakPID;

    // JTL_235 Commandeer — return commandeered units to their owners' hands at the start of regroup.
    $j235Found = true;
    while ($j235Found) {
        $j235Found = false;
        for ($jp = 1; $jp <= 2; $jp++) {
            $playerID = $jp;
            foreach (['myGroundArena', 'mySpaceArena'] as $jz) {
                foreach (ZoneSearch($jz, AnyUnitFilter) as $jmz) {
                    $jo = GetZoneObject($jmz);
                    if ($jo === null || !empty($jo->removed)) continue;
                    $juid = intval($jo->UniqueID ?? 0);
                    if (GlobalEffectCount(1, 'SWU_JTL235_RETURN_' . $juid) > 0 || GlobalEffectCount(2, 'SWU_JTL235_RETURN_' . $juid) > 0) {
                        SWUClearGlobalEffectsByPrefix(1, 'SWU_JTL235_RETURN_' . $juid);
                        SWUClearGlobalEffectsByPrefix(2, 'SWU_JTL235_RETURN_' . $juid);
                        SWUBounceUnit($jp, $jmz);   // return to owner's hand
                        $j235Found = true;
                        break 3;
                    }
                }
            }
        }
    }
    $playerID = $savedSneakPID;

    // Expire "for this phase" effects. Registry-known tokens (keyword grants, value keywords,
    // stats, lose-abilities / suppress markers) are dropped by SWUExpireTurnEffects via their
    // declared duration. The legacy predicate below still handles the attack/paid tokens that
    // remain in their pre-migration string form; the two cover disjoint token sets, so running
    // both is safe.
    SWUExpireTurnEffects(SWU_DUR_PHASE);
    $isPhaseStatEffect = fn($e) => strpos((string)$e, 'SWU_ATK_POWER_') === false // unconsumed attack bonus (fizzled attack)
                               && strpos((string)$e, 'SWU_DEF_DEBUFF_') === false // unconsumed Jyn defender debuff (fizzled attack)
                               && strpos((string)$e, 'SWU_PAID_')      === false; // Task 3.1: resources-paid stamp (per-play; WhenPlayed fires same turn)
    for ($p = 1; $p <= 2; $p++) {
        $g = &GetGroundArena($p);
        for ($i = 0; $i < count($g); $i++) {
            if (!empty($g[$i]->removed)) continue;
            $g[$i]->TurnEffects = array_values(array_filter($g[$i]->TurnEffects ?? [], $isPhaseStatEffect));
        }
        unset($g);
        $s = &GetSpaceArena($p);
        for ($i = 0; $i < count($s); $i++) {
            if (!empty($s[$i]->removed)) continue;
            $s[$i]->TurnEffects = array_values(array_filter($s[$i]->TurnEffects ?? [], $isPhaseStatEffect));
        }
        unset($s);
    }
    // A "for this phase" +HP buff that kept a damaged unit alive has now expired — defeat any unit
    // whose damage meets/exceeds its (un-buffed) current HP. (Same state-based sweep as shrinks.)
    SWUCheckShrinkDefeats();
    for ($p = 1; $p <= 2; $p++) {
        // LAW_245 Salvaged Materials — "At the start of the next regroup phase, defeat it." Defeat each
        // upgrade flagged SWU_LAW245_DEFEAT|{hostUID}|{cardID}, then clear the flag (one-shot).
        $geLaw245 = GetGlobalEffects($p);
        foreach ($geLaw245 as $ge) {
            $flag = (string)($ge->CardID ?? '');
            if (!str_starts_with($flag, 'SWU_LAW245_DEFEAT|')) continue;
            $fp = explode('|', $flag);   // [SWU_LAW245_DEFEAT, hostUID, cardID]
            $hostMz = SWUFindMzByUID(intval($fp[1] ?? 0));
            if ($hostMz !== null) {
                $hostObj = GetZoneObject($hostMz);
                $ups = $hostObj ? GetUpgradesOnUnit($hostObj) : [];
                for ($ui = 0; $ui < count($ups); $ui++) {
                    if (($ups[$ui]->CardID ?? '') === ($fp[2] ?? '')) { SWUDefeatUpgrade($p, $hostMz, $ui); break; }
                }
            }
        }
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LAW245_DEFEAT');
        RemoveGlobalEffect($p, 'SWU_ENEMY_DEFEATED');
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ENEMY_LEFT_PLAY');  // clear ALL (multiple leaves stack)
        SWUClearGlobalEffectsByPrefix($p, 'SWU_FRIENDLY_DEFEATED');  // clear ALL (multiple defeats stack)
        SWUClearGlobalEffectsByPrefix($p, 'SWU_REBEL_DEFEATED');     // LAW_005 Jyn "a friendly Rebel defeated this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_IMPERIAL_DEFEATED');  // ASH_008 Moff Gideon "a friendly Imperial defeated this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_FRIENDLY_UPGRADE_DEFEATED'); // ASH_039 "a friendly upgrade defeated this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH212_USED');               // ASH_212 Peli "first non-unit each phase ignores aspect penalty"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH006_SHIELDED_NEXT');      // ASH_006 Sabine "next unit you play gains Shielded this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_CREATED_TOKEN');      // LAW_016 The Client "if you created a token this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH047_USED');        // ASH_047 Gar Saxon "once each round" create-Mandalorian
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH128_USED');        // ASH_128 Bothan-5 "once each round" capture-from-discard
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH230_USED');        // ASH_230 Improvised Identity "once each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_BASE_ATTACKED');      // ASH_119 Greef Karga "if your base was attacked this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ATTACKER_DEFEATED');  // SEC_158 "friendly defeated while attacking this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_FRIENDLY_LEFT_PLAY');  // LOF_216 phase flag
        SWUClearGlobalEffectsByPrefix($p, 'SWU_FRIENDLY_LEADER_LEFT_PLAY'); // ASH_211 phase flag
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LOF203');              // LOF_203 "next initiative this phase" flag
        SWUClearGlobalEffectsByPrefix($p, 'SWU_EVENT_LOCK');          // SEC_126 "can't play events this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_FORCE_USED_THIS_PHASE'); // LOF_007 "times you used the Force this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_PLAYED_NONUNIT_FORCE');  // LOF_012 "played a non-unit Force card this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ATTACKED_JEDI');         // LOF_011 "attacked with a Jedi this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LOF108_CREATURE_USED');  // LOF_108 "first Creature you play each phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LOF197_REPEAT');         // LOF_197 "repeat the next When-Played ability"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_DEFEATED_CARD_');      // SOR_091 "defeated this phase" multiset
        SWUClearGlobalEffectsByPrefix($p, 'SWU_DMGBASE_');            // SOR_175 "base damaged this phase" set
        SWUClearGlobalEffectsByPrefix($p, 'SWU_BASEDMG_AMT_');        // SOR_013 Cassian "≥3 base damage this phase" amount
        // SOR_115 Kallus / SOR_013 Cassian once-per-round now reset via SWUResetAllNumUses (NumUses).
        SWUClearGlobalEffectsByPrefix($p, 'SWU_EVENT_PLAYED_ROUND');  // SOR_089 Relentless "first event each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_CARDS_PLAYED');        // clear ALL (multiple plays stack)
        SWUClearGlobalEffectsByPrefix($p, 'SWU_DISCARDED_HAND');      // LAW_179 "cards discarded from hand this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_DREW_PHASE');          // LAW_051 "cards drawn this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_DISCARDED_PHASE');     // LAW_076 "discarded from hand/deck this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LAW158_DISCOUNT_NEXT'); // LAW_158 "next Underworld unit -1"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH237_DISCOUNT_NEXT'); // ASH_237 Mouse Droid "next Imperial unit -1"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LAW058_DISCOUNT_NEXT'); // LAW_058 "next unit -1"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH027_DISCOUNT_NEXT'); // ASH_027 Enoch "next unit -N"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SHD006_DISCOUNT_NEXT'); // SHD_006 Jabba's bounty "next unit -N"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LAW053_USED');          // LAW_053 Dengar "once each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LAW094_USED');          // LAW_094 Hondo "once each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LAW176_USED');          // LAW_176 Sebulba's Podracer "once each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_NAMEBLOCK_PHASE');     // LAW_243 "named card can't be played this phase"
        RemoveGlobalEffect($p, 'SWU_PLAYED_VILLAINY');
        SWUClearGlobalEffectsByPrefix($p, 'SWU_PLAYED_FO');          // JTL_010 Captain Phasma
        SWUClearGlobalEffectsByPrefix($p, 'SWU_PLAYED_FORCE_CARD');  // LOF_243 Caretaker Matron
        SWUClearGlobalEffectsByPrefix($p, 'SWU_PLAYED_BOUNTYHUNTER'); // JTL_186 Mist Hunter
        SWUClearGlobalEffectsByPrefix($p, 'SWU_PLAYED_PILOT');        // JTL_186 Mist Hunter
        SWUClearGlobalEffectsByPrefix($p, 'SWU_KRENNIC_USED');       // JTL_032 Director Krennic per-round discount
        SWUClearGlobalEffectsByPrefix($p, 'SWU_DEALT_INDIRECT');     // JTL_138 "dealt indirect this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_GIDEON_TAX');         // JTL_188 Moff Gideon opponent-tax
        // JTL_157 Relentless Firespray once-per-round now via per-unit NumUses (SWUResetAllNumUses).
        SWUClearGlobalEffectsByPrefix($p, 'SWU_PILOT_DISCOUNT');     // JTL_008 Wedge (safety; consumed at charge)
        SWUClearGlobalEffectsByPrefix($p, 'SWU_PLAYED_UNIT_');
        SWUClearGlobalEffectsByPrefix($p, 'SWU_UNIT_ATTACKED_');
        SWUClearGlobalEffectsByPrefix($p, 'SWU_DEALT_BASEDMG_');
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ATTACKED_');  // clears SWU_ATTACKED_{uid} + ..._MANDALORIAN_{uid} + ..._VEHICLE
        SWUClearGlobalEffectsByPrefix($p, 'SWU_NEUTRAL_DISCOUNT');  // SOR_056 Bendu: "this phase" charge
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SNAP_DISCOUNT');     // JTL_098 Snap Wexley: "next Resistance card" charge
        SWUClearGlobalEffectsByPrefix($p, 'SWU_JTL260_USED');       // JTL_260 Death Star Plans: "first unit each round -2" use
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LAW229_USED');       // LAW_229 "first Gambit each round -1" use
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SEC110_DISCOUNT_NEXT'); // SEC_110 GNK "next unit -1" charge
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SEC064_USED');       // SEC_064 "first upgrade each phase -1" use
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH075_USED');       // ASH_075 Pit Droid "first upgrade each phase -1" use
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SEC261_OFFICIAL_DISCOUNT'); // SEC_261 "next Official unit -1" charge
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SEC001_PLOT_DISCOUNT');     // SEC_001 Palpatine "next Plot play -3" charge
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SEC002_USED');              // SEC_002 Jabba deployed "once each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH032_USED');              // ASH_032 Rancor Keeper "once each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH160_USED_');             // ASH_160 Kachirho Militia "once each round"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ASH248_READY');             // ASH_248 Neel "next ≤1-power unit this phase enters ready"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LEADER_DEFEATED_PHASE');    // ASH_093 Captain Pellaeon "leader defeated this phase → Raid 3"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SEC067_USED_');      // SEC_067 "first damage each phase prevented" per-unit
        SWUClearGlobalEffectsByPrefix($p, 'SWU_NOHEAL_BASE');       // SOR_160 Wolffe: "bases can't be healed this phase"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_SHIELD_GATE');       // JTL_074 Close the Shield Gate: unused base-damage prevention
        // JTL_013 Poe Dameron once-per-round hop now via leader NumUses (SWUResetAllNumUses).
        SWUClearGlobalEffectsByPrefix($p, 'SWU_THRAWN_REUSE_PENDING'); // safety: clear any dangling offer guard
        SWUClearGlobalEffectsByPrefix($p, 'SWU_BOBA_009_PENDING');     // JTL_009 safety: clear dangling offer guard
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ENFYS_REUSE_PENDING');  // LAW_014 safety: clear dangling offer guard
        SWUClearGlobalEffectsByPrefix($p, 'SWU_JABBA015_PENDING');     // LAW_015 safety: clear if a Jabba play fizzled
        SWUClearGlobalEffectsByPrefix($p, 'SWU_JABBA015_AMBUSH');      // LAW_015 safety
        RemoveGlobalEffect($p, 'SWU_DOOKU_NEXT_SEPARATIST_EXPLOIT');  // TWI_005 Dooku: "this phase" charge
        RemoveGlobalEffect($p, 'SWU_LOF180_NEXT_AMBUSH');            // LOF_180 Deceptive Shade: "this phase" charge
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LOF010_NEXT_HIDDEN');  // LOF_010 deployed "next unit gains Hidden"
        SWUClearGlobalEffectsByPrefix($p, 'SWU_LOF005_DISCOUNT_NEXT');// LOF_005 deployed "next unit costs 1 less"
    }
    SWUResetAllNumUses(); // refresh every card's once-per-round NumUses budget for the new round
    // Return all TEMPORARY_STEAL units to their owners. Drain loop because each
    // SWUTakeControlOfUnit call shifts arena indices.
    global $playerID;
    $savedPID = $playerID;
    $found = true;
    while ($found) {
        $found = false;
        for ($p = 1; $p <= 2; $p++) {
            $playerID = $p;
            foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
                foreach (ZoneSearch($zone, AnyUnitFilter) as $mzID) {
                    $obj = GetZoneObject($mzID);
                    if ($obj === null || ($obj->removed ?? false)) continue;
                    if (!in_array('TEMPORARY_STEAL', $obj->TurnEffects ?? [])) continue;
                    $owner = intval($obj->Owner ?? $p);
                    if ($owner === $p) continue;
                    SWUTakeControlOfUnit($owner, $mzID);
                    $found = true;
                    break 3;
                }
            }
        }
    }
    $playerID = $savedPID;
}

function ActionPhaseStart() {
    // Determine who holds the initiative going into this round.
    // If initiative was claimed last round (P1_CLAIMED/P2_CLAIMED), that player
    // keeps it; flip to _UNCLAIMED (available but not yet taken this round).
    $ic = GetInitiativeCounter();
    $holder = 1; // default
    if ($ic === 'P1_CLAIMED' || $ic === 'P1_UNCLAIMED') $holder = 1;
    elseif ($ic === 'P2_CLAIMED' || $ic === 'P2_UNCLAIMED') $holder = 2;
    else $holder = intval(GetFirstPlayer());

    SetTurnPlayer($holder);
    SetInitiativeCounter("P{$holder}_UNCLAIMED");
    SetSWUVar('PASS', '0');
    SetSWUVar('SWU_REGROUP_NUM', '0'); // LAW_072: reset the per-round regroup-phase counter

    // SOR_061 Guardian of the Whills: reset each Guardian's per-round upgrade-discount charge.
    for ($p = 1; $p <= 2; $p++) {
        SWUClearGlobalEffectsByPrefix($p, 'SWU_GUARDIAN_UPG_USED_');
        SWUClearGlobalEffectsByPrefix($p, 'SWU_ACTED_PHASE');   // SEC_145 "first action" gate resets each phase
    }

    // Clear per-round TurnEffects for Leaders and Bases.
    for ($p = 1; $p <= 2; $p++) {
        $leader = &GetLeader($p);
        for ($i = 0; $i < count($leader); $i++) {
            if (!isset($leader[$i]->removed) || !$leader[$i]->removed) $leader[$i]->TurnEffects = [];
        }
        $base = &GetBase($p);
        for ($i = 0; $i < count($base); $i++) {
            if (!isset($base[$i]->removed) || !$base[$i]->removed) $base[$i]->TurnEffects = [];
        }
    }
    AddGameLogEntry('PHASE', '— Action Phase —');

    // SOR_016 Grand Admiral Thrawn — APS passive (leader unit side):
    // "When the action phase starts: Look at the top card of each player's deck."
    global $playerID;
    $savedPID = $playerID;
    for ($p = 1; $p <= 2; $p++) {
        $playerID = $p;
        $leaderZone = GetLeader($p);
        $thrawnDeployed = false;
        foreach ($leaderZone as $lObj) {
            if (!empty($lObj->removed)) continue;
            if (($lObj->CardID ?? '') === 'SOR_016') {
                $thrawnDeployed = true;
                break;
            }
        }
        if (!$thrawnDeployed) continue;

        for ($deckOwner = 1; $deckOwner <= 2; $deckOwner++) {
            $playerID = $deckOwner;
            $deck = GetDeck($deckOwner);
            $active = array_values(array_filter($deck, fn($c) => empty($c->removed ?? false)));
            if (empty($active)) continue;
            AddGameLogEntry(
                'REVEAL',
                'Thrawn sees top of P' . $deckOwner . '\'s deck: ' . GameLogCardRef($active[0]->CardID),
                'P' . $p
            );
        }
    }

    // SOR_017 Han Solo — pending delayed trigger:
    // "At the start of the next action phase, defeat a resource you control."
    // One armed flag per ramp; resolve each as a mandatory choice among the
    // player's resources (auto-PASSes harmlessly if they control none).
    for ($p = 1; $p <= 2; $p++) {
        $pending = GlobalEffectCount($p, 'SWU_HAN_DEFEAT_RESOURCE');
        for ($k = 0; $k < $pending; $k++) {
            RemoveGlobalEffect($p, 'SWU_HAN_DEFEAT_RESOURCE');
            DecisionQueueController::AddDecision($p, 'MZCHOOSE', 'myResources', 1,
                'Choose_a_resource_to_defeat_(Han_Solo)');
            DecisionQueueController::AddDecision($p, 'CUSTOM', 'HAN_DEFEAT_RESOURCE', 1);
        }
    }

    // SEC_073 The Eye of Aldhani — "At the start of the next action phase, for each enemy unit, its
    // controller must pay 1 resource or exhaust that unit." The affected (enemy) player picks which units
    // to pay for via ONE MZMULTICHOOSE (capped at their ready resources); unselected units are exhausted.
    for ($armer = 1; $armer <= 2; $armer++) {
        if (GlobalEffectCount($armer, 'SWU_EYE_ALDHANI') <= 0) continue;
        SWUClearGlobalEffectsByPrefix($armer, 'SWU_EYE_ALDHANI');   // consume (all stacks → resolve once)
        $target = OtherPlayer($armer);
        $playerID = $target;
        $units = array_values(array_merge(ZoneSearch('myGroundArena', AnyUnitFilter), ZoneSearch('mySpaceArena', AnyUnitFilter)));
        if (empty($units)) continue;
        $cap = min(count($units), SWUResourceCount($target, true));
        if ($cap <= 0) { foreach ($units as $mz) OnExhaustCard($target, $mz); continue; }  // can't pay → all exhausted
        DecisionQueueController::AddDecision($target, "MZMULTICHOOSE", "0|{$cap}|" . implode('&', $units), 1,
            tooltip:"Pay_1_resource_each_to_keep_units_ready_(unselected_are_exhausted)");
        DecisionQueueController::AddDecision($target, "CUSTOM", "SEC_073#0|{$target}", 1);
        // leave $playerID = $target so MZCountChoices validates the relative mzIDs correctly
    }

    $playerID = $savedPID;
}

// ── SWU Gameplay Core ──────────────────────────────────────────────────────

// Which arena a unit card enters. arenaData is empty in generated dicts (API
// parsing gap), so fall back to Ground. Extend this list when space units are needed.
function CardTargetArena($cardID) {
    $arena = CardArena($cardID);
    if ($arena === 'Space') return 'SpaceArena';
    return 'GroundArena'; // default Ground
}

// Increment and return the next UniqueID counter value.
function NextUniqueID() {
    global $gUniqueIDCounter;
    $gUniqueIDCounter = intval($gUniqueIDCounter) + 1;
    return $gUniqueIDCounter;
}

// Move a unit from its current controller's arena to $newController's arena.
// Preserves Owner, Subcards, Damage, UniqueID, and Status. Strips TEMPORARY_STEAL
// from TurnEffects so returned units don't loop. Returns the new mzID or '' on failure.
// Caller must have $playerID set so that $mzID resolves correctly before the call.
function SWUTakeControlOfUnit(int $newController, string $mzID): string {
    global $playerID;
    $savedPID = $playerID;

    $unit = GetZoneObject($mzID);
    if ($unit === null || ($unit->removed ?? false)) {
        $playerID = $savedPID;
        return '';
    }
    // "Opponents can't take control of this unit" (LAW_149 Rey). Block when someone OTHER than the
    // owner is taking control (an opponent); returning control to the owner is always allowed.
    if (intval($newController) !== intval($unit->Owner ?? $newController) && SWUAvoidsTakeControl($unit)) {
        $playerID = $savedPID;
        return '';
    }

    $cardID      = $unit->CardID ?? '';
    $owner       = intval($unit->Owner ?? $newController);
    $damage      = intval($unit->Damage ?? 0);
    $subcards    = $unit->Subcards ?? [];
    $turnEffects = array_values(array_filter($unit->TurnEffects ?? [],
                    fn($e) => $e !== 'TEMPORARY_STEAL'));
    $uid         = intval($unit->UniqueID ?? 0);
    $status      = intval($unit->Status ?? 1);
    $location    = $unit->Location ?? 'GroundArena';

    $unit->removed = true;
    DecisionQueueController::CleanupRemovedCards();

    $playerID = $newController;
    $newCard  = null;
    if (strpos($location, 'Space') !== false) {
        $newCard = AddSpaceArena($newController, CardID:$cardID, Status:$status,
            Owner:$owner, Damage:$damage, Controller:$newController, UniqueID:$uid);
    } else {
        $newCard = AddGroundArena($newController, CardID:$cardID, Status:$status,
            Owner:$owner, Damage:$damage, Controller:$newController, UniqueID:$uid);
    }

    $newMzID = '';
    if ($newCard !== null) {
        $newCard->Subcards    = $subcards;
        $newCard->TurnEffects = $turnEffects;
        $newMzID              = $newCard->GetMzID();
    }

    $playerID = $savedPID;
    return $newMzID;
}

// Exhaust $count ready resources for player $player.
// Returns true if successful, false if insufficient ready resources.
// ── Credit tokens (CR §3.13) ─────────────────────────────────────────────────
// A Credit token (LAW_T01, card type "Credit Token") is created in a player's resource zone but is
// NOT a resource: it never counts toward resource totals (so it gives no early leader deploy and no
// extra play affordability) and is never exhausted to pay. Its only function is "While paying
// resources, you may defeat this token. If you do, pay 1 less" — handled by the alt-payment offer
// (SWUOfferAltPayment / CREDIT_PAY). All resource-counting / paying loops skip Credit tokens.
function SWUIsCreditToken(string $cardID): bool {
    return CardType($cardID) === 'Credit Token';
}

// Create $count Credit tokens (LAW_T01) in $player's resource zone.
function SWUCreateCreditToken(int $player, int $count = 1): void {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    for ($i = 0; $i < intval($count); $i++) {
        AddResources($player, 'LAW_T01', 1, $player, $player); // Status irrelevant (not a resource)
    }
    if (intval($count) > 0) {
        AddGlobalEffects(intval($player), 'SWU_CREATED_TOKEN'); // LAW_016 "if you created a token this phase"
        AddGameLogEntry('TOKEN', 'P' . intval($player) . ' created ' . intval($count)
            . ' Credit token' . (intval($count) === 1 ? '' : 's'));
    }
    $playerID = $savedPID;
}

// Number of Credit tokens $player controls (in their resource zone).
function SWUCountFriendlyCreditTokens(int $player): int {
    $n = 0;
    foreach (GetResources($player) as $r) {
        if (!empty($r->removed)) continue;
        if (SWUIsCreditToken($r->CardID ?? '')) $n++;
    }
    return $n;
}

// True if $player's Credit tokens have lost all abilities (so they can't be defeated to pay 1 less).
// LAW_117 Conveyex Security Captain: "Enemy Credit tokens lose all abilities." — i.e. a Credit token
// is disabled when its controller's OPPONENT controls an active (ability-bearing) LAW_117.
function SWUCreditAbilitiesDisabled(int $player): bool {
    $opp = GetOpponent($player);
    foreach (array_merge(GetGroundArena($opp) ?? [], GetSpaceArena($opp) ?? []) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (($u->CardID ?? '') === 'LAW_117' && !HasNoAbilities($u)) return true;
    }
    return false;
}

// mzIDs ("myResources-N") of $player's Credit tokens that may still be defeated to pay 1 less
// (empty if disabled by an enemy LAW_117). Raw zone indices, matching ZoneSearch/GetZoneObject.
function SWUUsableCreditTokenMzIDs(int $player): array {
    if (SWUCreditAbilitiesDisabled($player)) return [];
    $out = [];
    $resources = GetResources($player);
    for ($i = 0; $i < count($resources); $i++) {
        if (!empty($resources[$i]->removed)) continue;
        if (SWUIsCreditToken($resources[$i]->CardID ?? '')) $out[] = "myResources-{$i}";
    }
    return $out;
}

// mzIDs ("theirResources-N", from $player's frame) of the OPPONENT's Credit tokens — for LAW_106
// "defeat an enemy Credit token". Raw zone indices, matching GetZoneObject resolution.
function SWUEnemyCreditTokenMzIDs(int $player): array {
    $opp = GetOpponent($player);
    $out = [];
    $res = GetResources($opp);
    for ($i = 0; $i < count($res); $i++) {
        if (!empty($res[$i]->removed)) continue;
        if (SWUIsCreditToken($res[$i]->CardID ?? '')) $out[] = "theirResources-{$i}";
    }
    return $out;
}

// Keep Credit tokens at the END of $player's resource zone. They're appended on creation, but a card
// resourced afterward would otherwise land behind them. Resource order is free (CR 8.36.4), so a plain
// partition is safe; mzIndex is reindexed to match.
function SWUKeepCreditTokensLast(int $player): void {
    $resources = &GetResources($player);
    $hasCredit = false;
    foreach ($resources as $r) {
        if (SWUIsCreditToken($r->CardID ?? '')) { $hasCredit = true; break; }
    }
    if (!$hasCredit) return;
    usort($resources, function($a, $b) {
        return (SWUIsCreditToken($a->CardID ?? '') ? 1 : 0) <=> (SWUIsCreditToken($b->CardID ?? '') ? 1 : 0);
    });
    for ($i = 0; $i < count($resources); $i++) $resources[$i]->mzIndex = $i;
}

// Defeat a Credit token at $mzID — tokens leave play by being set aside (CR 3.2), NOT to a discard
// pile. Returns true if one was removed.
function SWUDefeatCreditToken(string $mzID): bool {
    $obj = GetZoneObject($mzID);
    if ($obj === null || !empty($obj->removed)) return false;
    if (!SWUIsCreditToken($obj->CardID ?? '')) return false;
    $obj->removed = true;
    DecisionQueueController::CleanupRemovedCards();
    return true;
}

// Count a player's resources (non-removed, EXCLUDING Credit tokens); $readyOnly restricts to ready ones.
function SWUResourceCount(int $player, bool $readyOnly = false): int {
    $resources = GetResources($player);
    $n = 0;
    foreach ($resources as $r) {
        if (isset($r->removed) && $r->removed) continue;
        if (SWUIsCreditToken($r->CardID ?? '')) continue; // Credit tokens are not resources (CR 3.13)
        if ($readyOnly && intval($r->Status) !== 1) continue;
        $n++;
    }
    return $n;
}

function SWUExhaustResources($player, $count) {
    $resources = &GetResources($player);
    $readyCount = 0;
    for ($i = 0; $i < count($resources); $i++) {
        if (isset($resources[$i]->removed) && $resources[$i]->removed) continue;
        if (SWUIsCreditToken($resources[$i]->CardID ?? '')) continue; // never exhaust a Credit token
        if (intval($resources[$i]->Status) === 1) $readyCount++;
    }
    if ($readyCount < $count) return false;
    $exhausted = 0;
    for ($i = 0; $i < count($resources) && $exhausted < $count; $i++) {
        if (isset($resources[$i]->removed) && $resources[$i]->removed) continue;
        if (SWUIsCreditToken($resources[$i]->CardID ?? '')) continue; // never exhaust a Credit token
        if (intval($resources[$i]->Status) === 1) {
            $resources[$i]->Status = 0;
            $exhausted++;
        }
    }
    return true;
}

// Single synchronous funnel to pay $cost, where $prepaid of it was already covered by an
// alternate source (e.g. SEC_122 Droids — wired in a later phase). Exhausts max(0,$cost-$prepaid)
// REAL resources. Returns true on success. Records resources actually paid (real resources only)
// in $gLastPlayResourcesPaid. NOTE: synchronous — the interactive Droid choice (later) is queued
// by the call-site and pre-resolved into $prepaid, never inside this function.
// JTL_105 The Starhawk — "While paying costs, you pay half as many resources, rounded up." Applies once
// per controlled Starhawk (each halves, rounded up). Used at the card-play affordability check AND the
// payment funnel so a card can be both PLAYED and PAID at the reduced rate. (Ability/upgrade-cost
// halving via direct SWUExhaustResources is a documented edge — most such costs are 1, where ceil is a
// no-op.)
function SWUApplyCostHalving(int $player, int $resCost): int {
    if ($resCost <= 0) return $resCost;
    $count = 0;
    foreach (array_merge(GetGroundArena($player) ?? [], GetSpaceArena($player) ?? []) as $u) {
        if (!empty($u->removed)) continue;
        if (($u->CardID ?? '') === 'JTL_105' && !LostAbilities($u)) $count++;
    }
    for ($i = 0; $i < $count; $i++) $resCost = intval(ceil($resCost / 2));
    return $resCost;
}

function SWUPayCost($player, $cost, $prepaid = 0): bool {
    $cost    = max(0, intval($cost));
    $resCost = max(0, $cost - intval($prepaid));
    $resCost = SWUApplyCostHalving(intval($player), $resCost); // JTL_105 The Starhawk
    $ok      = ($resCost === 0) ? true : SWUExhaustResources($player, $resCost);
    $GLOBALS['gLastPlayResourcesPaid'] = $ok ? $resCost : 0;
    if ($ok && $resCost > 0 && function_exists('SWUTelemetryBumpTurn')) SWUTelemetryBumpTurn($player, 'resourcesUsed', $resCost);
    return $ok;
}

// Put the card at $mzID (hand or deck) into play as a READY resource (Status:1).
// Normal resources enter exhausted; SOR_017 Han Solo's abilities ready the new one.
// Returns the new resource object or null on failure.
function SWURampResourceReady(int $player, string $mzID): ?object {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $newResource = MZMove($player, $mzID, "myResources");
    if ($newResource !== null) {
        $newResource->Status     = 1; // enters READY
        $newResource->Owner      = intval($player);
        $newResource->Controller = intval($player);
        AddGameLogEntry('RESOURCE', 'P' . intval($player) . ' put a card into play as a ready resource');
    }
    $playerID = $savedPID;
    return $newResource;
}

// "Put a card into play as a resource" — the DEFAULT: it enters EXHAUSTED (readied at the controller's
// next ReadyPhase), because in SWU cards enter play exhausted unless the text says otherwise. Only the
// explicit "...and ready it / and readies it" wording (SOR_017, SEC_242) uses SWURampResourceReady.
function SWURampResourceExhausted(int $player, string $mzID): ?object {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $newResource = MZMove($player, $mzID, "myResources");
    if ($newResource !== null) {
        $newResource->Status     = 0; // enters EXHAUSTED
        $newResource->Owner      = intval($player);
        $newResource->Controller = intval($player);
        AddGameLogEntry('RESOURCE', 'P' . intval($player) . ' put a card into play as a resource');
    }
    $playerID = $savedPID;
    return $newResource;
}

// Defeat the resource at $mzID, sending it to its owner's discard (From:RESOURCES).
// Used by SOR_017 Han Solo's "defeat a resource you control" pending trigger.
function SWUDefeatResource(int $player, string $mzID): bool {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($mzID);
    if ($obj === null || (isset($obj->removed) && $obj->removed)) {
        $playerID = $savedPID;
        return false;
    }
    $cardID = $obj->CardID;
    $owner  = intval($obj->Owner ?? 0);
    if ($owner === 0) $owner = intval($player);
    $obj->removed = true;
    SWUAddToDiscard($owner, $cardID, 'RESOURCES');
    AddGameLogEntry('DEFEAT', 'P' . intval($player) . ' defeated a resource');
    DecisionQueueController::CleanupRemovedCards();
    $playerID = $savedPID;
    return true;
}

// True if a unit's printed text makes it enter play ready (e.g. SOR_193 Millennium
// Falcon). Most units enter exhausted; these enter with Status:1.
function SWUUnitEntersReady(string $cardID): bool {
    $text = CardText($cardID) ?? '';
    return stripos($text, 'enters play ready') !== false;
}

// Swap TurnPlayer (1→2, 2→1), then auto-pass for any player who has claimed
// the initiative this round (they are treated as passing for the rest of APS).
function SWUSwapTurnPlayer() {
    global $gTurnPlayer;
    $gTurnPlayer = (intval($gTurnPlayer) === 1) ? 2 : 1;
    // Auto-pass for initiative claimant
    $ic = GetInitiativeCounter();
    $claimedPlayer = 0;
    if ($ic === 'P1_CLAIMED') $claimedPlayer = 1;
    elseif ($ic === 'P2_CLAIMED') $claimedPlayer = 2;
    if ($claimedPlayer !== 0 && intval($gTurnPlayer) === $claimedPlayer) {
        SWUPassAction($claimedPlayer);
    }
}

// ── SWU game-variable helpers ─────────────────────────────────────────────────
// gDecisionQueueVariables holds a pipe-delimited KEY=VALUE string.
// Legacy format (plain integer) is treated as PASS=N for backwards compat.

function _parseSWUVars(): array {
    global $gDecisionQueueVariables;
    $raw = (string)$gDecisionQueueVariables;
    if (preg_match('/^\d+$/', trim($raw))) {
        return ['PASS' => trim($raw)];
    }
    $result = [];
    foreach (explode('|', $raw) as $pair) {
        $kv = explode('=', $pair, 2);
        if (count($kv) === 2) $result[$kv[0]] = $kv[1];
    }
    return $result;
}

function GetSWUVar(string $key, string $default = ''): string {
    return _parseSWUVars()[$key] ?? $default;
}

function SetSWUVar(string $key, string $value): void {
    global $gDecisionQueueVariables;
    $vars = _parseSWUVars();
    $vars[$key] = $value;
    $pairs = [];
    foreach ($vars as $k => $v) $pairs[] = "$k=$v";
    $gDecisionQueueVariables = implode('|', $pairs);
}

function MarkUndoRequiresConsent(): void {
    SetSWUVar('UNDO_REQUIRES_CONSENT', 'true');
}

function ResetUndoDenyCount(int $playerID): void {
    SetSWUVar('UNDO_DENY_COUNT_' . $playerID, '0');
}

// Handle a pass action for $player.
// $gDecisionQueueVariables stores game-state variables as a pipe-delimited KEY=VALUE string.
// The PASS key tracks the consecutive-pass counter: 0 = no prior pass; 1 = opponent just passed.
function SWUPassAction($player) {
    $consecutivePasses = intval(GetSWUVar('PASS', '0'));
    if ($consecutivePasses >= 1) {
        // Both players have passed → end the action phase (MAIN→RGS). But a "when you take the
        // initiative" trigger (e.g. ASH_155 Grogu's bonus attack) can still be QUEUED when the
        // initiative-claim resolves its pass — and a pending decision makes EvaluateTransition
        // return PENDING_DECISION, so AdvanceAndExecute("PASS") is a no-op. If we cleared PASS
        // first and the exit didn't actually fire, the phase would stay MAIN with PASS=0 — a fresh
        // action sequence, letting BOTH players keep acting (the Grogu bug). So only clear PASS
        // when the exit really fires; otherwise keep PASS=1 and retry once the queue drains
        // (high block so it runs after the triggers; DontSkipOnPass so a PASS answer can't skip it).
        if (AdvanceAndExecute("PASS")) {
            SetSWUVar('PASS', '0');
            AutoAdvanceAndExecute();
        } else {
            DecisionQueueController::AddDecision(intval($player), 'CUSTOM', 'SWU_RETRY_ENDPHASE', 9, '', 1);
        }
    } else {
        // A player who has already claimed the initiative is locked out for the rest of the action
        // phase — the engine resolves their non-turns as passes, but they aren't choosing to pass,
        // so don't log a "passed" entry for them (their claim was already logged as "took the
        // initiative"). Other passes are real player choices and ARE logged.
        if (GetInitiativeCounter() !== 'P' . intval($player) . '_CLAIMED') {
            AddGameLogEntry('PASS', 'P' . intval($player) . ' passed');
        }
        SetSWUVar('PASS', '1');
        SWUSwapTurnPlayer();
    }
}

// Player claims the initiative: mark it CLAIMED, then treat as a pass.
function SWUTakeInitiative($player) {
    $ic = GetInitiativeCounter();
    // Only one player may take initiative per round.
    if ($ic === 'P1_CLAIMED' || $ic === 'P2_CLAIMED') {
        SetFlashMessage("Initiative has already been taken this round.");
        return;
    }
    SetInitiativeCounter("P{$player}_CLAIMED");
    AddGameLogEntry('INITIATIVE', 'P' . intval($player) . ' took the initiative');
    // LOF_203 Premonition of Doom — "The next time you take the initiative this phase, exhaust all units."
    if (GlobalEffectCount(intval($player), 'SWU_LOF203') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_LOF203');
        foreach ([1, 2] as $pl) {
            foreach (GetUnitsInPlay($pl) as $u) {
                if (empty($u->removed)) $u->Status = 0;  // exhaust
            }
        }
    }
    // SEC_168 Ziton Moj — "When you take the initiative: deal 2 to a base." One per controlled copy.
    foreach (GetUnitsInPlay(intval($player)) as $zm) {
        if (!empty($zm->removed) || ($zm->CardID ?? '') !== 'SEC_168') continue;
        SWUQueueChooseTarget(intval($player), ['myBase-0', 'theirBase-0'], "Deal_2_to_a_base", "DEAL_BASE_DAMAGE|2");
    }
    // ASH_014 The Mandalorian (leader) — "When you take the initiative: you may pay 1 resource; if you do,
    // draw a card." Fires whether the leader is deployed or undeployed (not gated on the leader being ready).
    $hasMando = false;
    foreach (GetLeader(intval($player)) as $l) { if (($l->CardID ?? '') === 'ASH_014' && empty($l->removed)) { $hasMando = true; break; } }
    if ($hasMando && SWUResourceCount(intval($player), true) >= 1) {
        DecisionQueueController::AddDecision(intval($player), "YESNO", "-", 1, tooltip: "Pay_1_resource_to_draw_a_card?");
        DecisionQueueController::AddDecision(intval($player), "CUSTOM", "ASH_014#0", 1);
    }
    // ASH_155 Grogu — "When you take the initiative: you may attack with a unit." One offer per controlled
    // Grogu. The bonus attack is OUT of the normal action sequence — SWUPassAction below already handles
    // this player's pass — so its terminal after-action must NOT swap the turn again; the ASH_155#0
    // continuation sets SWU_SUPPRESS_AFTERACTION before BeginSWUAttack (consumed in SWUAfterAction).
    foreach (GetUnitsInPlay(intval($player)) as $gz) {
        if (!empty($gz->removed) || ($gz->CardID ?? '') !== 'ASH_155') continue;
        global $playerID; $playerID = intval($player);
        $readyUnits = [];
        foreach (['myGroundArena', 'mySpaceArena'] as $zone) {
            $arr = GetZone($zone);
            for ($i = 0; $i < count($arr); $i++) {
                $u = $arr[$i];
                if ($u === null || !empty($u->removed) || intval($u->Status) !== 1) continue;
                $readyUnits[] = "{$zone}-{$i}";
            }
        }
        if (!empty($readyUnits)) {
            SWUQueueMayChooseTarget(intval($player), $readyUnits, "Grogu:_attack_with_a_unit?",
                "Choose_a_unit_to_attack_with", "ASH_155#0");
        }
    }
    SWUPassAction($player);
}

// Called after any real (non-pass) action: reset consecutive-pass counter and
// swap TurnPlayer to the opponent.
// SEC_192 Grand Moff Tarkin — "When this unit leaves play, that unit's owner takes control of [the
// stolen unit]." The steal is linked to Tarkin via a GlobalEffects flag SWU_SEC192|{tarkinUID}|{stolenUID}
// on Tarkin's controller. This lazy sweep (run after every action) reverts any steal whose Tarkin is
// no longer in play — covering ALL leave-play paths (defeat / bounce / capture / return-to-hand)
// uniformly, mirroring SWUFlushDeferredReplacements. (UIDs never repeat, so a stale flag can't mis-match.)
function _SWURevertSec192Steals(): void {
    global $playerID;
    foreach ([1, 2] as $p) {
        $ge = &GetGlobalEffects($p);
        for ($i = count($ge) - 1; $i >= 0; $i--) {
            $flag = (string)($ge[$i]->CardID ?? '');
            if (strpos($flag, 'SWU_SEC192|') !== 0) continue;
            $parts     = explode('|', $flag);
            $tarkinUID  = intval($parts[1] ?? 0);
            $stolenUID  = intval($parts[2] ?? 0);
            if (_SWUUnitInPlayWithUID($p, $tarkinUID)) continue; // Tarkin still in play → keep control
            // Tarkin gone → return the stolen unit (if still in play) to its owner; drop the flag.
            $savedPID = $playerID; $playerID = $p;
            $mz = SWUFindMzByUID($stolenUID);
            if ($mz !== null) {
                $o = GetZoneObject($mz);
                if ($o !== null && empty($o->removed)) {
                    $owner = intval($o->Owner ?? 0);
                    if ($owner > 0 && $owner !== intval($o->Controller ?? $owner)) {
                        SWUTakeControlOfUnit($owner, $mz);
                    }
                }
            }
            $playerID = $savedPID;
            array_splice($ge, $i, 1);
        }
    }
}

// Queue the action terminator — the step that ends the current action and passes the turn
// (the SWU_AFTER_ACTION handler → SWUAfterAction). ALWAYS use this instead of queuing
// SWU_AFTER_ACTION inline. It MUST run even when the action's last player decision was a
// declined optional "may" follow-up (Pass button → "PASS") or an auto-pass from an empty
// mandatory choice: the engine's decision queue makes a "PASS" answer sticky and would
// otherwise skip every subsequent CUSTOM (DecisionQueueController skip-on-pass at line ~77),
// swallowing this terminator → the turn never passes → the active player gets a free action.
// dontSkipOnPass marks the terminator exempt from that skip. (Events finalize the same way via
// FINISH_PLAY_CARD, which carries the same flag for the same reason.)
function SWUQueueAfterAction(int $player, int $block = 1): void {
    DecisionQueueController::AddDecision($player, "CUSTOM", "SWU_AFTER_ACTION", $block, dontSkipOnPass: 1);
}

function SWUAfterAction($player) {
    SWUFlushDeferredReplacements(); // resolve any "would be defeated → may instead …" deferrals first
    _SWURevertSec192Steals();       // SEC_192 Tarkin — revert any steal whose source left play
    // SEC_194 per-action tracking: finalize the just-completed action. SWU_LAST_ACTION records who acted
    // and whether it attacked a base (and whose), so SEC_194 can ask "did the opponent attack my base in
    // their previous action". The transient SWU_ACTION_BASEATK was set in ExecuteSWUAttack for base hits.
    $_ba = GetSWUVar('SWU_ACTION_BASEATK', '');
    SetSWUVar('SWU_ACTION_BASEATK', '');
    // ⚠ comma-delimited, NOT pipe: '|' is the SWUVar KEY=VALUE delimiter and would truncate the value.
    SetSWUVar('SWU_LAST_ACTION', $_ba !== '' ? (intval($player) . ',BASEATK,' . $_ba) : (intval($player) . ',OTHER'));
    // SEC_145 — mark that this player has acted this phase (gates "play only as your first action").
    if (GlobalEffectCount(intval($player), 'SWU_ACTED_PHASE') === 0) AddGlobalEffects(intval($player), 'SWU_ACTED_PHASE');
    // ASH_155 Grogu — a bonus attack triggered by taking the initiative must NOT run the action's
    // pass-reset/turn-swap (SWUTakeInitiative's SWUPassAction already passed). Consume the one-shot flag:
    // the deferred-replacement flush + tracking above still run, but leave PASS + TurnPlayer untouched.
    if (GetSWUVar('SWU_SUPPRESS_AFTERACTION', '') === '1') {
        SetSWUVar('SWU_SUPPRESS_AFTERACTION', '');
        DecisionQueueController::CleanupRemovedCards();
        return;
    }
    SetSWUVar('PASS', '0');
    DecisionQueueController::CleanupRemovedCards();
    // Plot window (CR §19): while a leader-deploy Plot window is open, a nested play's terminal
    // After Action must NOT end the deploy action. Redirect to the Plot orchestrator, which
    // replaces the just-played card's resource slot and re-offers the next Plot (or closes the
    // window and runs the real After Action — the turn swap below — once none remain).
    if (GetSWUVar('SWU_PLOT_IN_PROGRESS', '') === '1') {
        _SWUPlotAfterPlay(intval($player));
        return;
    }
    SWUSwapTurnPlayer();
}

// "Take an extra action" (JTL_018 Kazuda Xiono): finish the current action's cleanup but DON'T swap
// the turn player, so the same player immediately takes another action. Resets the consecutive-pass
// counter (this was an action, not a pass).
function SWUAfterActionExtra($player) {
    SetSWUVar('PASS', '0');
    DecisionQueueController::CleanupRemovedCards();
}

// ═══════════════════════════════════════════════════════════════════════════
// Trigger Bag — CR-correct triggered-ability collection and resolution
// ═══════════════════════════════════════════════════════════════════════════

// Ability registries — populated by the generator from the card-abilities DB.
// Tests may also inject closures directly for isolated ability testing.
global $whenPlayedAbilities, $whenDefeatedAbilities, $onAttackAbilities, $onDefenseAbilities, $onAttackEndAbilities;
$whenPlayedAbilities    = $whenPlayedAbilities    ?? [];
$whenDefeatedAbilities  = $whenDefeatedAbilities  ?? [];
$onAttackAbilities      = $onAttackAbilities      ?? [];
$onDefenseAbilities     = $onDefenseAbilities     ?? [];
$onAttackEndAbilities   = $onAttackEndAbilities   ?? [];

// Pending triggers collected at the current timing window before any DQ entries are queued.
global $gPendingTriggers, $gTriggerDepth;
$gPendingTriggers = $gPendingTriggers ?? [];
$gTriggerDepth    = $gTriggerDepth    ?? 1;

// Entry TurnEffects to apply when a unit with a specific UniqueID enters play.
// Keyed by UniqueID; consumed immediately inside ActivateCard after placement.
global $gPendingEntryEffects;
$gPendingEntryEffects = $gPendingEntryEffects ?? [];

// Exploit deferred-defeat-trigger bag (Task 1.2 of cost-payment rework, CR 16.d).
// When $gExploitDeferTriggers is true, CollectWhenDefeatedTriggers parks triggers here
// instead of dispatching them immediately.  SWUFlushExploitDeferredTriggers() replays
// them onto the EffectStack alongside the played card's When-Played trigger.
global $gExploitDeferTriggers, $gExploitDeferredBag;
$gExploitDeferTriggers = $gExploitDeferTriggers ?? false;
$gExploitDeferredBag   = $gExploitDeferredBag   ?? [];

// JTL defeat-replacement bag ("if this would be defeated, you may instead …"). A would-be-defeated
// unit with an available replacement is parked here (NOT discarded) and resolved at action end.
global $gDeferredReplacements, $gReplaceSnapshots, $gSec035DefeatSnapshot, $gCombatDefeatByMz;
$gDeferredReplacements = $gDeferredReplacements ?? [];
$gReplaceSnapshots     = $gReplaceSnapshots     ?? []; // uid → snapshot for pilot-upgrade→unit replacement
// SEC_035 Darth Sion — power-at-defeat snapshot (mzID → ['power','owner']). Captured in
// CollectWhenDefeatedTriggers while subcards (Experience) are still intact, read by the
// When Defeated closure after they've been stripped.
$gSec035DefeatSnapshot = $gSec035DefeatSnapshot ?? [];
$gCombatDefeatByMz = $gCombatDefeatByMz ?? [];   // mzID → bool "defeated by combat damage" (ASH_028/191)

// Task 1.3 — play-from-hand orchestrator globals.
// $gPlayGrantedExploit: extra Exploit X granted to the card being played (e.g. by TWI_005).
// Rides across the EXPLOIT_RESOLVE request boundary; restored from the CUSTOM param.
global $gPlayGrantedExploit;
$gPlayGrantedExploit = $gPlayGrantedExploit ?? 0;

// Task 3.1 — resources-paid stamp.
// Records the number of real resources exhausted to pay for the card most recently played.
// Droids (prepaid) are excluded; ignoreCost plays record 0.
// Readable until the next play or the end-of-phase sweep (RegroupPhaseStart clears SWU_PAID_*).
global $gLastPlayResourcesPaid;
$gLastPlayResourcesPaid = $gLastPlayResourcesPaid ?? 0;

function AddTrigger($player, $triggerType, $cardID, $mzID, $extraParams = ''): void {
    global $gPendingTriggers;
    $gPendingTriggers[] = [
        'player'      => intval($player),
        'triggerType' => $triggerType,
        'cardID'      => $cardID,
        'mzID'        => $mzID,
        'extraParams' => $extraParams,
    ];
}

// FlushTriggerBag — original DQ path used by combat/WhenDefeated triggers (single-player, RESOLVE_TRIGGER).
function FlushTriggerBag($activePlayer): bool {
    global $gPendingTriggers, $gTriggerDepth;
    if (empty($gPendingTriggers)) return false;

    $mine   = array_values(array_filter($gPendingTriggers, fn($t) => $t['player'] === intval($activePlayer)));
    $theirs = array_values(array_filter($gPendingTriggers, fn($t) => $t['player'] !== intval($activePlayer)));

    foreach (array_merge($mine, $theirs) as $trigger) {
        DecisionQueueController::AddDecision(
            $trigger['player'],
            "CUSTOM",
            "RESOLVE_TRIGGER|{$trigger['triggerType']}|{$trigger['cardID']}|{$trigger['mzID']}",
            $gTriggerDepth
        );
    }

    $gPendingTriggers = [];
    return true;
}

// _SWUQueueOrchestration — queue a trigger-orchestration / combat-commit CUSTOM decision that must NEVER
// be skipped by a sticky "PASS". When a player DECLINES an optional ("you may") trigger via the Pass
// button (lastDecision = "PASS"), that PASS persists across the rest of the drain and ExecuteStaticMethods
// skips every following CUSTOM that isn't DontSkipOnPass. The trigger's *effect* (DEAL_UNIT_DAMAGE etc.)
// SHOULD be skipped (it self-guards on '-'/'PASS' anyway), but the orchestration that resumes trigger
// resolution / commits combat damage / finalizes the action must still run — else declining an On Attack
// "you may" fizzles the attack's combat damage AND leaves the turn un-swapped (a free extra action).
// dontSkipOnPass=1 is a no-op for any non-PASS lastDecision, so this only changes the broken PASS path.
function _SWUQueueOrchestration($player, string $param, int $block): void {
    DecisionQueueController::AddDecision($player, "CUSTOM", $param, $block, '', 1);
}

// FlushEntryTriggerBag — EffectStack path for entry triggers (WhenPlayed, Shielded, Ambush).
// 0 triggers: returns 0.
// 1 trigger:  auto-dispatches via RESOLVE_NEXT_TRIGGER (no player choice). Returns 1.
// 2+ triggers, same player: populates EffectStack + queues MZCHOOSE for ordering. Returns 2.
// 2+ triggers, cross-player: populates EffectStack + queues YESNO for who resolves first. Returns 2.
function FlushEntryTriggerBag($activePlayer): int {
    global $gPendingTriggers, $gTriggerDepth;
    if (empty($gPendingTriggers)) return 0;

    $count = count($gPendingTriggers);

    // Build Params string (mzID + optional extraParams joined by |).
    $buildParams = fn($t) => $t['mzID'] . (($t['extraParams'] ?? '') !== '' ? '|' . $t['extraParams'] : '');

    if ($count === 1) {
        // Single trigger: add to EffectStack, auto-dispatch via RESOLVE_NEXT_TRIGGER.
        $t = $gPendingTriggers[0];
        $gPendingTriggers = [];
        $stack   = GetEffectStack();
        $stackIdx = count(array_filter($stack, fn($e) => empty($e->removed ?? false)));
        AddEffectStack(CardID:$t['cardID'], Controller:$t['player'], TriggerType:$t['triggerType'], Params:$buildParams($t));
        $mzID = "EffectStack-{$stackIdx}";
        _SWUQueueOrchestration($t['player'], "RESOLVE_NEXT_TRIGGER|{$mzID}", $gTriggerDepth);
        _SWUQueueOrchestration($t['player'], "SWU_TRIGGER_RESUME|{$activePlayer}", 20);
        return 1;
    }

    // 2+ triggers: populate EffectStack for all.
    $mine   = array_values(array_filter($gPendingTriggers, fn($t) => $t['player'] === intval($activePlayer)));
    $theirs = array_values(array_filter($gPendingTriggers, fn($t) => $t['player'] !== intval($activePlayer)));
    $gPendingTriggers = [];

    foreach (array_merge($mine, $theirs) as $t) {
        AddEffectStack(CardID:$t['cardID'], Controller:$t['player'], TriggerType:$t['triggerType'], Params:$buildParams($t));
    }

    _SWUQueueOrchestration(intval($activePlayer), "SWU_TRIGGER_RESUME|{$activePlayer}", 20);

    if (!empty($mine) && !empty($theirs)) {
        // Cross-player: active player picks who resolves first.
        DecisionQueueController::AddDecision(intval($activePlayer), "YESNO", "-", $gTriggerDepth,
            tooltip:"Resolve_Which_Player_First?");
        _SWUQueueOrchestration(intval($activePlayer),
            "SWU_TRIGGER_ORDER_CHOICE|{$activePlayer}", $gTriggerDepth);
    } else {
        // Single player has all triggers: go straight to MZCHOOSE.
        $choosingPlayer = !empty($mine) ? intval($activePlayer) : (intval($activePlayer) === 1 ? 2 : 1);
        $targetStr = _SWUEffectStackTargetsForPlayer($choosingPlayer);
        DecisionQueueController::AddDecision($choosingPlayer, "MZCHOOSE", $targetStr, $gTriggerDepth,
            tooltip:"Choose_trigger_to_resolve");
        _SWUQueueOrchestration($choosingPlayer,
            "RESOLVE_NEXT_TRIGGER|{$choosingPlayer}", $gTriggerDepth);
    }
    return 2;
}

// SWUFlushExploitDeferredTriggers — replays Exploit-deferred WhenDefeated / leave-play
// triggers onto the EffectStack in the same batch as the played card's WhenPlayed trigger.
// Called from ActivateCard's unit branch (Task 1.4) after the card's own entry triggers
// have been staged but before FlushEntryTriggerBag fires, so all triggers order together.
//
// Mechanism: mirrors FlushEntryTriggerBag — each descriptor in $gExploitDeferredBag is
// re-added to $gPendingTriggers via AddTrigger so that FlushEntryTriggerBag sees them
// together with the WhenPlayed trigger and handles ordering (1 trigger = auto-dispatch,
// 2+ = MZCHOOSE / YESNO).  After replay the bag is cleared and the flag reset.
function SWUFlushExploitDeferredTriggers(int $player): void {
    global $gExploitDeferTriggers, $gExploitDeferredBag;
    $gExploitDeferTriggers = false;
    if (empty($gExploitDeferredBag)) return;
    foreach ($gExploitDeferredBag as $entry) {
        $kind = $entry['__kind__'] ?? 'trigger';
        if ($kind === 'trigger') {
            AddTrigger($entry['player'], $entry['triggerType'], $entry['cardID'], $entry['mzID'], $entry['extraParams'] ?? '');
        } elseif ($kind === 'bounty') {
            // Replay bounty decisions at flush time, alongside the When-Played batch.
            DecisionQueueController::AddDecision($entry['activePlayer'], "YESNO", "-", 1, tooltip:"Collect_bounty?");
            DecisionQueueController::AddDecision($entry['activePlayer'], "CUSTOM", "SWUCollectBounty|{$entry['cardID']}", 1);
        }
    }
    $gExploitDeferredBag = [];
}

// FlushCombatTriggerBag — like FlushEntryTriggerBag but for combat Step 1 triggers.
// Instead of finalising via SWUAfterAction when the EffectStack empties, the queued
// SWU_TRIGGER_RESUME carries a COMBAT continuation that queues SWUCombatDamage.
// Returns the flush count (0 = no triggers; caller queues SWUCombatDamage directly).
function FlushCombatTriggerBag(int $activePlayer, string $attackerMzID, string $targetMzID): int {
    global $gPendingTriggers, $gTriggerDepth;
    if (empty($gPendingTriggers)) return 0;

    $count = count($gPendingTriggers);
    $attackerObj = GetZoneObject($attackerMzID);
    $attackerUID = $attackerObj !== null ? intval($attackerObj->UniqueID ?? 0) : 0;
    $cont  = "COMBAT|{$attackerMzID}|{$targetMzID}|{$attackerUID}";

    $buildParams = fn($t) => $t['mzID'] . (($t['extraParams'] ?? '') !== '' ? '|' . $t['extraParams'] : '');

    if ($count === 1) {
        $t = $gPendingTriggers[0];
        $gPendingTriggers = [];
        $stack    = GetEffectStack();
        $stackIdx = count(array_filter($stack, fn($e) => empty($e->removed ?? false)));
        AddEffectStack(CardID:$t['cardID'], Controller:$t['player'], TriggerType:$t['triggerType'], Params:$buildParams($t));
        // Orchestration (resolve + resume) rides the ACTIVE player's queue so it drains in the attacker's
        // action — even when the lone trigger is the defender's On Defense ($t['player'] != activePlayer).
        // The effect still dispatches under the EffectStack entry's Controller in RESOLVE_NEXT_TRIGGER.
        _SWUQueueOrchestration(intval($activePlayer), "RESOLVE_NEXT_TRIGGER|EffectStack-{$stackIdx}", $gTriggerDepth);
        _SWUQueueOrchestration(intval($activePlayer), "SWU_TRIGGER_RESUME|{$activePlayer}|{$cont}", 20);
        return 1;
    }

    // 2+ triggers: populate EffectStack for all (active player's first).
    $mine   = array_values(array_filter($gPendingTriggers, fn($t) => $t['player'] === intval($activePlayer)));
    $theirs = array_values(array_filter($gPendingTriggers, fn($t) => $t['player'] !== intval($activePlayer)));
    $gPendingTriggers = [];

    foreach (array_merge($mine, $theirs) as $t) {
        AddEffectStack(CardID:$t['cardID'], Controller:$t['player'], TriggerType:$t['triggerType'], Params:$buildParams($t));
    }

    _SWUQueueOrchestration(intval($activePlayer), "SWU_TRIGGER_RESUME|{$activePlayer}|{$cont}", 20);

    if (!empty($mine) && !empty($theirs)) {
        DecisionQueueController::AddDecision(intval($activePlayer), "YESNO", "-", $gTriggerDepth,
            tooltip:"Resolve_Which_Player_First?");
        _SWUQueueOrchestration(intval($activePlayer),
            "SWU_TRIGGER_ORDER_CHOICE|{$activePlayer}", $gTriggerDepth);
    } else {
        $choosingPlayer = !empty($mine) ? intval($activePlayer) : (intval($activePlayer) === 1 ? 2 : 1);
        $targetStr = _SWUEffectStackTargetsForPlayer($choosingPlayer);
        DecisionQueueController::AddDecision($choosingPlayer, "MZCHOOSE", $targetStr, $gTriggerDepth,
            tooltip:"Choose_trigger_to_resolve");
        _SWUQueueOrchestration($choosingPlayer,
            "RESOLVE_NEXT_TRIGGER|{$choosingPlayer}", $gTriggerDepth);
    }

    return $count;
}

// Returns a &-delimited mzID string of non-removed EffectStack entries for the given player.
function _SWUEffectStackTargetsForPlayer($player): string {
    $stack = GetEffectStack();
    $mzIDs = [];
    foreach ($stack as $i => $e) {
        if (!empty($e->removed)) continue;
        if (intval($e->Controller) === intval($player)) $mzIDs[] = "EffectStack-{$i}";
    }
    return implode('&', $mzIDs);
}

// On* dispatchers — call the registered closure(s) for the given card. A card may register multiple
// When-Played windows under contiguous ":N" tokens (LOF_070 is the first: ":0" Heroism, ":1" Villainy);
// each fires in order as its own separate ability. Single-window cards register only ":0".
function OnWhenPlayed($player, $cardID, $mzID): void {
    global $whenPlayedAbilities;
    $fired = false;
    for ($w = 0; isset($whenPlayedAbilities["{$cardID}:{$w}"]); $w++) {
        $whenPlayedAbilities["{$cardID}:{$w}"]($player, $mzID);
        $fired = true;
    }
    if ($fired) {
        // LOF_197 Qui-Gon Jinn's Aethersprite — "The next time you use a When Played ability this phase,
        // you may use that ability again." The flag is armed on its attack; the NEXT When-Played ability
        // consumes it and offers a repeat (re-dispatch the same ability on the same unit).
        if (GlobalEffectCount($player, 'SWU_LOF197_REPEAT') > 0) {
            RemoveGlobalEffect($player, 'SWU_LOF197_REPEAT');
            DecisionQueueController::AddDecision($player, "YESNO", "-", 1,
                tooltip: "Use_that_When_Played_ability_again_(Qui-Gon's_Aethersprite)?");
            DecisionQueueController::AddDecision($player, "CUSTOM", "LOF_197_REPEAT|{$cardID}|{$mzID}", 1);
        }
    }
}
$customDQHandlers["LOF_197_REPEAT"] = function($player, $parts, $lastDecision) {
    if ($lastDecision !== 'YES') return;
    global $playerID; $playerID = intval($player);
    $cardID = $parts[0] ?? ''; $mzID = $parts[1] ?? '';
    if ($cardID === '' || $mzID === '') return;
    OnWhenPlayed(intval($player), $cardID, $mzID); // flag already consumed → no re-arm/loop
};
function OnWhenDefeated($player, $cardID, $mzID): void {
    global $whenDefeatedAbilities;
    $key = $cardID . ':0';
    if (isset($whenDefeatedAbilities[$key])) $whenDefeatedAbilities[$key]($player, $mzID);
}
// OnAttackTrigger($player, $mzID) is defined in CombatLogic.php.

function OnDefenseTrigger($player, $cardID, $mzID): void {
    global $onDefenseAbilities;
    $key = $cardID . ':0';
    if (isset($onDefenseAbilities[$key])) {
        $onDefenseAbilities[$key]($player, $mzID);
        // Mark that THIS attack has an On Defense reaction pending on the defender's queue, so the combat
        // resume gates SWUCombatDamage behind it (combat-pause). Only true On Defense triggers set this —
        // On Attack opponent decisions (indirect damage, Watto) do NOT, so they keep their old timing.
        // Cleared at attack start and when combat commits. (If the closure queued nothing — e.g. no Force
        // for a may-use-Force On Defense — the resume's blocking-decision check is false, so no hop.)
        SetSWUVar('SWU_PENDING_DEF_REACTION', '1');
    }
}
function OnAttackEndTrigger($player, $cardID, $mzID): void {
    global $onAttackEndAbilities;
    $key = $cardID . ':0';
    if (isset($onAttackEndAbilities[$key])) $onAttackEndAbilities[$key]($player, $mzID);
}

// SOR_036 Gideon Hask reaction: give an Experience token to a friendly unit ($player = Gideon's
// controller). Mandatory; 1 friendly auto-resolves.
function GideonExpReaction($player): void {
    global $playerID;
    $playerID = intval($player);
    $friendlies = array_values(array_merge(
        ZoneSearch('myGroundArena', AnyUnitFilter),
        ZoneSearch('mySpaceArena',  AnyUnitFilter)
    ));
    SWUQueueChooseTarget(intval($player), $friendlies, 'Give_an_Experience_token_to_a_friendly_unit', 'GIVE_EXPERIENCE|1');
}

// SOR_002 Iden Versio (deployed leader unit) reaction: "Heal 1 damage from your base." Mandatory,
// no target — heal the controller's own base.
function IdenHealReaction($player): void {
    OnHealBase(intval($player), intval($player), 1);
}

// SOR_105 General Krell granted reaction: the controller of the defeated unit MAY draw a card.
function KrellDrawReaction($player): void {
    DecisionQueueController::AddDecision(intval($player), 'YESNO', '-', 1, 'Draw_a_card?');
    DecisionQueueController::AddDecision(intval($player), 'CUSTOM', 'KRELL_DRAW', 1);
}

// SOR_015 Boba Fett (undeployed leader) reaction: auto-resolve (always-yes) — exhaust the leader
// to ready a resource, but only when it readies something (collect-time already gated on an
// exhausted resource existing; re-checked here for safety). If nothing readies, the leader is NOT
// exhausted (no benefit → skip the cost).
function BobaLeftPlayReaction($player): void {
    global $playerID;
    $playerID = intval($player);
    if (!_SWULeaderReadyUndeployed(intval($player), 'SOR_015')) return;
    if (SWUReadyResources(intval($player), 1) <= 0) return; // resources full → skip the cost
    foreach (GetLeader(intval($player)) as &$l) {
        if (!empty($l->removed)) continue;
        if (($l->CardID ?? '') === 'SOR_015') { $l->Ready = false; break; }
    }
    unset($l);
}

// ── Combat-hit triggers (Phase 7.2): WhenDealsCombatDamage / WhenDefeats ──────
// SOR_085 Rukh — "deals combat damage to a non-leader unit while attacking: defeat that unit."
// $mzID = the defender. No-op if it was already defeated by the combat.
function RukhDefeatTrigger($player, $mzID): void {
    global $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($mzID);
    if ($obj === null || !empty($obj->removed) || IsLeaderUnit($obj)) return;
    SWUDefeatUnit(intval($player), $mzID);
}

// SOR_150 Heroic Sacrifice — granted self-defeat: defeat the attacker ($mzID) after it dealt combat
// damage. Unlike Rukh, this defeats the source unit itself (a deployed leader returns to its zone).
function HeroicSacrificeDefeatTrigger($player, $mzID): void {
    global $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($mzID);
    if ($obj === null || !empty($obj->removed)) return;
    SWUDefeatUnit(intval($player), $mzID);
}

// ASH_102 Ravager — "When you play a unit: you may have it deal damage equal to its power to a unit in
// the same arena." $playedUID = the just-played unit (the dealer). Targets are units in the dealer's arena.
function RavagerReaction($player, int $playedUID): void {
    global $playerID; $playerID = intval($player);
    if ($playedUID <= 0) return;
    $dealerMz = SWUFindMzByUID($playedUID);
    if ($dealerMz === null) return;
    $dealer = GetZoneObject($dealerMz);
    if ($dealer === null || !empty($dealer->removed)) return;
    $arena = strpos($dealerMz, 'SpaceArena') !== false ? 'SpaceArena' : 'GroundArena';
    $targets = [];
    foreach (["my{$arena}", "their{$arena}"] as $z) {
        foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o !== null && empty($o->removed) && intval($o->UniqueID ?? 0) !== $playedUID) $targets[] = $mz;
        }
    }
    if (empty($targets)) return;
    SWUQueueMayChooseTarget(intval($player), $targets, "Have_the_played_unit_deal_its_power_to_a_unit?", "Choose_a_unit_in_the_same_arena", "ASH_102#0|{$playedUID}");
}

// ASH_060 Cobb Vanth — "When you play another unit: you may deal 2 damage to this unit. If you do, give
// a Shield token to that unit." $spec = "{cobbUID},{playedUID}". Offered via YESNO.
function CobbVanthReaction($player, string $spec): void {
    global $playerID; $playerID = intval($player);
    $parts = explode(',', $spec);
    $cobbUID = intval($parts[0] ?? 0);
    $playedUID = intval($parts[1] ?? 0);
    if ($cobbUID <= 0 || $playedUID <= 0) return;
    if (SWUFindMzByUID($cobbUID) === null) return;   // Cobb left play
    DecisionQueueController::AddDecision(intval($player), "YESNO", "-", 1, tooltip: "Deal_2_to_Cobb_Vanth_to_Shield_the_played_unit?");
    DecisionQueueController::AddDecision(intval($player), "CUSTOM", "ASH_060#0|{$cobbUID}|{$playedUID}", 1);
}

