}

// SOR_088 Blizzard Assault AT-AT — "attacks and defeats a unit: you may deal the excess damage from
// this attack to an enemy ground unit." $excess = attack power − the defeated unit's remaining HP.
// ASH_137 Wipe Them Out — "you may deal its excess damage to another unit in the SAME ARENA." $attackerMz
// is the attacker (still in play); offer the excess to another unit in the attacker's arena.
function Ash137ExcessTrigger($player, string $attackerMz, int $excess): void {
    global $playerID; $playerID = intval($player);
    if ($excess <= 0) return;
    $atk = GetZoneObject($attackerMz);
    $atkUid = $atk ? intval($atk->UniqueID ?? 0) : 0;
    $arena = strpos($attackerMz, 'SpaceArena') !== false ? 'SpaceArena' : 'GroundArena';
    $targets = [];
    foreach (["my{$arena}", "their{$arena}"] as $z) {
        foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o !== null && empty($o->removed) && intval($o->UniqueID ?? 0) !== $atkUid) $targets[] = $mz;
        }
    }
    if (empty($targets)) return;
    SWUQueueMayChooseTarget(intval($player), $targets, "Deal_the_excess_damage_to_another_unit?", "Choose_a_unit_in_the_same_arena", "DEAL_UNIT_DAMAGE|{$excess}");
}

function BlizzardExcessTrigger($player, int $excess): void {
    global $playerID;
    $playerID = intval($player);
    if ($excess <= 0) return;
    $targets = array_values(ZoneSearch('theirGroundArena', AnyUnitFilter));
    SWUQueueMayChooseTarget(intval($player), $targets,
        'Deal_the_excess_damage_to_an_enemy_ground_unit', 'Choose_an_enemy_ground_unit', "DEAL_UNIT_DAMAGE|{$excess}");
}

// Fires after the first attack of a "then (may) attack with another unit" card completes.
// $spec = "{rebelOnly},{mayDecline},{bonus},{excludeUID}" (armed in SWU_CHAINED_ATTACK by the
// initiating leader action / event before the first BeginSWUAttack). Comma-delimited, NOT pipe:
// SWUVar values are stored in a pipe-delimited KEY=VALUE string, and this spec also rides through
// the pipe-delimited RESOLVE_TRIGGER param — a '|' in it would corrupt both.
function ChainedAttackTrigger($player, $spec): void {
    $p = explode(',', $spec);
    $rebelOnly  = (($p[0] ?? '0') === '1');
    $mayDecline = (($p[1] ?? '0') === '1');
    $bonus      = intval($p[2] ?? 0);
    $excludeUID = intval($p[3] ?? 0);
    $constraint = $p[4] ?? '';   // optional arena ("space"/"ground") or trait filter for the 2nd attacker
    SWUQueueAnotherAttack(intval($player), $rebelOnly, $mayDecline, $bonus, $excludeUID, $constraint);
}

// JTL_156 Trench Run granted On Attack: discard the top 2 cards of the defending player's deck and deal
// unpreventable damage equal to the difference in their costs to the attacking unit itself.
function JTL156AttackTrigger($player, $mzID): void {
    global $playerID;
    $playerID = intval($player);
    $opp = OtherPlayer(intval($player));
    $c1  = SWUMillTopCard($opp);
    $c2  = SWUMillTopCard($opp);
    if ($c1 === null && $c2 === null) return;
    $diff = abs(($c1 !== null ? intval(CardCost($c1)) : 0) - ($c2 !== null ? intval(CardCost($c2)) : 0));
    if ($diff <= 0) return;
    $obj = GetZoneObject($mzID);
    if ($obj === null || !empty($obj->removed)) return;
    SWUDealDamageToUnit($mzID, $diff, intval($player));   // direct (non-combat) damage → unpreventable
}

// JTL_202 Black Squadron Scout Wing — when an upgrade is played onto it, offer a "may attack (+1/+0)".
function JTL202UpgradeTrigger($player, $mzID): void {
    global $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($mzID);
    if ($obj === null || !empty($obj->removed) || intval($obj->Status) !== 1) return;  // must be ready to attack
    $uid = intval($obj->UniqueID ?? 0);
    DecisionQueueController::AddDecision($player, 'YESNO', '-', 1, tooltip: "Attack_with_this_unit_(+1/+0)?");
    DecisionQueueController::AddDecision($player, 'CUSTOM', "JTL_202#0|{$uid}", 1);
}

// JTL_223 Razor Crest — when a Pilot attaches: may return a non-leader unit costing ≤2, OR an exhausted
// non-leader unit costing ≤4, to its owner's hand.
function JTL223AttachTrigger($player): void {
    global $playerID;
    $playerID = intval($player);
    $targets = [];
    foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $z) {
        foreach (ZoneSearch($z, NonLeaderUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            $cost = intval(CardCost($o->CardID));
            $exhausted = intval($o->Status) !== 1;
            if ($cost <= 2 || ($exhausted && $cost <= 4)) $targets[] = $mz;
        }
    }
    if (empty($targets)) return;
    SWUQueueMayChooseTarget(intval($player), $targets, "Return_a_unit_to_its_owner's_hand", "Choose_a_unit_to_return", "BOUNCE_UNIT");
}

// JTL_191 Invincible — "When you deploy a leader: You may return a non-leader unit that costs 3 or
// less to its owner's hand." Fires once per Invincible the deploying player controls.
function JTL191DeployTrigger($player): void {
    global $playerID;
    $playerID = intval($player);
    $targets = [];
    foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $z) {
        foreach (ZoneSearch($z, NonLeaderUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            if (intval(CardCost($o->CardID)) <= 3) $targets[] = $mz;
        }
    }
    if (empty($targets)) return;
    SWUQueueMayChooseTarget(intval($player), $targets, "Return_a_unit_to_its_owner's_hand", "Choose_a_unit_to_return", "BOUNCE_UNIT");
}

// JTL_120 Dorsal Turret — defeat the defender it just dealt combat damage to (if still in play).
function JTL120DefeatTrigger($player, $mzID): void {
