}

function DispatchTrigger($player, $triggerType, $cardID, $mzID, $extra = []): void {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    switch ($triggerType) {
        case 'WhenPlayed':          OnWhenPlayed($player, $cardID, $mzID);          break;
        case 'WhenPlayedAsUpgrade': OnWhenPlayedAsUpgrade($player, $cardID, $mzID); break;
        case 'OnAttached':          OnOnAttached($player, $cardID, $mzID);          break;
        case 'WhenDefeated':
            OnWhenDefeated($player, $cardID, $mzID);
            SWUCollectThrawnReuse($player, $cardID, $mzID); // JTL_002 Thrawn "when you use a When Defeated ability"
            break;
        case 'JTL_169':   ShadowCasterReuseTrigger($player, $cardID, $mzID); break;
        case 'OnAttack':
            OnAttackTrigger($player, $mzID);
            SWUCollectEnfysReuse($player, $cardID, $mzID); // LAW_014 Enfys Nest "when you use an On Attack ability"
            break;
        case 'JTL_156': JTL156AttackTrigger($player, $mzID);         break;
        case 'LOF_205': LOF205BounceTrigger($player, $mzID);         break; // $mzID = the defender
        // LOF common Force bases — "When a friendly Force unit attacks: The Force is with you."
        case 'LOF_020': case 'LOF_021': case 'LOF_023': case 'LOF_024':
        case 'LOF_026': case 'LOF_027': case 'LOF_029': case 'LOF_030':
            TheForceIsWithYou($player); break;
        case 'LOF_087': EighthBrotherReaction($player); break; // "When you play another unit": may use the Force → +2/+2
        case 'LOF_229': KyloRenUpgradeReaction($player); break; // "When you play an upgrade on this unit": may use the Force → draw
        case 'ASH_047': Ash047UpgradeReaction($player); break;  // "When you play an upgrade on this unit": may create a Mandalorian token (once/round)
        case 'ASH_063': SWUCreateUnitToken($player, 'ASH_T01'); break; // Bo-Katan's Gauntlet — granted "When Defeated: create a Mandalorian token"
        case 'ASH_134': SWUCreateUnitToken($player, 'ASH_T01'); break; // Warrior's Legacy (upgrade) — granted "When Defeated: create a Mandalorian token"
        case 'LOF_249': LukeSkywalkerReaction($player, intval($extra[0] ?? 0)); break; // "another unique unit": may use the Force → Exp+Shield
        case 'ASH_060': CobbVanthReaction($player, (string)($extra[0] ?? '')); break;  // play another unit → may deal 2 to self + Shield the played unit
        case 'ASH_102': RavagerReaction($player, intval($extra[0] ?? 0)); break;       // play a unit → may have it deal its power to a unit in the same arena
        case 'LOF_166': LOF166BaseReaction($player, $mzID); break; // deals combat damage to a base → may give Exp to self
        case 'JTL_202': JTL202UpgradeTrigger($player, $mzID);       break;
        case 'JTL_223':  JTL223AttachTrigger($player);              break;
        case 'JTL_191':  JTL191DeployTrigger($player);              break;
        case 'JTL_120':  JTL120DefeatTrigger($player, $mzID);        break;
        // Upgrade-GRANTED When-Defeated abilities — the unit gained them, so JTL_002 Thrawn re-uses
        // them too (SWUCollectThrawnReuse with the granted trigger type).
        case 'JTL_073':  JTL073DefeatTrigger($player); SWUCollectThrawnReuse($player, $cardID, $mzID, $cardID); break;
        case 'SEC_039':  SEC039DefeatTrigger($player); SWUCollectThrawnReuse($player, $cardID, $mzID, $cardID); break;
        case 'SEC_156':  SEC156DefeatTrigger($player); SWUCollectThrawnReuse($player, $cardID, $mzID, $cardID); break;
        case 'OnAttackFromUpgrade':
            OnAttackFromUpgradeTrigger($player, $cardID, $mzID);
            SWUCollectEnfysReuse($player, $cardID, $mzID, true); // LAW_014 — upgrade-granted On Attack counts too
            break;
        case 'OnAttackEndFromUpgrade': OnAttackEndFromUpgradeTrigger($player, $cardID, $mzID); break;
        case 'OnAttackedFromUpgrade': OnAttackedFromUpgradeTrigger($player, $cardID, $mzID); break;
        case 'OnDefenseFromUpgrade': OnDefenseFromUpgradeTrigger($player, $cardID, $mzID); break;
        case 'SEC_101_PREVENT': SEC101PreventTrigger($player, $mzID); break;
        case 'ASH_062_PREVENT': Ash062PreventTrigger($player, $mzID); break;
        case 'OnDefense':    OnDefenseTrigger($player, $cardID, $mzID);   break;
        case 'OnAttackEnd':  OnAttackEndTrigger($player, $cardID, $mzID); break;
        case 'SOR_036':    GideonExpReaction($player);    break;
        case 'SEC_051':    GideonExpReaction($player);    break;   // Bo-Katan — same "Exp to a friendly" reaction
        case 'SOR_002':     IdenHealReaction($player);     break;
        case 'SOR_105':    KrellDrawReaction($player);    break;
        case 'SOR_015': BobaLeftPlayReaction($player); break;
        case 'SOR_085':        RukhDefeatTrigger($player, $mzID);              break;
        case 'ASH_101':        RukhDefeatTrigger($player, $mzID);              break;   // The Great Mothers — defeat the combat-damaged non-leader defender
        case 'SOR_150': HeroicSacrificeDefeatTrigger($player, $mzID); break;
        case 'LAW_205': HeroicSacrificeDefeatTrigger($player, $mzID); break;   // Flash the Vents self-defeat
        case 'ASH_184': Ash184GiveAdvTrigger($player); break;   // Follow Me — give 3 Advantage tokens to a unit
        case 'LAW_033': Law033Trigger($player, $mzID); break;   // Hound's Tooth — may defeat a lower-power unit
        case 'LAW_034': Law034Trigger($player, $mzID); break;   // Chewbacca — Exp + heal 3 self
        case 'LAW_054': Law054Trigger($player, $mzID); break;   // Maul — may take control of a non-leader unit
        case 'LAW_088': Law088Trigger($player, $mzID); break;   // Anakin — may return the attacker + heal 2
        case 'LAW_119': Law119Trigger($player); break;          // Rogue One — scry top 2
        case 'LAW_176': Law176Trigger($player, $mzID); break;   // Sebulba's Podracer — may ready on deck-discard
        case 'LAW_141': Law141Trigger($player, $mzID); SWUCollectThrawnReuse($player, $cardID, $mzID, $cardID); break;   // Targeted For Removal — opp creates Credits = host cost (granted WD; Thrawn-reusable)
        case 'LAW_201': Law201Trigger($player, $mzID); SWUCollectThrawnReuse($player, $cardID, $mzID, $cardID); break;   // Thermal Detonator — if host was ready, 2 to each enemy ground unit (granted WD; Thrawn-reusable)
        case 'LAW_007': Law007Trigger($player); break;          // Boba Fett (leader form) — may exhaust → Credit
        case 'LAW_046': Law046Trigger($player, $mzID); break;   // Chirrut — may heal 4 from another unit
        case 'ASH_005': Ash005Trigger($player, $mzID); break;   // Luke — may exhaust → heal 1 from the attacker
        case 'ASH_128': { $pp128 = explode(',', $mzID, 2); Ash128Trigger($player, intval($pp128[0] ?? 0), strval($pp128[1] ?? '')); break; }   // Bothan-5 — may capture defeated friendly from discard
        case 'ASH_013': Ash013Trigger($player, $mzID); break;   // Ezra — may exhaust → Advantage to a different unit
        case 'ASH_016': Ash016Trigger($player, $mzID, intval($extra[0] ?? 0)); break;   // Shin — may exhaust → exhaust a cheaper unit
        case 'ASH_017': Ash017Trigger($player, intval($extra[0] ?? 0)); break;          // Greef — may exhaust → Advantage to the played/created unit
        case 'ASH_018': Ash018Trigger($player); break;                                  // Grogu — may deploy on a uq-4+ play
        case 'SOR_149':         MaceReadyTrigger($player, $mzID);              break;
        case 'SEC_209':         SEC209CaptureTrigger($player, $mzID);          break;
        case 'SEC_088':         SEC088MayDrawTrigger($player, $mzID);          break;
        case 'SEC_147':         SEC147EachDiscardTrigger($player, $mzID);      break;
        case 'SEC_150':         SEC150SacTrigger($player, $mzID);              break;
        case 'SEC_205':         SEC205MillTrigger($player, $mzID);            break;
        case 'SEC_013':         SEC013AttackerDefeatedTrigger($player);        break;
        case 'SEC_017':         SEC017DeployBaseHitTrigger($player);           break;
        case 'SEC_017#1':       SEC017LeaderBaseHitTrigger($player);           break;
        case 'LOF_017':         RevanExpTrigger($player, $mzID);               break;
        case 'SOR_133': SeventhSisterBaseTrigger($player);            break;
        case 'SOR_088':    BlizzardExcessTrigger($player, intval($extra[0] ?? 0)); break;
        case 'ASH_137':    Ash137ExcessTrigger($player, $mzID, intval($extra[0] ?? 0)); break;   // Wipe Them Out — excess to another unit in the arena
        case 'SOR_115':        KallusDrawTrigger($player);                   break;
        case 'SOR_013':       CassianDrawTrigger($player);                  break;
        case 'TWI_210': CunningOpponentPlayedReaction($player); break;
        case 'SOR_182':        BosskPlayEventReaction($player);        break;
        case 'SOR_143':     FFFPlayAggressionReaction($player);     break;
        case 'SOR_109':           YularenHealReaction($player);           break;
        case 'Shielded':
            DoGiveShieldToken($player, $mzID);
            break;
        case 'Ambush':
            // Re-compute valid targets at dispatch time (units may have died between collect and dispatch).
            $ambushObj = GetZoneObject($mzID);
            if ($ambushObj === null || !empty($ambushObj->removed)) break;
            $ambushArena    = $ambushObj->Location ?? 'GroundArena';
            $ambushOpponent = OtherPlayer($player);
            $validTargets   = SWUGetValidAmbushTargets($ambushOpponent, $ambushObj, $ambushArena);
            if (empty($validTargets)) break;
            $targetStr = implode('&', $validTargets);
            DecisionQueueController::AddDecision($player, "YESNO", "-", 1, tooltip:"Ambush_attack?");
            DecisionQueueController::AddDecision($player, "CUSTOM", "SWUAmbushAnswer|{$mzID}|{$targetStr}", 1);
            break;
        case 'Support':
            // Re-compute eligible attackers at dispatch time (board may have changed since collect).
            // One combined "may choose" popup (pick an attacker OR decline) — mirrors IBH_064's
            // "may attack with another unit" so the interactive choice resolves cleanly inside the
            // entry-trigger resume (a YESNO + separate MZCHOOSE chain misorders here).
            $supObj = GetZoneObject($mzID);
            if ($supObj === null || !empty($supObj->removed)) break;
            $supAttackers = SWUGetValidSupportAttackers($player, $supObj);
            if (empty($supAttackers)) break;
            SWUQueueMayChooseTarget($player, $supAttackers, "Support__attack_with_another_unit?",
                "Choose_a_unit_to_attack_with", "SWUSupportChooseAttacker|{$mzID}");
            break;
        // Support-granted abilities fire the supporting unit's (S's) closure against the attacker's (A's)
        // mzID, so "this unit" resolves to A. Reuse the innate/upgrade dispatch helpers.
        case 'SupportOnAttack':    OnAttackFromUpgradeTrigger($player, $cardID, $mzID); break;
        case 'SupportOnAttackEnd': OnAttackEndTrigger($player, $cardID, $mzID);         break;
        case 'SupportWhenDefeated': OnWhenDefeated($player, $cardID, $mzID);            break;
        case 'AdvantageShed':      _SWUResolveAdvantageShed($player, $mzID);            break;
    }
    $playerID = $savedPID;
}

function SWUApplyPassiveEntryGrants(int $player, string $cardID, string $mzID): void {
    // ASH_006 Sabine Wren (leader) — "the next unit you play this phase gains Shielded." Consume the flag at
    // the first unit entry and give it a Shield token (Shielded's "give a Shield token" clarification).
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false
        && GlobalEffectCount($player, 'SWU_ASH006_SHIELDED_NEXT') > 0) {
        RemoveGlobalEffect($player, 'SWU_ASH006_SHIELDED_NEXT');
        DoGiveShieldToken($player, $mzID);
    }
    if (HasTrait($cardID, 'Vehicle')) {
        $ground = GetGroundArena($player);
        foreach ($ground as $u) {
            if (isset($u->removed) && $u->removed) continue;
            if ($u->CardID === 'SOR_100') {
                AddTurnEffect($mzID, 'SOR_100');   // CardID token (registry: Ambush, perm) — provenance for Active Effects
                break;
            }
        }
    }
}

// CollectEntryTriggers — collect WhenPlayed, Shielded, and Ambush triggers when a unit enters play.
// Uses FlushEntryTriggerBag (EffectStack path). Returns the flush count (0, 1, or 2+).
// $isPlay distinguishes a genuine card play (the default) from a non-play entry such as a leader
// deploy: "when you play a card" observer reactions (FFF/Bossk/Cunning) only fire on a real play.
function CollectEntryTriggers($activePlayer, $cardID, $mzID, $targetArena, bool $isPlay = true): int {
    // SEC_046 Galen Erso — a named card the enemy Galen targets has lost its abilities, so its When
    // Played does not fire (the $cardID/hand-source path can't rely on the object's Owner being set).
    if (HasWhenPlayedAbility($cardID) && !_SWUGalenSuppressesCard($activePlayer, $cardID)) {
        AddTrigger($activePlayer, 'WhenPlayed', $cardID, $mzID);
    }

    $obj = GetZoneObject($mzID);
    if ($obj !== null && HasKeyword_Shielded($obj)) {
        AddTrigger($activePlayer, 'Shielded', $cardID, $mzID);
    }

    if ($obj !== null && HasKeyword_Ambush($obj)) {
        // Ambush CR 5.9.a: "attack that enemy unit" — units only, not the base.
        $opponent      = OtherPlayer($activePlayer);
        $ambushTargets = SWUGetValidAmbushTargets($opponent, $obj, $targetArena);
        if (!empty($ambushTargets)) {
            AddTrigger($activePlayer, 'Ambush', $cardID, $mzID, implode('&', $ambushTargets));
        }
    }

    // Support (ASH) — "When you play/deploy this unit, you may attack with another unit." Fires on
    // both unit plays and leader deploys (this collector runs for both). Only offer if there's a ready
    // OTHER friendly unit to attack with; the chosen attacker gains S's other abilities for that attack.
    if ($obj !== null && HasKeyword_Support($obj)) {
        $supportAttackers = SWUGetValidSupportAttackers($activePlayer, $obj);
        if (!empty($supportAttackers)) {
            AddTrigger($activePlayer, 'Support', $cardID, $mzID, implode('&', $supportAttackers));
        }
    }

    // ASH_041 Outcast — "When a friendly unit enters play (including this one): it gets +1/+0 for this
    // phase." Buff the entering unit once per ASH_041 the active player controls (self-buffs on its own
    // entry, since it's already in the arena by now).
    if ($obj !== null) {
        $a041 = 0;
        foreach (GetUnitsInPlay($activePlayer) as $u) {
            if (empty($u->removed) && ($u->CardID ?? '') === 'ASH_041') $a041++;
        }
        for ($i = 0; $i < $a041; $i++) SWUApplyPhaseBuff($mzID, 1, 0, 'ASH_041');
    }

    // Task 5.1 — observer triggers: "when an opponent plays a card / unit / event / upgrade".
    // TWI_210 Cunning fires once per copy in play when the opponent paid less than printed cost.
    // AddTrigger here so the reactions batch with the played card's own WhenPlayed via
    // FlushEntryTriggerBag (cross-player → YESNO ordering choice, single → auto-dispatch).
    // Skipped for non-play entries (e.g. leader deploy): deploying a leader is not "playing a card".
    if ($isPlay) {
        SWUCollectOpponentPlayReactions($activePlayer, $cardID, intval($GLOBALS['gLastPlayResourcesPaid']));
        // Batch E.1 — own-play reactions (Bossk/FFF). Pass the played unit's UID so an Aggression unit
        // doesn't trigger its own copy ("another …").
        SWUCollectOwnPlayReactions($activePlayer, $cardID, ($obj !== null ? intval($obj->UniqueID ?? 0) : 0));
    }
    return FlushEntryTriggerBag($activePlayer);
}

// CollectWhenPlayedAsUpgradeTriggers — parallel to CollectEntryTriggers for upgrades.
// If the card has a WhenPlayedAsUpgrade ability, that fires; otherwise falls back to
// WhenPlayed if the card also has that. Returns FlushEntryTriggerBag count (0/1/2+).
function CollectWhenPlayedAsUpgradeTriggers(int $player, string $cardID, string $targetMzID): int {
    // SEC_046 Galen Erso — a named upgrade/pilot that lost its abilities fires no When-Played(-as-Upgrade).
    if (_SWUGalenSuppressesCard($player, $cardID)) { /* suppressed: no entry trigger */ }
    elseif (HasWhenPlayedAsUpgradeAbility($cardID)) {
        AddTrigger($player, 'WhenPlayedAsUpgrade', $cardID, $targetMzID);
    } elseif (HasWhenPlayedAbility($cardID)) {
        AddTrigger($player, 'WhenPlayed', $cardID, $targetMzID);
    }
    // Task 5.1 — TWI_210 Cunning observer: fires on upgrade plays too.
    SWUCollectOpponentPlayReactions($player, $cardID, intval($GLOBALS['gLastPlayResourcesPaid']));
    // Batch E.1 — own-play reactions (an Aggression upgrade triggers FFF; an upgrade is never a unit, so no self-UID).
    SWUCollectOwnPlayReactions($player, $cardID, 0);
    // LOF_229 Kylo Ren — "When you play an upgrade on this unit: may use the Force → draw a card." The
    // host is known here; the reaction is owned by the active (playing) player, so no cross-player race.
    $lof229Host = GetZoneObject($targetMzID);
    if ($lof229Host !== null && ($lof229Host->CardID ?? '') === 'LOF_229') {
        AddTrigger($player, 'LOF_229', 'LOF_229', '');
    }
    // ASH_047 Gar Saxon — "When you play an upgrade on this unit: you may create a Mandalorian token
    // (once each round)." Host known here; reaction owned by the active player. The once-per-round gate
    // is enforced in the reaction (so the trigger always collects; it no-ops if already used).
    if ($lof229Host !== null && ($lof229Host->CardID ?? '') === 'ASH_047'
        && GlobalEffectCount($player, 'SWU_ASH047_USED') <= 0) {
        AddTrigger($player, 'ASH_047', 'ASH_047', '');
    }
    return FlushEntryTriggerBag($player);
}

// CollectOnAttachedTriggers — fires when a card BECOMES ATTACHED (any source: normal upgrade
// play, Piloting, leader flip-attach, ship hop), distinct from WhenPlayedAsUpgrade (play trigger).
// Gated by HasOnAttachedAbility (manual dictionary). Returns FlushEntryTriggerBag count (0/1/2+).
function CollectOnAttachedTriggers(int $player, string $cardID, string $targetMzID): int {
    if (!HasOnAttachedAbility($cardID)) return 0;
    AddTrigger($player, 'OnAttached', $cardID, $targetMzID);
    return FlushEntryTriggerBag($player);
}

// OnWhenPlayedAsUpgrade — dispatches the WhenPlayedAsUpgrade closure if registered,
// otherwise delegates to OnWhenPlayed for cards that share that window.
function OnWhenPlayedAsUpgrade(int $player, string $cardID, string $mzID): void {
    global $whenPlayedAsUpgradeAbilities;
    $key = $cardID . ':0';
    if (isset($whenPlayedAsUpgradeAbilities[$key])) {
        $whenPlayedAsUpgradeAbilities[$key]($player, $mzID);
        return;
    }
    OnWhenPlayed($player, $cardID, $mzID);
}

// OnOnAttached — dispatches the OnAttached closure for the given card.
function OnOnAttached(int $player, string $cardID, string $mzID): void {
    global $onAttachedAbilities;
    $key = $cardID . ':0';
    if (isset($onAttachedAbilities[$key])) {
        $onAttachedAbilities[$key]($player, $mzID);
    }
}

// ── Reactive "an enemy unit is defeated / leaves play" dispatch (Phase 7.1) ───
// Distinct from the SWU_ENEMY_DEFEATED phase flag: these fire a real reaction (queue a decision)
// at the moment a unit leaves play, observed by units/leaders in play.

// Count non-removed units with $cardID controlled by $player (across both arenas).
function _SWUCountUnitsWithCardID(int $player, string $cardID): int {
    $n = 0;
    foreach (GetUnitsInPlay($player) as $u) {
        if (!empty($u->removed)) continue;
        if (($u->CardID ?? '') === $cardID) $n++;
    }
    return $n;
}

// Like _SWUCountUnitsWithCardID but excludes copies that have lost their abilities (SEC_046 Galen Erso) —
// for REACTIVE-OBSERVER triggers, where a suppressed copy must not react. (Plain control/"you control N"
// counts still use _SWUCountUnitsWithCardID — a suppressed unit is still controlled.)
function _SWUCountActiveUnitsWithCardID(int $player, string $cardID): int {
    $n = 0;
    foreach (GetUnitsInPlay($player) as $u) {
        if (!empty($u->removed) || ($u->CardID ?? '') !== $cardID) continue;
        if (LostAbilities($u)) continue;
        $n++;
    }
    return $n;
}

// True if $player's leader is $cardID, undeployed, and ready (so it can pay an "exhaust this
// leader" cost). Leader-side reactive abilities are active only while the leader is undeployed.
function _SWULeaderReadyUndeployed(int $player, string $cardID): bool {
    foreach (GetLeader($player) as $l) {
        if (!empty($l->removed)) continue;
        if (($l->CardID ?? '') === $cardID && empty($l->Deployed) && !empty($l->Ready)) return true;
    }
    return false;
}

// Ready up to $count exhausted resources for $player (resources are fungible, so no choice needed).
// Returns how many were readied.
function SWUReadyResources(int $player, int $count): int {
    $resources = &GetResources($player);
    $readied = 0;
    for ($i = 0; $i < count($resources) && $readied < $count; $i++) {
        if (!empty($resources[$i]->removed)) continue;
        if (intval($resources[$i]->Status) === 0) {
            $resources[$i]->Status = 1;
            $readied++;
        }
    }
    return $readied;
}

// For each unit that just left play ($leftCards entries: ['player'=>controller, 'cardID'=>…]),
// add the reactive triggers observed by the OTHER player and (for defeats) the granted
// When-Defeated abilities on the leaving unit. Also sets the SWU_ENEMY_LEFT_PLAY phase flag on the
// opponent (for "if an enemy unit left play this phase" checks — Boba's deployed OnAttackEnd).
// Caller flushes the trigger bag. $defeated distinguishes a defeat from a bounce/other leave.
function SWUCollectLeavePlayReactions(array $leftCards, bool $defeated): void {
    foreach ($leftCards as $d) {
        $controller = intval($d['player'] ?? 0);
        if ($controller <= 0) continue;
        $opp = GetOpponent($controller);
        AddGlobalEffects($opp, 'SWU_ENEMY_LEFT_PLAY');
        AddGlobalEffects($controller, 'SWU_FRIENDLY_LEFT_PLAY'); // "if a friendly unit left play this phase" (LOF_216)
        // ASH_211 Fateful Goodbye — "if a friendly LEADER unit left play this phase" (any leave, not just defeat).
        if (strpos(CardType($d['cardID'] ?? '') ?? '', 'Leader') !== false) {
            AddGlobalEffects($controller, 'SWU_FRIENDLY_LEADER_LEFT_PLAY');
        }

        // SOR_015 Boba Fett (undeployed leader of $opp): "When an enemy unit leaves play: you may
        // exhaust this leader; if you do, ready a resource." Treated as an always-yes auto-resolve
        // (like SLT SOR_083): only fires when there is a benefit — the leader is ready+undeployed
        // AND there is an exhausted resource to ready (total > ready). If resources are full, skip.
        if (_SWULeaderReadyUndeployed($opp, 'SOR_015')
            && SWUResourceCount($opp) > SWUResourceCount($opp, true)) {
            AddTrigger($opp, 'SOR_015', 'SOR_015', '');
        }

        if ($defeated) {
            // LAW_005 Jyn Erso — track "a friendly Rebel unit was defeated this phase" on the controller.
            if (HasTrait($d['cardID'] ?? '', 'Rebel')) AddGlobalEffects($controller, 'SWU_REBEL_DEFEATED');
            // ASH_008 Moff Gideon — "a friendly Imperial unit was defeated this phase" on the controller.
            if (HasTrait($d['cardID'] ?? '', 'Imperial')) AddGlobalEffects($controller, 'SWU_IMPERIAL_DEFEATED');
            // ASH_093 Captain Pellaeon — "While a leader unit has been defeated this phase, gains Raid 3."
            // Flag BOTH players (any leader, friendly or enemy). Cleared at RegroupPhaseStart.
            if (strpos(CardType($d['cardID'] ?? '') ?? '', 'Leader') !== false) {
                AddGlobalEffects(1, 'SWU_LEADER_DEFEATED_PHASE');
                AddGlobalEffects(2, 'SWU_LEADER_DEFEATED_PHASE');
            }
            // ASH_127 The Twins (controlled by $controller): "When another friendly unit is defeated: heal 1
            // from your base." The just-defeated unit is removed, so an in-play Twins is always "another".
            $twins = _SWUCountActiveUnitsWithCardID($controller, 'ASH_127');
            for ($i = 0; $i < $twins; $i++) {
                OnHealBase($controller, $controller, 1);
            }
            // ASH_128 Bothan-5 (controlled by $controller): "When another friendly non-Vehicle unit is
            // defeated: you may have this unit capture that unit from your discard pile. Once each round."
            $dCardID128 = $d['cardID'] ?? '';
            if ($dCardID128 !== '' && strpos(CardType($dCardID128) ?? '', 'Unit') !== false
                && strpos(strtolower(CardType($dCardID128) ?? ''), 'token') === false
                && !HasTrait($dCardID128, 'Vehicle')
                && GlobalEffectCount($controller, 'SWU_ASH128_USED') <= 0) {
                foreach (GetUnitsInPlay($controller) as $bothan) {
                    if (!empty($bothan->removed) || ($bothan->CardID ?? '') !== 'ASH_128') continue;
                    // Encode captor UID + defeated CardID in mzID: the flat FlushTriggerBag path (used by
                    // leave-play reactions) drops extraParams, so both must ride the mzID field (comma-sep).
                    AddTrigger($controller, 'ASH_128', 'ASH_128', strval(intval($bothan->UniqueID ?? 0)) . ',' . $dCardID128);
                    break;   // one Bothan-5 reaction per defeat
                }
            }
            // SOR_036 Gideon Hask (controlled by $opp): "When an enemy unit is defeated: give an
            // Experience token to a friendly unit." Fires once per Gideon in play.
            $gideons = _SWUCountActiveUnitsWithCardID($opp, 'SOR_036');
            for ($i = 0; $i < $gideons; $i++) {
                AddTrigger($opp, 'SOR_036', 'SOR_036', '');
            }
            // SEC_051 Bo-Katan Kryze (controlled by $opp): "When an enemy unit is defeated: give an
            // Experience token to a friendly unit." Same shape as Gideon.
            $bokatans = _SWUCountActiveUnitsWithCardID($opp, 'SEC_051');
            for ($i = 0; $i < $bokatans; $i++) {
                AddTrigger($opp, 'SEC_051', 'SEC_051', '');
            }
            // LOF_130 HK-47 (controlled by $opp): "When an enemy unit is defeated: deal 1 damage to its
            // controller's base." $controller is the defeated unit's controller (the enemy from HK-47's view).
            $hk47s = _SWUCountActiveUnitsWithCardID($opp, 'LOF_130');
            for ($i = 0; $i < $hk47s; $i++) {
                SWUDealDamageToBase(1, $controller);
            }
            // SOR_002 Iden Versio (deployed leader unit of $opp): "When an enemy unit is defeated:
            // Heal 1 damage from your base." Fires once per defeated enemy unit.
            if (_SWULeaderDeployed($opp, 'SOR_002')) {
                AddTrigger($opp, 'SOR_002', 'SOR_002', '');
            }
            // ASH_052 Chimaera (controlled by $opp): "When an enemy unit is defeated: heal 2 damage from
            // your base." Fires once per Chimaera in play; non-interactive.
            $chimaeras = _SWUCountActiveUnitsWithCardID($opp, 'ASH_052');
            for ($i = 0; $i < $chimaeras; $i++) {
                OnHealBase($opp, $opp, 2);
            }
            // LAW_053 Dengar (controlled by $opp): "When a unit with the highest cost among enemy units
            // is defeated: create a Credit token. Use only once each round." The defeated unit
            // (controlled by $controller, i.e. an enemy of $opp) was the highest-cost enemy iff its cost
            // is >= every other still-in-play unit of $controller. Per-round flag cleared at RGS.
            if (_SWUCountActiveUnitsWithCardID($opp, 'LAW_053') > 0 && GlobalEffectCount($opp, 'SWU_LAW053_USED') <= 0) {
                $defCost  = intval(CardCost($d['cardID'] ?? ''));
                $maxOther = 0;
                foreach (GetUnitsInPlay($controller) as $u) {
                    if (empty($u->removed)) $maxOther = max($maxOther, intval(CardCost($u->CardID ?? '')));
                }
                if ($defCost >= $maxOther) {
                    SWUCreateCreditToken($opp, 1);
                    AddGlobalEffects($opp, 'SWU_LAW053_USED');
                }
            }
            // LAW_119 Rogue One (controlled by $controller): "When a friendly unit is defeated: look at
            // the top 2 cards, put any number on the bottom, rest on top." Fires once per Rogue One.
            $rogueones = _SWUCountActiveUnitsWithCardID($controller, 'LAW_119');
            for ($i = 0; $i < $rogueones; $i++) AddTrigger($controller, 'LAW_119', 'LAW_119', '');
            // SOR_105 General Krell (controlled by $controller): grants "When Defeated: you may draw
            // a card" to each OTHER friendly unit. The leaving unit qualifies if it isn't Krell.
            if (($d['cardID'] ?? '') !== 'SOR_105' && _SWUCountUnitsWithCardID($controller, 'SOR_105') > 0) {
                AddTrigger($controller, 'SOR_105', 'SOR_105', '');
            }
            // SOR_115 Agent Kallus: "When another UNIQUE unit is defeated: you may draw a card. Use
            // only once each round." Any unique unit (friendly OR enemy) other than Kallus himself —
            // a defeated Kallus is already removed, so an in-play Kallus never sees its own defeat.
            // Fires for each Kallus controller (both seats) whose once-per-round flag is unused.
            if (CardUnique($d['cardID'] ?? '')) {
                foreach ([1, 2] as $kp) {
                    // Per-instance once-per-round via each Kallus unit's NumUses budget.
                    foreach (array_merge(GetGroundArena($kp) ?? [], GetSpaceArena($kp) ?? []) as $ku) {
                        if (empty($ku->removed) && ($ku->CardID ?? '') === 'SOR_115' && SWUHasUseAvailable($ku)) {
                            AddTrigger($kp, 'SOR_115', 'SOR_115', '');
                            SWUConsumeUse($ku);
                        }
                    }
                }
            }
        }
    }
}

// Task 5.1 — TWI_210 Cunning: "When an opponent plays a card: If that opponent paid less than
// the card's cost to play it, ready or exhaust a unit."
// Called immediately after $gLastPlayResourcesPaid is finalised for the play. For each TWI_210
// controlled by the OPPONENT of $playingPlayer that is in play (ground or space), if
// resourcesPaid < printed cost, queue a trigger for that TWI_210's controller.
// Uses AddTrigger + FlushEntryTriggerBag (batches with the played card's own entry triggers).
// $resourcesPaid is passed explicitly so this never re-reads the global (race-safety).
function SWUCollectOpponentPlayReactions(int $playingPlayer, string $playedCardID, int $resourcesPaid): void {
    $opp = GetOpponent($playingPlayer);
    if ($opp === null) return;
    $printedCost = intval(CardCost($playedCardID));
    if ($resourcesPaid >= $printedCost) return; // condition not met — no trigger
    $count = _SWUCountActiveUnitsWithCardID($opp, 'TWI_210');   // SEC_046 Galen — named observer doesn't react
    for ($i = 0; $i < $count; $i++) {
        AddTrigger($opp, 'TWI_210', 'TWI_210', '');
    }
}

// Batch E.1 — reactive "when YOU (the controller) play a card" observers. Mirror of
// SWUCollectOpponentPlayReactions but for the PLAYING player's own units. Called from the same
// three play sites (unit entry, upgrade attach, event play). $playedUID = the just-played unit's
// UniqueID (0 for events/upgrades) so an observer can exclude the card it was triggered by
// ("another …" — a played Aggression unit must not trigger its own copy).
function SWUCollectOwnPlayReactions(int $playingPlayer, string $playedCardID, int $playedUID = 0): void {
    $isEvent       = strpos(CardType($playedCardID) ?? '', 'Event') !== false;
    $isAggression  = strpos(CardAspect($playedCardID) ?? '', 'Aggression') !== false;
    $isCommandUnit = (strpos(CardType($playedCardID) ?? '', 'Unit') !== false)
                  && (strpos(CardAspect($playedCardID) ?? '', 'Command') !== false);
    foreach (GetUnitsInPlay($playingPlayer) as $u) {
        if (!empty($u->removed) || LostAbilities($u)) continue;   // SEC_046 Galen — a named observer doesn't react
        $cid = $u->CardID ?? '';
        $uid = intval($u->UniqueID ?? 0);
        // SOR_182 Bossk: "When you play an event: you may deal 2 damage to a unit."
        if ($cid === 'SOR_182' && $isEvent) {
            AddTrigger($playingPlayer, 'SOR_182', 'SOR_182', '');
        }
        // SOR_143 Fighters for Freedom: "When you play another [Aggression] card: you may deal 1 to a base."
        if ($cid === 'SOR_143' && $isAggression && $uid !== $playedUID) {
            AddTrigger($playingPlayer, 'SOR_143', 'SOR_143', '');
        }
        // SOR_109 Colonel Yularen: "When you play a [Command] unit (including this one): Heal 1 from
        // your base." No self-exclusion — "including this one" means Yularen's own play counts too.
        if ($cid === 'SOR_109' && $isCommandUnit) {
            AddTrigger($playingPlayer, 'SOR_109', 'SOR_109', '');
        }
        // LAW_003 Agent Kallus (deployed) — "When you play a Heroism card: heal 2 from your base."
        // Mandatory, no decision → heal immediately.
        if ($cid === 'LAW_003' && strpos(CardAspect($playedCardID) ?? '', 'Heroism') !== false) {
            OnHealBase($playingPlayer, $playingPlayer, 2);
        }
        // LOF_087 Eighth Brother: "When you play another unit: you may use the Force → give a unit +2/+2."
        if ($cid === 'LOF_087' && (strpos(CardType($playedCardID) ?? '', 'Unit') !== false) && $uid !== $playedUID) {
            AddTrigger($playingPlayer, 'LOF_087', 'LOF_087', '');
        }
        // LOF_249 Luke Skywalker: "When you play another <uq> unit: may use the Force → give an Experience
        // and a Shield token to this unit." Carries Luke's UID so the reaction can target him.
        if ($cid === 'LOF_249' && (strpos(CardType($playedCardID) ?? '', 'Unit') !== false)
            && CardUnique($playedCardID) && $uid !== $playedUID) {
            AddTrigger($playingPlayer, 'LOF_249', 'LOF_249', '', strval($uid));
        }
        // ASH_060 Cobb Vanth: "When you play another unit: you may deal 2 damage to THIS unit. If you do,
        // give a Shield token to THAT (the played) unit." Carries Cobb's UID + the played unit's UID.
        if ($cid === 'ASH_060' && (strpos(CardType($playedCardID) ?? '', 'Unit') !== false) && $uid !== $playedUID && $playedUID > 0) {
            AddTrigger($playingPlayer, 'ASH_060', 'ASH_060', '', $uid . ',' . $playedUID);
        }
        // ASH_102 Ravager: "When you play a unit: you may have it deal damage equal to its power to a unit
        // in the same arena." Carries the played unit's UID (the dealer). Not "another" — Ravager's own
        // play counts; but the played unit must still be in play (a unit-type entry).
        if ($cid === 'ASH_102' && (strpos(CardType($playedCardID) ?? '', 'Unit') !== false) && $playedUID > 0) {
            AddTrigger($playingPlayer, 'ASH_102', 'ASH_102', '', strval($playedUID));
        }
        // LOF_096 Obi-Wan Kenobi: "When you play a Force unit (including this one): this unit gains
        // Sentinel for this phase." No self-exclusion; grant immediately (no decision).
        if ($cid === 'LOF_096'
            && strpos(CardType($playedCardID) ?? '', 'Unit') !== false && HasTrait($playedCardID, 'Force')) {
            $obiMz = SWUFindMzByUID($uid);
            if ($obiMz !== null) AddTurnEffect($obiMz, 'SENTINEL');
        }
    }
    // ── Leader observers (undeployed leaders are NOT in GetUnitsInPlay) ──
    $isUnit = strpos(CardType($playedCardID) ?? '', 'Unit') !== false;
    // ASH_017 Greef Karga — "When you play OR create a unit: you may exhaust this leader; if you do, give an
    // Advantage token to that unit." (The create half is hooked in SWUCreateUnitToken.)
    if ($isUnit && $playedUID > 0 && _SWULeaderReadyUndeployed($playingPlayer, 'ASH_017')) {
        AddTrigger($playingPlayer, 'ASH_017', 'ASH_017', '', strval($playedUID));
    }
    // ASH_018 Grogu — "When you play a <uq> unit that costs 4 or more: if this leader is ready, you may
    // deploy him." (Grogu has no Epic Action; this trigger is his only deploy path.)
    if ($isUnit && CardUnique($playedCardID) && intval(CardCost($playedCardID)) >= 4
        && _SWULeaderReadyUndeployed($playingPlayer, 'ASH_018')) {
        AddTrigger($playingPlayer, 'ASH_018', 'ASH_018', '');
    }
}

// SOR_182 Bossk reaction: "you may deal 2 damage to a unit." (Any unit — Bossk always self-qualifies.)
function BosskPlayEventReaction(int $player): void {
    global $playerID;
    $playerID = intval($player);
    $targets = _SWUCollectUnits(-1, fn($o) => true);
    if (empty($targets)) return;
    SWUQueueMayChooseTarget(intval($player), $targets,
        "Bossk:_deal_2_to_a_unit?", "Deal_2_damage_to_a_unit", "DEAL_UNIT_DAMAGE|2");
}

// SOR_143 Fighters for Freedom reaction: "you may deal 1 damage to a base." (Either base.)
function FFFPlayAggressionReaction(int $player): void {
    global $playerID;
    $playerID = intval($player);
    SWUQueueMayChooseTarget(intval($player), ["myBase-0", "theirBase-0"],
        "Deal_1_to_a_base?", "Deal_1_damage_to_a_base", "DEAL_BASE_DAMAGE|1");
}

// SOR_109 Colonel Yularen reaction: mandatory heal 1 from the controller's own base (no decision).
function YularenHealReaction(int $player): void {
    OnHealBase(intval($player), intval($player), 1);
}

// TWI_210 Cunning reaction dispatcher: queue the ready-or-exhaust choice for the TWI_210 controller.
function CunningOpponentPlayedReaction(int $player): void {
    global $playerID;
    $playerID = intval($player);
    // Collect ALL units (any arena, any player) — "a unit" has no restriction.
    $allUnits = _SWUCollectUnits(-1, fn($o) => true);
    if (empty($allUnits)) return; // no units in play — effect is a no-op
    // Present the mode choice first; the unit-choose handler reads $lastDecision to know the mode.
    DecisionQueueController::AddDecision(intval($player), "OPTIONCHOOSE", "Ready&Exhaust", 1, "Ready_or_exhaust_a_unit?");
    DecisionQueueController::AddDecision(intval($player), "CUSTOM", "TWI_210#1|" . implode('&', $allUnits), 1);
}

function CollectWhenDefeatedTriggers($activePlayer, array $defeatedCards): void {
    global $gPendingTriggers, $gExploitDeferTriggers, $gExploitDeferredBag;

    global $playerID;
    foreach ($defeatedCards as $d) {
        // ASH_063 Bo-Katan's Gauntlet — "Each OTHER friendly non-token unit gains: When Defeated:
        // create a Mandalorian token." Field-presence grant: a friendly non-token unit's defeat creates
        // a Mandalorian for its controller while they control an ASH_063 unit.
        $dctrl63 = intval($d['player'] ?? 0);
        if ($dctrl63 > 0 && ($d['cardID'] ?? '') !== 'ASH_063'
            && strpos(CardType($d['cardID'] ?? '') ?? '', 'Token') === false
            && _SWUCountUnitsWithCardID($dctrl63, 'ASH_063') > 0) {
            AddTrigger($dctrl63, 'ASH_063', 'ASH_063', '');
        }
        // SEC_046 Galen Erso — a named card that lost its abilities fires no When Defeated.
        if (HasWhenDefeatedAbility($d['cardID']) && !_SWUGalenSuppressesCard(intval($d['player'] ?? 0), $d['cardID'])) {
            AddTrigger($d['player'], 'WhenDefeated', $d['cardID'], $d['mzID']);
            // JTL_169 Shadow Caster — "When a friendly unit is defeated: you may use all of its
            // When Defeated abilities again." One reuse offer per controlled copy. Collected at
            // defeat time (defeat-event hook), distinct from Thrawn's use-time hook.
            foreach (array_merge(GetGroundArena($d['player']) ?? [], GetSpaceArena($d['player']) ?? []) as $u) {
                if (!empty($u->removed)) continue;
                if (($u->CardID ?? '') === 'JTL_169') {
                    AddTrigger($d['player'], 'JTL_169', $d['cardID'], $d['mzID']);
                }
            }
        }
        // Upgrade-granted When Defeated (JTL_073 Grim Valor: "Attached unit gains When Defeated: you may
        // exhaust a unit"). The defeated unit is still in the array (removed=true) with its subcards
        // intact at this collection point — resolve it under the active player's frame.
        if (!empty($d['mzID'])) {
            $savedDPID = $playerID;
            $playerID = intval($activePlayer);
            $defObj = GetZoneObject($d['mzID']);
            // Snapshot "was this defeated BY COMBAT DAMAGE" per mzID (marker set at the combat-defeat
            // sites in SWUCombatDamage), and consume the flag — read by ASH_028/ASH_191 whenDefeated.
            $GLOBALS['gCombatDefeatByMz'][$d['mzID']] = ($defObj !== null
                && GlobalEffectCount(intval($d['player'] ?? 0), 'SWU_COMBATDEF_' . intval($defObj->UniqueID ?? 0)) > 0);
            if ($defObj !== null) RemoveGlobalEffect(intval($d['player'] ?? 0), 'SWU_COMBATDEF_' . intval($defObj->UniqueID ?? 0));
            if ($defObj !== null && is_array($defObj->Subcards ?? null)) {
                foreach ($defObj->Subcards as $sub) {
                    $scid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
                    $srem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
                    if (!$srem && $scid === 'JTL_073') { AddTrigger($d['player'], 'JTL_073', 'JTL_073', ''); }
                    if (!$srem && $scid === 'SEC_039') { AddTrigger($d['player'], 'SEC_039', 'SEC_039', ''); }
                    if (!$srem && $scid === 'SEC_156') { AddTrigger($d['player'], 'SEC_156', 'SEC_156', ''); }
                    if (!$srem && $scid === 'ASH_134') { AddTrigger($d['player'], 'ASH_134', 'ASH_134', ''); } // Warrior's Legacy — granted "When Defeated: create a Mandalorian token"
                    // LAW_141 Targeted For Removal — "When Defeated: An opponent creates Credit tokens
                    // equal to this unit's cost." Pass the host's printed cost via the mzID slot (the
                    // FlushTriggerBag path drops extraParams), since the host is gone by dispatch time.
                    if (!$srem && $scid === 'LAW_141') { AddTrigger($d['player'], 'LAW_141', 'LAW_141', (string)intval(CardCost($d['cardID'] ?? ''))); }
                    // LAW_201 Thermal Detonator — "When Defeated: If this unit was ready, deal 2 damage
                    // to each enemy ground unit." Snapshot the host's ready status now (still intact);
                    // pass it via the mzID slot ('1' = was ready).
                    if (!$srem && $scid === 'LAW_201') { AddTrigger($d['player'], 'LAW_201', 'LAW_201', (intval($defObj->Status ?? 0) === 1) ? '1' : '0'); }
                }
            }
            // Support (ASH) — A was defeated during a supported attack while bearing the grant. Fire the
            // supporting unit's "When Defeated" ability against A's mzID (so "this unit" = A). The marker
            // is still on the (removed) object at this collection point.
            if ($defObj !== null) {
                $sgDef = _SWUSupportGrant($defObj);
                if ($sgDef !== null && $sgDef['cardID'] !== '' && HasWhenDefeatedAbility($sgDef['cardID'])) {
                    AddTrigger($d['player'], 'SupportWhenDefeated', $sgDef['cardID'], $d['mzID']);
                }
            }
            // SEC_035 Darth Sion — "When Defeated: if this unit had 7+ power, return him to hand."
            // Snapshot his power NOW (Experience subcards still attached); the When Defeated closure
            // runs after they're stripped, so it reads base power without this. Keyed by mzID (the
            // same string the closure receives).
            if ($defObj !== null && ($d['cardID'] ?? '') === 'SEC_035') {
                global $gSec035DefeatSnapshot;
                $gSec035DefeatSnapshot[$d['mzID']] = [
                    'power' => intval(ObjectCurrentPower($defObj)),
                    'owner' => intval($defObj->Owner ?? $d['player']),
                ];
            }
            // Granted custom Bounty (SHD_006 phase grant / SHD_123 upgrade grant) — snapshot the
            // reward(s) NOW while the (removed) object still carries its turn-effects + subcards, so the
            // bounty can be offered after cleanup. Each granted Bounty is an independent ability
            // (CR 13.b); the innate $Bounty_Cards bounty is offered separately. A reward = the source
            // CardID + a param (SHD_006: the discount 1/2; SHD_123: 1 if the host was unique → top 10).
            if ($defObj !== null) {
                global $gGrantedBountySnapshot;
                $rewards = [];
                foreach (SWUParsedTurnEffects($defObj) as $e) {
                    if (($e['kind'] ?? '') === 'GRANT_KEYWORD' && ($e['value'] ?? '') === 'BOUNTY') {
                        $rewards[] = ['reward' => $e['base'], 'param' => intval($e['params'][0] ?? 0)];
                    }
                }
                if (is_array($defObj->Subcards ?? null)) {
                    foreach ($defObj->Subcards as $sub) {
                        $scid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
                        $srem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
                        if (!$srem && $scid === 'SHD_123') {
                            $rewards[] = ['reward' => 'SHD_123', 'param' => CardUnique($d['cardID'] ?? '') ? 1 : 0];
                        }
                    }
                }
                if (!empty($rewards)) { $GLOBALS['gGrantedBountySnapshot'][$d['mzID']] = $rewards; }
            }
            $playerID = $savedDPID;
        }
    }
    SWUCollectLeavePlayReactions($defeatedCards, true);

    // Exploit deferred-defeat-trigger bag (CR 16.d / Task 1.2):
    // When a unit is sacrificed for Exploit mid-payment, its WhenDefeated triggers,
    // leave-play reactions, AND bounty rewards must not fire immediately — they are
    // collected here (as typed entries) and parked in $gExploitDeferredBag so
    // SWUFlushExploitDeferredTriggers() can replay them alongside the played card's
    // WhenPlayed trigger.  The deferral activates whenever the flag is set, regardless
    // of whether $gPendingTriggers is non-empty — this ensures a unit with Bounty but
    // no WhenDefeated is also deferred (Bug B fix), and a unit with both does not lose
    // its bounty via an early return (Bug A fix).
    if (!empty($gExploitDeferTriggers)) {
        // Park trigger descriptors (tagged with __kind__ = 'trigger').
        foreach ($gPendingTriggers as $t) {
            $gExploitDeferredBag[] = ['__kind__' => 'trigger'] + $t;
        }
        $gPendingTriggers = [];

        // Park bounty descriptors (tagged with __kind__ = 'bounty'). SEC_046 Galen — a named unit has no Bounty.
        global $Bounty_Cards;
        foreach ($defeatedCards as $d) {
            if (isset($Bounty_Cards[$d['cardID']]) && !_SWUGalenSuppressesCard(intval($d['player'] ?? 0), $d['cardID'])) {
                $gExploitDeferredBag[] = [
                    '__kind__'    => 'bounty',
                    'activePlayer' => intval($activePlayer),
                    'cardID'      => $d['cardID'],
                ];
            }
        }
        return;
    }

    FlushTriggerBag($activePlayer);

    // Bounty (CR 7.6.3): after WhenDefeated triggers, offer the bounty reward to the defeating player.
    // SEC_046 Galen Erso — a named defeated unit has lost its Bounty (no reward offered).
    global $Bounty_Cards;
    foreach ($defeatedCards as $d) {
        if (isset($Bounty_Cards[$d['cardID']]) && !_SWUGalenSuppressesCard(intval($d['player'] ?? 0), $d['cardID'])) {
            DecisionQueueController::AddDecision(intval($activePlayer), "YESNO", "-", 1, tooltip:"Collect_bounty?");
            DecisionQueueController::AddDecision(intval($activePlayer), "CUSTOM", "SWUCollectBounty|{$d['cardID']}", 1);
        }
    }

    // Granted custom bounties (SHD_006 phase grant / SHD_123 upgrade grant), snapshotted above while the
    // object still had its turn-effects/subcards. Each is an independent ability (CR 13.b) offered to the
    // defeating player ($activePlayer = the opponent of the bountied unit's controller, CR 13.f).
    global $gGrantedBountySnapshot;
    foreach ($defeatedCards as $d) {
        $mz = $d['mzID'] ?? '';
        if ($mz === '' || empty($gGrantedBountySnapshot[$mz])) continue;
        if (!_SWUGalenSuppressesCard(intval($d['player'] ?? 0), $d['cardID'] ?? '')) {
            foreach ($gGrantedBountySnapshot[$mz] as $rw) {
                DecisionQueueController::AddDecision(intval($activePlayer), "YESNO", "-", 1, tooltip:"Collect_bounty?");
                DecisionQueueController::AddDecision(intval($activePlayer), "CUSTOM", "SWUCollectBounty|{$rw['reward']}|{$rw['param']}", 1);
            }
        }
        unset($gGrantedBountySnapshot[$mz]);
    }
}

// ─── JTL Phase 23 — reuse a "When Defeated" ability ───────────────────────────
// Re-invoke primitive: fire a card's registered When-Defeated ability on demand,
// decoupled from an actual defeat. Routed through the trigger system so the dispatch
// path also re-collects the Thrawn "when you use a When Defeated ability" reaction
// (JTL_002), letting uses chain (Thrawn + Shadow Caster can use one ability up to
// three times). On a Thrawn/Shadow-Caster replay the source unit is already in discard;
// $mzID is passed as-is — the JTL When-Defeated pool targets other units/players/bases,
// so it doesn't need the dead unit's live state (self-referential reads degrade). Used
// by JTL_039 Chimaera (a living unit), JTL_002, and JTL_169.
// $grantedType (non-null) = the When-Defeated was GRANTED by an attached upgrade and dispatches via a
// per-card trigger type (e.g. 'JTL_073'), not the generic 'WhenDefeated' window. Re-arm that same type
// + snapshot mzID (the granted handlers don't depend on the now-defeated host being present).
function SWUUseWhenDefeatedAbility(int $owner, string $cardID, string $mzID, ?string $grantedType = null): void {
    if ($grantedType !== null) {
        AddTrigger($owner, $grantedType, $grantedType, $mzID);
        FlushTriggerBag($owner);
        return;
    }
    if (!HasWhenDefeatedAbility($cardID)) return;
    AddTrigger($owner, 'WhenDefeated', $cardID, $mzID);
    FlushTriggerBag($owner);
}

// JTL_002 Grand Admiral Thrawn — usability of the "use that ability again" reaction.
// Undeployed: may exhaust the (ready) leader. Deployed leader unit: no cost, once each round.
function _SWUThrawnReuseMode(int $owner): ?string {
    if (_SWULeaderDeployed($owner, 'JTL_002')) {
        return SWUHasUseAvailable(SWUGetLeader($owner)) ? 'deployed' : null; // once/round via leader NumUses
    }
    if (_SWULeaderReadyUndeployed($owner, 'JTL_002')) return 'undeployed';
    return null;
}

// ── Per-card once-per-round budget via the NumUses field (Leader / GroundArena / SpaceArena / Base) ──
// NumUses = remaining uses this round (default 1). The parser writes -1 for an absent field (old
// gamestate) — normalize that to the default. Reset to 1 for every card at RegroupPhaseStart so the
// budget refreshes each round. Replaces the ad-hoc SWU_*_USED GlobalEffect flags.
function SWUNumUses($obj): int {
    $n = intval($obj->NumUses ?? 1);
    return $n < 0 ? 1 : $n; // -1 = parser's "absent" sentinel → treat as the default
}
function SWUHasUseAvailable($obj): bool {
    return $obj !== null && SWUNumUses($obj) > 0;
}
function SWUConsumeUse($obj): void {
    if ($obj !== null) $obj->NumUses = max(0, SWUNumUses($obj) - 1);
}
// Refresh every card's once-per-round budget (called from RegroupPhaseStart). Repeatable base Actions
// with a per-GAME budget ($baseActionNumUses, e.g. LOF_022) are EXEMPT — their NumUses must persist
// across rounds, so they are not refilled here.
function SWUResetAllNumUses(): void {
    global $baseActionNumUses;
    for ($p = 1; $p <= 2; $p++) {
        foreach ([GetLeader($p) ?? [], GetGroundArena($p) ?? [], GetSpaceArena($p) ?? [], GetBase($p) ?? []] as $zone) {
            for ($i = 0; $i < count($zone); $i++) {
                if (empty($zone[$i]->removed) && !isset($baseActionNumUses[$zone[$i]->CardID ?? ''])) {
                    $zone[$i]->NumUses = 1;
                }
            }
        }
    }
}

function _SWUExhaustUndeployedLeader(int $player, string $cardID): void {
    $leaderArr = &GetLeader($player);
    for ($i = 0; $i < count($leaderArr); $i++) {
        if (!empty($leaderArr[$i]->removed)) continue;
        if (($leaderArr[$i]->CardID ?? '') === $cardID) { $leaderArr[$i]->Ready = false; break; }
    }
}

// JTL_009 Boba Fett (undeployed leader) — "When you deal NON-COMBAT damage: you may exhaust this leader;
// if you do, deal 1 indirect damage to a player." Called by the non-combat damage funnels after the
// damage is applied, for the dealing player. The SWU_BOBA_009_PENDING guard keeps at most one offer
// outstanding; the leader exhausts on accept, so the reaction's own indirect (a base hit) can't re-fire
// it. Combat damage is excluded by the $gInCombatDamage flag at the call site.
function _SWUCollectBobaNonCombatReaction(int $dealer): void {
    if ($dealer <= 0) return;
    if (!_SWULeaderReadyUndeployed($dealer, 'JTL_009')) return;
    if (GlobalEffectCount($dealer, 'SWU_BOBA_009_PENDING') > 0) return;
    AddGlobalEffects($dealer, 'SWU_BOBA_009_PENDING');
    DecisionQueueController::AddDecision($dealer, "YESNO", "-", 1,
        tooltip:"Exhaust_Boba_Fett_to_deal_1_indirect_damage?");
    DecisionQueueController::AddDecision($dealer, "CUSTOM", "JTL_009#0|{$dealer}", 1);
}

// Use-time hook (JTL_002 Thrawn): after any When-Defeated ability resolves under $owner, offer the
// reuse. The SWU_THRAWN_REUSE_PENDING guard keeps at most one outstanding offer, so a chained replay
// (which also dispatches WhenDefeated) can't stack duplicate prompts before the first is answered.
// Mode is re-checked at resolve time (Thrawn may have exhausted meanwhile). Called from DispatchTrigger.
// $grantedType (non-null) = an upgrade-granted When-Defeated ability that dispatched via its per-card
// trigger type — the unit gained it, so Thrawn re-uses it the same as an innate one.
function SWUCollectThrawnReuse(int $owner, string $cardID, string $mzID, ?string $grantedType = null): void {
    if ($grantedType === null && !HasWhenDefeatedAbility($cardID)) return;
    if (GlobalEffectCount($owner, 'SWU_THRAWN_REUSE_PENDING') > 0) return;
    if (_SWUThrawnReuseMode($owner) === null) return;
    AddGlobalEffects($owner, 'SWU_THRAWN_REUSE_PENDING');
    DecisionQueueController::AddDecision($owner, "YESNO", "-", 1,
        tooltip:"Use_that_When_Defeated_ability_again_(Thrawn)?");
    DecisionQueueController::AddDecision($owner, "CUSTOM", "THRAWN_REUSE|{$owner}|{$cardID}|{$mzID}|" . ($grantedType ?? ''), 1);
}

// ── LAW_014 Enfys Nest — "When you use an 'On Attack' ability: use that ability again." ──
// Direct mirror of JTL_002 Thrawn's When-Defeated reuse, on the On-Attack window instead.
// Re-invoke an On-Attack ability by re-dispatching it on the same attacker mzID. The mode gate +
// PENDING guard bound this to exactly one replay (the cost makes a second offer return mode null).
// $fromUpgrade = the ability was GRANTED by an attached upgrade ("attached unit gains: On Attack: …")
// — re-dispatch via the OnAttackFromUpgrade seam ($cardID is the upgrade's, $mzID the host unit).
function SWUUseOnAttackAbility(int $owner, string $cardID, string $mzID, bool $fromUpgrade = false): void {
    global $onAttackAbilities;
    if (!isset($onAttackAbilities["{$cardID}:0"])) return;
    AddTrigger($owner, $fromUpgrade ? 'OnAttackFromUpgrade' : 'OnAttack', $cardID, $mzID);
    FlushTriggerBag($owner);
}

// Usability of Enfys's reaction. Undeployed (front): pay 2 resources AND exhaust the (ready) leader.
// Deployed leader unit: no cost, once each round (leader NumUses budget).
function _SWUEnfysReuseMode(int $owner): ?string {
    if (_SWULeaderDeployed($owner, 'LAW_014')) {
        return SWUHasUseAvailable(SWUGetLeader($owner)) ? 'deployed' : null;
    }
    if (_SWULeaderReadyUndeployed($owner, 'LAW_014') && SWUResourceCount($owner, true) >= 2) return 'undeployed';
    return null;
}

// Use-time hook (called from DispatchTrigger after an On-Attack ability resolves under $owner). The
// PENDING guard keeps at most one outstanding offer; mode is re-checked at resolve time. Only the
// attacker-controller's own On-Attack abilities reach here ($owner = the attacking player). Covers
// both innate On-Attack and upgrade-GRANTED On-Attack ("attached unit gains: On Attack: …", $fromUpgrade).
function SWUCollectEnfysReuse(int $owner, string $cardID, string $mzID, bool $fromUpgrade = false): void {
    global $onAttackAbilities;
    if (!isset($onAttackAbilities["{$cardID}:0"])) return;
    if (GlobalEffectCount($owner, 'SWU_ENFYS_REUSE_PENDING') > 0) return;
    if (_SWUEnfysReuseMode($owner) === null) return;
    AddGlobalEffects($owner, 'SWU_ENFYS_REUSE_PENDING');
    DecisionQueueController::AddDecision($owner, "YESNO", "-", 1,
        tooltip:"Use_that_On_Attack_ability_again_(Enfys_Nest)?");
    DecisionQueueController::AddDecision($owner, "CUSTOM", "ENFYS_REUSE|{$owner}|{$cardID}|{$mzID}|" . ($fromUpgrade ? '1' : '0'), 1);
}

// Dispatch target for the Shadow Caster (JTL_169) reuse trigger collected at defeat time.
function ShadowCasterReuseTrigger(int $owner, string $cardID, string $mzID): void {
    if (!HasWhenDefeatedAbility($cardID)) return;
    DecisionQueueController::AddDecision($owner, "YESNO", "-", 1,
        tooltip:"Use_its_When_Defeated_ability_again_(Shadow_Caster)?");
    DecisionQueueController::AddDecision($owner, "CUSTOM", "SHADOW_CASTER_REUSE|{$owner}|{$cardID}|{$mzID}", 1);
}

// Drain all static DQ entries for both players after each action.
// Called by EngineActionRunner after every mode if the function exists.
// Processes RESOLVE_TRIGGER and other CUSTOM/SYSTEM entries until a
// non-static decision (MZCHOOSE, YESNO, etc.) blocks further progress.
function ProcessGoldfishAutomation(): bool {
    $madeProgress = false;
    $dqController = new DecisionQueueController();
    for ($cycle = 0; $cycle < 64; ++$cycle) {
        $before1 = count(GetDecisionQueue(1));
        $before2 = count(GetDecisionQueue(2));
        $dqController->ExecuteStaticMethods(1);
        $dqController->ExecuteStaticMethods(2);
        $after1 = count(GetDecisionQueue(1));
        $after2 = count(GetDecisionQueue(2));
        if ($after1 === $before1 && $after2 === $before2) break;
        $madeProgress = true;
    }
    return $madeProgress;
}

// DQ handler: resolve a single trigger from the bag.
global $customDQHandlers;
$customDQHandlers["RESOLVE_TRIGGER"] = function($player, $parts, $lastDecision) {
    global $gTriggerDepth, $playerID;
    $savedPID    = $playerID;
    $playerID    = intval($player);
    $triggerType = $parts[0] ?? '';
    $cardID      = $parts[1] ?? '';
    $mzID        = $parts[2] ?? '';

    $gTriggerDepth++;
    DispatchTrigger($player, $triggerType, $cardID, $mzID);
    // Flush any nested triggers the ability closure just collected (e.g. Vader defeating a
    // unit whose When Defeated also triggers). They queue at higher depth, resolving first.
    FlushTriggerBag($player);
    $gTriggerDepth--;
    $playerID = $savedPID;
};

// JTL_002 Thrawn — resolve the "use that When Defeated ability again" offer. Always clears the
// pending guard; on YES pays the cost (undeployed: exhaust leader / deployed: once-per-round flag)
// and re-invokes. Re-checks usability (a prior link in the chain may have consumed Thrawn).
$customDQHandlers["THRAWN_REUSE"] = function($player, $parts, $lastDecision) {
    $owner       = intval($parts[0] ?? $player);
    $cardID      = $parts[1] ?? '';
    $mzID        = $parts[2] ?? '';
    $grantedType = ($parts[3] ?? '') !== '' ? $parts[3] : null;
    RemoveGlobalEffect($owner, 'SWU_THRAWN_REUSE_PENDING');
    if ($lastDecision !== "YES") return;
    $mode = _SWUThrawnReuseMode($owner);
    if ($mode === null) return;
    if ($mode === 'undeployed') _SWUExhaustUndeployedLeader($owner, 'JTL_002');
    else SWUConsumeUse(SWUGetLeader($owner)); // deployed: spend the once/round NumUses budget
    SWUUseWhenDefeatedAbility($owner, $cardID, $mzID, $grantedType);
};

// LAW_014 Enfys Nest — resolve the "use that On Attack ability again" offer. Clears the pending guard;
// on YES pays the cost (undeployed: 2 resources + exhaust the leader / deployed: once-per-round) and
// re-invokes. Mode re-checked at resolve time.
$customDQHandlers["ENFYS_REUSE"] = function($player, $parts, $lastDecision) {
    $owner       = intval($parts[0] ?? $player);
    $cardID      = $parts[1] ?? '';
    $mzID        = $parts[2] ?? '';
    $fromUpgrade = ($parts[3] ?? '0') === '1';
    RemoveGlobalEffect($owner, 'SWU_ENFYS_REUSE_PENDING');
    if ($lastDecision !== "YES") return;
    $mode = _SWUEnfysReuseMode($owner);
    if ($mode === null) return;
    if ($mode === 'undeployed') { SWUExhaustResources($owner, 2); _SWUExhaustUndeployedLeader($owner, 'LAW_014'); }
    else SWUConsumeUse(SWUGetLeader($owner)); // deployed: spend the once/round NumUses budget
    SWUUseOnAttackAbility($owner, $cardID, $mzID, $fromUpgrade);
};

// JTL_169 Shadow Caster — resolve the "use its When Defeated ability again" offer.
$customDQHandlers["SHADOW_CASTER_REUSE"] = function($player, $parts, $lastDecision) {
    if ($lastDecision !== "YES") return;
    $owner  = intval($parts[0] ?? $player);
    $cardID = $parts[1] ?? '';
    $mzID   = $parts[2] ?? '';
    SWUUseWhenDefeatedAbility($owner, $cardID, $mzID);
};

// DQ handler: cleanup + swap turn player after all When Played triggers fully resolve.
$customDQHandlers["FINISH_PLAY_CARD"] = function($player, $parts, $lastDecision) {
    global $gShootFirstPending;
    DecisionQueueController::CleanupRemovedCards();
    if (!empty($gShootFirstPending)) {
        // Shoot First event: SWUCombatDamage at the end of the attack calls SWUAfterAction.
        $gShootFirstPending = false;
        return;
    }
    SWUAfterAction($player);
};

// Task 5.1 — TWI_210 Cunning event-play observer. Queued at block 5 during the event branch
// of ActivateCard so it fires after the event's own effects (block 1) but before FINISH_PLAY_CARD
// (block 10). $parts[0]=playingPlayer, $parts[1]=playedCardID, $parts[2]=resourcesPaid.
// Calls SWUCollectOpponentPlayReactions and immediately FlushTriggerBag for the playing player.
$customDQHandlers["TWI_210#0"] = function($player, $parts, $lastDecision) {
    $playingPlayer = intval($parts[0] ?? $player);
    $playedCardID  = $parts[1] ?? '';
    $resourcesPaid = intval($parts[2] ?? 0);
    if ($playedCardID === '') return;
    SWUCollectOpponentPlayReactions($playingPlayer, $playedCardID, $resourcesPaid);
    // Batch E.1 — own-play reactions on event plays (Bossk's "when you play an event"; FFF on an Aggression event).
    SWUCollectOwnPlayReactions($playingPlayer, $playedCardID, 0);
    FlushTriggerBag($playingPlayer);
};

// DQ handler: pop the chosen EffectStack entry and dispatch it.
// $parts[0] = EffectStack mzID of the chosen trigger (from MZCHOOSE result or auto-dispatch).
$customDQHandlers["RESOLVE_NEXT_TRIGGER"] = function($player, $parts, $lastDecision) {
    global $gTriggerDepth, $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);

    // Auto-dispatch: RESOLVE_NEXT_TRIGGER|EffectStack-N → $parts[0] = "EffectStack-N" (contains '-').
    // After MZCHOOSE: RESOLVE_NEXT_TRIGGER|{player} → $parts[0] = player number; mzID is $lastDecision.
    $p0   = $parts[0] ?? '';
    $mzID = str_contains($p0, '-')
        ? $p0
        : (($lastDecision && $lastDecision !== '-' && $lastDecision !== '') ? $lastDecision : '');

    $entry = GetZoneObject($mzID);
    if ($entry === null || !empty($entry->removed)) { $playerID = $savedPID; return; }

    $triggerType = $entry->TriggerType ?? '';
    $cardID      = $entry->CardID ?? '';
    $params      = $entry->Params ?? '';
    $controller  = intval($entry->Controller ?? $player);

    $entry->Remove();

    $paramParts = $params !== '' ? explode('|', $params) : [];
    $unitMzID   = $paramParts[0] ?? '';
    $extra      = array_slice($paramParts, 1);

    $gTriggerDepth++;
    DispatchTrigger($controller, $triggerType, $cardID, $unitMzID, $extra);
    $gTriggerDepth--;

    $playerID = $savedPID;
};

// DQ handler: called at block 20 after all interactive decisions from the current trigger resolve.
// Checks the EffectStack and either queues the next trigger or finalises the action.
// True if $player has a pending BLOCKING decision (one that requires input: MZCHOOSE/YESNO/etc.) on
// their queue. Static decisions (CUSTOM/SYSTEM/MZMOVE/PASSPARAMETER) drain without input and are NOT
// blocking — so a hopped SWU_TRIGGER_RESUME (a CUSTOM) doesn't count itself. Used by the combat resume
// to gate SWUCombatDamage behind a defender's On Defense reaction (LOF_047/067/252 combat-pause).
function _SWUPlayerHasBlockingDecision(int $player): bool {
    $q = GetDecisionQueue($player);
    if (empty($q)) return false;
    static $staticTypes = ['CUSTOM', 'SYSTEM', 'MZMOVE', 'PASSPARAMETER'];
    foreach ($q as $d) {
        if (!in_array($d->Type ?? '', $staticTypes, true)) return true;
    }
    return false;
}

$customDQHandlers["SWU_TRIGGER_RESUME"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID    = $playerID;
    $activePlayer = intval($parts[0] ?? $player);
    $playerID     = $activePlayer;

    // Continuation: "COMBAT|{attackerMzID}|{targetMzID}" when this resume drives a
    // combat attack. When the EffectStack empties, queue SWUCombatDamage instead of
    // finalising via SWUAfterAction. Forwarded verbatim on each re-queue.
    $continuation = $parts[1] ?? '';
    $contStr      = ($continuation !== '')
        ? "|{$continuation}|" . ($parts[2] ?? '') . "|" . ($parts[3] ?? '') . "|" . ($parts[4] ?? '')
        : '';

    $stack = GetEffectStack();
    $remaining = array_values(array_filter($stack, fn($e) => empty($e->removed ?? false)));

    if (empty($remaining)) {
        DecisionQueueController::CleanupRemovedCards();
        if ($continuation === 'COMBAT') {
            $aMz = $parts[2] ?? '';
            $tMz = $parts[3] ?? '';
            $uid = $parts[4] ?? '0';
            if ($aMz !== '' && $tMz !== '') {
                // Combat-pause: a defender's On Defense reaction (LOF_047/067/252 — "when this unit is
                // attacked, before damage") is a NON-active-player decision that must resolve BEFORE
                // combat damage. Its YESNO sits on the defender's queue, which the active player's drain
                // never reaches before this resume. If the non-active player still has a pending blocking
                // decision, hop this resume onto THEIR queue (after their reaction) instead of committing
                // SWUCombatDamage now; the re-fired resume commits combat once their reaction resolves.
                $other = OtherPlayer($activePlayer);
                if (GetSWUVar('SWU_PENDING_DEF_REACTION', '') === '1' && _SWUPlayerHasBlockingDecision($other)) {
                    _SWUQueueOrchestration($other, "SWU_TRIGGER_RESUME|{$activePlayer}{$contStr}", 20);
                    $playerID = $savedPID;
                    return;
                }
                SetSWUVar('SWU_PENDING_DEF_REACTION', ''); // reaction (if any) resolved → commit combat
                // Queue combat damage onto the CURRENT drain's queue ($player — the active player normally,
                // or the defender when a combat-pause hop resumed here) so it runs in the same drain rather
                // than stranding on the other player's queue. The trailing |{$activePlayer} carries the
                // attacker frame so SWUCombatDamage resolves "my…" mzIDs correctly regardless of $player.
                _SWUQueueOrchestration($player, "SWUCombatDamage|{$aMz}|{$tMz}|{$uid}|{$activePlayer}", 1);
            }
        } else {
            // Chained "then (may) attack with another unit" (SOR_009 / SOR_103): an attack just
            // completed its full trigger resolution (the stack emptied). If one is armed, fire it
            // NOW — after the just-finished attack and any nested OnAttackEnd chain — and re-queue a
            // resume so SWUAfterAction fires once THIS chained attack also resolves. Else finalise.
            $chainSpec = GetSWUVar('SWU_CHAINED_ATTACK', '');
            if ($chainSpec !== '') {
                SetSWUVar('SWU_CHAINED_ATTACK', '');
                _SWUQueueOrchestration($activePlayer, "SWU_TRIGGER_RESUME|{$activePlayer}", 20);
                ChainedAttackTrigger($activePlayer, $chainSpec);
            } elseif (GetSWUVar('SWU_MONMOTHMA_LOOP', '') !== '') {
                // SEC_103 Mon Mothma — a looped attack just resolved; re-offer the next "attack with
                // another unit". Don't re-queue a resume here (each accepted attack's CollectAfterAttack-
                // Triggers queues the next one while the loop var is set); a decline clears the var so the
                // play's FINISH_PLAY_CARD finalizes the action.
                _SWUMonMothmaOffer($activePlayer);
            } else {
                SWUAfterAction($activePlayer);
            }
        }
        $playerID = $savedPID;
        return;
    }

    // Check if remaining triggers all belong to one player.
    $myRemaining    = array_filter($remaining, fn($e) => intval($e->Controller) === $activePlayer);
    $theirRemaining = array_filter($remaining, fn($e) => intval($e->Controller) !== $activePlayer);

    // Re-queue SWU_TRIGGER_RESUME for the next round at block 20, forwarding the continuation.
    _SWUQueueOrchestration($activePlayer, "SWU_TRIGGER_RESUME|{$activePlayer}{$contStr}", 20);

    if (count($remaining) === 1) {
        // Single trigger left: auto-dispatch via RESOLVE_NEXT_TRIGGER.
        $e = $remaining[0];
        $stackIdx = array_search($e, $stack);
        $choosingPlayer = intval($e->Controller);
        _SWUQueueOrchestration($choosingPlayer,
            "RESOLVE_NEXT_TRIGGER|EffectStack-{$stackIdx}", 1);
    } elseif (!empty($myRemaining) && empty($theirRemaining)) {
        // Active player still has multiple triggers: MZCHOOSE.
        $targetStr = _SWUEffectStackTargetsForPlayer($activePlayer);
        DecisionQueueController::AddDecision($activePlayer, "MZCHOOSE", $targetStr, 1,
            tooltip:"Choose_trigger_to_resolve");
        _SWUQueueOrchestration($activePlayer, "RESOLVE_NEXT_TRIGGER|{$activePlayer}", 1);
    } elseif (empty($myRemaining) && !empty($theirRemaining)) {
        // Switch to other player's triggers.
        $other = intval($activePlayer) === 1 ? 2 : 1;
        $targetStr = _SWUEffectStackTargetsForPlayer($other);
        DecisionQueueController::AddDecision($other, "MZCHOOSE", $targetStr, 1,
            tooltip:"Choose_trigger_to_resolve");
        _SWUQueueOrchestration($other, "RESOLVE_NEXT_TRIGGER|{$other}", 1);
    } else {
        // Mixed: ask active player who goes first (shouldn't normally happen mid-resolution, but handle it).
        DecisionQueueController::AddDecision($activePlayer, "YESNO", "-", 1,
            tooltip:"Resolve_Which_Player_First?");
        _SWUQueueOrchestration($activePlayer,
            "SWU_TRIGGER_ORDER_CHOICE|{$activePlayer}", 1);
    }

    $playerID = $savedPID;
};

// DQ handler: active player chose YES (mine first) or NO (theirs first) for cross-player ordering.
$customDQHandlers["SWU_TRIGGER_ORDER_CHOICE"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID     = $playerID;
    $activePlayer = intval($parts[0] ?? $player);
    $playerID     = $activePlayer;

    $mineFirst = ($lastDecision === 'YES' || $lastDecision === '1');
    $first  = $mineFirst ? $activePlayer : (intval($activePlayer) === 1 ? 2 : 1);
    $targetStr = _SWUEffectStackTargetsForPlayer($first);

    DecisionQueueController::AddDecision($first, "MZCHOOSE", $targetStr, 1,
        tooltip:"Choose_trigger_to_resolve");
    _SWUQueueOrchestration($first, "RESOLVE_NEXT_TRIGGER|{$first}", 1);

    $playerID = $savedPID;
};

// Ambush: player answered the "Ambush attack?" YESNO.
// $parts[0] = attackerMzID; $parts[1..] = target mzIDs (joined as &-separated parts).
global $customDQHandlers;
$customDQHandlers["SWUAmbushAnswer"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID     = $playerID;
    $playerID     = intval($player);
    $attackerMzID = $parts[0] ?? '';
    $targetStr    = implode('&', array_slice($parts, 1));
    if ($lastDecision === "YES" || $lastDecision === "1") {
        AddTurnEffect($attackerMzID, 'SWU_AMBUSH_ATTACK'); // ASH_207 — "while attacking using Ambush, +2/+0"
        $targets = array_values(array_filter(explode('&', $targetStr), fn($t) => $t !== ''));
        if (count($targets) === 1) {
            // Only one valid target — auto-fire, no player choice needed.
            ExecuteSWUAttack($player, $attackerMzID, $targets[0]);
        } else {
            DecisionQueueController::AddDecision($player, "MZCHOOSE", $targetStr, 1, tooltip:"Choose_Ambush_target");
            DecisionQueueController::AddDecision($player, "CUSTOM", "SWUAmbushAttack|{$attackerMzID}", 1);
        }
    } else {
        // Declined — SWU_TRIGGER_RESUME (block 20) handles SWUAfterAction; just cleanup here.
        DecisionQueueController::CleanupRemovedCards();
    }
    $playerID = $savedPID;
};

// Ambush: player chose an attack target.
global $customDQHandlers;
$customDQHandlers["SWUAmbushAttack"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID     = $playerID;
    $playerID     = intval($player);
    $attackerMzID = $parts[0] ?? '';
    if ($lastDecision === "PASS" || $lastDecision === "" || $lastDecision === "-") {
        // Passed on target — SWU_TRIGGER_RESUME handles SWUAfterAction.
        DecisionQueueController::CleanupRemovedCards();
    } else {
        ExecuteSWUAttack($player, $attackerMzID, $lastDecision);
    }
    $playerID = $savedPID;
};

// Support (ASH): player chose which friendly unit makes the supported attack (or declined via the
// MZMAYCHOOSE Pass button → '-'). On accept, lend S's other abilities to the chosen attacker and attack.
global $customDQHandlers;
$customDQHandlers["SWUSupportChooseAttacker"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID  = $playerID;
    $playerID  = intval($player);
    $supportMz = $parts[0] ?? '';
    if ($lastDecision === "PASS" || $lastDecision === "" || $lastDecision === "-") {
        // Declined — the SWU_TRIGGER_RESUME (block 20) handles SWUAfterAction; just clean up.
        DecisionQueueController::CleanupRemovedCards();
    } else {
        _SWUSupportGrantAbilities(intval($player), $supportMz, $lastDecision);   // grants + BeginSWUAttack
    }
    $playerID = $savedPID;
};

// Advantage shed (ASH_T02) — resolves the attacker's "When attack ends: defeat this upgrade" as one bag
// slot. If other triggers are still pending AND 2+ tokens remain, offer "defeat 1" (to interleave with
// the other triggers) vs "defeat all". If nothing else is pending (or only 1 token), auto-defeat all.
// The current EffectStack entry was already Remove()'d in RESOLVE_NEXT_TRIGGER before this dispatch.
function _SWUResolveAdvantageShed(int $player, string $mzID): void {
    global $playerID; $playerID = $player;
    $unit = GetZoneObject($mzID);
    if ($unit === null || !empty($unit->removed)) return;
    // ASH_149 Eviscerator — the controller's units don't shed Advantage after combat (skip the picker too).
    if (_SWUControlsCardInPlay(intval($unit->Controller ?? $player), 'ASH_149')) return;
    $count = _SWUCountAdvantageSubcards($unit);
    if ($count <= 0) return;
    $otherPending = 0;
    foreach (GetEffectStack() as $e) { if (empty($e->removed ?? false)) $otherPending++; }
    if ($count === 1 || $otherPending === 0) { _SWUDefeatAllAdvantageTokens($mzID); return; }
    DecisionQueueController::AddDecision($player, "OPTIONCHOOSE",
        "Defeat_1_Advantage_token&Defeat_all_Advantage_tokens", 1, "Advantage_tokens:_defeat_one_or_all?");
    DecisionQueueController::AddDecision($player, "CUSTOM", "AdvantageShed#0|{$mzID}", 1);
}
global $customDQHandlers;
$customDQHandlers["AdvantageShed#0"] = function($player, $parts, $lastDecision) {
    global $playerID; $playerID = intval($player);
    $mzID = $parts[0] ?? '';
    if ($lastDecision === 'Defeat_all_Advantage_tokens') {
        _SWUDefeatAllAdvantageTokens($mzID);
        return;
    }
    // "Defeat 1" (default) — defeat one, then re-enter the bag so any remaining tokens re-order with the
    // still-pending triggers (the block-20 SWU_TRIGGER_RESUME re-offers ordering each round).
    _SWUDefeatOneAdvantageToken($mzID);
    $unit = GetZoneObject($mzID);
    if ($unit !== null && empty($unit->removed) && _SWUCountAdvantageSubcards($unit) > 0) {
        AddEffectStack('ASH_T02', intval($player), 'AdvantageShed', $mzID);
    }
};

// Bounty: player answered the "Collect bounty?" YESNO.
global $customDQHandlers;
$customDQHandlers["SWUCollectBounty"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    if ($lastDecision === "YES" || $lastDecision === "1") {
        $cardID = $parts[0] ?? '';
        switch ($cardID) {
            case 'SHD_027': // Hylobon Enforcer — draw 1 card
                DoDrawCard($player, 1);
                break;
            case 'SHD_006': // Jabba's granted bounty — "the next unit you play this phase costs N less"
                            // (N = the discount carried in parts[1]: 1 from the front Action, 2 deployed).
                $amt = max(1, intval($parts[1] ?? 1));
                for ($i = 0; $i < $amt; $i++) AddGlobalEffects($player, 'SWU_SHD006_DISCOUNT_NEXT');
                break;
            case 'SHD_123': // Bounty Hunter's Quarry — search the top 5 (10 if the bountied unit was
                            // unique) of YOUR deck for a unit costing 3 or less and play it for free.
                $n = (intval($parts[1] ?? 0) === 1) ? 10 : 5;
                if (count(GetDeck($player)) > 0) {
                    DoTopDeckPlay($player, $n,
                        fn($c) => stripos(CardType($c) ?? '', 'Unit') !== false && intval(CardCost($c)) <= 3,
                        3, 1);
                }
                break;
        }
    }
    $playerID = $savedPID;
};

// Deal $amount non-combat damage to the unit at $unitMzID (perspective of $player).
// Handles defeat + When Defeated triggers. Shared by DEAL_UNIT_DAMAGE and
// ability closures (e.g. SOR_137) that need to damage a unit directly.
// Find the current relative mzID of the unit with $uid across all four arenas, or
// null if it's gone. Caller must have $playerID set (uses relative zone names).
// Use after a step that may have shifted indices (defeat/cleanup) to re-resolve a
// unit captured earlier by UniqueID.
function SWUFindMzByUID(int $uid): ?string {
    foreach (["myGroundArena", "mySpaceArena", "theirGroundArena", "theirSpaceArena"] as $zone) {
        foreach (ZoneSearch($zone, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o !== null && empty($o->removed) && intval($o->UniqueID ?? -1) === $uid) return $mz;
        }
    }
    return null;
}

function SWUDealDamageToUnit(string $unitMzID, int $amount, int $player, ?string $sourceMzID = null, bool $skipPrevent = false): void {
    global $playerID;
    $saved    = $playerID;
    $playerID = intval($player);
    $unit     = GetZoneObject($unitMzID);
    if ($unit !== null && !($unit->removed ?? false)) {
        // ASH_196 Gorian Shard's Corsair — damage dealt by a friendly Underworld card (the threaded
        // source) is unpreventable: skip every prevention/reduction below and apply the full amount.
        if (!$skipPrevent && $amount > 0 && $sourceMzID !== null
            && _SWUDamageUnpreventable(GetZoneObject($sourceMzID))) {
            $unit->Damage = intval($unit->Damage) + $amount;
            SWUQueueDamageAnim($unitMzID, intval($amount), intval($player));
            $hp = ObjectCurrentHP($unit);
            if ($hp > 0 && intval($unit->Damage) >= $hp && !SWUImmuneToHpDefeat($unit)) {
                SWUDefeatUnit(intval($player), $unitMzID, false, true);
            }
            $playerID = $saved;
            return;
        }
        // SEC_101 Queen Amidala — interactive prevention of effect/ability damage. Offer her controller a
        // chance to defeat a trait-sharing friendly to prevent; defer this damage to AMIDALA_PREVENT_ABILITY
        // (which re-applies with $skipPrevent on decline). Indirect damage never reaches here (it writes
        // Damage directly), so it's unpreventable as required.
        if (!$skipPrevent && $amount > 0 && ($unit->CardID ?? '') === 'SEC_101') {
            $targets = _SWUAmidalaPreventTargets($unit);
            if (!empty($targets)) {
                $ctrl = intval($unit->Controller ?? $player);
                $uid  = intval($unit->UniqueID ?? 0);
                // Queue the prevent for Amidala's controller; the MZMAYCHOOSE waits on THEIR queue (so it
                // validates under their context when drained). Restore $playerID so the caller — e.g. an
                // opponent's event handler that does more after this damage — continues in its own frame.
                $targets = _SWUAmidalaPreventTargets($unit);   // re-collect under the controller's frame
                $tstr = $targets ? implode('&', $targets) : '';
                DecisionQueueController::AddDecision($ctrl, 'MZMAYCHOOSE', $tstr, 1,
                    tooltip: 'Defeat_a_trait-sharing_friendly_to_prevent_damage_to_Queen_Amidala?');
                DecisionQueueController::AddDecision($ctrl, 'CUSTOM', "AMIDALA_PREVENT_ABILITY|{$uid}|{$amount}|{$player}", 1);
                $playerID = $saved;
                return;   // damage deferred to the handler
            }
        }
        // ASH_062 The Mandalorian — interactive prevention of effect/ability damage to ANOTHER friendly
        // unit. Offer the controller a chance to defeat a Shield on a friendly ASH_062; defer to
        // ASH062_PREVENT_ABILITY (which re-applies with $skipPrevent on decline / no shield). Skip when the
        // target IS an ASH_062 (its own Shielded keyword covers it — "another friendly unit" doesn't apply).
        if (!$skipPrevent && $amount > 0 && ($unit->CardID ?? '') !== 'ASH_062'
            && _SWUAsh062Provider($unit) !== null) {
            $ctrl = intval($unit->Controller ?? $player);
            $uid  = intval($unit->UniqueID ?? 0);
            DecisionQueueController::AddDecision($ctrl, 'YESNO', '-', 1,
                tooltip: 'Defeat_a_Shield_on_The_Mandalorian_to_prevent_damage_to_this_unit?');
            DecisionQueueController::AddDecision($ctrl, 'CUSTOM', "ASH062_PREVENT_ABILITY|{$uid}|{$amount}|{$player}", 1);
            $playerID = $saved;
            return;   // damage deferred to the handler
        }
        // "Can't be damaged by enemy card abilities" (SHD_187). This funnel is effect/ability damage
        // only (combat damage is applied inline in SWUCombatDamage), so prevent the whole instance when
        // an opponent's ability would deal it.
        if (intval($player) !== intval($unit->Controller ?? $player) && SWUAvoidsAbilityDamage($unit)) {
            $playerID = $saved;
            return;
        }
        // LOF_108 Malakili — "If a friendly Creature unit would deal damage to a friendly unit, prevent
        // that damage." Source-aware: the dealing handler passes its own mz; prevent the whole instance
        // when that source is a Creature and source + target share a controller who has Malakili in play.
        if ($sourceMzID !== null && _SWULof108PreventsCreatureDamage($sourceMzID, $unit)) {
            $playerID = $saved;
            return;
        }
        // Shield (CR 8.31): a Shield token absorbs the ENTIRE instance of damage from any source —
        // combat (handled in SWUCombatDamage) OR a card ability/effect (this funnel). Consume one token
        // and prevent the whole instance. ASH_196 unpreventable already bypassed this above; indirect
        // damage never reaches this funnel (it writes Damage directly), so it correctly ignores Shields.
        if ($amount > 0 && SWUConsumeShieldToken($unit)) {
            SWUQueuePreventedAnim($unitMzID, intval($player));
            SWUQueueShieldBreakAnim($unitMzID, intval($player));
            $playerID = $saved;
            return;
        }
        // SEC_042 Cassian Andor — "If an enemy card ability would deal damage to this unit, prevent 2."
        if (($unit->CardID ?? '') === 'SEC_042' && intval($player) !== intval($unit->Controller ?? $player)) {
            $amount = max(0, $amount - 2);
        }
        $amount = _SWUApplyDamagePrevention($unit, $amount); // LOF_220 prevent-2 / SEC_050 / ASH_150 doubling
        $unit->Damage = intval($unit->Damage) + $amount;
        SWUQueueDamageAnim($unitMzID, intval($amount), intval($player));
        $hp = ObjectCurrentHP($unit);
        if ($hp > 0 && intval($unit->Damage) >= $hp && !SWUImmuneToHpDefeat($unit)) {
            // SWUDefeatUnit now collects WhenDefeated + leave-play reactions itself (single point).
            SWUDefeatUnit(intval($player), $unitMzID, false, true); // SBA "no remaining HP" (not an ability-defeat)
        }
        // JTL_009 Boba Fett — effect damage to a unit is always non-combat (combat damage to units never
        // routes through this funnel; it modifies Damage directly in SWUCombatDamage).
        if ($amount > 0) _SWUCollectBobaNonCombatReaction(intval($player));
        // "When damage is dealt to this unit" reactions (SEC_143, SEC_002) — only if it survived.
        if ($amount > 0 && empty($unit->removed)) _SWUOnUnitDamaged($unit, intval($amount));
    }
    $playerID = $saved;
}

// Deal a divided-damage assignment SIMULTANEOUSLY. $assignmentStr is the MZSPLITASSIGN result —
// comma-separated "mzID:amount" pairs. All assigned damage is applied first (so a unit killed by
// its share can't stale a co-target's mzID), then defeats resolve in a single sweep. Targets are
// snapshotted by UniqueID and re-resolved with SWUFindMzByUID during the sweep (SWUDefeatUnit
// cleans up and shifts indices per defeat). Source-less: damage is unattributed (matches "deal N
// damage divided among units" cards — SOR_135). Caller need not set $playerID; saved/restored here.
function SWUDealSplitDamage(int $player, string $assignmentStr): void {
    if ($assignmentStr === '' || $assignmentStr === '-' || $assignmentStr === 'PASS') return;
    global $playerID;
    $saved    = $playerID;
    $playerID = intval($player);

    // Phase 0: resolve each "mzID:amount" to a (UniqueID, amount) hit. Nothing is mutated yet,
    // so the submitted mzIDs are still valid; capture UID so the sweep survives reindexing.
    $hits = [];
    foreach (explode(',', $assignmentStr) as $pair) {
        $p = explode(':', $pair);
        if (count($p) < 2) continue;
        $amt = intval($p[1]);
        if ($amt <= 0) continue;
        $obj = GetZoneObject(trim($p[0]));
        if ($obj === null || !empty($obj->removed)) continue;
        $hits[] = ['uid' => intval($obj->UniqueID ?? 0), 'amount' => $amt];
    }

    // Phase 1: apply ALL assigned damage (no defeats — indices stay put through this loop).
    foreach ($hits as $h) {
        $mz  = SWUFindMzByUID($h['uid']);
        if ($mz === null) continue;
        $obj = GetZoneObject($mz);
        if ($obj === null || !empty($obj->removed)) continue;
        $obj->Damage = intval($obj->Damage) + $h['amount'];
        SWUQueueDamageAnim($mz, $h['amount'], intval($player));
    }

    // Phase 2: defeat sweep — any unit now at/over its current HP. Re-resolve by UID each time
    // because SWUDefeatUnit cleans up and shifts indices.
    foreach ($hits as $h) {
        $mz  = SWUFindMzByUID($h['uid']);
        if ($mz === null) continue;
        $obj = GetZoneObject($mz);
        if ($obj === null || !empty($obj->removed)) continue;
        $hp = ObjectCurrentHP($obj);
        if ($hp > 0 && intval($obj->Damage) >= $hp && !SWUImmuneToHpDefeat($obj)) {
            // SWUDefeatUnit now collects WhenDefeated + leave-play reactions itself (single point).
            SWUDefeatUnit(intval($player), $mz, false, true); // SBA "no remaining HP" (not an ability-defeat)
        }
    }
    $playerID = $saved;
}

// "Distribute N Advantage tokens among units (divided as you choose)" — the SPLIT_DAMAGE analogue for
// the Advantage-token cards (ASH_195/211/224). $assignmentStr = "mzID:count,mzID:count" (MZSPLITASSIGN).
// No defeats occur, so apply directly by mzID; DoGiveAdvantageToken gives one token per count.
function SWUGiveSplitAdvantage(int $player, string $assignmentStr): void {
    if ($assignmentStr === '' || $assignmentStr === '-' || $assignmentStr === 'PASS') return;
    global $playerID;
    $saved    = $playerID;
    $playerID = intval($player);
    foreach (explode(',', $assignmentStr) as $pair) {
        $p = explode(':', $pair);
        if (count($p) < 2) continue;
        $mz  = trim($p[0]);
        $cnt = intval($p[1]);
        if ($cnt <= 0) continue;
        $obj = GetZoneObject($mz);
        if ($obj === null || !empty($obj->removed)) continue;
        for ($k = 0; $k < $cnt; $k++) DoGiveAdvantageToken(intval($player), $mz);
    }
    $playerID = $saved;
}

// Queue a "distribute $total Advantage tokens among $targets" decision (MZSPLITASSIGN → SPLIT_ADVANTAGE).
// $upto=true allows assigning fewer than $total (the "may / up to" wording); false requires all $total.
function SWUQueueDistributeAdvantage(int $player, int $total, array $targets, bool $upto, string $tooltip): void {
    if ($total <= 0 || empty($targets)) return;
    $spec = "{$total}|" . implode("&", $targets) . ($upto ? "|UPTO" : "");
    DecisionQueueController::AddDecision($player, "MZSPLITASSIGN", $spec, 1, tooltip: $tooltip);
    DecisionQueueController::AddDecision($player, "CUSTOM", "SPLIT_ADVANTAGE", 1);
}

// ── Indirect damage (CR §35) ────────────────────────────────────────────────
// "Deal N indirect damage to a player": that player (the assigner) assigns N unpreventable damage,
// divided as they choose, among their units + base — capped per unit at remaining HP (shields are
// ignored but NOT consumed, CR 35.2.a). All damage simultaneous (CR 35.5); attributed to the
// controller (CR 35.4). Built on MZSPLITASSIGN (per-target caps, base targets, forced-full pool).

// CardIDs whose presence makes the CONTROLLER assign indirect damage to opponents (override of
// CR 35.1's "the chosen player assigns"). JTL_143 Devastator; JTL_171's per-unit grant slots in later.
function SWUIndirectAssignToOpponentSources(): array {
    return ["JTL_143"];
}

// Resolve who assigns the indirect damage. Default: the damaged player. Override → the controller,
// when the damaged player is an opponent AND the controller controls an "assign to opponents" source.
function SWUControllerAssignsIndirect(int $controller, int $damagedPlayer): int {
    if ($damagedPlayer === $controller) return $damagedPlayer; // self-target never overrides
    $sources = SWUIndirectAssignToOpponentSources();
    if (empty($sources)) return $damagedPlayer;
    global $playerID;
    $saved = $playerID; $playerID = $controller;
    $controls = false;
    foreach (["myGroundArena", "mySpaceArena"] as $z) {
        foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            // JTL_143 Devastator (source CardID) OR a unit bearing JTL_171 Targeting Computer ("you assign
            // all indirect dealt by this unit"). The exact per-unit "by this unit" scoping would need the
            // source unit threaded through the funnel — here any controlled JTL_171 host enables the
            // override (a minor over-approximation only when indirect comes from a different source).
            if (in_array($o->CardID, $sources, true) || _SWUUnitHasUpgrade($o, 'JTL_171')) { $controls = true; break 2; }
        }
    }
    $playerID = $saved;
    return $controls ? $controller : $damagedPlayer;
}

// Apply an indirect assignment string ("mz:amt,mz:amt") SIMULTANEOUSLY: raw damage to units
// (bypasses + preserves shields), base via SWUDealDamageToBase attributed to the controller,
// then one UID-snapshot defeat sweep. Shared by the DQ handler and the auto-resolve path.
// $thenHandler (optional) is a "Name~arg1~arg2" continuation dispatched AFTER the assignment is applied,
// with the results exposed in $gLastIndirectBaseDmg (total base damage dealt this way) and
// $gLastIndirectUnitUIDs (UniqueIDs of units damaged this way). Threaded through the decision param so it
// survives the request boundary on the interactive MZSPLITASSIGN path. (JTL_152/218/222 reactive seams.)
function SWUApplyIndirectAssignment(int $controller, int $damagedPlayer, string $assignmentStr, string $thenHandler = ''): void {
    global $playerID, $gLastIndirectBaseDmg, $gLastIndirectUnitUIDs;
    $gLastIndirectBaseDmg = 0; $gLastIndirectUnitUIDs = [];
    if ($assignmentStr === '' || $assignmentStr === '-' || $assignmentStr === 'PASS') {
        if ($thenHandler !== '') SWUDispatchIndirectThen($controller, $thenHandler);
        return;
    }
    $saved    = $playerID;
    $assigner = SWUControllerAssignsIndirect($controller, $damagedPlayer);

    // Phase 0: parse the submitted assignment under the ASSIGNER's frame (the queued mzIDs are
    // assigner-relative). Capture units by UniqueID so later phases are frame-independent.
    $playerID = $assigner;
    $hits = []; $baseDmg = 0;
    foreach (explode(',', $assignmentStr) as $pair) {
        $p = explode(':', $pair);
        if (count($p) < 2) continue;
        $mz = trim($p[0]); $amt = intval($p[1]);
        if ($amt <= 0) continue;
        if (strpos($mz, 'Base') !== false) { $baseDmg += $amt; continue; }
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        $hits[] = ['uid' => intval($o->UniqueID ?? 0), 'amount' => $amt];
    }
    // Expose the results for an optional reactive continuation (JTL_152/218/222).
    $gLastIndirectBaseDmg  = $baseDmg;
    $gLastIndirectUnitUIDs = array_map(fn($h) => $h['uid'], $hits);

    // Phases 1-2 run under the CONTROLLER's frame so SWUFindMzByUID / SWUQueueDamageAnim /
    // SWUDefeatUnit stay consistent and the defeat is attributed to the controller (CR 35.4).
    $playerID = $controller;

    // Phase 1: apply all unit damage (no defeats — indices/UIDs stay valid through the loop).
    foreach ($hits as $h) {
        $mz = SWUFindMzByUID($h['uid']); if ($mz === null) continue;
        $o  = GetZoneObject($mz); if ($o === null || !empty($o->removed)) continue;
        $o->Damage = intval($o->Damage) + $h['amount'];
        SWUQueueDamageAnim($mz, $h['amount'], $controller);
    }

    // Base damage — attributed to the controller (self-target suppresses the enemy-base flags).
    if ($baseDmg > 0) {
        SWUDealDamageToBase($baseDmg, $damagedPlayer, $controller);
    }

    // Phase 2: simultaneous defeat sweep (re-resolve by UID — SWUDefeatUnit shifts indices).
    foreach ($hits as $h) {
        $mz = SWUFindMzByUID($h['uid']); if ($mz === null) continue;
        $o  = GetZoneObject($mz); if ($o === null || !empty($o->removed)) continue;
        $hp = ObjectCurrentHP($o);
        if ($hp > 0 && intval($o->Damage) >= $hp && !SWUImmuneToHpDefeat($o)) SWUDefeatUnit($controller, $mz, false, true); // SBA
    }

    // JTL_133 Allegiant General Pryde — "When indirect damage is dealt to a unit: you may defeat a
    // non-unique upgrade on it." For each surviving unit damaged this way, if $controller controls Pryde,
    // offer to defeat one of that unit's non-unique upgrades. (Single damaged unit is the common case;
    // multi-unit would clobber the shared DefeatUpg StoreVariables — a documented edge.)
    $prydeControls = false;
    foreach (array_merge(GetGroundArena($controller) ?? [], GetSpaceArena($controller) ?? []) as $pu) {
        if (empty($pu->removed) && ($pu->CardID ?? '') === 'JTL_133') { $prydeControls = true; break; }
    }
    if ($prydeControls) {
        foreach ($gLastIndirectUnitUIDs as $uid) {
            if (SWUFindMzByUID(intval($uid)) === null) continue;
            SWUQueueDefeatUpgrade($controller, "You_may_defeat_a_non-unique_upgrade_on_the_damaged_unit",
                may: true, max: 1, filter: "unique=0", min: 0, onlyHostUID: intval($uid));
        }
    }

    $playerID = $saved;
    if ($thenHandler !== '') SWUDispatchIndirectThen($controller, $thenHandler);
}

// Dispatch an indirect "then" continuation: "Name~arg1~arg2" → $customDQHandlers[Name]($controller,[args]).
function SWUDispatchIndirectThen(int $controller, string $thenHandler): void {
    global $customDQHandlers;
    $parts = explode('~', $thenHandler);
    $name  = array_shift($parts);
    if ($name !== '' && isset($customDQHandlers[$name]) && is_callable($customDQHandlers[$name])) {
        $customDQHandlers[$name]($controller, $parts, '');
    }
}

// Core funnel: deal $amount indirect damage to $damagedPlayer, dealt by $controller. $thenHandler is an
// optional "Name~args" continuation (see SWUApplyIndirectAssignment).
function SWUDealIndirectDamage(int $controller, int $amount, int $damagedPlayer, string $thenHandler = ''): void {
    if ($amount <= 0) { if ($thenHandler !== '') SWUDispatchIndirectThen($controller, $thenHandler); return; }
    // JTL_165 Hunting Aggressor: indirect damage you deal to opponents is increased by 1.
    if ($damagedPlayer !== $controller) {
        foreach (GetUnitsInPlay($controller) as $u) { if (($u->CardID ?? '') === 'JTL_165' && empty($u->removed)) { $amount += 1; break; } }
    }
    AddGlobalEffects($controller, 'SWU_DEALT_INDIRECT'); // JTL_138 "if you dealt indirect damage this phase"
    global $playerID;
    $assigner = SWUControllerAssignsIndirect($controller, $damagedPlayer);
    $saved = $playerID; $playerID = $assigner;
    $persp = ($assigner === $damagedPlayer) ? 'my' : 'their'; // 'their' only in the override case

    $specs = [];
    foreach ([$persp . "GroundArena", $persp . "SpaceArena"] as $z) {
        foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            $cap = ObjectCurrentHP($o) - intval($o->Damage); // shields don't reduce the cap (CR 35.3)
            if ($cap > 0) $specs[] = "{$mz}:{$cap}";
        }
    }
    // The base is an UNLIMITED sink for indirect damage — unlike units (capped at remaining HP
    // per the CR), the base can be assigned damage past its remaining HP and goes over capacity.
    // Cap the spec at $amount (the most that could ever be assigned to one target) so the player
    // may dump the whole pool onto the base and overkill is dealt/displayed in full.
    $base = GetBase($damagedPlayer);
    if (count($base) > 0 && empty($base[0]->removed)) {
        $specs[] = "{$persp}Base-0:{$amount}";
    }
    if (empty($specs)) { $playerID = $saved; if ($thenHandler !== '') SWUDispatchIndirectThen($controller, $thenHandler); return; }

    $cap = 0; foreach ($specs as $s) { $cap += intval(explode(':', $s)[1]); }
    $pool = min($amount, $cap);                 // assign as much as possible (CR 35.3)
    if ($pool <= 0) { $playerID = $saved; if ($thenHandler !== '') SWUDispatchIndirectThen($controller, $thenHandler); return; }

    if (count($specs) === 1) {                  // no meaningful choice — auto-resolve, no popup
        $mz = explode(':', $specs[0])[0];
        SWUApplyIndirectAssignment($controller, $damagedPlayer, "{$mz}:{$pool}", $thenHandler);
        $playerID = $saved;
        return;
    }

    $applyParam = "INDIRECT_APPLY|{$controller}|{$damagedPlayer}" . ($thenHandler !== '' ? "|{$thenHandler}" : '');
    DecisionQueueController::AddDecision($assigner, "MZSPLITASSIGN", "{$pool}|" . implode("&", $specs), 1, tooltip:"Assign_{$pool}_indirect_damage");
    DecisionQueueController::AddDecision($assigner, "CUSTOM", $applyParam, 1);
    // Leave $playerID = $assigner: MZCountChoices validates the relative-mzID split next, under it.
}

// "Deal N indirect damage to a player" — controller picks You or Opponent (2-player; Twin Suns later).
// $thenHandler optional (see SWUApplyIndirectAssignment).
function SWUDealIndirectToChosenPlayer(int $controller, int $amount, string $thenHandler = ''): void {
    global $playerID; $playerID = $controller;
    $param = "INDIRECT_CHOOSE_PLAYER|{$controller}|{$amount}" . ($thenHandler !== '' ? "|{$thenHandler}" : '');
    DecisionQueueController::AddDecision($controller, "OPTIONCHOOSE", "You&Opponent", 1, "Choose_a_player_to_deal_indirect_damage");
    DecisionQueueController::AddDecision($controller, "CUSTOM", $param, 1);
}

// "Deal N indirect damage to each opponent" (2-player: the one opponent; Twin Suns multi-opponent later).
function SWUDealIndirectToEachOpponent(int $controller, int $amount): void {
    foreach ([GetOpponent($controller)] as $opp) {
        SWUDealIndirectDamage($controller, $amount, intval($opp));
    }
}

// Apply an indirect assignment ($lastDecision = "mz:amt,..."); param = controller|damagedPlayer.
$customDQHandlers["INDIRECT_APPLY"] = function($player, $parts, $lastDecision) {
    $controller = intval($parts[0] ?? $player);
    $damaged    = intval($parts[1] ?? $player);
    $thenHandler = (string)($parts[2] ?? '');
    SWUApplyIndirectAssignment($controller, $damaged, (string)$lastDecision, $thenHandler);
};

// Resolve the You/Opponent choice for "deal N indirect to a player"; param = controller|amount[|thenHandler].
$customDQHandlers["INDIRECT_CHOOSE_PLAYER"] = function($player, $parts, $lastDecision) {
    $controller = intval($parts[0] ?? $player);
    $amount     = intval($parts[1] ?? 0);
    $thenHandler = (string)($parts[2] ?? '');
    $target     = ((string)$lastDecision === 'Opponent') ? GetOpponent($controller) : $controller;
    SWUDealIndirectDamage($controller, $amount, intval($target), $thenHandler);
};

// DQ handler: deal N damage to the unit at the mzID stored in $lastDecision.
// Queued by WhenPlayed abilities that target a unit chosen via MZCHOOSE.
$customDQHandlers["DEAL_UNIT_DAMAGE"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '') return;
    SWUDealDamageToUnit($lastDecision, intval($parts[0] ?? 1), intval($player));
};

// Universal handler: give the unit at $lastDecision a "for this phase" shrink of
// –{$parts[0]}/–{$parts[1]}. Callers queue PASSPARAMETER/MZCHOOSE + CUSTOM APPLY_PHASE_DEBUFF|power|hp.
$customDQHandlers["APPLY_PHASE_DEBUFF"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    global $playerID;
    $playerID = intval($player);
    SWUApplyPhaseDebuff($lastDecision, intval($parts[0] ?? 0), intval($parts[1] ?? 0), (string)($parts[2] ?? ''));
};

// Universal handler: give the unit at $lastDecision a "for this phase" buff of
// +{$parts[0]}/+{$parts[1]}. Optional $parts[2] = source CardID (shown in the Active
// Effects popup). Callers queue PASSPARAMETER/MZCHOOSE + CUSTOM APPLY_PHASE_BUFF|power|hp|source.
$customDQHandlers["APPLY_PHASE_BUFF"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    global $playerID;
    $playerID = intval($player);
    SWUApplyPhaseBuff($lastDecision, intval($parts[0] ?? 0), intval($parts[1] ?? 0), (string)($parts[2] ?? ''));
};

$customDQHandlers["BOUNCE_UNIT"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    global $playerID;
    $playerID = intval($player);
    SWUBounceUnit($player, $lastDecision);
};

// Universal handler: heal $parts[0] from the chosen target ($lastDecision), which
// may be a unit mzID or a base mzID (myBase-0 / theirBase-0). Queued by
// PASSPARAMETER/MZCHOOSE + CUSTOM HEAL_TARGET|N. (SOR_074 Repair.)
$customDQHandlers["HEAL_TARGET"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    global $playerID;
    $playerID = intval($player);
    $amount = intval($parts[0] ?? 0);
    if (strpos($lastDecision, 'Base') !== false) {
        $targetPlayer = (strpos($lastDecision, 'my') === 0) ? intval($player) : GetOpponent(intval($player));
        OnHealBase(intval($player), $targetPlayer, $amount);
    } else {
        OnHealUnit(intval($player), $lastDecision, $amount);
    }
};

// Universal handler: deal N damage to a chosen UNIT or BASE (mzID may be a unit mzID or
// myBase-0/theirBase-0). Param DEAL_TARGET|N. No-ops on a '-' decline. Mirror of HEAL_TARGET.
$customDQHandlers["DEAL_TARGET"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    global $playerID;
    $playerID = intval($player);
    $amount = intval($parts[0] ?? 0);
    if (strpos($lastDecision, 'Base') !== false) {
        $targetPlayer = (strpos($lastDecision, 'my') === 0) ? intval($player) : GetOpponent(intval($player));
        SWUDealDamageToBase($amount, $targetPlayer);
    } else {
        SWUDealDamageToUnit($lastDecision, $amount, intval($player));
    }
};

// Universal handler: close the current action. Lets base/leader epic abilities reuse
// the universal effect handlers (DEAL_UNIT_DAMAGE, APPLY_PHASE_DEBUFF, HEAL_TARGET, …
// which deliberately do NOT call SWUAfterAction so events can use them too) and then
// end the action by queuing CUSTOM SWU_AFTER_ACTION last.
$customDQHandlers["SWU_AFTER_ACTION"] = function($player, $parts, $lastDecision) {
    SWUAfterAction(intval($player));
};

// Like SWU_AFTER_ACTION but DON'T swap the turn player — JTL_018 Kazuda's "take an extra action".
$customDQHandlers["SWU_AFTER_ACTION_EXTRA"] = function($player, $parts, $lastDecision) {
    SWUAfterActionExtra(intval($player));
};

// Universal handler: ready the resource at the mzID passed via $lastDecision.
// Callers queue PASSPARAMETER($mzID) + CUSTOM READY_RESOURCE.
$customDQHandlers["READY_RESOURCE"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    OnReadyCard($player, $lastDecision);
};

// Universal handler: exhaust the unit at the mzID passed via $lastDecision.
// Callers queue PASSPARAMETER($mzID) or MZCHOOSE + CUSTOM EXHAUST_UNIT.
$customDQHandlers["EXHAUST_UNIT"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    OnExhaustCard($player, $lastDecision);
};

// Universal handler: ready the unit at the mzID passed via $lastDecision.
// Callers queue PASSPARAMETER($mzID) or MZCHOOSE + CUSTOM READY_UNIT.
$customDQHandlers["READY_UNIT"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    OnReadyCard($player, $lastDecision);
};

// ── Scry infrastructure ───────────────────────────────────────────────────────
// DoScry($player, $n): peek top $n cards, let player place each to top or bottom.
// Queues a single SCRY decision (frontend panel) followed by SCRY_FINALIZE.
// Result format: "topID1,topID2|bottomID1,bottomID2" (topmost-first | order-added).
$gScryState = null; // ['peeked'=>[DeckObj,...], 'top'=>[...], 'bottom'=>[...], 'player'=>int]

function DoScry($player, $n) {
    global $gScryState;
    $deck = &GetDeck($player);
    $n = min($n, count($deck));
    if ($n === 0) return;
    $peeked = array_splice($deck, 0, $n);
    foreach ($deck as $i => $card) { $card->mzIndex = $i; }
    $gScryState = ['peeked' => $peeked, 'top' => [], 'bottom' => [], 'player' => intval($player)];
    $cardIDs = implode(',', array_map(fn($c) => $c->CardID, $peeked));
    DecisionQueueController::AddDecision($player, "SCRY", $cardIDs, 1, tooltip:"Look_at_top_cards");
    DecisionQueueController::AddDecision($player, "CUSTOM", "SCRY_FINALIZE", 1);
    MarkUndoRequiresConsent();
}

function _ScryPutBack($player) {
    global $gScryState;
    $deck = &GetDeck($player);
    foreach (array_reverse($gScryState['top']) as $cardObj) { array_unshift($deck, $cardObj); }
    foreach ($gScryState['bottom'] as $cardObj)              { array_push($deck, $cardObj); }
    foreach ($deck as $i => $cardObj) { $cardObj->mzIndex = $i; }
    $gScryState = null;
}

$customDQHandlers["SCRY_FINALIZE"] = function($player, $parts, $lastDecision) {
    global $gScryState;
    $sections = explode('|', $lastDecision);
    $topStr    = $sections[0] ?? '';
    $bottomStr = $sections[1] ?? '';
    $topIDs    = $topStr    !== '' ? explode(',', $topStr)    : [];
    $bottomIDs = $bottomStr !== '' ? explode(',', $bottomStr) : [];
    $byID = [];
    foreach ($gScryState['peeked'] as $card) { $byID[$card->CardID] = $card; }
    $gScryState['top']    = array_values(array_filter(array_map(fn($id) => $byID[$id] ?? null, $topIDs)));
    $gScryState['bottom'] = array_values(array_filter(array_map(fn($id) => $byID[$id] ?? null, $bottomIDs)));
    _ScryPutBack($player);
};

// ── Reveal-top-N → discard-any + reorder-rest ─────────────────────────────────
// Generic finalize for "reveal the top N cards … you may discard any of the revealed cards and
// put the rest back on top in any order" (SOR_152 For a Cause I Believe In). The revealed cards
// are still the FRONT N of the deck (no global state held across the request boundary — the
// caller only reveals/peeks; this handler does the actual deck mutation when the player answers).
// $parts[0] = N (count revealed). $lastDecision = "keptID1,keptID2|discardID1,discardID2":
//   kept go back on top in the listed order (first = top); discarded go to discard (From DECK).
$customDQHandlers["REVEALARRANGE_FINALIZE"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $playerID = intval($player);
    $n = max(0, intval($parts[0] ?? 0));
    if ($n === 0) return;
    $deck = &GetDeck($player);
    $revealed = array_splice($deck, 0, $n);          // pull the revealed cards off the top
    foreach ($deck as $i => $c) { $c->mzIndex = $i; }

    $byID = [];
    foreach ($revealed as $c) { $byID[$c->CardID][] = $c; }  // lists handle duplicate CardIDs

    $sections   = explode('|', (string)$lastDecision);
    $keptIDs    = ($sections[0] ?? '') !== '' ? explode(',', $sections[0]) : [];
    $discardIDs = ($sections[1] ?? '') !== '' ? explode(',', $sections[1]) : [];

    foreach ($discardIDs as $id) {
        if (!empty($byID[$id])) { $c = array_shift($byID[$id]); SWUAddToDiscard($player, $c->CardID, 'DECK'); }
    }
    // Put kept back on top in the listed order (first listed ends up on top).
    foreach (array_reverse($keptIDs) as $id) {
        if (!empty($byID[$id])) { $c = array_shift($byID[$id]); array_unshift($deck, $c); }
    }
    // Safety: any revealed card the answer didn't account for goes back on top.
    foreach ($byID as $list) { foreach ($list as $c) { array_unshift($deck, $c); } }
    foreach ($deck as $i => $c) { $c->mzIndex = $i; }
};

// ── Look-at-top-of-deck helpers ───────────────────────────────────────────────
// "Top of deck" for the look-at-top family (R2-D2, Inferno Four, Reinforcement Walker,
// Ezra Bridger) is the FRONT of the deck array (index 0) — the same end DoScry peeks and
// the test harness' topCardID reads. These operate on that front card.

// First non-removed deck index (the top), or -1 if the deck is empty.
function _SWUTopDeckFrontIdx(int $player): int {
    $deck = GetDeck($player);
    for ($i = 0; $i < count($deck); $i++) {
        if (empty($deck[$i]->removed)) return $i;
    }
    return -1;
}

// Draw the top (front) card to $player's hand. Returns its CardID, or null if deck empty.
function SWUDrawTopCardFront(int $player): ?string {
    global $playerID;
    $saved = $playerID; $playerID = intval($player);
    $idx = _SWUTopDeckFrontIdx($player);
    if ($idx === -1) { $playerID = $saved; return null; }
    $obj = MZMove($player, "myDeck-$idx", "myHand");
    $playerID = $saved;
    return $obj ? $obj->CardID : null;
}

// Play the top (front) card of $player's deck, paying its cost minus $discount (floored at 0), or
// free when $ignoreCost. Used by effects that let you "play the top card" as part of ANOTHER action
// (SOR_192 Ezra's On Attack End, SOR_246 You're My Only Hope's event) — it does NOT advance the
// turn: the parent action (combat / the event's FINISH_PLAY_CARD) owns SWUAfterAction, so the inner
// ActivateCard's own turn advance is neutralised by capturing/restoring the turn state around it.
// Returns true if a card was played (false on empty deck). Unaffordable → ActivateCard no-ops.
function SWUPlayTopDeckCard(int $player, bool $ignoreCost = false, int $discount = 0): bool {
    $idx = _SWUTopDeckFrontIdx($player);
    if ($idx === -1) return false;
    global $gTurnPlayer;
    $savedTP   = $gTurnPlayer;
    $savedPass = GetSWUVar('PASS', '0');
    ActivateCard($player, "myDeck-$idx", $ignoreCost, $discount);
    $gTurnPlayer = $savedTP;
    SetSWUVar('PASS', $savedPass);
    return true;
}

// Mill (discard) the top (front) card to $player's discard with From='DECK'.
// Returns its CardID, or null if deck empty.
function SWUMillTopCard(int $player): ?string {
    global $playerID;
    $saved = $playerID; $playerID = intval($player);
    $deck = &GetDeck($player);
    $idx  = _SWUTopDeckFrontIdx($player);
    if ($idx === -1) { $playerID = $saved; return null; }
    $cardID = $deck[$idx]->CardID;
    SWUAddToDiscard($player, $cardID, 'DECK');
    $deck[$idx]->removed = true;
    DecisionQueueController::CleanupRemovedCards();
    AddGlobalEffects(intval($player), 'SWU_DISCARDED_PHASE');   // "discarded from your deck this phase" (LAW_076)
    // LAW_176 Sebulba's Podracer — "When you discard a card from your deck: you may ready this unit"
    // (once each round). Collect the reactive may-ready trigger for the milling player; it flushes at
    // the enclosing action's completion (combat / play-card). Gated to an EXHAUSTED Podracer so the
    // offer only appears when it's meaningful, and to once-per-round via SWU_LAW176_USED.
    if (GlobalEffectCount(intval($player), 'SWU_LAW176_USED') <= 0) {
        foreach (GetUnitsInPlay(intval($player)) as $pu) {
            if (empty($pu->removed) && ($pu->CardID ?? '') === 'LAW_176' && intval($pu->Status ?? 1) === 0) {
                AddTrigger(intval($player), 'LAW_176', 'LAW_176', $pu->GetMzID());
                break;
            }
        }
    }
    $playerID = $saved;
    return $cardID;
}

// ── Top-deck search infrastructure ───────────────────────────────────────────
// DoTopDeckSearch($player, $n, $filter, $maxPicks):
//   Peek top $n cards, player picks up to $maxPicks matching cards to draw.
//   Constraint encoded as "count:N" in the TOPDECKSEARCH decision param.
//
// DoTopDeckPlay($player, $n, $filter, $costBudget):
//   Peek top $n cards, player picks any number of matching units whose combined
//   cost ≤ $costBudget, each is played for free (no WhenPlayed triggers).
//   Constraint encoded as "cost:N" in the TOPDECKSEARCH decision param.
//
// The peeked card IDs are embedded in the CUSTOM finalize handler param so they
// survive PHP's stateless HTTP request boundary. Format: HANDLER|ID1,ID2,...
// Decision param format: "allIDs|matchingIDs|constraint|costMap"
// Finalize answer format: comma-separated chosen CardIDs (empty = choose none).

// True if $player controls a unit with CardID $cardID in play (any arena, incl. deployed leaders).
function _SWUControlsCardInPlay(int $player, string $cardID): bool {
    foreach (GetUnitsInPlay($player) as $u) {
        if (empty($u->removed) && ($u->CardID ?? '') === $cardID) return true;
    }
    return false;
}

// True if $player controls a unit carrying the upgrade $upgradeCardID.
function _SWUControlsUnitWithUpgrade(int $player, string $upgradeCardID): bool {
    foreach (GetUnitsInPlay($player) as $u) {
        if (!empty($u->removed)) continue;
        foreach (GetUpgradesOnUnit($u) as $up) {
            $ucid = is_array($up) ? ($up['CardID'] ?? '') : ($up->CardID ?? '');
            if ($ucid === $upgradeCardID) return true;
        }
    }
    return false;
}

function _topDeckSearchBegin(int $player, int $n, callable $filter, string $constraint, string $finalizeHandler): void {
    // ASH_084 Arcana Star Map — "If you would search a number of cards from your deck, search twice that
    // number of cards instead." Applies to every deck-search/play-from-deck routed through this funnel.
    if ($n > 0 && _SWUControlsUnitWithUpgrade($player, 'ASH_084')) $n *= 2;
    $deck = &GetDeck($player);
    $n = min($n, count($deck));
    if ($n === 0) return;
    $peeked = array_splice($deck, 0, $n);
    foreach ($deck as $i => $card) { $card->mzIndex = $i; }

    $allIDs   = implode(',', array_map(fn($c) => $c->CardID, $peeked));
    $matchIDs = implode(',', array_map(
        fn($c) => $c->CardID,
        array_filter($peeked, fn($c) => $filter($c->CardID))
    ));
    // cost map for all peeked cards: "CardID:cost,..." so frontend can enforce budget.
    $costMap  = implode(',', array_map(fn($c) => $c->CardID . ':' . intval(CardCost($c->CardID)), $peeked));

    $param = $allIDs . '|' . $matchIDs . '|' . $constraint . '|' . $costMap;
    DecisionQueueController::AddDecision($player, "TOPDECKSEARCH", $param, 1, tooltip: "Search_top_cards");
    // Embed allIDs in the finalize param — survives the HTTP request boundary.
    DecisionQueueController::AddDecision($player, "CUSTOM", $finalizeHandler . '|' . $allIDs, 1);
    MarkUndoRequiresConsent();
}

function DoTopDeckSearch(int $player, int $n, callable $filter, int $maxPicks): void {
    _topDeckSearchBegin($player, $n, $filter, "count:$maxPicks", "TOPDECKSEARCH_FINALIZE");
}

function DoTopDeckPlay(int $player, int $n, callable $filter, int $costBudget, int $maxCount = 0): void {
    // Constraint "cost:N" (any number within budget) or "cost:N:M" (≤M picks AND within budget,
    // e.g. SOR_104 U-Wing Reinforcement: up to 3 units, combined cost ≤7). Frontend-enforced.
    $constraint = $maxCount > 0 ? "cost:$costBudget:$maxCount" : "cost:$costBudget";
    _topDeckSearchBegin($player, $n, $filter, $constraint, "SOR_087#0");
}

// Resolve chosen CardIDs from $lastDecision against the flat list of all peeked IDs.
// Index-based dedup handles duplicate IDs (e.g. three copies of the same card).
// Returns ['drawn' => [cardID,...], 'remaining' => [cardID,...]].
function _topDeckResolveFromIDs(array $allIDs, string $lastDecision): array {
    $chosenIDs   = ($lastDecision !== '' && $lastDecision !== 'PASS')
        ? array_values(array_filter(explode(',', $lastDecision))) : [];
    $usedIndices = [];
    $drawnIDs    = [];
    foreach ($chosenIDs as $cid) {
        foreach ($allIDs as $idx => $aid) {
            if (!in_array($idx, $usedIndices, true) && $aid === $cid) {
                $drawnIDs[]    = $cid;
                $usedIndices[] = $idx;
                break;
            }
        }
    }
    $remainingIDs = [];
    foreach ($allIDs as $idx => $aid) {
        if (!in_array($idx, $usedIndices, true)) $remainingIDs[] = $aid;
    }
    return ['drawn' => $drawnIDs, 'remaining' => $remainingIDs];
}

// Shuffle remaining card IDs and push new Deck objects to the bottom of the deck.
function _topDeckPutRemainingToBottom(int $player, array $remainingIDs): void {
    shuffle($remainingIDs);
    $deck = &GetDeck($player);
    foreach ($remainingIDs as $cardID) {
        $obj          = new Deck($cardID, 'Deck', $player);
        $obj->mzIndex = count($deck);
        array_push($deck, $obj);
    }
    foreach ($deck as $i => $card) { $card->mzIndex = $i; }
}

// TOPDECKSEARCH_FINALIZE: draw chosen cards to hand; shuffle rest to bottom of deck.
$customDQHandlers["TOPDECKSEARCH_FINALIZE"] = function($player, $parts, $lastDecision) {
    $allIDs  = array_values(array_filter(explode(',', $parts[0] ?? '')));
    $resolved = _topDeckResolveFromIDs($allIDs, $lastDecision ?? '');
    foreach ($resolved['drawn'] as $cardID) {
        AddHand(intval($player), CardID: $cardID);
    }
    _topDeckPutRemainingToBottom(intval($player), $resolved['remaining']);
};

// LOF_103 Following the Path: chosen Force units go on TOP of the deck (chosen order; first chosen ends
// up on top); the non-chosen peeked cards go to the bottom in random order.
$customDQHandlers["LOF_103#0"] = function($player, $parts, $lastDecision) {
    $allIDs   = array_values(array_filter(explode(',', $parts[0] ?? '')));
    $resolved = _topDeckResolveFromIDs($allIDs, $lastDecision ?? '');
    _topDeckPutRemainingToBottom(intval($player), $resolved['remaining']);
    $deck = &GetDeck(intval($player));
    $chosen = $resolved['drawn'];
    for ($i = count($chosen) - 1; $i >= 0; $i--) {
        $obj = new Deck($chosen[$i], 'Deck', intval($player));
        array_unshift($deck, $obj);
    }
    foreach ($deck as $i => $card) { $card->mzIndex = $i; }
};

// SOR_087: play chosen Villainy units for free (no WhenPlayed triggers);
// shuffle rest to bottom of deck.
$customDQHandlers["SOR_087#0"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $allIDs   = array_values(array_filter(explode(',', $parts[0] ?? '')));
    $resolved = _topDeckResolveFromIDs($allIDs, $lastDecision ?? '');
    // SOR_062 Regional Governor: a card named by an opponent can't be played — even by a play-from-
    // deck effect. Blocked picks are not placed; they join the remaining cards put on the bottom.
    $blockedBack = [];
    foreach ($resolved['drawn'] as $cardID) {
        if (SWUCardPlayBlocked(intval($player), $cardID)) { $blockedBack[] = $cardID; continue; }
        $uid = NextUniqueID();
        if (CardArena($cardID) === 'Space') {
            AddSpaceArena($player, CardID: $cardID, Status: 0, Owner: $player, Controller: $player, UniqueID: $uid);
        } else {
            AddGroundArena($player, CardID: $cardID, Status: 0, Owner: $player, Controller: $player, UniqueID: $uid);
        }
        AddGlobalEffects(intval($player), 'SWU_CARDS_PLAYED');  // each unit played-from-deck counts
    }
    _topDeckPutRemainingToBottom(intval($player), array_merge($resolved['remaining'], $blockedBack));
    $playerID = $savedPID;
};

// SOR_199 Bamboozle: handles the alternate-cost YESNO answer.
// YES → discard the first Cunning card found in player's hand (Bamboozle is already in discard).
// NO  → exhaust resources equal to the normal cost encoded in $parts[0].
$customDQHandlers["SOR_199#0"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === "YES" || $lastDecision === "1") {
        global $playerID;
        $playerID = intval($player);
        $hand = GetHand($player);
        for ($i = 0; $i < count($hand); $i++) {
            if (!empty($hand[$i]->removed)) continue;
            if (strpos(CardAspect($hand[$i]->CardID) ?? '', 'Cunning') !== false) {
                $hand[$i]->removed = true;
                SWUAddToDiscard($player, $hand[$i]->CardID, 'HAND');
                DecisionQueueController::CleanupRemovedCards();
                return;
            }
        }
    } else {
        SWUExhaustResources($player, intval($parts[0] ?? 0));
    }
};

// SOR_199 Bamboozle: exhausts the chosen unit and bounces all upgrades to their owners' hands.
// Token upgrades are set aside (SWUDefeatUpgrade bounce:true handles this).
$customDQHandlers["SOR_199#1"] = function($player, $parts, $lastDecision) {
    if ($lastDecision === null || $lastDecision === '-' || $lastDecision === '' || $lastDecision === 'PASS') return;
    global $playerID;
    $playerID = intval($player);
    $obj = GetZoneObject($lastDecision);
    if ($obj === null || ($obj->removed ?? false)) return;
    $obj->Status = 0;
    while (SWUDefeatUpgrade($player, $lastDecision, 0, bounce: true)) {}
    DecisionQueueController::CleanupRemovedCards();
};

// Returns an array of valid arena mzIDs that the given upgrade can target.
// Defaults to all friendly units (ground + space). Card-specific restrictions
// are handled in the switch statement below.
//
// $upgradeObj (optional): when provided, the returned list is further filtered to
// only hosts the player can actually afford at the host-specific cost — i.e.,
// SWUComputePlayCost($player, $upgradeObj, $candidateObj) ≤ ready resources.
// This closes the "attach to non-Guardian even though you can only afford Guardian" edge.
function SWUGetUpgradeValidTargets(int $player, string $cardID, $upgradeObj = null): array {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $all = array_merge(
        ZoneSearch("myGroundArena", AnyUnitFilter),
        ZoneSearch("mySpaceArena",  AnyUnitFilter)
    );
    $playerID = $savedPID;
    switch ($cardID) {
        // "Attach to a non-Vehicle unit."
        case 'SOR_054': // Jedi Lightsaber
        case 'LOF_215': // Ascension Cable
        case 'SOR_137': // Fallen Lightsaber
        case 'SOR_136': // Vader's Lightsaber
        case 'SOR_071': // Electrostaff
        case 'LOF_040': // Kylo Ren's Lightsaber
        case 'LOF_053': // Heirloom Lightsaber
        case 'LOF_102': // Yoda's Lightsaber
        case 'LOF_122': // Pillio Star Compass
        case 'LOF_171': // Heavy Blaster Cannon
        case 'LOF_187': // Corrupted Saber
        case 'LOF_140': // Maul's Lightsaber
        case 'LOF_201': // Qui-Gon Jinn's Lightsaber
        case 'LOF_238': // Darth Revan's Lightsabers
        case 'SEC_156': // Nemik's Manifesto
        case 'LAW_200': // Salvaged Blaster
        case 'ASH_180': // Bokken Saber
        case 'ASH_066': // Luke's Jedi Lightsaber
        case 'ASH_114': // Sabine's Lightsaber
        case 'ASH_183': // Whistling Birds
        case 'ASH_210': // DDC Defender
            $all = array_values(array_filter($all, fn($mz) =>
                !HasTrait(GetZoneObject($mz)->CardID ?? '', 'Vehicle')));
            break;
        // "Attach to a damaged unit." (Mark My Words gives Overwhelm — a friendly damaged unit.)
        case 'ASH_181':
            $all = array_values(array_filter($all, fn($mz) => intval(GetZoneObject($mz)->Damage ?? 0) > 0));
            break;
        // "Attach to a Vehicle unit."
        case 'SEC_227': // Special Modifications
            $all = array_values(array_filter($all, fn($mz) =>
                HasTrait(GetZoneObject($mz)->CardID ?? '', 'Vehicle')));
            break;
        // "Attach to a friendly unique unit."
        case 'SEC_256': // Moral Authority
            $all = array_values(array_filter($all, fn($mz) =>
                CardUnique(GetZoneObject($mz)->CardID ?? '')));
            break;
        // "Attach to a Jedi non-Vehicle unit."
        case 'LOF_151': // Knight's Saber
            $all = array_values(array_filter($all, function($mz) {
                $cid = GetZoneObject($mz)->CardID ?? '';
                return HasTrait($cid, 'Jedi') && !HasTrait($cid, 'Vehicle');
            }));
            break;
        // "Attach to a Force unit."
        case 'LOF_051': // Jedi Holocron
        case 'LOF_052': // Jedi Trials
        case 'LOF_074': // Bolstered Endurance
        case 'LOF_138': // Sith Holocron
        case 'LOF_261': // Constructed Lightsaber
            $all = array_values(array_filter($all, fn($mz) =>
                _SWUUnitHasTrait(GetZoneObject($mz), 'Force')));
            break;
        // "Attach to a Vehicle unit."
        case 'JTL_120': // Dorsal Turret
        case 'JTL_172': // Twin Laser Turret
        case 'SOR_121': // Hardpoint Heavy Blaster
            $all = array_values(array_filter($all, fn($mz) =>
                HasTrait(GetZoneObject($mz)->CardID ?? '', 'Vehicle')));
            break;
        // "Attach to a Capital Ship or Transport unit." (JTL_227 Superheavy Ion Cannon)
        case 'JTL_227':
            $all = array_values(array_filter($all, function($mz) {
                $cid = GetZoneObject($mz)->CardID ?? '';
                return HasTrait($cid, 'Capital Ship') || HasTrait($cid, 'Transport');
            }));
            break;
        // SOR_122 Traitorous / SHD_072 (loses abilities) / SEC_038 Condemn — attach to any unit, any
        // arena (Condemn has no attach restriction: playable on a friendly OR an enemy unit).
        case 'SOR_122':
        case 'SHD_072':
        case 'SEC_038':
        case 'ASH_054': // Pointless to Resist — debuff Condition, attach to any unit (typically an enemy)
        case 'ASH_085': // Grav Charge — Condition, attach to any unit (typically an enemy)
        case 'ASH_198': // Nowhere to Hide — Condition (grants Sentinel), attach to any unit
        case 'ASH_150': // Deadly Vulnerability — Condition (double damage), attach to any unit
            $playerID = $player;
            $all = array_values(array_merge(
                ZoneSearch("myGroundArena",    AnyUnitFilter),
                ZoneSearch("mySpaceArena",     AnyUnitFilter),
                ZoneSearch("theirGroundArena", AnyUnitFilter),
                ZoneSearch("theirSpaceArena",  AnyUnitFilter)
            ));
            $playerID = $savedPID;
            break;
    }

    // Affordability filter: when the upgrade object is provided, only keep hosts whose
    // host-specific cost is ≤ the player's current ready-resource count.
    if ($upgradeObj !== null) {
        $ready = 0;
        foreach (GetResources($player) as $r) {
            if (SWUIsCreditToken($r->CardID ?? '')) continue; // Credit tokens aren't resources
            if (empty($r->removed) && intval($r->Status) === 1) $ready++;
        }
        $all = array_values(array_filter($all, function($mz) use ($player, $upgradeObj, $ready) {
            $candidateObj = GetZoneObject($mz);
            if ($candidateObj === null || !empty($candidateObj->removed)) return false;
            $hostCost = SWUComputePlayCost($player, $upgradeObj, $candidateObj);
            return $ready >= $hostCost;
        }));
    }

    return $all;
}

// Number of Pilot upgrades currently on a host (Subcards flagged IsPilot).
function SWUVehiclePilotCount($host): int {
    if ($host === null || !is_array($host->Subcards ?? null)) return 0;
    $n = 0;
    foreach ($host->Subcards as $sub) {
        $isPilot = is_array($sub) ? ($sub['IsPilot'] ?? false) : ($sub->IsPilot ?? false);
        if ($isPilot) $n++;
    }
    return $n;
}

// Max pilots a host may carry: 1 by default, +1 per "additional Pilot" grant
// (the host's own innate, e.g. Millennium Falcon, plus any attached pilot that
// grants it, e.g. R2-D2). CR 8.346.c — these grants override the base restriction.
function SWUVehiclePilotCapacity($host): int {
    if ($host === null) return 0;
    $cap = 1;
    if (CardPilotAddsCapacity($host->CardID ?? '')) $cap++;
    foreach (GetUpgradesOnUnit($host) as $u) {
        if (CardPilotAddsCapacity($u->CardID ?? '')) $cap++;
    }
    return $cap;
}

// Whether $pilotCardID may attach as a Pilot to $host right now.
// Default: host is a friendly Vehicle AND current pilots < capacity.
// Per-card overrides mirror SWUGetUpgradeValidTargets.
//
// $context controls which rule set applies:
//   'piloting'   (default) — normal Piloting hand-play / leader-deploy path;
//                uses the generic count < capacity rule for all pilots including JTL_100.
//   'freeattach' — JTL_100's own "when played as a unit" free-attach ability
//                (Task 10); applies the strict "0 pilots on host" rule.
//
// R2-D2's CardPilotIgnoresOccupied override applies in BOTH contexts.
function SWUPilotCanAttach(string $pilotCardID, $host, string $context = 'piloting'): bool {
    if ($host === null || !empty($host->removed)) return false;
    $hostID = $host->CardID ?? '';
    if (!HasTrait($hostID, 'Vehicle')) return false;

    // R2-D2 (JTL_245): may attach to a Vehicle WITH a Pilot already on it.
    // This override applies regardless of context.
    if (CardPilotIgnoresOccupied($pilotCardID)) return true;

    // Poe Dameron unit (JTL_100) free-attach clause: strict "without a Pilot"
    // (capacity grants do NOT loosen this specific ability — CR card text).
    // Only applies in the 'freeattach' context (Task 10).
    // In 'piloting' context JTL_100 uses the generic capacity rule below.
    if ($pilotCardID === 'JTL_100' && $context === 'freeattach') {
        return SWUVehiclePilotCount($host) === 0;
    }

    return SWUVehiclePilotCount($host) < SWUVehiclePilotCapacity($host);
}

// Friendly Vehicles a pilot may attach to right now, affordability-filtered
// against the piloting cost. Mirrors the affordability filter in
// SWUGetUpgradeValidTargets.
function SWUGetPilotValidTargets(int $player, string $pilotCardID): array {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $all = array_merge(
        ZoneSearch("myGroundArena", AnyUnitFilter),
        ZoneSearch("mySpaceArena",  AnyUnitFilter)
    );
    $playerID = $savedPID;

    $pilotObj = (object)['CardID' => $pilotCardID];
    $cost = SWUComputePilotCost($player, $pilotObj);
    $ready = 0;
    foreach (GetResources($player) as $r) {
        if (SWUIsCreditToken($r->CardID ?? '')) continue; // Credit tokens aren't resources
        if (empty($r->removed) && intval($r->Status) === 1) $ready++;
    }
    if ($ready < $cost) return [];

    return array_values(array_filter($all, function($mz) use ($pilotCardID) {
        $hostObj = GetZoneObject($mz);
        return SWUPilotCanAttach($pilotCardID, $hostObj);
    }));
}

// Friendly Vehicles a leader may deploy onto as a Pilot (capacity-only; deploy is free).
// No affordability check — the deploy threshold is the only gate. Mirrors the
// $playerID save/restore idiom used throughout this file.
function SWUGetLeaderPilotVehicles(int $player): array {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $all = array_merge(
        ZoneSearch("myGroundArena", AnyUnitFilter),
        ZoneSearch("mySpaceArena",  AnyUnitFilter)
    );
    $playerID = $savedPID;
    return array_values(array_filter($all, function($mz) {
        $hostObj = GetZoneObject($mz);
        if ($hostObj === null || !empty($hostObj->removed)) return false;
        if (!HasTrait($hostObj->CardID ?? '', 'Vehicle')) return false;
        return SWUVehiclePilotCount($hostObj) < SWUVehiclePilotCapacity($hostObj);
    }));
}

// JTL_013 Poe Dameron leader Action: returns mzIDs of friendly Vehicles with exactly 0 pilots.
// Used both as the affordability guard and as the attach target list.
// "Without a Pilot on it" = strict 0-pilot check (SWUVehiclePilotCount === 0), not the
// capacity-based check used by normal Piloting; Poe's action text requires no pilot at all.
function SWUGetPoe013AttachVehicles(int $player): array {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $all = array_merge(
        ZoneSearch("myGroundArena", AnyUnitFilter),
        ZoneSearch("mySpaceArena",  AnyUnitFilter)
    );
    $playerID = $savedPID;
    return array_values(array_filter($all, function($mz) {
        $hostObj = GetZoneObject($mz);
        if ($hostObj === null || !empty($hostObj->removed)) return false;
        if (!HasTrait($hostObj->CardID ?? '', 'Vehicle')) return false;
        return SWUVehiclePilotCount($hostObj) === 0;
    }));
}

// Returns true when $cardID's alternate cost path is available for $player right now.
// For SOR_199: hand must have ≥2 Cunning cards — Bamboozle itself is Cunning, so
// ≥2 means there is at least one other Cunning card available to discard.
function SWUCheckAlternateCost(int $player, string $cardID): bool {
    switch ($cardID) {
        case 'SOR_199': {
            $count = 0;
            foreach (GetHand($player) as $h) {
                if (!empty($h->removed)) continue;
                if (strpos(CardAspect($h->CardID) ?? '', 'Cunning') !== false) $count++;
            }
            return $count >= 2;
        }
        default:
            return false;
    }
}

// Returns mzIDs of all arena units (both players, both arenas) that have at
// least one non-captive upgrade. Caller must have $playerID set correctly.
// A host counts only if it carries >=1 upgrade matching $filter (empty filter =
// every upgrade matches, so this is backward-compatible for all existing callers).
function SWUGetUnitsWithUpgrades(string $filter = ''): array {
    $result = [];
    foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $zone) {
        foreach (ZoneSearch($zone, ['Unit', 'Leader Unit', 'Token Unit']) as $mzID) {
            $obj = GetZoneObject($mzID);
            if ($obj === null || ($obj->removed ?? false)) continue;
            foreach (GetUpgradesOnUnit($obj) as $up) {
                if (SWUUpgradeMatchesFilter($up->CardID ?? '', $filter)) {
                    $result[] = $mzID;
                    break;
                }
            }
        }
    }
    return $result;
}

// Predicate over a candidate upgrade's CardID. $filter is a comma-separated list of
// AND-ed clauses "field op value"; fields unique/leader/cost, ops = != < <= > >=.
// Empty filter => always true. Used by SWUGetUnitsWithUpgrades + the defeat-upgrade
// host resolver (future Piloting cards LOF_155 unique=1, JTL_175 leader!=1, …).
function SWUUpgradeMatchesFilter(string $cardID, string $filter): bool {
    if ($filter === '') return true;
    foreach (explode(',', $filter) as $clause) {
        $clause = trim($clause);
        if ($clause === '') continue;
        if (!preg_match('/^(\w+)\s*(<=|>=|!=|=|<|>)\s*(.+)$/', $clause, $m)) continue;
        $field = $m[1];
        $op    = $m[2];
        $target = intval(trim($m[3]));
        switch ($field) {
            case 'unique': $actual = CardUnique($cardID) ? 1 : 0; break;
            case 'leader': $actual = (strpos(CardType($cardID) ?? '', 'Leader') !== false) ? 1 : 0; break;
            case 'cost':   $actual = intval(CardCost($cardID)); break;
            default: continue 2; // unknown field → ignore the clause
        }
        $ok = match ($op) {
            '='  => $actual === $target,
            '!=' => $actual !== $target,
            '<'  => $actual <  $target,
            '<=' => $actual <= $target,
            '>'  => $actual >  $target,
            '>=' => $actual >= $target,
            default => true,
        };
        if (!$ok) return false;
    }
    return true;
}

// Generic "defeat an upgrade" entry point shared by SOR_162/SHD_166 (may, single),
// SOR_251/SHD_262 (mandatory, single), SOR_170 (any number, min 0). Stages the chosen
// host's matching upgrades into TempZone and lets the player pick which to defeat.
//   $may    — host selection is pick-or-pass (MZMAYCHOOSE) vs mandatory.
//   $max    — max upgrades to defeat (1 = single pick; >1 = MZMULTICHOOSE).
//   $filter — SWUUpgradeMatchesFilter predicate string (default '' = any upgrade).
//   $min    — min upgrades to defeat (0 = optional / soft-pass).
// Leaves $playerID set so MZCountChoices resolves the relative arena names.
// $thenHandler — optional CUSTOM handler name fired AFTER this defeat fully resolves (a successful
// pick, not a decline). Used to chain "defeat up to N upgrades, possibly on DIFFERENT units" as N
// sequential "may defeat 1" flows (SOR_155): each flow re-reads the board, so the picks can span units.
function SWUQueueDefeatUpgrade(int $player, string $tooltip, bool $may = false,
                              int $max = 1, string $filter = '', int $min = 1, string $thenHandler = '',
                              int $onlyHostUID = 0): void {
    global $playerID;
    $playerID = intval($player);
    $targets = SWUGetUnitsWithUpgrades($filter);
    // Scope to a single host (e.g. "defeat an upgrade on IT" — JTL_133 Pryde on the indirect-damaged unit).
    if ($onlyHostUID > 0) {
        $targets = array_values(array_filter($targets, function($mz) use ($onlyHostUID) {
            $o = GetZoneObject($mz);
            return $o !== null && intval($o->UniqueID ?? 0) === $onlyHostUID;
        }));
    }
    if (empty($targets)) {
        // No legal host → fizzle. Still honour the continuation so a chain doesn't dead-end early
        // (e.g. all upgrades already defeated by an earlier link).
        if ($thenHandler !== '') {
            global $customDQHandlers;
            DecisionQueueController::StoreVariable("DefeatUpgThen", "");
            if (isset($customDQHandlers[$thenHandler])) $customDQHandlers[$thenHandler]($player, [], '');
        }
        return;
    }
    DecisionQueueController::StoreVariable("DefeatUpgParams", $min . '|' . $max . '|' . $filter);
    DecisionQueueController::StoreVariable("DefeatUpgThen", $thenHandler);
    if ($may) {
        DecisionQueueController::AddDecision($player, "MZMAYCHOOSE", implode("&", $targets), 1, tooltip: $tooltip);
    } else if (count($targets) === 1) {
        DecisionQueueController::AddDecision($player, "PASSPARAMETER", $targets[0], 1);
    } else {
        DecisionQueueController::AddDecision($player, "MZCHOOSE", implode("&", $targets), 1, tooltip: $tooltip);
    }
    DecisionQueueController::AddDecision($player, "CUSTOM", "DEFEAT_UPGRADE", 1);
}

// Returns a non-leader unit to its owner's hand (bounce mechanic).
// Defeats all upgrades on the unit first per CR 9.3:
//   tokens are set aside (no discard entry); non-tokens go to owner's discard.
// The unit itself is removed from the arena; a fresh copy (no damage/counters)
// is added to the owner's hand.
function SWUBounceUnit(int $player, string $mzID): bool {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);

    $obj = &GetZoneObject($mzID);
    if ($obj === null || ($obj->removed ?? false)) {
        $playerID = $savedPID;
        return false;
    }
    // "Can't be returned to hand by enemy card abilities" (JTL_103 / TWI_220 / LOF_073). Bounce is
    // always ability-driven; only block when an opponent is doing it.
    if (intval($player) !== intval($obj->Controller ?? $player) && SWUAvoidsBounce($obj)) {
        $playerID = $savedPID;
        return false;
    }
    if (IsLeaderUnit($obj)) {
        $playerID = $savedPID;
        return false;
    }

    $cardID = $obj->CardID;
    $owner  = intval($obj->Owner);

    // Defeat all attached upgrades (CR 9.3)
    if (!empty($obj->Subcards) && is_array($obj->Subcards)) {
        foreach ($obj->Subcards as $sub) {
            $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
            $isRemoved = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
            if ($isCaptive || $isRemoved) continue;
            $subCardID  = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
            $subOwner   = is_array($sub) ? intval($sub['Owner'] ?? $owner) : intval($sub->Owner ?? $owner);
            if ($subCardID === '') continue;
            if (strpos(strtolower(CardType($subCardID) ?? ''), 'token') === false) {
                SWUAddToDiscard($subOwner, $subCardID, 'PLAY');
            }
        }
    }

    $controller = intval($obj->Controller ?? $owner);
    // CR 8.34.4: rescue any captives guarded by this unit before it leaves play (bounce).
    SWURescueCaptivesOf($obj);
    $obj->removed = true;
    // Token units are set aside (out of the game) when they leave play — never return to hand.
    if (strpos(strtolower(CardType($cardID) ?? ''), 'token') === false) {
        AddHand($owner, CardID:$cardID);
    }

    // "Leaves play" reactions (not a defeat): Boba Fett's leader trigger + the phase flag.
    SWUCollectLeavePlayReactions([['player' => $controller, 'cardID' => $cardID]], false);
    FlushTriggerBag($controller);

    DecisionQueueController::CleanupRemovedCards();
    $playerID = $savedPID;
    return true;
}

// Move a non-leader unit from the arena to the BOTTOM of its OWNER's deck (SOR_187 "put the other on
// the bottom of its owner's deck"). Mirrors SWUBounceUnit (defeat non-token upgrades, rescue captives,
// fire leave-play reactions) but the body goes to deck-bottom instead of hand. Token units are set
// aside (never enter a deck), same as bounce.
function SWUUnitToBottomOfDeck(int $player, string $mzID, bool $toTop = false): bool {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);

    $obj = &GetZoneObject($mzID);
    if ($obj === null || ($obj->removed ?? false) || IsLeaderUnit($obj)) {
        $playerID = $savedPID;
        return false;
    }
    $cardID = $obj->CardID;
    $owner  = intval($obj->Owner);

    // Defeat all attached non-token upgrades (CR 9.3)
    if (!empty($obj->Subcards) && is_array($obj->Subcards)) {
        foreach ($obj->Subcards as $sub) {
            $isCaptive = is_array($sub) ? !empty($sub['IsCaptive']) : !empty($sub->IsCaptive);
            $isRemoved = is_array($sub) ? !empty($sub['removed'])   : !empty($sub->removed);
            if ($isCaptive || $isRemoved) continue;
            $subCardID = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
            $subOwner  = is_array($sub) ? intval($sub['Owner'] ?? $owner) : intval($sub->Owner ?? $owner);
            if ($subCardID === '') continue;
            if (strpos(strtolower(CardType($subCardID) ?? ''), 'token') === false) {
                SWUAddToDiscard($subOwner, $subCardID, 'PLAY');
            }
        }
    }

    $controller = intval($obj->Controller ?? $owner);
    SWURescueCaptivesOf($obj);
    $obj->removed = true;
    if (strpos(strtolower(CardType($cardID) ?? ''), 'token') === false) {
        $deck = &GetDeck($owner);
        $d = new Deck($cardID, 'Deck', $owner);
        if ($toTop) array_unshift($deck, $d); else array_push($deck, $d); // LOF_200: owner chooses top/bottom
        foreach ($deck as $i => $c) { $c->mzIndex = $i; }
    }

    SWUCollectLeavePlayReactions([['player' => $controller, 'cardID' => $cardID]], false);
    FlushTriggerBag($controller);

    DecisionQueueController::CleanupRemovedCards();
    $playerID = $savedPID;
    return true;
}

// Play a card from the player's hand (mzID like "myHand-2").
// Pays cost in resources, moves the card to its arena (unit) or discard (event).
// This is the SWUSim equivalent of GA's ActivateCard.
function ActivateCard($player, $mzID, $ignoreCost, $discount = 0, $prepaid = 0) {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);

    $obj = GetZoneObject($mzID);
    if ($obj === null || (isset($obj->removed) && $obj->removed)) {
        $playerID = $savedPID;
        return;
    }

    $cardID        = $obj->CardID;
    // SEC_053 One in a Million etc.: "This card can't be played from your hand." Block ONLY the
    // hand-source play (myHand-N); the Plot/resource path (myResources-N) is unaffected.
    if (strpos($mzID, 'Hand') !== false && _SWUCantPlayFromHand($cardID)) {
        SetFlashMessage("That card can't be played from your hand.");
        $playerID = $savedPID;
        return;
    }
    // SOR_062 Regional Governor: an opponent's named card can't be played (no cost, no state change).
    if (SWUCardPlayBlocked(intval($player), $cardID)) {
        SetFlashMessage("That card can't be played (named by an opponent).");
        $playerID = $savedPID;
        return;
    }
    AddGameLogEntry('PLAY', 'P' . intval($player) . ' played ' . GameLogCardRef($cardID));
    AddGlobalEffects(intval($player), 'SWU_CARDS_PLAYED');  // cards-played-this-phase counter (any type)
    if (function_exists('SWUTelemetryBumpCard')) { SWUTelemetryBumpCard($player, $cardID, 'played'); SWUTelemetryBumpTurn($player, 'cardsUsed'); }
    $rawType       = CardType($cardID);
    // Cost (base + aspect penalty + all play-cost modifiers) — single source of
    // truth shared with the UI affordability check. See $playCostModifiers.
    // $discount (e.g. SOR_093 "It costs 1 resource less") is subtracted, floored at 0.
    $cost          = max(0, SWUComputePlayCost($player, $obj) - intval($discount));
    // SOR_056 Bendu: consume the one-shot "next neutral card -2" charge now that the cost
    // (which already read the discount) is locked in for a qualifying card being played.
    if (_SWUIsNeutralCard($cardID) && GlobalEffectCount(intval($player), 'SWU_NEUTRAL_DISCOUNT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_NEUTRAL_DISCOUNT');
    }
    // JTL_098 Snap Wexley: consume the one-shot "next Resistance card -1" charge now that the cost is locked.
    if (HasTrait($cardID, 'Resistance') && GlobalEffectCount(intval($player), 'SWU_SNAP_DISCOUNT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_SNAP_DISCOUNT');
    }
    // ASH_212 Peli Motto: "Ignore the aspect penalties of the first non-unit card you play each phase." Mark
    // it used now that this non-unit card's (already-waived) cost is locked in. Cleared at RegroupPhaseStart.
    if (stripos(CardType($cardID) ?? '', 'Unit') === false
            && GlobalEffectCount(intval($player), 'SWU_ASH212_USED') <= 0
            && _SWUControlsCardInPlay(intval($player), 'ASH_212')) {
        AddGlobalEffects(intval($player), 'SWU_ASH212_USED');
    }
    // JTL_260 Death Star Plans: mark the once-per-round "first unit costs 2 less" discount used when the
    // player plays a unit while controlling a JTL_260 bearer. Cleared at RegroupPhaseStart.
    if (strpos(CardType($cardID) ?? '', 'Unit') !== false
            && GlobalEffectCount(intval($player), 'SWU_JTL260_USED') <= 0
            && _SWUControlsUnitBearingUpgrade(intval($player), 'JTL_260')) {
        AddGlobalEffects(intval($player), 'SWU_JTL260_USED');
    }
    // LAW_229 The Master Codebreaker: mark the once-per-round "first Gambit -1" discount used when the
    // player plays a Gambit card while controlling LAW_229. Cleared at RegroupPhaseStart.
    if (HasTrait($cardID, 'Gambit')
            && GlobalEffectCount(intval($player), 'SWU_LAW229_USED') <= 0
            && _SWUCountUnitsWithCardID(intval($player), 'LAW_229') > 0) {
        AddGlobalEffects(intval($player), 'SWU_LAW229_USED');
    }
    // LAW_058 Honor-Bound Partisan: consume the one-shot "next unit -1" charge.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false
            && GlobalEffectCount(intval($player), 'SWU_LAW058_DISCOUNT_NEXT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_LAW058_DISCOUNT_NEXT');
    }
    // ASH_027 Enoch: consume ALL "next unit -N" charges on the next unit play.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false
            && GlobalEffectCount(intval($player), 'SWU_ASH027_DISCOUNT_NEXT') > 0) {
        SWUClearGlobalEffectsByPrefix(intval($player), 'SWU_ASH027_DISCOUNT_NEXT');
    }
    // SHD_006 Jabba's collected Bounty: consume ALL "next unit -N" charges on the next unit play.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false
            && GlobalEffectCount(intval($player), 'SWU_SHD006_DISCOUNT_NEXT') > 0) {
        SWUClearGlobalEffectsByPrefix(intval($player), 'SWU_SHD006_DISCOUNT_NEXT');
    }
    // LAW_158 Khetanna: consume the one-shot "next Underworld unit -1" charge.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false && HasTrait($cardID, 'Underworld')
            && GlobalEffectCount(intval($player), 'SWU_LAW158_DISCOUNT_NEXT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_LAW158_DISCOUNT_NEXT');
    }
    // ASH_237 Mouse Droid: consume the "next Imperial unit -1" charge on an Imperial unit play.
    if (stripos(CardType($cardID) ?? '', 'Unit') !== false && HasTrait($cardID, 'Imperial')
            && GlobalEffectCount(intval($player), 'SWU_ASH237_DISCOUNT_NEXT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_ASH237_DISCOUNT_NEXT');
    }
    // SEC_110 GNK Power Droid: consume the one-shot "next unit -1" charge now that the cost is locked in.
    if (strpos(CardType($cardID) ?? '', 'Unit') !== false
            && GlobalEffectCount(intval($player), 'SWU_SEC110_DISCOUNT_NEXT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_SEC110_DISCOUNT_NEXT');
    }
    // SEC_261 Inspiring Senator: consume the "next Official unit -1" charge on an Official unit play.
    if (strpos(CardType($cardID) ?? '', 'Unit') !== false && HasTrait($cardID, 'Official')
            && GlobalEffectCount(intval($player), 'SWU_SEC261_OFFICIAL_DISCOUNT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_SEC261_OFFICIAL_DISCOUNT');
    }
    // SEC_001 Chancellor Palpatine: consume the "next Plot play −3" charge when a Plot card is actually
    // played from resources (a Resources object). Mirrors the SWUComputePlayCost gate above.
    global $Plot_Cards;
    if (isset($Plot_Cards[$cardID]) && is_object($obj) && ($obj instanceof Resources)
            && GlobalEffectCount(intval($player), 'SWU_SEC001_PLOT_DISCOUNT') > 0) {
        RemoveGlobalEffect(intval($player), 'SWU_SEC001_PLOT_DISCOUNT');
    }
    $cardTypeLower = strtolower($rawType ?? '');
    $isEvent       = strpos($cardTypeLower, 'unit') === false && strpos($cardTypeLower, 'upgrade') === false;

    global $hasAlternateCostCards;
    $hasAltCost = $isEvent
                  && isset($hasAlternateCostCards[$cardID])
                  && SWUCheckAlternateCost($player, $cardID);

    // Upgrades check valid targets BEFORE paying cost (unlike units/events).
    // Alt-cost events defer payment to the event branch (YESNO choice).
    // The early resource exhaust is skipped for both; upgrades pay after target
    // confirmation, alt-cost events pay via the SOR_199 handler.
    if (!$ignoreCost && !$hasAltCost && strpos($cardTypeLower, 'upgrade') === false) {
        $ok = SWUPayCost($player, $cost, $prepaid);
        if (!$ok) {
            SetFlashMessage("Not enough ready resources (need $cost).");
            $playerID = $savedPID;
            return;
        }
    }

    // LOF_012 Rey: "played a non-unit Force card this phase" — a Force EVENT commits here (cost paid).
    // Force UPGRADES set the same flag in the upgrade branch once a valid host is confirmed.
    if ($isEvent && HasTrait($cardID, 'Force')) {
        AddGlobalEffects($player, 'SWU_PLAYED_NONUNIT_FORCE');
    }

    // Task 3.1 / Task 6.1: stamp how many real resources were paid for this play (unit + event paths).
    // Upgrades defer payment to ATTACH_UPGRADE (post-host selection), so $gLastPlayResourcesPaid is
    // written there. Alt-cost events defer to SOR_199. This block covers the early paths only.
    // SWUPayCost is the single owner of $gLastPlayResourcesPaid for normal (non-ignoreCost, non-altCost,
    // non-upgrade) plays. ignoreCost explicitly records 0; altCost reads what SOR_199 sets.
    if ($ignoreCost) {
        $resourcesPaid = 0;
        $GLOBALS['gLastPlayResourcesPaid'] = 0;
    } elseif (!$hasAltCost && strpos($cardTypeLower, 'upgrade') === false) {
        // SWUPayCost already wrote $gLastPlayResourcesPaid; just read it back.
        $resourcesPaid = intval($GLOBALS['gLastPlayResourcesPaid']);
    } elseif ($hasAltCost) {
        // Alt-cost events: old computation; SOR_199 will overwrite $gLastPlayResourcesPaid.
        $resourcesPaid = max(0, $cost - intval($prepaid));
        $GLOBALS['gLastPlayResourcesPaid'] = $resourcesPaid;
    } else {
        // Upgrades: payment deferred to ATTACH_UPGRADE. Do NOT write $gLastPlayResourcesPaid here;
        // ATTACH_UPGRADE calls SWUPayCost which will set it to the exact host-specific cost.
        $resourcesPaid = 0; // unused by the upgrade branch; ATTACH_UPGRADE owns it.
    }

    if (strpos($cardTypeLower, 'unit') !== false) {
        // Remove from hand first.
        $obj->Remove();

        // Add directly to the arena with correct Owner/Controller so that
        // BuildIndex() runs with the right player — otherwise GetMzID() returns
        // "theirGroundArena-N" for the unit we just played.
        $targetArena = CardTargetArena($cardID);
        $uid = NextUniqueID();
        // CR 8.22.f: units enter play exhausted — unless the card says otherwise
        // (SOR_193 Millennium Falcon: "This unit enters play ready."), or the play source forces it
        // (SOR_129 Admiral Ozzel: "Play an Imperial unit … It enters play ready." sets $gForceEnterReady).
        global $gForceEnterReady;
        $entersReady = SWUUnitEntersReady($cardID);
        // SEC_170 Corellian Hounds — "If an opponent controls no ground units, this unit enters play ready."
        // (SWUUnitEntersReady text-matches its "enters play ready" line; gate it on the condition.)
        if ($cardID === 'SEC_170') {
            $oppGround = 0;
            foreach (GetGroundArena(OtherPlayer(intval($player))) as $gu) { if (empty($gu->removed)) $oppGround++; }
            $entersReady = ($oppGround === 0);
        }
        // LAW_210 Salacious Crumb — "If you control Jabba the Hutt (as a leader or unit), this unit
        // enters play ready." (Its text matches SWUUnitEntersReady unconditionally; gate on Jabba.)
        if ($cardID === 'LAW_210') {
            $entersReady = _SWUControlsTitle(intval($player), ['Jabba the Hutt']);
        }
        // LAW_223 Rose Tico — "If you control a non-unique unit, this unit enters play ready."
        if ($cardID === 'LAW_223') {
            $entersReady = false;
            foreach (GetUnitsInPlay(intval($player)) as $ru) {
                if (empty($ru->removed) && !CardUnique($ru->CardID ?? '')) { $entersReady = true; break; }
            }
        }
        // ASH_224 Elzar Mann — "While you control a Force leader, this unit enters play ready."
        if ($cardID === 'ASH_224') {
            $entersReady = false;
            foreach (GetLeader(intval($player)) as $el) {
                if (empty($el->removed) && HasTrait($el->CardID ?? '', 'Force')) { $entersReady = true; break; }
            }
        }
        // ASH_248 Neel — "The next unit you play this phase with 1 or less power enters play ready."
        // Armed flag consumed by the next ≤1-power unit the controller plays.
        if (GlobalEffectCount(intval($player), 'SWU_ASH248_READY') > 0 && intval(CardPower($cardID)) <= 1) {
            $entersReady = true;
            RemoveGlobalEffect(intval($player), 'SWU_ASH248_READY');
        }
        $entryStatus = (!empty($gForceEnterReady) || $entersReady) ? 1 : 0;
        if ($targetArena === 'SpaceArena') {
            $newCard = AddSpaceArena($player, CardID:$cardID, Status:$entryStatus,
                Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
        } else {
            $newCard = AddGroundArena($player, CardID:$cardID, Status:$entryStatus,
                Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
        }

        $newCardMzID = $newCard->GetMzID();

        // Task 3.1: durable paid-resources stamp on the arena object so a deferred WhenPlayed
        // (resolved in a later request via the EffectStack) can still read it.
        // Cleared at RegroupPhaseStart alongside other per-phase TurnEffects.
        AddTurnEffect($newCardMzID, "SWU_PAID_{$resourcesPaid}");

        // A play SOURCE may grant a TurnEffect token to the entering unit (consume-once, like
        // $gForceEnterReady): SOR_003 Chewbacca tags it 'SOR_003' (Sentinel this phase), SOR_219
        // Sneak Attack tags it 'SWU_SNEAK_DEFEAT' (defeated at the next regroup).
        global $gPlayGrantTurnEffect;
        if (!empty($gPlayGrantTurnEffect)) {
            AddTurnEffect($newCardMzID, $gPlayGrantTurnEffect);
            $gPlayGrantTurnEffect = null;
        }
        // A play SOURCE may also give Shield token(s) to the entering unit (consume-once):
        // LOF_076 Soresu Stance plays a Force unit and gives it a Shield.
        global $gPlayGrantShield;
        if (!empty($gPlayGrantShield)) {
            for ($gs = 0; $gs < intval($gPlayGrantShield); $gs++) DoGiveShieldToken($player, $newCardMzID);
            $gPlayGrantShield = null;
        }
        // …or Experience token(s): LOF_125 The Burden of Masters plays a unit and gives it 2 Experience.
        global $gPlayGrantExp;
        if (!empty($gPlayGrantExp)) {
            for ($ge = 0; $ge < intval($gPlayGrantExp); $ge++) DoGiveExperienceToken($player, $newCardMzID);
            $gPlayGrantExp = null;
        }
        // …or the LOF_220 "prevent 2 of next damage" one-shot marker (applied BEFORE entry triggers so a
        // granted-Ambush attack's counter-damage is the instance that gets prevented).
        global $gPlayGrantPrevent2;
        if (!empty($gPlayGrantPrevent2)) {
            AddTurnEffect($newCardMzID, 'PREVENT_DMG_2');
            $gPlayGrantPrevent2 = null;
        }
        // LOF_180 Deceptive Shade — "the next unit you play this phase gains Ambush." Lingering flag,
        // consumed at this (the next) unit's entry — before entry triggers collect, so Ambush can fire.
        if (GlobalEffectCount(intval($player), 'SWU_LOF180_NEXT_AMBUSH') > 0) {
            AddTurnEffect($newCardMzID, 'AMBUSH');
            RemoveGlobalEffect(intval($player), 'SWU_LOF180_NEXT_AMBUSH');
        }
        // LOF_010 Third Sister (deployed) — "the next unit you play this phase gains Hidden."
        if (GlobalEffectCount(intval($player), 'SWU_LOF010_NEXT_HIDDEN') > 0) {
            AddTurnEffect($newCardMzID, 'HIDDEN');
            RemoveGlobalEffect(intval($player), 'SWU_LOF010_NEXT_HIDDEN');
        }
        // LAW_015 Jabba (deployed) — the Underworld unit played by Jabba's action gains Ambush this phase
        // IF a Credit was defeated paying its cost (CREDIT_PAY armed SWU_JABBA015_AMBUSH). Consume both
        // flags here, before entry triggers collect, so the granted Ambush can fire its entry attack.
        if (GlobalEffectCount(intval($player), 'SWU_JABBA015_PENDING') > 0) {
            RemoveGlobalEffect(intval($player), 'SWU_JABBA015_PENDING');
            if (GlobalEffectCount(intval($player), 'SWU_JABBA015_AMBUSH') > 0) {
                AddTurnEffect($newCardMzID, 'AMBUSH');
                RemoveGlobalEffect(intval($player), 'SWU_JABBA015_AMBUSH');
            }
        }
        // LOF_005 Morgan Elsbeth (deployed) — consume the one-shot "next unit you play" discount slot
        // (the discount itself is applied in SWUComputePlayCost; this just spends the charge).
        if (GlobalEffectCount(intval($player), 'SWU_LOF005_DISCOUNT_NEXT') > 0) {
            RemoveGlobalEffect(intval($player), 'SWU_LOF005_DISCOUNT_NEXT');
        }

        AddGlobalEffects($player, 'SWU_PLAYED_UNIT_' . $uid);
        // JTL_032 Director Krennic: consume the "first When-Defeated unit you play each round" slot on
        // ANY such play — even before Krennic is in play and even when no discount applied. So a
        // WhenDefeated unit played, THEN Krennic, leaves the next WhenDefeated unit un-discounted (the
        // first slot is already spent). Krennic's -1 discount (above) only fires while this flag is 0.
        if (GlobalEffectCount($player, 'SWU_KRENNIC_USED') <= 0 && HasWhenDefeatedAbility($cardID)) {
            AddGlobalEffects($player, 'SWU_KRENNIC_USED');
        }
        // LOF_108 Malakili: consume the "first Creature you play each phase" discount slot.
        if (GlobalEffectCount($player, 'SWU_LOF108_CREATURE_USED') <= 0 && HasTrait($cardID, 'Creature')) {
            AddGlobalEffects($player, 'SWU_LOF108_CREATURE_USED');
        }
        if (strpos(CardAspect($cardID) ?? '', 'Villainy') !== false) {
            AddGlobalEffects($player, 'SWU_PLAYED_VILLAINY');
        }
        if (HasTrait($cardID, 'First Order')) {
            AddGlobalEffects($player, 'SWU_PLAYED_FO');  // JTL_010 Captain Phasma "played a First Order card"
        }
        if (HasTrait($cardID, 'Force')) {
            AddGlobalEffects($player, 'SWU_PLAYED_FORCE_CARD');  // LOF_243 Caretaker Matron "played a Force card"
        }
        if (HasTrait($cardID, 'Bounty Hunter')) {
            AddGlobalEffects($player, 'SWU_PLAYED_BOUNTYHUNTER');  // JTL_186 Mist Hunter
        }
        if (HasTrait($cardID, 'Pilot')) {
            AddGlobalEffects($player, 'SWU_PLAYED_PILOT');         // JTL_186 Mist Hunter
        }

        // Apply pending entry TurnEffects keyed by UniqueID (e.g. AMBUSH granted by Energy Conversion Lab).
        global $gPendingEntryEffects;
        if (isset($gPendingEntryEffects[$uid])) {
            foreach ($gPendingEntryEffects[$uid] as $effect) {
                AddTurnEffect($newCardMzID, $effect);
            }
            unset($gPendingEntryEffects[$uid]);
        }

        // Collect all entry triggers: WhenPlayed, Shielded, Ambush.
        // FlushEntryTriggerBag populates EffectStack (2+ triggers) or auto-dispatches (1 trigger).
        // SWU_TRIGGER_RESUME (block 20) handles SWUAfterAction when all triggers are resolved.
        SWUApplyPassiveEntryGrants($player, $cardID, $newCardMzID);

        // A unit entering play can change the board's continuous shrinks: e.g. SHD_037
        // Snoke shrinks every enemy non-leader unit (defeating any reduced to 0 HP), and
        // a small unit entering under an enemy Snoke is itself immediately defeated.
        SWUCheckShrinkDefeats();

        // CR 16.d / Task 1.4: Exploit-defeated units' WhenDefeated triggers were parked while
        // $gExploitDeferTriggers was true.  Replay them into $gPendingTriggers NOW — before
        // FlushEntryTriggerBag runs — so they batch with the played card's WhenPlayed trigger.
        // We do this BEFORE the "defeated on entry" check so the deferred triggers always fire
        // even if the played unit was immediately defeated on entry (e.g. by a Snoke shrink).
        SWUFlushExploitDeferredTriggers($player);

        // If the unit was itself defeated on entry (entered under an enemy Snoke), don't
        // run entry triggers on a now-stale mzID — just finish the action.
        // Any Exploit-deferred triggers that were just replayed into $gPendingTriggers still
        // need to be flushed here; FlushEntryTriggerBag handles that and takes over cleanup
        // when it returns > 0 (SWU_TRIGGER_RESUME queued).
        $enteredStill = false;
        foreach (GetZone($targetArena === 'SpaceArena' ? 'mySpaceArena' : 'myGroundArena') as $u) {
            if (empty($u->removed) && intval($u->UniqueID ?? 0) === $uid) { $enteredStill = true; break; }
        }
        if (!$enteredStill) {
            $deferredTriggered = FlushEntryTriggerBag($player);
            DecisionQueueController::CleanupRemovedCards();
            if ($deferredTriggered === 0) {
                SWUAfterAction($player);
            }
            // deferredTriggered >= 1: SWU_TRIGGER_RESUME (already queued) handles cleanup.
            $playerID = $savedPID;
            return;
        }

        $triggered = CollectEntryTriggers($player, $cardID, $newCardMzID, $targetArena);

        if ($triggered === 0) {
            // No entry triggers — end action immediately.
            DecisionQueueController::CleanupRemovedCards();
            SWUAfterAction($player);
        }
        // triggered >= 1: SWU_TRIGGER_RESUME (already queued at block 20) handles cleanup.
    } elseif (strpos($cardTypeLower, 'upgrade') !== false) {
        // Upgrades: validate affordable targets (host-specific cost), then queue host selection
        // and ATTACH_UPGRADE. Cost is paid AFTER the host is chosen (inside ATTACH_UPGRADE) so
        // that host-dependent discounts (SOR_061) are exact with no claw-back.
        // The upgrade stays in hand until ATTACH_UPGRADE succeeds, giving natural rollback on
        // payment failure (the card remains playable on a future action).
        $validTargets = SWUGetUpgradeValidTargets($player, $cardID, $ignoreCost ? null : $obj);
        if (empty($validTargets)) {
            SetFlashMessage("No valid targets for upgrade.");
            $playerID = $savedPID;
            return;
        }
        // LOF_012 Rey: a Force upgrade with a valid host is a "non-unit Force card" played this phase.
        if (HasTrait($cardID, 'Force')) {
            AddGlobalEffects($player, 'SWU_PLAYED_NONUNIT_FORCE');
        }
        // Do NOT pay here and do NOT $obj->Remove() yet — ATTACH_UPGRADE handles both.
        // Pass the upgrade's current hand mzID so ATTACH_UPGRADE can remove it on success.
        $upgradeMz = $mzID;
        if (count($validTargets) === 1) {
            DecisionQueueController::AddDecision($player, "PASSPARAMETER", $validTargets[0], 0);
        } else {
            DecisionQueueController::AddDecision($player, "MZCHOOSE", implode('&', $validTargets), 0, tooltip:"Choose_upgrade_target");
        }
        $igc = $ignoreCost ? 1 : 0;
        DecisionQueueController::AddDecision($player, "CUSTOM", "ATTACH_UPGRADE|{$cardID}|{$upgradeMz}|{$igc}", 0);
    } else {
        // Events: move to discard, resolve immediate effect, then cleanup.
        // Mark that this discard is the event's OWN play (From='HAND' but NOT a "discarded from hand"
        // event) so "when discarded from hand or deck" triggers (LAW_206) don't fire on normal play.
        $GLOBALS['gPlayingEventCardID'] = $cardID;
        $obj->Remove();
        SWUAddToDiscard($player, $cardID, 'HAND');
        unset($GLOBALS['gPlayingEventCardID']);
        // SOR_153 Saw Gerrera (enemy in play): "As an additional cost for each opponent to play an
        // event, they must deal 2 damage to their base." Applied at play time (always payable).
        if (_SWUCountUnitsWithCardID(OtherPlayer(intval($player)), 'SOR_153') > 0) {
            SWUDealDamageToBase(2, intval($player));
        }
        // LOF_142 Adi Gallia (enemy in play): "When an opponent plays an event: deal 1 to that player's base."
        $adiCount = _SWUCountUnitsWithCardID(OtherPlayer(intval($player)), 'LOF_142');
        for ($ai = 0; $ai < $adiCount; $ai++) SWUDealDamageToBase(1, intval($player));
        // SOR_089 Relentless (enemy in play): "The first event played by each opponent each round loses
        // all abilities." If this is $player's first event this round AND an opponent controls Relentless,
        // skip the event's effect (it still goes to discard). The per-round flag clears at RegroupPhaseStart.
        $eventBlanked = false;
        if (GlobalEffectCount(intval($player), 'SWU_EVENT_PLAYED_ROUND') <= 0
            && _SWUCountUnitsWithCardID(OtherPlayer(intval($player)), 'SOR_089') > 0) {
            $eventBlanked = true;
            AddGameLogEntry('ABILITY', GameLogCardRef($cardID) . " loses all abilities (Relentless)");
        }
        AddGlobalEffects(intval($player), 'SWU_EVENT_PLAYED_ROUND');
        if ($hasAltCost && !$eventBlanked) {
            // Queue YESNO before OnPlayEvent so cost choice resolves first.
            DecisionQueueController::AddDecision($player, "YESNO", "-", 1, tooltip:"Use_alternate_cost?");
            DecisionQueueController::AddDecision($player, "CUSTOM", "SOR_199#0|{$cost}", 1);
        }
        // SEC_046 Galen Erso — a named event has lost all abilities, so its effect doesn't resolve
        // (it still pays its cost and goes to discard).
        if (!$eventBlanked && !_SWUGalenSuppressesCard(intval($player), $cardID)) OnPlayEvent($player, $cardID);
        // Task 5.1 — TWI_210 Cunning observer: fire after event effects (block 1) but before
        // FINISH_PLAY_CARD (block 10). resourcesPaid is already finalised at $gLastPlayResourcesPaid.
        // Skip when hasAltCost: SOR_199 may later change what was paid; documented as a known
        // limitation (the alt-cost branch resolves asynchronously via SOR_199 handler).
        if (!$hasAltCost) {
            DecisionQueueController::AddDecision($player, "CUSTOM",
                "TWI_210#0|{$player}|{$cardID}|{$resourcesPaid}", 5);
        }
        DecisionQueueController::AddDecision($player, "CUSTOM", "FINISH_PLAY_CARD", 10, dontSkipOnPass: 1);
        // Do NOT restore $playerID here — ExecuteStaticMethods calls MZCountChoices
        // immediately after this returns, and it needs $playerID = $player to resolve
        // relative zone names like "theirGroundArena" correctly.
        return;
    }

    $playerID = $savedPID;
}

// Task 3.1: reader helper — resources paid for the play that put $obj into play.
// Reads the SWU_PAID_n TurnEffect stamped by ActivateCard; returns 0 if absent.
// Only meaningful for units (events have no arena object; use $gLastPlayResourcesPaid instead).
function SWUUnitResourcesPaid($obj): int {
    if (!empty($obj->TurnEffects)) {
        foreach ($obj->TurnEffects as $te) {
            if (preg_match('/^SWU_PAID_(\d+)$/', $te, $m)) return intval($m[1]);
        }
    }
    return 0;
}

// ── Task 1.3: Play-from-hand orchestrator (Exploit pre-step) ────────────────

// Effective Exploit X for a card being PLAYED: printed registry + granted-this-play + EXPLOIT_n
// TurnEffects. Hand cards carry no TurnEffects, so the grant rides in $gPlayGrantedExploit
// (set by e.g. TWI_005). Returns 0 if the card has no Exploit at all.
function SWUEffectivePlayExploit($obj): int {
    global $gPlayGrantedExploit;
    if ($obj === null || !isset($obj->CardID)) return 0;
    $base = GetKeyword_Exploit_Value($obj);   // additive; may return null when 0
    return intval($base) + intval($gPlayGrantedExploit ?? 0);
}

// Display flag for the hand "Exploit available" icon (schema Virtual: ExploitAvailable).
// 1 when a card in hand could be played with Exploit: it HAS Exploit (printed or granted
// on the card itself), OR it is a Separatist card while TWI_005 Count Dooku's "next
// Separatist card you play this phase gains Exploit" charge is active for the hand's owner
// (SWU_DOOKU_NEXT_SEPARATIST_EXPLOIT). Returns 1/0 for the Image counter (ShowZero hides 0).
function HandCardExploitAvailable($obj): int {
    if ($obj === null || !isset($obj->CardID)) return 0;
    if (HasKeyword_Exploit($obj)) return 1;
    $player = intval($obj->PlayerID ?? 0);
    if ($player > 0
            && HasTrait($obj->CardID, 'Separatist')
            && GlobalEffectCount($player, 'SWU_DOOKU_NEXT_SEPARATIST_EXPLOIT') > 0) {
        return 1;
    }
    return 0;
}

// Friendly units the player may defeat for Exploit (CR 16): ANY friendly unit — non-leader
// Units, Token Units (Battle Droids, etc.), AND a deployed Leader Unit. Single source of truth
// shared by SWUBeginPlayCard (offer + max) and EXPLOIT_RESOLVE (validate the answer), so a unit
// type can never be offered-but-not-defeatable or vice versa.
function SWUExploitFodder($player): array {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $fodder = array_merge(
        ZoneSearch("myGroundArena", AnyUnitFilter),
        ZoneSearch("mySpaceArena",  AnyUnitFilter)
    );
    $playerID = $savedPID;
    return $fodder;
}

// SEC_122 Vuutun Palaa: "Each friendly Droid unit may be exhausted to pay costs as if it were a resource."
// Returns mzIDs of the player's friendly units that (a) have trait Droid and (b) are READY (Status===1).
// Uses the same ready predicate as SWUUnitAction's exhaust cost-kind: intval($obj->Status) === 1.
// Uses ZoneSearch (like SWUExploitFodder) with $playerID save/restore so relative zone names resolve.
// GetField objects' trait-filtering uses HasTrait (not ZoneSearch cardSubtypes, which is a dead stub).
function SWUReadyFriendlyDroids($player): array {
    global $playerID;
    $savedPID = $playerID;
    $playerID = intval($player);
    $candidates = array_merge(
        ZoneSearch("myGroundArena", AnyUnitFilter),
        ZoneSearch("mySpaceArena",  AnyUnitFilter)
    );
    $playerID = $savedPID;
    $droids = [];
    foreach ($candidates as $mz) {
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        if (intval($o->Status) !== 1) continue;              // not ready — cannot be exhausted
        if (!HasTrait($o->CardID ?? '', 'Droid')) continue;  // not a Droid
        $droids[] = $mz;
    }
    return $droids;
}

// Returns true if the player controls SEC_122 (Vuutun Palaa) in play (either arena).
function SWUPlayerControlsSEC122(int $player): bool {
    foreach (GetField($player) as $u) {
        if ($u === null || !empty($u->removed)) continue;
        if (($u->CardID ?? '') === 'SEC_122') return true;
    }
    return false;
}

// Play-from-hand entry point. Chains optional interactive cost steps (Exploit, then later the
// Droid alt-pay step) before the actual play. If neither applies, plays immediately via
// ActivateCard. Routing here must be fully transparent to non-Exploit plays.
function SWUBeginPlayCard($player, $mzID) {
    global $playerID, $gPlayGrantedExploit;
    $savedPID = $playerID;
    $playerID = intval($player);

    $obj = GetZoneObject($mzID);
    if ($obj === null || (isset($obj->removed) && $obj->removed)) {
        $playerID = $savedPID;
        return;
    }

    // TWI_005 Count Dooku (deployed) On Attack: "the next Separatist card you play this phase
    // gains Exploit 3." Consume the flag NOW (before SWUEffectivePlayExploit reads
    // $gPlayGrantedExploit) whenever a Separatist card is being played, regardless of how many
    // units the player ultimately chooses to defeat. A non-Separatist play does NOT consume.
    $cardID = $obj->CardID ?? '';
    if (GlobalEffectCount(intval($player), 'SWU_DOOKU_NEXT_SEPARATIST_EXPLOIT') > 0
            && HasTrait($cardID, 'Separatist')) {
        $gPlayGrantedExploit = intval($gPlayGrantedExploit ?? 0) + 3;
        RemoveGlobalEffect(intval($player), 'SWU_DOOKU_NEXT_SEPARATIST_EXPLOIT');
    }

    // Piloting: a unit with the Piloting keyword may be played as an upgrade on a
    // friendly Vehicle. Decide Unit vs Pilot BEFORE the Exploit step (Exploit only
    // applies on the unit-play branch, which re-enters after this block).
    // SEC_046 Galen Erso — a named card has lost Piloting; it can only be played as a unit (the hand
    // object's Owner isn't reliably set, so gate on $player explicitly rather than HasKeyword_Piloting).
    if (HasKeyword_Piloting($obj) && !_SWUGalenSuppressesCard(intval($player), $obj->CardID ?? '')) {
        $ready = 0;
        foreach (GetResources($player) as $r) {
            if (SWUIsCreditToken($r->CardID ?? '')) continue; // Credit tokens aren't resources
            if (empty($r->removed) && intval($r->Status) === 1) $ready++;
        }
        $unitCost  = SWUComputePlayCost($player, $obj);
        $vehicles  = SWUGetPilotValidTargets(intval($player), $cardID);
        $canUnit   = $ready >= $unitCost;
        $canPilot  = !empty($vehicles); // SWUGetPilotValidTargets is affordability-gated

        if ($canUnit && $canPilot) {
            // Both options available — ask the player.
            DecisionQueueController::AddDecision($player, "OPTIONCHOOSE",
                "Unit&Pilot", 1, tooltip:"Play_as_Unit_or_Pilot?");
            DecisionQueueController::AddDecision($player, "CUSTOM",
                "PILOT_PLAY_CHOICE|{$mzID}|{$cardID}", 1);
            $playerID = $savedPID;
            return;
        }
        if (!$canUnit && $canPilot) {
            // Pilot-only (cannot afford the unit cost) — go straight to Vehicle pick.
            SWUQueuePilotVehiclePick(intval($player), $mzID, $cardID, $vehicles);
            $playerID = $savedPID;
            return;
        }
        // else: fall through to normal unit play (no valid Vehicle, or can only afford unit).
    }

    _SWUBeginPlayCardUnitPath(intval($player), $mzID);
    $playerID = $savedPID;
}

// ── _SWUBeginPlayCardUnitPath — the Exploit + play funnel for the unit-play branch ──
// Shared by the SWUBeginPlayCard fall-through AND the PILOT_PLAY_CHOICE "Unit" answer,
// so choosing "Unit" from the pilot prompt runs the IDENTICAL path as playing a
// non-pilot unit (Exploit included).
// $playerID must be set correctly by the caller before invoking this.
// CRITICAL: does NOT restore $playerID on return — callers (SWUBeginPlayCard,
// PILOT_PLAY_CHOICE) own the restore so that the event branch of ActivateCard can
// leave $playerID = $player for MZCountChoices (see the SWUContinuePlayAfterExploit
// note and the general engine gotcha in the instructions).
function _SWUBeginPlayCardUnitPath(int $player, string $mzID): void {
    global $gPlayGrantedExploit;

    $obj = GetZoneObject($mzID);
    if ($obj === null || (isset($obj->removed) && $obj->removed)) return;

    $exploitX = SWUEffectivePlayExploit($obj);
    $grant    = intval($gPlayGrantedExploit ?? 0); // capture before reset
    $gPlayGrantedExploit = 0; // prevent the grant from leaking to any subsequent unrelated play
    $friendly = SWUExploitFodder($player);

    if ($exploitX > 0 && !empty($friendly)) {
        $max   = min($exploitX, count($friendly));
        DecisionQueueController::AddDecision($player, "MZMULTICHOOSE",
            "0|{$max}|" . implode("&", $friendly), 1,
            tooltip:"Defeat_up_to_{$max}_units_(Exploit)");
        DecisionQueueController::AddDecision($player, "CUSTOM",
            "EXPLOIT_RESOLVE|{$mzID}|{$grant}|{$exploitX}", 1);
        return;
    }

    // No Exploit — delegate directly. The event branch of ActivateCard deliberately does
    // NOT restore $playerID before returning (so ExecuteStaticMethods / MZCountChoices
    // can resolve relative zone names). Caller restores $playerID after this returns.
    SWUContinuePlayAfterExploit($player, $mzID, 0);
}

// ── SWUOfferAltPayment — alternate-payment funnel (Credit tokens, then Droids) ──
// The single site for offering non-resource payment when paying $cost to play a card / attach an
// upgrade / keep the Falcon. Offers Credit-token defeat first (CR 3.13: "While paying resources, you
// may defeat this token. If you do, pay 1 less"); if the player has none usable, falls through to the
// SEC_122 Droid offer (SWUOfferDroidPayment), which itself falls through to the bare continuation.
//   Credit branch: queue MZMULTICHOOSE (defeat 0..min(credits,cost) tokens) + CUSTOM CREDIT_PAY, and
//   leave $playerID = $player (mirrors the Droid offer — MZCountChoices resolves the relative mzIDs
//   right after this returns). CREDIT_PAY then dispatches the continuation with prepaid = tokens
//   defeated (it does NOT chain into the Droid offer — a single payment uses one alt-pay source,
//   which is sufficient for all current cards; SEC_122 + Credits in one deck would not stack).
function SWUOfferAltPayment(int $player, int $cost, string $continuation, string $args, int $block = 1): void {
    if ($cost > 0) {
        $credits = SWUUsableCreditTokenMzIDs($player);
        if (!empty($credits)) {
            $max = min(count($credits), $cost); // can't pay below 0
            global $playerID;
            $playerID = $player; // leave set: MZCountChoices resolves the relative mzIDs after return
            DecisionQueueController::AddDecision($player, "MZMULTICHOOSE",
                "0|{$max}|" . implode("&", $credits), $block,
                tooltip:"Defeat_any_number_of_Credit_tokens_to_pay_1_resource_less_each");
            DecisionQueueController::AddDecision($player, "CUSTOM",
                "CREDIT_PAY|{$continuation}|{$args}", $block);
            return; // $playerID intentionally left = $player
        }
    }
    // No usable Credit tokens — fall through to the Droid offer (then the bare continuation).
    SWUOfferDroidPayment($player, $cost, $continuation, $args, $block);
}

// ── SWUOfferDroidPayment — central SEC_122 alt-pay offer ─────────────────────
// Single entry point for the "exhaust a Droid to pay costs" mechanic (SEC_122).
// If $cost > 0 AND the player controls SEC_122 AND has ready Droids:
//   - Queues MZMULTICHOOSE (pick Droids to exhaust, capped at $cost) at $block.
//   - Queues CUSTOM "DROID_PAY|{$continuation}|{$args}" at $block.
//   - Leaves $playerID = $player on return (CRITICAL: MZCountChoices resolves the
//     relative mzIDs in the MZMULTICHOOSE param under $playerID immediately after
//     this function returns; if $playerID is restored to a different player, the
//     count is 0 and the choice auto-resolves to "-", silently skipping the pick).
//   - Returns without calling the continuation.
// If no Droid offer applies (cost 0 / no SEC_122 / no ready Droids):
//   - Dispatches the continuation immediately with $prepaid = 0.
//   - Leaves $playerID unchanged (caller is responsible for save/restore).
//
// Param encoding: $continuation is a single pipe-free token; $args is the rest
// of the payload (may contain "|") — in DROID_PAY, $parts[0] = continuation,
// implode("|", array_slice($parts, 1)) = args.
//
// $block: 1 for card-play / Falcon (matches existing queuing), 0 for upgrades.
function SWUOfferDroidPayment(int $player, int $cost, string $continuation, string $args, int $block = 1): void {
    if ($cost > 0 && SWUPlayerControlsSEC122($player)) {
        $droids = SWUReadyFriendlyDroids($player);
        if (!empty($droids)) {
            $max = min(count($droids), $cost); // CR 8.16: cannot exceed the remaining cost
            // Set $playerID = $player and leave it set — MZCountChoices validates the
            // relative mzIDs in the MZMULTICHOOSE param right after this returns.
            global $playerID;
            $playerID = $player;
            DecisionQueueController::AddDecision($player, "MZMULTICHOOSE",
                "0|{$max}|" . implode("&", $droids), $block,
                tooltip:"Pick_any_number_of_Droids_to_exhaust_for_this_card");
            DecisionQueueController::AddDecision($player, "CUSTOM",
                "DROID_PAY|{$continuation}|{$args}", $block);
            return; // $playerID intentionally left = $player
        }
    }
    // No Droid offer — invoke the continuation immediately with prepaid = 0.
    SWUDispatchDroidContinuation($player, $continuation, $args, 0);
}

// ── SWUDispatchDroidContinuation — continuation registry ─────────────────────
// Dispatches to the named continuation after Droid exhaustion (or immediately on
// the no-droid path). $prepaid = number of Droids already exhausted.
// Continuations:
//   PLAY_CARD    args = "{mzID}|{discount}"   → ActivateCard (pays remainder + records resourcesPaid)
//   ATTACH_UPGRADE args = "{cardID}|{upgradeMz}|{hostMz}" → _SWUFinalizeUpgradeAttach (pays remainder)
//   FALCON_KEEP  args = "{falconMz}"          → SWUPayCost(1, prepaid) → keep/bounce Falcon
// Note: PLAY_CARD and ATTACH_UPGRADE do NOT call SWUPayCost here — their downstream
// functions (ActivateCard / _SWUFinalizeUpgradeAttach) already handle payment.
function SWUDispatchDroidContinuation(int $player, string $continuation, string $args, int $prepaid): void {
    switch ($continuation) {
        case 'PLAY_CARD': {
            $argParts = explode('|', $args, 2);
            $mzID     = $argParts[0] ?? '';
            $discount = intval($argParts[1] ?? 0);
            ActivateCard($player, $mzID, false, $discount, $prepaid);
            break;
        }
        case 'ATTACH_UPGRADE': {
            $argParts  = explode('|', $args, 4);
            $cardID    = $argParts[0] ?? '';
            $upgradeMz = $argParts[1] ?? '';
            $hostMz    = $argParts[2] ?? '';
            $isPilot   = !empty($argParts[3]); // 4th field set to '1' on the pilot path
            _SWUFinalizeUpgradeAttach($player, $cardID, $upgradeMz, $hostMz, $prepaid, false, $isPilot);
            break;
        }
        case 'FALCON_KEEP': {
            $falconMz = $args;
            $paidOk   = SWUPayCost($player, 1, $prepaid);
            _SWUFalconKeepOrBounce($player, $falconMz, $paidOk);
            break;
        }
    }
}

// Stage 2 of the play ceremony: discount from Exploit is known. Routes through the
// central SWUOfferDroidPayment to offer the Droid alt-pay step if SEC_122 is in play.
// NOTE: the event branch of ActivateCard does NOT restore $playerID before returning, so we must
// not restore $playerID here either — callers (SWUBeginPlayCard, EXPLOIT_RESOLVE) handle that.
function SWUContinuePlayAfterExploit($player, $mzID, $discount) {
    $obj  = GetZoneObject($mzID);
    $cost = ($obj !== null && empty($obj->removed))
          ? max(0, SWUComputePlayCost($player, $obj) - intval($discount))
          : 0;
    SWUOfferAltPayment(intval($player), $cost, 'PLAY_CARD', "{$mzID}|{$discount}", 1);
}

// ── Leader: get the non-removed leader card object for a player ────────────
function SWUGetLeader(int $player): ?object {
    $arr = &GetLeader($player);
    for ($i = 0; $i < count($arr); $i++) {
        if (!isset($arr[$i]->removed) || !$arr[$i]->removed) return $arr[$i];
    }
    return null;
}

// ── Deploy a leader unit to the Ground Arena (or as a Pilot onto a Vehicle) ───
// $mode = 'Unit'  → standard deploy to Ground Arena (existing behaviour).
// $mode = 'Pilot' → attach the leader as a Pilot upgrade onto $hostMz (Asajj JTL_001 etc.).
//                   $hostMz must be a friendly Vehicle mzID (capacity already verified by caller).
// When called with mode='Unit' for a CardLeaderCanDeployAsUpgrade leader AND eligible Vehicles
// exist, queues OPTIONCHOOSE Unit/Pilot before committing — the LEADER_DEPLOY_CHOICE handler
// then calls back with the chosen mode.
// Marks EpicActionUsed/Deployed/Ready=false in all branches. Leaders deploy for free
// (the threshold is a condition, not a cost).
function SWUDeployLeader(int $player, string $mode = 'Unit', string $hostMz = ''): void {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;

    $leaderArr = &GetLeader($player);
    $leader    = null;
    for ($i = 0; $i < count($leaderArr); $i++) {
        if (!isset($leaderArr[$i]->removed) || !$leaderArr[$i]->removed) {
            $leader = &$leaderArr[$i];
            break;
        }
    }
    if ($leader === null) { $playerID = $savedPID; return; }

    $cardID = $leader->CardID;

    // Deploy gate. Standard leaders use the once-per-game Epic Action (free; threshold = printed cost,
    // ready or exhausted). JTL_014 Admiral Trench instead deploys via a NON-epic, repeatable
    // Action [3 resources, Exhaust]: requires the leader ready, controlling 6+ resources, and 3 ready
    // resources to pay — and does NOT consume the epic action, so he can redeploy after returning to
    // leader form.
    if ($leader->Deployed ?? false) { $playerID = $savedPID; return; }
    if ($cardID === 'JTL_014') {
        if (empty($leader->Ready)
            || SWUResourceCount($player) < 6
            || SWUResourceCount($player, readyOnly: true) < 3) {
            $playerID = $savedPID;
            return;
        }
        SWUExhaustResources($player, 3);
    } elseif ($cardID === 'LOF_007') {
        // Avar Kriss Epic Action: deploy if (resources you control) + (times you used the Force this
        // phase) ≥ 9 (her printed deploy threshold).
        $forceUses = GlobalEffectCount($player, 'SWU_FORCE_USED_THIS_PHASE');
        if (($leader->EpicActionUsed ?? false)
            || (SWUResourceCount($player) + $forceUses) < intval(CardCost($cardID))) {
            $playerID = $savedPID;
            return;
        }
    } elseif ($cardID === 'ASH_018') {
        // Grogu has no Epic Action; he deploys ONLY via his "play a uq unit costing 4+" trigger, which
        // just requires he is ready (no resource threshold).
        if (empty($leader->Ready)) { $playerID = $savedPID; return; }
    } else {
        if (($leader->EpicActionUsed ?? false)
            || SWUResourceCount($player) < intval(CardCost($cardID))) {
            $playerID = $savedPID;
            return;
        }
    }

    // For CardLeaderCanDeployAsUpgrade leaders deploying as 'Unit' (not 'UnitDirect'):
    // if eligible Vehicles exist, offer Unit/Pilot choice BEFORE committing state changes.
    // 'UnitDirect' is the internal mode used by LEADER_DEPLOY_CHOICE after the player
    // already chose "Unit" — it skips the re-offer gate.
    if ($mode === 'Unit' && CardLeaderCanDeployAsUpgrade($cardID)) {
        $vehicles = SWUGetLeaderPilotVehicles($player);
        if (!empty($vehicles)) {
            DecisionQueueController::AddDecision($player, "OPTIONCHOOSE",
                "Unit&Pilot", 1, tooltip:"Deploy_as_Unit_or_Pilot?");
            DecisionQueueController::AddDecision($player, "CUSTOM",
                "LEADER_DEPLOY_CHOICE|{$cardID}", 1);
            $playerID = $savedPID;
            return;
        }
    }

    AddGameLogEntry('PLAY', 'P' . intval($player) . ' deployed ' . GameLogCardRef($cardID));

    // Mark the leader side: epic action consumed (NOT for JTL_014's non-epic repeatable deploy),
    // leader flipped to deployed state.
    $leader->EpicActionUsed = ($cardID !== 'JTL_014');
    $leader->Deployed       = true;
    $leader->Ready          = false; // leader side exhausted after the deploy action

    // JTL_191 Invincible — "When you deploy a leader: ...". Add its reaction to the pending-trigger
    // bag NOW (before the mode branches) so it rides whichever flush runs: the Unit branch's
    // CollectEntryTriggers or the Pilot branch's CollectWhenPlayedAsUpgradeTriggers.
    foreach (GetUnitsInPlay($player) as $u) {
        if (empty($u->removed) && ($u->CardID ?? '') === 'JTL_191') {
            AddTrigger($player, 'JTL_191', 'JTL_191', '');
        }
    }

    // CR §19 Plot: a leader deploy opens a Plot window for the deploying player. Arm it now if any
    // affordable Plot card sits in their resources; the window actually opens when this deploy's After
    // Action runs (intercepted in SWUAfterAction), i.e. after the leader's own When Deployed resolves.
    // SWU_PLOT_K snapshots the resource count so replacements appended during the window are excluded
    // from re-offering (CR 19.d). Both deploy branches (Unit / Pilot) funnel through SWUAfterAction.
    if (PlayerHasPlotsToPlay($player)) {
        SetSWUVar('SWU_PLOT_IN_PROGRESS', '1');
        SetSWUVar('SWU_PLOT_K', strval(SWUResourceCount($player)));
        SetSWUVar('SWU_PLOT_P', '0');
        SetSWUVar('SWU_PLOT_PENDING_REPLACE', '');
    }

    if ($mode === 'Pilot') {
        // ── Pilot branch: attach leader as a Pilot upgrade onto the chosen Vehicle ──
        // $hostMz must be a valid Vehicle mzID (verified by caller / LEADER_DEPLOY_PILOT).
        // DeployedUniqueID is 0: the leader exists as a Subcard on the host, not a
        // standalone arena unit, so there is no arena UniqueID to track back.
        $leader->DeployedUniqueID = 0;

        // Attach as a Pilot subcard (ignoreCost=true — deploy is free; isPilot=true).
        // _SWUFinalizeUpgradeAttach expects $playerID = $player (already set above)
        // and handles the Subcard append, WhenPlayedAsUpgrade / OnAttached triggers,
        // and SWUAfterAction.
        _SWUFinalizeUpgradeAttach($player, $cardID, '', $hostMz, 0, true, true);

        $playerID = $savedPID;
        return;
    }

    // ── Unit branch (default): create the arena unit entry ──────────────────
    $uid = NextUniqueID();
    $newCard = AddGroundArena($player, CardID:$cardID, Status:1,
        Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
    $leader->DeployedUniqueID = $uid;

    $newCardMzID = $newCard->GetMzID();
    // A leader deploy is not "playing a card": its When Deployed (WhenPlayed) entry trigger still
    // fires, but reactive "when you play a card" observers (FFF/Bossk/Cunning) must not. ($isPlay=false)
    $triggered = CollectEntryTriggers($player, $cardID, $newCardMzID, 'GroundArena', false);

    if ($triggered === 0) {
        DecisionQueueController::CleanupRemovedCards();
        SWUAfterAction($player);
    }

    $playerID = $savedPID;
}

// Returns true if every cost of the leader's action ability can be paid:
// the resource component (from $leaderActionResourceCosts) and any printed
// additional cost. Checked before the leader exhausts — an unaffordable
// action must be a no-op, not a soft pass that spends the leader.
function SWULeaderActionAffordable(int $player, string $cardID): bool {
    global $leaderActionResourceCosts, $playerID;

    $cost = $leaderActionResourceCosts[$cardID] ?? 0;
    if ($cost > 0 && SWUResourceCount($player, readyOnly: true) < $cost) return false;

    // SOR_006 Emperor Palpatine: "defeat a friendly unit" is part of the cost.
    if ($cardID === 'SOR_006') {
        $savedPID = $playerID;
        $playerID = $player;
        $friendlies = array_merge(
            ZoneSearch("myGroundArena", AnyUnitFilter),
            ZoneSearch("mySpaceArena",  AnyUnitFilter)
        );
        $playerID = $savedPID;
        if (empty($friendlies)) return false;
    }

    // SOR_017 Han Solo: "Put a card from your hand into play as a resource" —
    // requires at least one card in hand, else there is nothing to resource.
    if ($cardID === 'SOR_017') {
        $savedPID = $playerID;
        $playerID = $player;
        $hand = ZoneSearch("myHand");
        $playerID = $savedPID;
        if (empty($hand)) return false;
    }

    // SHD_006 Jabba the Hutt: "Choose a unit" to give a Bounty — requires ≥1 unit in play (any arena,
    // either side), else there's nothing to choose.
    if ($cardID === 'SHD_006') {
        $savedPID = $playerID;
        $playerID = $player;
        $hasUnit = !empty(ZoneSearch('myGroundArena', AnyUnitFilter))
                || !empty(ZoneSearch('mySpaceArena',  AnyUnitFilter))
                || !empty(ZoneSearch('theirGroundArena', AnyUnitFilter))
                || !empty(ZoneSearch('theirSpaceArena',  AnyUnitFilter));
        $playerID = $savedPID;
        if (!$hasUnit) return false;
    }

    // JTL_013 Poe Dameron: "attach to a friendly Vehicle without a Pilot" — requires ≥1
    // such Vehicle in play, else the action has no valid target (leader stays ready).
    if ($cardID === 'JTL_013') {
        $savedPID = $playerID;
        $vehicles = SWUGetPoe013AttachVehicles($player);
        $playerID = $savedPID;
        if (empty($vehicles)) return false;
    }

    // TWI_005 Count Dooku: "Play a Separatist card from your hand" — requires ≥1
    // affordable Separatist card in hand, else the ability has no valid target.
    if ($cardID === 'TWI_005') {
        $savedPID = $playerID;
        $playerID = $player;
        $hasSeparatist = !empty(_SWUSeparatistHandPlayables($player));
        $playerID = $savedPID;
        if (!$hasSeparatist) return false;
    }

    // SEC_002 Jabba the Hutt: "a friendly damaged unit deals damage to an enemy unit" — needs both a
    // friendly damaged unit AND an enemy unit in play.
    if ($cardID === 'SEC_002') {
        $savedPID = $playerID; $playerID = $player;
        $hasDamaged = false;
        foreach (['myGroundArena', 'mySpaceArena'] as $z) {
            foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                $o = GetZoneObject($mz);
                if ($o !== null && empty($o->removed) && intval($o->Damage) > 0) { $hasDamaged = true; break 2; }
            }
        }
        $hasEnemy = !empty(ZoneSearch('theirGroundArena', AnyUnitFilter))
                 || !empty(ZoneSearch('theirSpaceArena',  AnyUnitFilter));
        $playerID = $savedPID;
        if (!$hasDamaged || !$hasEnemy) return false;
    }

    // SEC_003 Lama Su: "play an upgrade from your hand on a friendly non-Vehicle unit" — needs ≥1 hand
    // upgrade with a valid non-Vehicle host, affordable at the −1 discount.
    if ($cardID === 'SEC_003') {
        $savedPID = $playerID;
        $playable = _SWUSec003PlayableHandUpgrades($player);
        $playerID = $savedPID;
        if (empty($playable)) return false;
    }

    // SEC_004 Leia Organa: "Disclose ... If you do, give Experience" — needs ≥1 hand card with one of
    // the disclosable aspect icons (Vigilance/Command/Aggression/Cunning/Heroism).
    if ($cardID === 'SEC_004') {
        $savedPID = $playerID;
        $ok = !empty(_SWUSec004DiscloseableHand($player));
        $playerID = $savedPID;
        if (!$ok) return false;
    }

    // SEC_005 Satine Kryze: "Heal up to 2 from a unit" — needs ≥1 damaged unit.
    if ($cardID === 'SEC_005') {
        $savedPID = $playerID; $playerID = $player;
        $hasDamaged = false;
        foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $z) {
            foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                $o = GetZoneObject($mz);
                if ($o !== null && empty($o->removed) && intval($o->Damage) > 0) { $hasDamaged = true; break 2; }
            }
        }
        $playerID = $savedPID;
        if (!$hasDamaged) return false;
    }

    // SEC_006 Colonel Yularen: "Attack with a unit" — needs ≥1 ready friendly unit.
    if ($cardID === 'SEC_006') {
        $savedPID = $playerID; $playerID = $player;
        $hasReady = false;
        foreach (['myGroundArena', 'mySpaceArena'] as $z) {
            foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                $o = GetZoneObject($mz);
                if ($o !== null && empty($o->removed) && intval($o->Status) === 1) { $hasReady = true; break 2; }
            }
        }
        $playerID = $savedPID;
        if (!$hasReady) return false;
    }

    // SEC_007 Dryden Vos: additional cost "discard a card costing 6+" + effect "play a unit costing ≤5".
    // Needs a 6+ card to discard AND ≥1 affordable ≤5 unit in hand.
    if ($cardID === 'SEC_007') {
        $savedPID = $playerID; $playerID = $player;
        $has6 = false; $hasPlayable = false;
        $ready = SWUResourceCount($player, readyOnly: true);
        foreach (ZoneSearch('myHand') as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            if (intval(CardCost($o->CardID)) >= 6) $has6 = true;
            if (stripos(CardType($o->CardID) ?? '', 'Unit') !== false
                    && intval(CardCost($o->CardID)) <= 5
                    && SWUComputePlayCost($player, $o) <= $ready) $hasPlayable = true;
        }
        $playerID = $savedPID;
        if (!$has6 || !$hasPlayable) return false;
    }

    // SEC_010 Dedra Meero: "Choose an enemy unit" — needs ≥1 enemy unit.
    if ($cardID === 'SEC_010') {
        $savedPID = $playerID; $playerID = $player;
        $hasEnemy = !empty(ZoneSearch('theirGroundArena', AnyUnitFilter))
                 || !empty(ZoneSearch('theirSpaceArena',  AnyUnitFilter));
        $playerID = $savedPID;
        if (!$hasEnemy) return false;
    }

    // SEC_011 Governor Pryce: "Ready a token unit" — needs ≥1 friendly EXHAUSTED token unit.
    if ($cardID === 'SEC_011') {
        $savedPID = $playerID; $playerID = $player;
        $hasToken = false;
        foreach (['myGroundArena', 'mySpaceArena'] as $z) {
            foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                $o = GetZoneObject($mz);
                if ($o !== null && empty($o->removed) && EffectiveCardType($o) === 'Token Unit'
                        && intval($o->Status ?? 0) !== 1) { $hasToken = true; break 2; }
            }
        }
        $playerID = $savedPID;
        if (!$hasToken) return false;
    }

    // SEC_018 DJ: "Choose a friendly unit … play a unit from your hand … the chosen unit captures it." —
    // needs ≥1 friendly unit (captor) AND ≥1 affordable (−1) hand unit.
    if ($cardID === 'SEC_018') {
        $savedPID = $playerID; $playerID = $player;
        $hasCaptor = !empty(ZoneSearch('myGroundArena', AnyUnitFilter)) || !empty(ZoneSearch('mySpaceArena', AnyUnitFilter));
        $ready = SWUResourceCount($player, readyOnly: true);
        $hasPlayable = false;
        foreach (ZoneSearch('myHand') as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            if (stripos(CardType($o->CardID) ?? '', 'Unit') !== false
                    && max(0, SWUComputePlayCost($player, $o) - 1) <= $ready) { $hasPlayable = true; break; }
        }
        $playerID = $savedPID;
        if (!$hasCaptor || !$hasPlayable) return false;
    }

    // LOF leaders whose Action cost includes "use the Force (lose your Force token)" — the player must
    // control their Force token to pay, else the Action isn't available.
    global $leaderActionForceCost;
    if (!empty($leaderActionForceCost[$cardID]) && !PlayerHasTheForce($player)) return false;

    // LAW_001 Saw Gerrera (front) — needs a ready friendly unit to attack with.
    if ($cardID === 'LAW_001') {
        $savedPID = $playerID; $playerID = $player;
        $ok = false;
        foreach (['myGroundArena', 'mySpaceArena'] as $z) {
            foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                $o = GetZoneObject($mz);
                if ($o !== null && empty($o->removed) && intval($o->Status ?? 0) === 1) { $ok = true; break 2; }
            }
        }
        $playerID = $savedPID;
        if (!$ok) return false;
    }
    // LAW_002 Tobias Beckett (front) — needs a friendly non-leader unit to give away.
    if ($cardID === 'LAW_002') {
        $savedPID = $playerID; $playerID = $player;
        $ok = !empty(ZoneSearch('myGroundArena', NonLeaderUnitFilter)) || !empty(ZoneSearch('mySpaceArena', NonLeaderUnitFilter));
        $playerID = $savedPID;
        if (!$ok) return false;
    }
    // LAW_003 Agent Kallus (front) — needs a hand card affordable after waiving its full aspect penalty.
    if ($cardID === 'LAW_003') {
        $savedPID = $playerID; $playerID = $player;
        $ready = SWUResourceCount($player, readyOnly: true);
        $ok = false;
        foreach (ZoneSearch('myHand') as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed) || _SWUCantPlayFromHand($o->CardID)) continue;
            // the [1 resource] cost is already paid before this card's cost; require it affordable then
            if (max(0, SWUComputePlayCost($player, $o) - SWUAspectPenalty($player, $o->CardID)) <= $ready - 1) { $ok = true; break; }
        }
        $playerID = $savedPID;
        if (!$ok) return false;
    }
    // LAW_004 Aurra Sing (front) — needs a non-leader unit with 1 or less remaining HP.
    if ($cardID === 'LAW_004') {
        if (empty(_SWULaw004Targets($player, 1))) return false;
    }
    // LAW_005 Jyn Erso (front) — needs a friendly Rebel unit to have been defeated this phase.
    if ($cardID === 'LAW_005' && GlobalEffectCount($player, 'SWU_REBEL_DEFEATED') <= 0) return false;
    // LAW_006 Vel Sartha (front) — needs at least one unit in play to give the Experience token to.
    if ($cardID === 'LAW_006') {
        $savedPID = $playerID; $playerID = $player;
        $any = false;
        foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $z) {
            if (!empty(ZoneSearch($z, AnyUnitFilter))) { $any = true; break; }
        }
        $playerID = $savedPID;
        if (!$any) return false;
    }
    // LAW_008 Director Krennic (front) — needs a friendly unit to defeat (the cost).
    if ($cardID === 'LAW_008') {
        $savedPID = $playerID; $playerID = $player;
        $ok = !empty(ZoneSearch('myGroundArena', AnyUnitFilter)) || !empty(ZoneSearch('mySpaceArena', AnyUnitFilter));
        $playerID = $savedPID;
        if (!$ok) return false;
    }
    // LAW_009 Hera Syndulla — passive only, no front Action.
    if ($cardID === 'LAW_009') return false;
    // LAW_010 Leia Organa (front) — needs a unit to buff (cost 2 gated above).
    if ($cardID === 'LAW_010') {
        $savedPID = $playerID; $playerID = $player;
        $any = false;
        foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $z) { if (!empty(ZoneSearch($z, AnyUnitFilter))) { $any = true; break; } }
        $playerID = $savedPID;
        if (!$any) return false;
    }
    // LAW_011 Darth Vader (front) — needs a card in hand to discard (the cost).
    if ($cardID === 'LAW_011') {
        $savedPID = $playerID; $playerID = $player;
        $ok = !empty(ZoneSearch('myHand'));
        $playerID = $savedPID;
        if (!$ok) return false;
    }
    // LAW_012 Sebulba (front) — needs a friendly unit to grant Raid 1.
    if ($cardID === 'LAW_012') {
        $savedPID = $playerID; $playerID = $player;
        $ok = !empty(ZoneSearch('myGroundArena', AnyUnitFilter)) || !empty(ZoneSearch('mySpaceArena', AnyUnitFilter));
        $playerID = $savedPID;
        if (!$ok) return false;
    }
    // LAW_014 Enfys Nest — front is a reaction (no Action).
    if ($cardID === 'LAW_014') return false;
    // LAW_015 Jabba (front) — needs a friendly Underworld unit to return (the additional cost); the
    // 1-resource cost is already gated above via $leaderActionResourceCosts.
    if ($cardID === 'LAW_015') {
        if (empty(_SWULaw015FriendlyUnderworldUnits($player))) return false;
    }
    // LAW_017 Han Solo (front) — needs a friendly token (Token Unit or Credit) to defeat (the cost).
    if ($cardID === 'LAW_017') {
        if (empty(_SWULaw017Tokens($player))) return false;
    }
    // LAW_016 The Client (front) — needs a token created this phase AND an enemy unit to exhaust.
    if ($cardID === 'LAW_016') {
        if (GlobalEffectCount($player, 'SWU_CREATED_TOKEN') <= 0) return false;
        $savedPID = $playerID; $playerID = $player;
        $ok = !empty(ZoneSearch('theirGroundArena', AnyUnitFilter)) || !empty(ZoneSearch('theirSpaceArena', AnyUnitFilter));
        $playerID = $savedPID;
        if (!$ok) return false;
    }

    return true;
}

// ── Exhaust leader and trigger its action ability ──────────────────────────
// Dispatches to the per-card handler in $leaderAbilities. If no handler is
// registered for the card, the leader is exhausted but nothing else happens.
function SWULeaderAction(int $player, string $cardID): void {
    global $playerID, $leaderAbilities;
    $savedPID = $playerID;
    $playerID = $player;

    // A leader's "Action: …" ability is a player action — legal ONLY during the action phase.
    // The UI gates on this, but guard the engine entry too: once both players have passed (e.g.
    // a player takes the initiative after the opponent passed) the action phase ends, and a
    // stray/bypassed call must not still exhaust the leader and fire the ability.
    if (GetCurrentPhase() !== 'MAIN') { $playerID = $savedPID; return; }

    $leaderArr = &GetLeader($player);
    $leader    = null;
    for ($i = 0; $i < count($leaderArr); $i++) {
        if (!isset($leaderArr[$i]->removed) || !$leaderArr[$i]->removed) {
            $leader = &$leaderArr[$i];
            break;
        }
    }

    if ($leader === null || !$leader->Ready || $leader->Deployed) {
        $playerID = $savedPID;
        return;
    }

    // Costs must be payable before anything happens — leader stays ready and
    // the player keeps their action if not.
    if (!SWULeaderActionAffordable($player, $cardID)) {
        $playerID = $savedPID;
        return;
    }

    $leader->Ready = false; // exhaust

    if (isset($leaderAbilities[$cardID]) && is_callable($leaderAbilities[$cardID])) {
        ($leaderAbilities[$cardID])($player);
        // Ability handlers are responsible for calling SWUAfterAction
    } else {
        SWUAfterAction($player);
    }

    $playerID = $savedPID;
}

// Remaining uses of a repeatable base Action this game. The NumUses field is lazily seeded: an
// absent/sentinel (<0) value means "untouched" → the full per-game budget. Returns 0 for a base
// that is not a registered repeatable-action base.
function _SWUBaseActionUsesLeft($base, string $cardID): int {
    global $baseActionNumUses;
    if ($base === null || !isset($baseActionNumUses[$cardID])) return 0;
    $n = isset($base->NumUses) ? intval($base->NumUses) : -1;
    return ($n < 0) ? intval($baseActionNumUses[$cardID]) : $n;
}

function SWUBaseAction(int $player): void {
    global $playerID, $baseAbilities, $baseActionNumUses, $baseActionRepeatable;
    $savedPID = $playerID;
    $playerID = $player;

    $baseArr = &GetBase($player);
    $base    = null;
    for ($i = 0; $i < count($baseArr); $i++) {
        if (!isset($baseArr[$i]->removed) || !$baseArr[$i]->removed) {
            $base = &$baseArr[$i];
            break;
        }
    }

    if ($base === null) {
        $playerID = $savedPID;
        return;
    }
    $cardID = $base->CardID;

    // SEC_046 Galen Erso — if the enemy Galen named this base, it has lost its abilities → no base action.
    if (_SWUGalenSuppressesCard($player, $cardID)) { $playerID = $savedPID; return; }

    // Repeatable base Action with a card-cost (e.g. LOF_028 Tomb of Eilram): runs every time, the
    // ability closure pays its own cost. Does NOT consume EpicActionUsed or a NumUses budget.
    if (isset($baseActionRepeatable[$cardID])) {
        if (isset($baseAbilities[$cardID]) && is_callable($baseAbilities[$cardID])) {
            ($baseAbilities[$cardID])($player);
        } else {
            SWUAfterAction($player);
        }
        $playerID = $savedPID;
        return;
    }

    // Repeatable base Action (e.g. LOF_022 Mystic Monastery): gated per GAME by the NumUses field,
    // NOT the once-per-game EpicActionUsed flag (so it doesn't consume the epic slot). The budget is
    // exempted from the per-round NumUses refill (SWUResetAllNumUses), making it whole-game.
    if (isset($baseActionNumUses[$cardID])) {
        $left = _SWUBaseActionUsesLeft($base, $cardID);
        if ($left <= 0) {
            $playerID = $savedPID;
            return;
        }
        $base->NumUses = $left - 1; // lazily seed + consume in one step
        if (isset($baseAbilities[$cardID]) && is_callable($baseAbilities[$cardID])) {
            ($baseAbilities[$cardID])($player);
        } else {
            SWUAfterAction($player);
        }
        $playerID = $savedPID;
        return;
    }

    // Standard once-per-game Epic Action base.
    if ($base->EpicActionUsed) {
        $playerID = $savedPID;
        return;
    }
    $base->EpicActionUsed = true;

    if (isset($baseAbilities[$cardID]) && is_callable($baseAbilities[$cardID])) {
        ($baseAbilities[$cardID])($player);
    } else {
        SWUAfterAction($player);
    }

    $playerID = $savedPID;
}

// ── Unit activated abilities ("Action [Exhaust]: …") ────────────────────────
// Parallel to SWULeaderAction. A unit's action can be provided by the unit itself
// ($unitAbilities[unitCardID]) OR by an attached upgrade ($unitAbilities[upgradeCardID]),
// mirroring OnAttackFromUpgrade. Returns the providing CardID, or '' if none.
function SWUGetUnitActionProvider($obj): string {
    global $unitAbilities;
    if ($obj === null || !empty($obj->removed)) return '';
    if (isset($unitAbilities[$obj->CardID])) return $obj->CardID;
    foreach (GetUpgradesOnUnit($obj) as $u) {
        $uid = is_array($u) ? ($u['CardID'] ?? '') : ($u->CardID ?? '');
        if ($uid !== '' && isset($unitAbilities[$uid])) return $uid;
    }
    return '';
}

// Affordability for a unit action: resource cost (rare) + per-card additional costs.
// The Exhaust cost is checked separately by SWUUnitAction (the unit must be ready).
function SWUUnitActionAffordable(int $player, string $mzID, string $providerCardID): bool {
    global $playerID, $unitActionResourceCosts;
    $cost = $unitActionResourceCosts[$providerCardID] ?? 0;
    if ($cost > 0 && SWUResourceCount($player, readyOnly: true) < $cost) return false;

    $savedPID = $playerID;
    $playerID = $player;
    $ok = true;
    // A unit that has lost its abilities can't use its activated ("Action [Exhaust]:") ability.
    $actor = GetZoneObject($mzID);
    if ($actor !== null && LostAbilities($actor)) { $playerID = $savedPID; return false; }
    switch ($providerCardID) {
        case 'ASH_119': // Greef Karga: only useful if your base was attacked this phase.
            if (GlobalEffectCount($player, 'SWU_BASE_ATTACKED') <= 0) $ok = false;
            break;
        case 'ASH_230': // Improvised Identity (granted): once each round.
            if (GlobalEffectCount($player, 'SWU_ASH230_USED') > 0) $ok = false;
            break;
        case 'ASH_109': // T-6 Shuttle: needs ANOTHER unit to buff.
        case 'ASH_118': { // 8D8: needs ANOTHER friendly unit to damage.
            $selfUid = $actor ? intval($actor->UniqueID ?? 0) : 0;
            $zones = $providerCardID === 'ASH_109'
                ? ['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena']
                : ['myGroundArena', 'mySpaceArena'];
            $found = false;
            foreach ($zones as $z) { foreach (ZoneSearch($z, AnyUnitFilter) as $mz) { $o = GetZoneObject($mz); if ($o !== null && empty($o->removed) && intval($o->UniqueID ?? 0) !== $selfUid) { $found = true; break 2; } } }
            if (!$found) $ok = false;
            break;
        }
        case 'LAW_084': // Krrsantan: needs 2+ cards in hand to pay the discard cost.
            if (count(array_filter(GetHand($player), fn($c) => empty($c->removed))) < 2) $ok = false;
            break;
        case 'ASH_217': // Mayor's Majordomo: needs 1+ card in hand to pay the discard cost.
            if (count(array_filter(GetHand($player), fn($c) => empty($c->removed))) < 1) $ok = false;
            break;
        case 'LAW_015': // Jabba (deployed): needs a playable Underworld unit in hand (ready resources + Credits).
            if (empty(_SWULaw015PlayableUnderworldUnits($player))) $ok = false;
            break;
        case 'LAW_156': // Hunter For Hire: cost is defeating a friendly Credit token (the acting player's).
            if (empty(SWUUsableCreditTokenMzIDs($player))) $ok = false;
            break;
        case 'LAW_003': { // Agent Kallus (deployed): needs a hand card affordable after waiving its full aspect penalty (the 1-resource action cost is already gated above).
            $ready = SWUResourceCount($player, readyOnly: true);
            $hasPlay = false;
            foreach (ZoneSearch('myHand') as $mz) {
                $o = GetZoneObject($mz);
                if ($o === null || !empty($o->removed) || _SWUCantPlayFromHand($o->CardID)) continue;
                if (max(0, SWUComputePlayCost($player, $o) - SWUAspectPenalty($player, $o->CardID)) <= $ready - 1) { $hasPlay = true; break; }
            }
            if (!$hasPlay) $ok = false;
            break;
        }
        case 'ASH_002': { // Fennec Shand (deployed): needs 1 ready resource, a hand unit, and a ready friendly unit (the cost).
            if (SWUResourceCount($player, readyOnly: true) < 1) { $ok = false; break; }
            if (empty(ZoneSearch('myHand', ['Unit', 'Token Unit']))) { $ok = false; break; }
            $hasReady = false;
            foreach (['myGroundArena', 'mySpaceArena'] as $z) {
                foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
                    $o = GetZoneObject($mz);
                    if ($o !== null && empty($o->removed) && intval($o->Status) === 1) { $hasReady = true; break 2; }
                }
            }
            if (!$hasReady) $ok = false;
            break;
        }
        case 'LOF_013': // Barriss Offee (deployed): needs the Force token + a playable event (at the −1 discount).
            if (!PlayerHasTheForce($player) || empty(SWUHandPlayablesAtDiscount($player, ['Event'], 1))) $ok = false;
            break;
        case 'LOF_018': { // Anakin (deployed): needs the Force token + a playable Villainy non-unit at printed cost.
            if (!PlayerHasTheForce($player)) { $ok = false; break; }
            $ready = SWUResourceCount($player, readyOnly: true);
            $has = false;
            foreach (GetHand($player) as $c) {
                if ($c === null || !empty($c->removed)) continue;
                $cid = $c->CardID;
                if (CardType($cid) === 'Unit' || strpos(CardAspect($cid) ?? '', 'Villainy') === false) continue;
                if ($ready >= intval(CardCost($cid))) { $has = true; break; }
            }
            if (!$has) $ok = false;
            break;
        }
        case 'SEC_007': { // Dryden Vos (deployed): needs a card to discard + a playable unit in hand.
            if (empty(ZoneSearch('myHand'))) { $ok = false; break; }
            $ready = SWUResourceCount($player, readyOnly: true);
            $has = false;
            foreach (ZoneSearch('myHand') as $hmz) {
                $u = GetZoneObject($hmz);
                if ($u !== null && empty($u->removed) && stripos(CardType($u->CardID) ?? '', 'Unit') !== false
                    && SWUComputePlayCost($player, $u) <= $ready) { $has = true; break; }
            }
            if (!$has) $ok = false;
            break;
        }
        case 'LAW_126': { // Adventurer Sniper Rifle: needs an undamaged non-leader ground unit to target.
            $has = false;
            foreach (["myGroundArena", "theirGroundArena"] as $z) {
                foreach (ZoneSearch($z, NonLeaderUnitFilter) as $mz) {
                    $o = GetZoneObject($mz);
                    if ($o !== null && empty($o->removed) && intval($o->Damage ?? 0) === 0) { $has = true; break 2; }
                }
            }
            if (!$has) $ok = false;
            break;
        }
        case 'LAW_094': // Hondo Ohnaka: deck non-empty AND not used this round.
            if (_SWUTopDeckFrontIdx($player) === -1 || GlobalEffectCount($player, 'SWU_LAW094_USED') > 0) $ok = false;
            break;
        case 'SOR_094': // Bail Organa: "Give Experience to ANOTHER friendly unit" — needs one.
            $others = SWUOtherFriendlyUnits($player, $mzID);
            if (empty($others)) $ok = false;
            break;
        case 'SOR_093': // Alliance Dispatcher / Strategic Acumen: play a UNIT from hand at −1.
        case 'TWI_120': // Needs ≥1 hand unit affordable after the discount.
            if (empty(SWUHandPlayablesAtDiscount($player, ['Unit'], 1))) $ok = false;
            break;
        case 'LOF_094': // Jedi Consular — Action [Exhaust, use the Force]: play a unit at −2.
            if (!PlayerHasTheForce($player) || empty(SWUHandPlayablesAtDiscount($player, ['Unit'], 2))) $ok = false;
            break;
        case 'LOF_178': // Adept of Anger — Action [Exhaust, use the Force]: exhaust a unit.
            if (!PlayerHasTheForce($player)) $ok = false;
            break;
        case 'LOF_098': // Action [use the Force]: only while in the SPACE arena + you hold the Force.
            if (!PlayerHasTheForce($player) || strpos((string)$mzID, 'SpaceArena') === false) $ok = false;
            break;
        case 'SOR_177': // Bib Fortuna: play an EVENT from hand at −1.
            if (empty(SWUHandPlayablesAtDiscount($player, ['Event'], 1))) $ok = false;
            break;
        case 'JTL_050': { // Phantom II: attach to The Ghost — needs The Ghost (JTL_053) in play.
            $hasGhost = false;
            foreach (array_merge(GetGroundArena($player) ?? [], GetSpaceArena($player) ?? []) as $u) {
                if (empty($u->removed) && ($u->CardID ?? '') === 'JTL_053') { $hasGhost = true; break; }
            }
            if (!$hasGhost) $ok = false;
            break;
        }
        case 'SOR_110': // Frontline Shuttle: defeat self, then ANOTHER friendly unit attacks
            // a non-base target — needs ≥1 such attacker (excluding the Shuttle itself).
            $self = GetZoneObject($mzID);
            $selfUID = $self ? intval($self->UniqueID ?? -1) : -1;
            if (empty(SWUUnitsWithNonBaseAttackTarget($player, $selfUID))) $ok = false;
            break;
        case 'SOR_184': // Fett's Firespray: "Exhaust a non-unique unit" — needs ≥1 in play.
            if (empty(_SWUNonUniqueUnitTargets($player))) $ok = false;
            break;
        case 'JTL_013': // Poe Dameron hop: once-per-round + needs ≥1 empty Vehicle target (not self).
            if (!SWUHasUseAvailable(SWUGetLeader($player))) { $ok = false; break; }
            $hopTargets = array_values(array_filter(
                array_merge(
                    ZoneSearch("myGroundArena", AnyUnitFilter),
                    ZoneSearch("mySpaceArena",  AnyUnitFilter)
                ),
                function($mz) use ($mzID) {
                    if ($mz === $mzID) return false;
                    $hostObj = GetZoneObject($mz);
                    if ($hostObj === null || !empty($hostObj->removed)) return false;
                    if (!HasTrait($hostObj->CardID ?? '', 'Vehicle')) return false;
                    return SWUVehiclePilotCount($hostObj) === 0;
                }
            ));
            if (empty($hopTargets)) $ok = false;
            break;
    }
    $playerID = $savedPID;
    return $ok;
}

// True if $player controls a card with one of the given titles, as a LEADER (deployed or not),
// a UNIT in an arena, or an UPGRADE attached to a friendly unit (SOR_184 "control Boba Fett or
// Jango Fett (as a leader, unit, or upgrade)"). Title match is exact (CardTitle).
function _SWUControlsTitle(int $player, array $titles): bool {
    foreach (GetLeader($player) as $l) {
        if (empty($l->removed) && in_array(CardTitle($l->CardID ?? ''), $titles, true)) return true;
    }
    foreach (GetUnitsInPlay($player) as $u) {
        if (!empty($u->removed)) continue;
        if (in_array(CardTitle($u->CardID ?? ''), $titles, true)) return true;
        if (is_array($u->Subcards ?? null)) {
            foreach ($u->Subcards as $sub) {
                $scid = is_array($sub) ? ($sub['CardID'] ?? '') : ($sub->CardID ?? '');
                $srem = is_array($sub) ? !empty($sub['removed']) : !empty($sub->removed);
                if (!$srem && in_array(CardTitle($scid), $titles, true)) return true;
            }
        }
    }
    return false;
}

// All NON-unique units in play (both players, both arenas) as mzIDs — SOR_184 "exhaust a non-unique
// unit". Deployed leaders are unique, so they're excluded. Caller sets $playerID.
function _SWUNonUniqueUnitTargets(int $player): array {
    $out = [];
    foreach (['myGroundArena', 'mySpaceArena', 'theirGroundArena', 'theirSpaceArena'] as $z) {
        foreach (ZoneSearch($z, AnyUnitFilter) as $mz) {
            $o = GetZoneObject($mz);
            if ($o === null || !empty($o->removed)) continue;
            if (CardUnique($o->CardID ?? '')) continue;
            $out[] = $mz;
        }
    }
    return $out;
}

// Hand card mzIDs of the given $types whose play cost — after $discount (floored at 0) —
// the player can pay with ready resources. Single source of truth for "play a card from
// hand at −N" actions (SOR_093/TWI_120 units, SOR_177 events): used both by the
// affordability gate and by the ability closures. Caller sets $playerID.
function SWUHandPlayablesAtDiscount(int $player, array $types, int $discount): array {
    $ready = SWUResourceCount($player, readyOnly: true);
    $out = [];
    foreach (ZoneSearch("myHand", $types) as $mz) {
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        $cost = max(0, SWUComputePlayCost($player, $o) - $discount);
        if ($cost <= $ready) $out[] = $mz;
    }
    return $out;
}

// Hand cards (any type) with the Separatist trait whose play cost the player can afford
// with their current ready resources (no discount). Shared by TWI_005 Count Dooku's
// affordability gate and its ability closures (leader side + deployed-unit side).
// Caller must set $playerID before calling.
function _SWUSeparatistHandPlayables(int $player): array {
    $ready = SWUResourceCount($player, readyOnly: true);
    $out = [];
    foreach (ZoneSearch("myHand") as $mz) {
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        if (!HasTrait($o->CardID ?? '', 'Separatist')) continue;
        $cost = SWUComputePlayCost($player, $o);
        if ($cost <= $ready) $out[] = $mz;
    }
    return $out;
}

// Friendly units that could make a non-base attack: those in an arena where the opponent
// has ≥1 unit (attacks are same-arena; "can't attack bases" leaves only enemy units).
// Optionally exclude one unit by UniqueID (the SOR_110 Shuttle, defeated as its cost).
// Caller sets $playerID. Shared by SOR_110's affordability gate and its ability closure.
function SWUUnitsWithNonBaseAttackTarget(int $player, int $excludeUID = -1): array {
    $out = [];
    foreach (['GroundArena', 'SpaceArena'] as $arena) {
        $oppArr = GetZone("their{$arena}");
        $hasEnemyUnit = false;
        foreach ($oppArr as $u) { if ($u !== null && empty($u->removed)) { $hasEnemyUnit = true; break; } }
        if (!$hasEnemyUnit) continue;
        $myArr = GetZone("my{$arena}");
        for ($i = 0; $i < count($myArr); $i++) {
            $u = $myArr[$i];
            if ($u === null || !empty($u->removed)) continue;
            if (intval($u->UniqueID ?? -2) === $excludeUID) continue;
            $out[] = "my{$arena}-{$i}";
        }
    }
    return $out;
}

// All friendly units except the one at $mzID (by UniqueID). Caller sets $playerID.
function SWUOtherFriendlyUnits(int $player, string $mzID): array {
    $self    = GetZoneObject($mzID);
    $selfUID = $self ? intval($self->UniqueID ?? -1) : -1;
    $out = [];
    foreach (array_merge(
        ZoneSearch("myGroundArena", AnyUnitFilter),
        ZoneSearch("mySpaceArena",  AnyUnitFilter)
    ) as $mz) {
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        if (intval($o->UniqueID ?? -2) === $selfUID) continue;
        $out[] = $mz;
    }
    return $out;
}

// Pay the base action cost and dispatch the unit's action ability. Full no-op if the cost
// is unaffordable — the player keeps their action. Base cost is 'exhaust' (requires ready,
// exhausts the unit) by default, or 'defeat' (no ready requirement; the unit is defeated to
// pay — SOR_110). The Exhaust cost-kind requires Status===1; 'defeat' may act while exhausted.
function SWUUnitAction(int $player, string $mzID): void {
    global $playerID, $unitAbilities, $unitActionResourceCosts, $unitActionCostKind;
    $savedPID = $playerID;
    $playerID = $player;

    $obj = GetZoneObject($mzID);
    if ($obj === null || !empty($obj->removed)) {
        $playerID = $savedPID;
        return;
    }
    $provider = SWUGetUnitActionProvider($obj);
    if ($provider === '') {
        $playerID = $savedPID;
        return;
    }
    $costKind = $unitActionCostKind[$provider] ?? 'exhaust';
    if ($costKind === 'exhaust' && intval($obj->Status) !== 1) {
        $playerID = $savedPID;
        return; // not ready → can't pay the Exhaust cost
    }
    if (!SWUUnitActionAffordable($player, $mzID, $provider)) {
        $playerID = $savedPID;
        return;
    }

    // Pay the base cost.
    if ($costKind === 'defeat') {
        SWUDefeatUnit($player, $mzID); // the unit leaves play; closure attacks with another unit
    } elseif ($costKind === 'exhaust') {
        $obj->Status = 0; // exhaust (the default action cost)
    }
    // 'none': no base cost — a pure "Action [N resources]:" ability (no exhaust, no ready needed,
    // repeatable while resources last, e.g. SOR_184 Fett's Firespray). The resource cost is paid below.
    $rc = $unitActionResourceCosts[$provider] ?? 0;
    if ($rc > 0) SWUExhaustResources($player, $rc);

    if (isset($unitAbilities[$provider]) && is_callable($unitAbilities[$provider])) {
        ($unitAbilities[$provider])($player, $mzID);
        // Ability handlers are responsible for calling SWUAfterAction.
    } else {
        SWUAfterAction($player);
    }

    $playerID = $savedPID;
}

// ── Plot (CR §19) ────────────────────────────────────────────────────────────
// "When you deploy a leader, you may play this card from your resource zone by paying its cost,
// replacing it with the top card of your deck." Detection is generated ($Plot_Cards / HasKeyword_Plot);
// only execution lives here. The window is orchestrated through SWUAfterAction (see SWU_PLOT_IN_PROGRESS):
// the deploy arms it, each play re-offers until the player declines or no affordable Plot remains.

// True if the player has at least one Plot card in their resources they can afford right now.
// Affordability uses ready resources (the Plot card itself may pay for it — it counts toward ready
// when ready), including aspect penalties (folded into SWUComputePlayCost).
function PlayerHasPlotsToPlay(int $player): bool {
    global $playerID, $Plot_Cards;
    $saved = $playerID; $playerID = $player;
    $ready = SWUResourceCount($player, readyOnly: true);
    $resources = &GetResources($player);
    $found = false;
    for ($i = 0; $i < count($resources); $i++) {
        if (isset($resources[$i]->removed) && $resources[$i]->removed) continue;
        $cardID = $resources[$i]->CardID ?? '';
        if (!isset($Plot_Cards[$cardID])) continue;
        if (_SWUGalenSuppressesCard($player, $cardID)) continue;   // SEC_046 Galen Erso — named → lost Plot
        if (SWUCardPlayBlocked($player, $cardID)) continue;      // SOR_062 named-card lock
        if (SWUComputePlayCost($player, $resources[$i]) <= $ready) { $found = true; break; }
    }
    $playerID = $saved;
    return $found;
}

// Resource mzIDs (myResources-N) eligible to be played as a Plot this deploy: a Plot card,
// affordable, and inside the original-resources window [0, K-P) so top-of-deck replacements
// appended during this window are not re-offered (CR 19.d).
function _SWUEligiblePlotResources(int $player): array {
    global $playerID, $Plot_Cards;
    $saved = $playerID; $playerID = $player;
    $window = intval(GetSWUVar('SWU_PLOT_K', '0')) - intval(GetSWUVar('SWU_PLOT_P', '0'));
    $ready  = SWUResourceCount($player, readyOnly: true);
    $resources = &GetResources($player);
    $out = [];
    $pos = 0;
    for ($i = 0; $i < count($resources); $i++) {
        if (isset($resources[$i]->removed) && $resources[$i]->removed) continue;
        $here = $pos; $pos++;
        if ($here >= $window) continue;                          // a replacement (CR 19.d) — skip
        $cardID = $resources[$i]->CardID ?? '';
        if (!isset($Plot_Cards[$cardID])) continue;
        if (_SWUGalenSuppressesCard($player, $cardID)) continue;   // SEC_046 Galen Erso — named → lost Plot
        if (SWUCardPlayBlocked($player, $cardID)) continue;
        if (SWUComputePlayCost($player, $resources[$i]) > $ready) continue;
        $out[] = "myResources-{$here}";
    }
    $playerID = $saved;
    return $out;
}

// Replace the just-played Plot card's slot with the top of the deck (enters exhausted, CR 19.c).
// If the deck is empty there is no replacement (and no base damage — CR 19 has no mill).
function _SWUPlotReplaceSlot(int $player): void {
    global $playerID;
    $saved = $playerID; $playerID = $player;
    $deck = &GetDeck($player);
    for ($i = 0; $i < count($deck); $i++) {
        if (isset($deck[$i]->removed) && $deck[$i]->removed) continue;
        $topCardID = $deck[$i]->CardID;
        $deck[$i]->Remove();
        AddResources($player, $topCardID, 0, $player, $player);   // Status 0 = exhausted
        break;
    }
    DecisionQueueController::CleanupRemovedCards();
    $playerID = $saved;
}

// Called from SWUAfterAction while a Plot window is open. If a Plot card was just played, replace its
// slot and count it; then re-offer the next eligible Plot (or close the window).
function _SWUPlotAfterPlay(int $player): void {
    if (GetSWUVar('SWU_PLOT_PENDING_REPLACE', '') === '1') {
        SetSWUVar('SWU_PLOT_PENDING_REPLACE', '');
        _SWUPlotReplaceSlot($player);
        SetSWUVar('SWU_PLOT_P', strval(intval(GetSWUVar('SWU_PLOT_P', '0')) + 1));
    }
    _SWUPlotReoffer($player);
}

// Offer the next Plot (MZMAYCHOOSE over eligible resources). When none remain, close the window and
// run the real After Action (swap the turn — ending the deploy action).
function _SWUPlotReoffer(int $player): void {
    $eligible = _SWUEligiblePlotResources($player);
    if (empty($eligible)) {
        SetSWUVar('SWU_PLOT_IN_PROGRESS', '');
        SetSWUVar('SWU_PLOT_K', '0');
        SetSWUVar('SWU_PLOT_P', '0');
        SetSWUVar('SWU_PLOT_PENDING_REPLACE', '');
        SWUSwapTurnPlayer();
        return;
    }
    global $playerID; $playerID = $player;   // for relative mzID resolution in MZCountChoices
    DecisionQueueController::AddDecision($player, "MZMAYCHOOSE", implode('&', $eligible), 1,
        tooltip: "Play_a_Plot_card_from_your_resources");
    DecisionQueueController::AddDecision($player, "CUSTOM", "PLOT_PLAY", 1);
}

// MZMAYCHOOSE resolver: $lastDecision is the chosen resource mzID, or '-'/'' to decline.
$customDQHandlers["PLOT_PLAY"] = function($player, $parts, $lastDecision) {
    global $playerID;
    $savedPID = $playerID; $playerID = intval($player);
    $ans = $lastDecision ?? '';
    if ($ans === '' || $ans === '-' || $ans === 'PASS') {
        // Declined → close the window and end the deploy action (flag cleared → real swap).
        SetSWUVar('SWU_PLOT_IN_PROGRESS', '');
        SetSWUVar('SWU_PLOT_K', '0');
        SetSWUVar('SWU_PLOT_P', '0');
        SetSWUVar('SWU_PLOT_PENDING_REPLACE', '');
        SWUAfterAction(intval($player));
        $playerID = $savedPID;
        return;
    }
    $resObj = GetZoneObject($ans);
    if ($resObj === null || !empty($resObj->removed)) { _SWUPlotReoffer(intval($player)); $playerID = $savedPID; return; }
    // A Plot is being played: mark for slot-replacement at the next After Action (CR 19.c).
    SetSWUVar('SWU_PLOT_PENDING_REPLACE', '1');
    AddGameLogEntry('PLAY', 'P' . intval($player) . ' plays ' . GameLogCardRef($resObj->CardID) . ' using Plot');
    // Play from resources at full cost (the Plot card may exhaust itself toward its cost). ActivateCard
    // removes it and routes unit/upgrade/event; its terminal After Action is intercepted (window stays open).
    ActivateCard(intval($player), $ans, false);
    _SWUSec008HealOnResourcePlay(intval($player));   // SEC_008 Bail Organa — "play a card from your resources"
    // Do NOT restore $playerID — the upgrade/event paths return without restoring and rely on $playerID
    // staying = $player for MZCountChoices on any decision they queued.
};

// ── Disclose (CR §38) ────────────────────────────────────────────────────────
// "Disclose" reveals any number of hand cards; if their aspect icons collectively cover the required
// icons, the rest of the ability resolves (CR 38.1-2). Otherwise nothing is revealed and the effect
// does not happen (CR 38.3). Optional ("you may disclose") effects simply aren't offered when the
// requirement cannot be met.

// The aspect icons a card shows, as a multiset list (e.g. SEC_054 → ['Vigilance','Vigilance']).
function SWUCardAspectIcons(string $cardID): array {
    $a = CardAspect($cardID);
    if ($a === null || $a === '') return [];
    return array_values(array_filter(array_map('trim', explode(',', $a))));
}

// True if the multiset $have covers the multiset $required (icon counts).
function _SWUAspectsCover(array $have, array $required): bool {
    $pool = [];
    foreach ($have as $x) { $pool[$x] = ($pool[$x] ?? 0) + 1; }
    foreach ($required as $r) {
        if (($pool[$r] ?? 0) <= 0) return false;
        $pool[$r]--;
    }
    return true;
}

// Can the player's hand collectively disclose the required aspect icons?
function PlayerCanDisclose(int $player, array $required): bool {
    if (empty($required)) return true;
    // Resolve the hand mzIDs UNDER $player — keep $playerID = $player across the whole loop, since
    // GetZoneObject("myHand-N") resolves "my" against the ambient $playerID. Restoring before the loop
    // (the old bug) read the caller's hand when $player != the ambient $playerID — e.g. SEC_038 Condemn,
    // whose disclose belongs to the DEFENDER but fires under the ATTACKER's $playerID.
    global $playerID; $saved = $playerID; $playerID = $player;
    $hand = ZoneSearch("myHand");
    $have = [];
    foreach ($hand as $mz) {
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        $have = array_merge($have, SWUCardAspectIcons($o->CardID ?? ''));
    }
    $playerID = $saved;
    return _SWUAspectsCover($have, $required);
}

// Queue an optional disclose over the player's hand. If the requirement can't be met it's not offered
// (CR 38.3). On a covering selection the chosen cards are revealed (logged; they stay in hand) and
// $thenHandler (a CUSTOM handler string, e.g. "DRAW_CARD|1") is dispatched. The server re-validates
// coverage on the answer, so a client can't bypass the requirement.
// $elseHandler (optional): a CUSTOM handler queued when the player CAN'T meet the requirement or
// DECLINES it — for "you may disclose X; if you DON'T, <penalty>" cards (SEC_164). It is encoded into
// the resolver token after a "@@ELSE@@" sentinel (neither handler may contain that literal).
function SWUQueueDisclose(int $player, array $required, string $thenHandler, string $tooltip, string $elseHandler = ''): void {
    if (!PlayerCanDisclose($player, $required)) {
        if ($elseHandler !== '') DecisionQueueController::AddDecision($player, "CUSTOM", $elseHandler, 1);
        return;
    }
    // Compact any removed-but-not-cleaned cards (e.g. the event/unit that triggered this disclose was
    // just removed from hand) so the offered hand mzIDs match what they resolve to at answer time.
    DecisionQueueController::CleanupRemovedCards();
    global $playerID; $saved = $playerID; $playerID = $player;
    $hand = ZoneSearch("myHand");
    $playerID = $saved;
    if (empty($hand)) {
        if ($elseHandler !== '') DecisionQueueController::AddDecision($player, "CUSTOM", $elseHandler, 1);
        return;
    }
    if ($elseHandler !== '') $thenHandler = $thenHandler . '@@ELSE@@' . $elseHandler;
    $reqCSV = implode(',', $required);
    // The "~REQ~aspects" tooltip suffix carries the required icons to the client so the popup can gate
    // its Confirm on aspect coverage (window.aspectData supplies each candidate's icons). The popup
    // strips it for display; the server never parses the tooltip semantically. The server re-validates
    // coverage in DISCLOSE_RESOLVE regardless, so this is purely a client-UX side channel.
    $discloseTooltip = $tooltip . "~REQ~" . implode('-', $required);
    DecisionQueueController::AddDecision($player, "MZMULTICHOOSE", "0|" . count($hand) . "|" . implode('&', $hand),
        1, tooltip: $discloseTooltip);
    DecisionQueueController::AddDecision($player, "CUSTOM", "DISCLOSE_RESOLVE|{$reqCSV}|{$thenHandler}", 1);
}

// Validates the disclosed selection and dispatches the "if you do" effect.
$customDQHandlers["DISCLOSE_RESOLVE"] = function($player, $parts, $lastDecision) {
    global $playerID; $playerID = intval($player);
    $required    = array_values(array_filter(explode(',', $parts[0] ?? '')));
    $combined    = implode('|', array_slice($parts, 1));   // handler may carry '|'-delimited args
    $hb          = explode('@@ELSE@@', $combined);          // optional "if you don't" handler
    $thenHandler = $hb[0];
    $elseHandler = $hb[1] ?? '';
    $selected = ($lastDecision !== null && $lastDecision !== '-' && $lastDecision !== '' && $lastDecision !== 'PASS')
        ? array_values(array_filter(explode('&', $lastDecision)))
        : [];
    $have = [];
    foreach ($selected as $mz) {
        $o = GetZoneObject($mz);
        if ($o === null || !empty($o->removed)) continue;
        $have = array_merge($have, SWUCardAspectIcons($o->CardID ?? ''));
    }
    if (empty($selected) || !_SWUAspectsCover($have, $required)) {   // declined / insufficient (CR 38.3)
        if ($elseHandler !== '') DecisionQueueController::AddDecision(intval($player), "CUSTOM", $elseHandler, 1);
        return;
    }
    foreach ($selected as $mz) {
        $o = GetZoneObject($mz);
        if ($o !== null) AddGameLogEntry('DISCLOSE', 'P' . intval($player) . ' discloses ' . GameLogCardRef($o->CardID ?? ''));
    }
    // SEC_016 Padmé Amidala — disclosing reveals cards from hand ("reveal 1 or more cards from your hand").
    if (function_exists('_SWUSec016React')) _SWUSec016React(intval($player));
    if ($thenHandler !== '') DecisionQueueController::AddDecision(intval($player), "CUSTOM", $thenHandler, 1);
};

// Play a card from the player's resource zone using Smuggle (CR 8.22).
// $resourceIdx is the 0-based index into the player's non-removed Resources entries.
function SWUSmuggleResource(int $player, int $resourceIdx): void {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;

    // Locate the resource at the given logical index.
    $resources = &GetResources($player);
    $actualIdx = -1;
    $count = 0;
    for ($i = 0; $i < count($resources); $i++) {
        if (isset($resources[$i]->removed) && $resources[$i]->removed) continue;
        if (SWUIsCreditToken($resources[$i]->CardID ?? '')) continue; // Credit tokens aren't smugglable resources
        if ($count === $resourceIdx) { $actualIdx = $i; break; }
        $count++;
    }

    if ($actualIdx === -1) {
        SetFlashMessage("Invalid resource index.");
        $playerID = $savedPID;
        return;
    }

    $resourceObj = $resources[$actualIdx];
    $cardID      = $resourceObj->CardID;

    // SOR_062 Regional Governor: an opponent's named card can't be played, including via Smuggle.
    if (SWUCardPlayBlocked(intval($player), $cardID)) {
        SetFlashMessage("That card can't be played (named by an opponent).");
        $playerID = $savedPID;
        return;
    }

    // SEC_046 Galen Erso — if the enemy Galen named this card, it has lost Smuggle (and all abilities).
    if (_SWUGalenSuppressesCard($player, $cardID)) {
        SetFlashMessage("That card doesn't have Smuggle.");
        $playerID = $savedPID;
        return;
    }
    // Determine effective cost: min(native Smuggle path, Tech path), factoring in aspect penalties.
    $totalCost = GetEffectiveSmuggleCost($player, $cardID);
    if ($totalCost < 0) {
        SetFlashMessage("That card doesn't have Smuggle.");
        $playerID = $savedPID;
        return;
    }

    // CR 8.22.e: the card can exhaust itself toward payment while still in resources.
    // SWUExhaustResources exhausts ready resources in order, so it naturally includes the card.
    $exhaustOk = SWUExhaustResources($player, $totalCost);
    if (!$exhaustOk) {
        SetFlashMessage("Not enough ready resources (need {$totalCost}).");
        $playerID = $savedPID;
        return;
    }

    AddGlobalEffects(intval($player), 'SWU_CARDS_PLAYED');  // playing via Smuggle counts
    // Remove card from resources zone (it has now been exhausted above).
    $resources[$actualIdx]->Remove();

    // CR 8.22.g: replace the slot with the top card of the deck (enters exhausted).
    // If deck is empty, no replacement and no base damage (CR 8.22.h).
    $deck = &GetDeck($player);
    for ($i = 0; $i < count($deck); $i++) {
        if (isset($deck[$i]->removed) && $deck[$i]->removed) continue;
        $topCardID = $deck[$i]->CardID;
        $deck[$i]->Remove();
        AddResources($player, $topCardID, 0, $player, $player); // Status 0 = exhausted
        break;
    }

    // CR 8.22.f: unit enters play exhausted.
    $targetArena = CardTargetArena($cardID);
    $uid = NextUniqueID();
    if ($targetArena === 'SpaceArena') {
        $newCard = AddSpaceArena($player, CardID:$cardID, Status:0,
            Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
    } else {
        $newCard = AddGroundArena($player, CardID:$cardID, Status:0,
            Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
    }

    // CR 8.22.f: WhenPlayed and other entry triggers fire just as for normal play.
    $newCardMzID = $newCard->GetMzID();
    _SWUSec008HealOnResourcePlay($player);   // SEC_008 Bail Organa — "play a card from your resources"
    $triggered   = CollectEntryTriggers($player, $cardID, $newCardMzID, $targetArena);

    if ($triggered === 0) {
        DecisionQueueController::CleanupRemovedCards();
        SWUAfterAction($player);
    }

    $playerID = $savedPID;
}

function SWUPlayFromDiscard(int $player, int $discardIdx): void {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;

    $discard  = &GetDiscard($player);
    $actualIdx = -1;
    $count = 0;
    for ($i = 0; $i < count($discard); $i++) {
        if (isset($discard[$i]->removed) && $discard[$i]->removed) continue;
        if ($count === $discardIdx) { $actualIdx = $i; break; }
        $count++;
    }
    if ($actualIdx === -1) {
        SetFlashMessage("Invalid discard index.");
        $playerID = $savedPID;
        return;
    }

    $entry    = $discard[$actualIdx];
    $cardID   = $entry->CardID;
    $modifier = $entry->Modifier ?? '';

    if ($modifier !== 'TPF' && $modifier !== 'TPP') {
        SetFlashMessage("That card cannot be played from discard this phase.");
        $playerID = $savedPID;
        return;
    }

    // SOR_062 Regional Governor: an opponent's named card can't be played, including from discard.
    if (SWUCardPlayBlocked(intval($player), $cardID)) {
        SetFlashMessage("That card can't be played (named by an opponent).");
        $playerID = $savedPID;
        return;
    }

    // Upgrades (LAW_200 Salvaged Blaster) attach to a host — route through ActivateCard, which offers the
    // host choice and pays/removes the upgrade via ATTACH_UPGRADE. TPF → free (ignoreCost); TPP → at cost.
    // On a failed attach (no valid host / unaffordable) the upgrade stays in discard with its modifier.
    if (strpos(CardType($cardID), 'Upgrade') !== false) {
        ActivateCard($player, "myDiscard-{$actualIdx}", $modifier === 'TPF');
        $playerID = $savedPID;
        return;
    }

    if ($modifier === 'TPP') {
        $cost = intval(CardCost($cardID)) + SWUAspectPenalty($player, $cardID);
        if (!SWUExhaustResources($player, $cost)) {
            SetFlashMessage("Not enough ready resources.");
            $playerID = $savedPID;
            return;
        }
        // Task 5.1: stamp resources paid for TWI_210 observer (at-cost play = full cost paid).
        $GLOBALS['gLastPlayResourcesPaid'] = $cost;
    } else {
        // TPF = free play from discard (e.g. The Power of the Force) → 0 resources paid.
        $GLOBALS['gLastPlayResourcesPaid'] = 0;
    }

    AddGlobalEffects(intval($player), 'SWU_CARDS_PLAYED');  // playing from discard counts
    $entry->removed = true;
    $targetArena = CardTargetArena($cardID);
    $uid = NextUniqueID();
    if ($targetArena === 'SpaceArena') {
        $newCard = AddSpaceArena($player, CardID:$cardID, Status:0,
            Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
    } else {
        $newCard = AddGroundArena($player, CardID:$cardID, Status:0,
            Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
    }
    $newCardMzID = $newCard->GetMzID();

    global $gPendingEntryEffects;
    if (isset($gPendingEntryEffects[$uid])) {
        foreach ($gPendingEntryEffects[$uid] as $effect) {
            AddTurnEffect($newCardMzID, $effect);
        }
        unset($gPendingEntryEffects[$uid]);
    }

    SWUApplyPassiveEntryGrants($player, $cardID, $newCardMzID);
    $triggered = CollectEntryTriggers($player, $cardID, $newCardMzID, $targetArena);
    if ($triggered === 0) {
        DecisionQueueController::CleanupRemovedCards();
        SWUAfterAction($player);
    }

    $playerID = $savedPID;
}

// Effect-driven play of a SPECIFIC discard card at a discount (SOR_102 Home One: "Play a [Heroism]
// unit from your discard pile. It costs 3 less."). Mirrors SWUPlayFromDiscard's placement but bypasses
// the player-initiated Modifier (TPF/TPP) gate and applies $discount. Returns the new unit's
// owner-relative mzID ('' on failure) — callers that only need a success flag can treat it as bool
// ('' is falsy). JTL_121 Salvage uses the returned mzID to deal 1 damage to the played unit.
// Does NOT call SWUAfterAction — the caller's play flow (the source's WhenPlayed) owns the action.
function SWUPlayDiscardUnitDiscounted(int $player, int $discardIdx, int $discount): string {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;
    $discard = &GetDiscard($player);
    $actualIdx = -1; $count = 0;
    for ($i = 0; $i < count($discard); $i++) {
        if (!empty($discard[$i]->removed)) continue;
        if ($count === $discardIdx) { $actualIdx = $i; break; }
        $count++;
    }
    if ($actualIdx === -1) { $playerID = $savedPID; return ''; }
    $entry  = $discard[$actualIdx];
    $cardID = $entry->CardID;
    if (SWUCardPlayBlocked($player, $cardID)) { $playerID = $savedPID; return ''; }
    $cost = max(0, intval(CardCost($cardID)) + SWUAspectPenalty($player, $cardID) - $discount);
    if ($cost > 0 && !SWUExhaustResources($player, $cost)) { $playerID = $savedPID; return ''; }
    $GLOBALS['gLastPlayResourcesPaid'] = $cost;
    AddGlobalEffects($player, 'SWU_CARDS_PLAYED');
    $entry->removed = true;
    $targetArena = CardTargetArena($cardID);
    $uid = NextUniqueID();
    if ($targetArena === 'SpaceArena') {
        $newCard = AddSpaceArena($player, CardID:$cardID, Status:0, Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
    } else {
        $newCard = AddGroundArena($player, CardID:$cardID, Status:0, Owner:$player, Damage:0, Controller:$player, UniqueID:$uid);
    }
    $newCardMzID = $newCard->GetMzID();
    global $gPendingEntryEffects;
    if (isset($gPendingEntryEffects[$uid])) {
        foreach ($gPendingEntryEffects[$uid] as $effect) AddTurnEffect($newCardMzID, $effect);
        unset($gPendingEntryEffects[$uid]);
    }
    SWUApplyPassiveEntryGrants($player, $cardID, $newCardMzID);
    CollectEntryTriggers($player, $cardID, $newCardMzID, $targetArena);
    $playerID = $savedPID;
    return $newCardMzID;
}

function SWUPlayFromOpponentDiscard(int $player, int $discardIdx): void {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;

    $opponent  = OtherPlayer($player);
    $discard   = &GetDiscard($opponent);
    $actualIdx = -1;
    $count = 0;
    for ($i = 0; $i < count($discard); $i++) {
        if (isset($discard[$i]->removed) && $discard[$i]->removed) continue;
        if ($count === $discardIdx) { $actualIdx = $i; break; }
        $count++;
    }
    if ($actualIdx === -1) {
        SetFlashMessage("Invalid discard index.");
        $playerID = $savedPID;
        return;
    }

    $entry    = $discard[$actualIdx];
    $cardID   = $entry->CardID;
    $modifier = $entry->Modifier ?? '';

    if ($modifier !== 'OTPF' && $modifier !== 'OTPP' && $modifier !== 'OTPN') {
        SetFlashMessage("That card cannot be played from opponent's discard this phase.");
        $playerID = $savedPID;
        return;
    }

    // SOR_062 Regional Governor: an opponent's named card can't be played, including from a discard.
    if (SWUCardPlayBlocked(intval($player), $cardID)) {
        SetFlashMessage("That card can't be played (named by an opponent).");
        $playerID = $savedPID;
        return;
    }

    AddGlobalEffects(intval($player), 'SWU_CARDS_PLAYED');  // playing from opponent's discard counts
    if ($modifier === 'OTPP' || $modifier === 'OTPN') {
        // OTPP = at cost (with aspect penalty); OTPN = at cost, IGNORING aspect penalties (SEC_205).
        $cost = intval(CardCost($cardID)) + ($modifier === 'OTPN' ? 0 : SWUAspectPenalty($player, $cardID));
        if (!SWUExhaustResources($player, $cost)) {
            SetFlashMessage("Not enough ready resources.");
            $playerID = $savedPID;
            return;
        }
        // Task 5.1: stamp resources paid for TWI_210 observer (at-cost play = full cost paid).
        $GLOBALS['gLastPlayResourcesPaid'] = $cost;
    } else {
        // OTPF = free play from opponent's discard → 0 resources paid.
        $GLOBALS['gLastPlayResourcesPaid'] = 0;
    }

    $entry->removed = true;
    $targetArena = CardTargetArena($cardID);
    $uid = NextUniqueID();
    if ($targetArena === 'SpaceArena') {
        $newCard = AddSpaceArena($player, CardID:$cardID, Status:0,
            Owner:$opponent, Damage:0, Controller:$player, UniqueID:$uid);
    } else {
        $newCard = AddGroundArena($player, CardID:$cardID, Status:0,
            Owner:$opponent, Damage:0, Controller:$player, UniqueID:$uid);
    }
    $newCardMzID = $newCard->GetMzID();

    global $gPendingEntryEffects;
    if (isset($gPendingEntryEffects[$uid])) {
        foreach ($gPendingEntryEffects[$uid] as $effect) {
            AddTurnEffect($newCardMzID, $effect);
        }
        unset($gPendingEntryEffects[$uid]);
    }

    SWUApplyPassiveEntryGrants($player, $cardID, $newCardMzID);
    $triggered = CollectEntryTriggers($player, $cardID, $newCardMzID, $targetArena);
    if ($triggered === 0) {
        DecisionQueueController::CleanupRemovedCards();
        SWUAfterAction($player);
    }

    $playerID = $savedPID;
}

function SWUComputeActionsData(int $player): array {
    global $baseAbilities, $baseActionNumUses, $baseActionRepeatable;

    $isMain   = (GetCurrentPhase() === 'MAIN');
    $isMyTurn = (intval(GetTurnPlayer()) === $player);
    $dq       = new DecisionQueueController();
    $dqEmpty  = $dq->AllQueuesEmpty();
    $active   = $isMain && $isMyTurn && $dqEmpty;

    $data = [
        'leaderAbility'       => false,
        'leaderDeploy'        => false,
        'baseEpic'            => false,
        'unitActions'         => [],
        'attackers'           => [],
        'smugglableResources' => [],
        'readyResources'      => 0,
    ];

    if (!$active) return $data;

    // Leader
    $leaderObj = SWUGetLeader($player);
    if ($leaderObj !== null) {
        $ready    = (bool)($leaderObj->Ready ?? false);
        $deployed = (bool)($leaderObj->Deployed ?? false);
        $epicUsed = (bool)($leaderObj->EpicActionUsed ?? false);
        $data['leaderAbility'] = $ready && !$deployed
            && SWULeaderActionAffordable($player, $leaderObj->CardID ?? '');
        if (($leaderObj->CardID ?? '') === 'JTL_014') {
            // Trench: non-epic repeatable deploy — ready, control 6+ resources, 3 ready resources.
            $data['leaderDeploy'] = $ready && !$deployed
                && SWUResourceCount($player) >= 6
                && SWUResourceCount($player, readyOnly: true) >= 3;
        } else {
            $data['leaderDeploy']  = !$epicUsed && !$deployed
                && SWUResourceCount($player) >= intval(CardCost($leaderObj->CardID ?? ''));
        }
    }

    // Base — has an available action if registered in $baseAbilities. Repeatable-action bases
    // (LOF_022) are gated by remaining NumUses; standard epic bases by EpicActionUsed.
    $baseArr = GetBase($player);
    foreach ($baseArr as $b) {
        if (isset($b->removed) && $b->removed) continue;
        $bCardID = $b->CardID ?? '';
        if (isset($baseActionRepeatable[$bCardID])) {
            // Repeatable card-cost action (LOF_028): available iff the cost can be paid (a ready friendly unit).
            $hasReady = false;
            foreach (array_merge(GetGroundArena($player), GetSpaceArena($player)) as $ru) {
                if ($ru === null || !empty($ru->removed)) continue;
                if (intval($ru->Status ?? 0) === 1) { $hasReady = true; break; }
            }
            $data['baseEpic'] = $hasReady && isset($baseAbilities[$bCardID]);
        } elseif (isset($baseActionNumUses[$bCardID])) {
            $data['baseEpic'] = _SWUBaseActionUsesLeft($b, $bCardID) > 0 && isset($baseAbilities[$bCardID]);
        } else {
            $epicUsed = (bool)($b->EpicActionUsed ?? false);
            $data['baseEpic'] = !$epicUsed && isset($baseAbilities[$bCardID]);
        }
        break; // only one live base per player
    }

    // Unit activated abilities — ready arena units (own or upgrade-granted) with an
    // affordable action. mzIDs are player-relative ("myGroundArena-N").
    global $unitActionCostKind;
    foreach (['GroundArena' => GetGroundArena($player), 'SpaceArena' => GetSpaceArena($player)] as $arenaName => $arr) {
        for ($i = 0; $i < count($arr); $i++) {
            $u = $arr[$i];
            if ($u === null || !empty($u->removed)) continue;
            $provider = SWUGetUnitActionProvider($u);
            if ($provider === '') continue;
            // Exhaust-cost actions need a ready unit; 'defeat'-cost actions (SOR_110) may act
            // while exhausted, so don't gate those on Status.
            $costKind = $unitActionCostKind[$provider] ?? 'exhaust';
            if ($costKind === 'exhaust' && intval($u->Status) !== 1) continue;
            $mz = "my{$arenaName}-{$i}";
            if (SWUUnitActionAffordable($player, $mz, $provider)) $data['unitActions'][] = $mz;
        }
    }

    // Attacker glow — friendly units that could declare an attack right now (ready + ≥1 valid target).
    // Purely the green "can attack" highlight; the attack itself is the framework unit-click. Set
    // $playerID = $player so SWUGetValidAttackTargets resolves the "their{arena}" frame correctly.
    global $playerID; $savedAtkPID = $playerID; $playerID = $player;
    foreach (['GroundArena' => GetGroundArena($player), 'SpaceArena' => GetSpaceArena($player)] as $arenaName => $arr) {
        for ($i = 0; $i < count($arr); $i++) {
            if (_SWUUnitCanAttackNow($player, $arr[$i], $arenaName)) $data['attackers'][] = "my{$arenaName}-{$i}";
        }
    }
    $playerID = $savedAtkPID;

    // Any-player-usable unit actions (LAW_156 Hunter For Hire) — also surface them on the OPPONENT's
    // units, as "their{Arena}-N" (SWUUnitAction has no controller gate, so the live click resolves).
    global $anyPlayerUnitActions;
    $oppAP = OtherPlayer($player);
    foreach (['GroundArena' => GetGroundArena($oppAP), 'SpaceArena' => GetSpaceArena($oppAP)] as $arenaName => $arr) {
        for ($i = 0; $i < count($arr); $i++) {
            $u = $arr[$i];
            if ($u === null || !empty($u->removed)) continue;
            $provider = SWUGetUnitActionProvider($u);
            if ($provider === '' || empty($anyPlayerUnitActions[$provider])) continue;
            $mz = "their{$arenaName}-{$i}";
            if (SWUUnitActionAffordable($player, $mz, $provider)) $data['unitActions'][] = $mz;
        }
    }

    // Resources — two passes: count ready first, then check affordability
    $resources  = GetResources($player);
    $readyCount = 0;
    $allCards   = [];
    $logical    = 0;
    foreach ($resources as $r) {
        if (isset($r->removed) && $r->removed) continue;
        if (SWUIsCreditToken($r->CardID ?? '')) continue; // Credit tokens aren't resources / not smugglable
        if (intval($r->Status) === 1) $readyCount++;
        $allCards[] = ['idx' => $logical, 'cardID' => $r->CardID];
        $logical++;
    }
    $data['readyResources'] = $readyCount;
    foreach ($allCards as $c) {
        $cost = GetEffectiveSmuggleCost($player, $c['cardID']);
        if ($cost >= 0 && $readyCount >= $cost) { // -1 = no Smuggle path for this card
            $data['smugglableResources'][] = $c['idx'];
        }
    }

    $playableDiscards = [];
    $myDiscard = GetDiscard($player);
    $di = 0;
    for ($i = 0; $i < count($myDiscard); $i++) {
        if (isset($myDiscard[$i]->removed) && $myDiscard[$i]->removed) continue;
        $mod = $myDiscard[$i]->Modifier ?? '';
        if ($mod === 'TPF') {
            $playableDiscards[] = ['idx' => $di, 'free' => true];
        } elseif ($mod === 'TPP') {
            $dCost = intval(CardCost($myDiscard[$i]->CardID)) + SWUAspectPenalty($player, $myDiscard[$i]->CardID);
            if ($readyCount >= $dCost) $playableDiscards[] = ['idx' => $di, 'free' => false];
        }
        $di++;
    }
    $data['playableDiscards'] = $playableDiscards;

    $opponentPlayableDiscards = [];
    $oppPlayer = OtherPlayer($player);
    $oppDiscard = GetDiscard($oppPlayer);
    $odi = 0;
    for ($i = 0; $i < count($oppDiscard); $i++) {
        if (isset($oppDiscard[$i]->removed) && $oppDiscard[$i]->removed) continue;
        $mod = $oppDiscard[$i]->Modifier ?? '';
        if ($mod === 'OTPF') {
            $opponentPlayableDiscards[] = ['idx' => $odi, 'free' => true];
        } elseif ($mod === 'OTPP') {
            $dCost = intval(CardCost($oppDiscard[$i]->CardID)) + SWUAspectPenalty($player, $oppDiscard[$i]->CardID);
            if ($readyCount >= $dCost) $opponentPlayableDiscards[] = ['idx' => $odi, 'free' => false];
        }
        $odi++;
    }
    $data['opponentPlayableDiscards'] = $opponentPlayableDiscards;

    // Hand cards playable via alternate cost (glow even when readyResources < normal cost).
    global $hasAlternateCostCards;
    $alternateCostHand = [];
    $myHand = GetHand($player);
    $hIdx   = 0;
    foreach ($myHand as $h) {
        if (!empty($h->removed)) continue;
        $hID = $h->CardID ?? '';
        if (isset($hasAlternateCostCards[$hID]) && SWUCheckAlternateCost($player, $hID)) {
            $alternateCostHand[] = $hIdx;
        }
        $hIdx++;
    }
    $data['alternateCostHand'] = $alternateCostHand;
    $data['pilotPlayableHand'] = SWUComputePilotPlayableHand($player);

    return $data;
}

// Returns the array of hand indices (0-based, RAW array indices including removed
// tombstones) for cards in $player's hand that are playable via the Piloting upgrade
// path: they have the Piloting keyword AND SWUGetPilotValidTargets returns at least
// one eligible Vehicle.
//
// Index convention: indices match the raw hand array position — the same space used by
// GetZoneObject("myHand-N") and ActionMap/PlayHand. Removed tombstone slots are counted
// (pIdx is incremented on removed entries) so that index N here maps to the same physical
// hand slot as PlayHand:N. Note: the sibling alternateCostHand list in SWUComputeActionsData
// uses a live-only (non-removed) index space — that is a pre-existing discrepancy; do NOT
// change this function to match it.
//
// Unlike SWUComputeActionsData this function has no $active guard — it is safe to call
// outside the normal action window (e.g. from the test assertion layer).
function SWUComputePilotPlayableHand(int $player): array {
    global $playerID;
    $savedPID = $playerID;
    $playerID = $player;      // Prophylactic pin: SWUComputePilotCost and SWUPilotCanAttach
                               // may do their own relative ("my*") zone lookups via $playerID.
                               // Pinning here ensures they resolve under the correct player
                               // when this function is called outside a normal action window.
    $pilotPlayableHand = [];
    $pIdx = 0;
    foreach (GetHand($player) as $h) {
        if (!empty($h->removed)) { $pIdx++; continue; }
        $hID = $h->CardID ?? '';
        if ($hID !== '' && HasKeyword_Piloting($h) && !empty(SWUGetPilotValidTargets($player, $hID))) {
            $pilotPlayableHand[] = $pIdx;
        }
        $pIdx++;
    }
    $playerID = $savedPID;
    return $pilotPlayableHand;
}

