};

/**
 * Resolves a Glimpse decision. Called after the player submits their MZREARRANGE choice.
 * $lastDecision is the serialized pile string, e.g. "Top=cardA;Bottom=cardB,cardC".
 * Cards in the "Top" pile are placed on top of the deck (in order).
 * Cards in the "Bottom" pile are placed on the bottom of the deck (in order).
 */
$customDQHandlers["GlimpseApply"] = function($player, $parts, $lastDecision) {
    $zone = &GetDeck($player);
    $n = intval(DecisionQueueController::GetVariable("glimpseCount"));
    $fromTempZone = DecisionQueueController::GetVariable("glimpsedToTempZone") === "1";

    // Parse the MZREARRANGE result into piles
    $piles = ["Top" => [], "Bottom" => []];
    $pileStrings = explode(";", $lastDecision);
    foreach($pileStrings as $pileStr) {
        $eqPos = strpos($pileStr, "=");
        if($eqPos === false) continue;
        $pileName = substr($pileStr, 0, $eqPos);
        $cardsStr = trim(substr($pileStr, $eqPos + 1));
        $pidList = ($cardsStr !== "") ? explode(",", $cardsStr) : [];
        $piles[$pileName] = $pidList;
    }

    if($fromTempZone) {
        // Cards were moved to myTempZone by Glimpse() for face-up display
        // Collect their objects and build a cardIDâ†’object map
        $tempZone = &GetTempZone($player);
        $tempObjs = [];
        for($i = 0; $i < count($tempZone); ++$i) {
            if(!$tempZone[$i]->removed) {
                $tempObjs[] = $tempZone[$i];
            }
        }
        $tCardMap = [];
        foreach($tempObjs as $obj) {
            $tCardMap[$obj->CardID][] = $obj;
        }
        $popTCard = function($cardID) use (&$tCardMap) {
            if(empty($tCardMap[$cardID])) return null;
            return array_shift($tCardMap[$cardID]);
        };
        // Remove all tempzone objects cleanly
        foreach($tempObjs as $obj) { $obj->Remove(); }
        DecisionQueueController::CleanupRemovedCards();

        // Top pile: add to deck front (reverse iterate preserves original order)
        $topCards = $piles["Top"];
        for($i = count($topCards) - 1; $i >= 0; --$i) {
            $newObj = new Deck($topCards[$i], 'Deck', $player);
            array_unshift($zone, $newObj);
        }
        // Bottom pile: add to deck back
        foreach($piles["Bottom"] as $cid) {
            $newObj = new Deck($cid, 'Deck', $player);
            $zone[] = $newObj;
        }
        return;
    }

    // Original deck-top path: remove top N cards and re-insert per player choice
    $removedCards = [];
    for($i = 0; $i < $n; ++$i) {
        if(count($zone) > 0) {
            $removedCards[] = array_shift($zone);
        }
    }

    // Build a map from cardID to the actual card object
    $cardMap = [];
    foreach($removedCards as $cardObj) {
        // A deck can have duplicates; map each ID to an array of objects
        $cardMap[$cardObj->CardID][] = $cardObj;
    }
    // Helper to pop one card object by ID from the map
    $popCard = function($cardID) use (&$cardMap) {
        if(!isset($cardMap[$cardID]) || count($cardMap[$cardID]) === 0) return null;
        return array_shift($cardMap[$cardID]);
    };

    // Put "Top" pile cards at the front of the deck (reverse-iterate to preserve order)
    $topCards = $piles["Top"];
    for($i = count($topCards) - 1; $i >= 0; --$i) {
        $obj = $popCard($topCards[$i]);
        if($obj !== null) array_unshift($zone, $obj);
    }

    // Put "Bottom" pile cards at the back of the deck (in order)
    $bottomCards = $piles["Bottom"];
    foreach($bottomCards as $cardID) {
        $obj = $popCard($cardID);
        if($obj !== null) array_push($zone, $obj);
    }
};

$customDQHandlers["CosmicAstroscopeGlimpse"] = function($player, $parts, $lastDecision) {
    $targetPlayer = intval($parts[0] ?? 0);
    $originalAmount = intval($parts[1] ?? 0);
    if($targetPlayer < 1) return;
    Glimpse($targetPlayer, $lastDecision === "YES" ? 3 : $originalAmount, false);
};

/**
 * Starcalling offer handler: player either chose a card to starcall or passed.
 * If they chose a card, pay its starcalling cost, put ALL other glimpsed cards
 * on the bottom of the deck, then activate the starcalled card.
 * If they passed, fall back to normal Glimpse rearrange.
 */
$customDQHandlers["StarcallingOffer"] = function($player, $parts, $lastDecision) {
    $n = intval(DecisionQueueController::GetVariable("glimpseCount"));
    $tempBaseIndex = intval(DecisionQueueController::GetVariable("glimpseTempBaseIndex"));
    $cardIDsStr = DecisionQueueController::GetVariable("glimpseCardIDs");
    $cardIDs = explode(",", $cardIDsStr);

    if($lastDecision === "-" || $lastDecision === "" || $lastDecision === "PASS") {
        // Player declined starcalling â€” check for aethercalling candidates before rearranging
        $aethercallStr = DecisionQueueController::GetVariable("aethercallCandidates");
        if(!empty($aethercallStr)) {
            $aethercallIndices = array_map('intval', explode(",", $aethercallStr));
            // Filter to indices that are still valid (cards still in tempzone)
            $validIndices = [];
            foreach($aethercallIndices as $idx) {
                $tObj = GetZoneObject("myTempZone-" . ($tempBaseIndex + $idx));
                if($tObj !== null && !$tObj->removed) $validIndices[] = $idx;
            }
            if(!empty($validIndices)) {
                $candidateStr = implode("&", array_map(fn($i) => "myTempZone-" . ($tempBaseIndex + $i), $validIndices));
                DecisionQueueController::AddDecision($player, "MZMAYCHOOSE", $candidateStr, 1, "Load_into_Aetherwing?");
                // Must run even if player passes/auto-passes so glimpse flow continues.
                DecisionQueueController::AddDecision($player, "CUSTOM", "AethercallingOffer", 1, "", 1);
                return;
            }
        }
        // No aethercalling â€” cards are in tempzone; GlimpseApply will recover them
        $param = "Top=" . implode(",", $cardIDs) . ";Bottom=";
        DecisionQueueController::StoreVariable("glimpsedToTempZone", "1"); // ensure flag is set
        DecisionQueueController::AddDecision($player, "MZREARRANGE", $param, 1, "Glimpse:_Top=return_to_top,_Bottom=put_on_bottom");
        DecisionQueueController::AddDecision($player, "CUSTOM", "GlimpseApply", 1);
        return;
    }

    // Player chose a card to starcall â€” lastDecision is e.g. "myTempZone-2"
    $tmpParts = explode("-", $lastDecision);
    $chosenTempIndex = intval($tmpParts[1]); // absolute tempzone index
    $chosenRelativeIndex = $chosenTempIndex - $tempBaseIndex;
    if($chosenRelativeIndex < 0 || $chosenRelativeIndex >= count($cardIDs)) return;
    $chosenCardID = $cardIDs[$chosenRelativeIndex];
    $starcallingCost = GetStarcallingCost($player, $chosenCardID);

    // Consume free starcalling if applicable
    $usedFreeStarcalling = false;
    if($starcallingCost == 0 && GlobalEffectCount($player, "FREE_STARCALLING") > 0) {
        // Arisanna L3 (q3huqj5bba): once per turn
        if(GlobalEffectCount($player, "ARISANNA_FREE_STARCALLING") > 0) {
            RemoveGlobalEffect($player, "ARISANNA_FREE_STARCALLING");
            RemoveGlobalEffect($player, "FREE_STARCALLING");
            $usedFreeStarcalling = true;
        }
        // Elysian Astrolabe (4nmxqsm4o9): until end of turn, unlimited
        if(GlobalEffectCount($player, "ASTROLABE_FREE_STARCALLING") > 0) {
            $usedFreeStarcalling = true;
            DecisionQueueController::StoreVariable("astrolabeGlimpseAfterStarcall", "1");
        }
    }

    // Move chosen card from tempzone to hand using direct zone ops so cross-player
    // glimpse flows (e.g. Astroscope redirect) do not perspective-flip zones.
    $tempZoneRef = &GetTempZone($player);
    $chosenTempObj = ($chosenTempIndex >= 0 && $chosenTempIndex < count($tempZoneRef))
        ? $tempZoneRef[$chosenTempIndex]
        : null;
    if($chosenTempObj === null || $chosenTempObj->removed) return;
    $chosenTempObj->Remove();
    MZAddZone($player, "myHand", $chosenCardID, $chosenTempObj);
    DecisionQueueController::CleanupRemovedCards();
    // Remove chosen card from the tracked glimpse list; all remaining glimpsed cards
    // must be put on the bottom of the deck (Starcalling rule).
    array_splice($cardIDs, $chosenRelativeIndex, 1);
    $newN = max(0, $n - 1);
    DecisionQueueController::StoreVariable("glimpseCount", strval($newN));
    DecisionQueueController::StoreVariable("glimpseCardIDs", implode(",", $cardIDs));
    DecisionQueueController::StoreVariable("glimpsedToTempZone", "1");

    // Find the chosen card in hand (search from end for most-recently-added)
    $hand = GetZone("myHand");
    $handMZ = null;
    for($hi = count($hand) - 1; $hi >= 0; --$hi) {
        if(!$hand[$hi]->removed && $hand[$hi]->CardID === $chosenCardID) {
            $handMZ = "myHand-" . $hi;
            break;
        }
    }
    if($handMZ === null) return;

    // Pay starcalling cost, then activate the card
    if($starcallingCost > 0) {
        for($i = 0; $i < $starcallingCost; ++$i) {
            DecisionQueueController::AddDecision($player, "CUSTOM", "ReserveCard", 100);
        }
    }
    DecisionQueueController::AddDecision($player, "CUSTOM", "StarcallingActivate|$handMZ|$chosenCardID", 100);
    if($newN > 0) {
        // Let the player choose the order for cards going to bottom only.
        $param = "Bottom=" . implode(",", $cardIDs);
        DecisionQueueController::AddDecision($player, "MZREARRANGE", $param, 101, "Starcalling:_order_cards_for_bottom");
        DecisionQueueController::AddDecision($player, "CUSTOM", "StarcallingBottomApply", 101);
    }
};

/**
 * Process Starcalling remainder reorder: all remaining glimpsed cards go to
 * the bottom of the deck in chosen order, regardless of pile assignment.
 */
$customDQHandlers["StarcallingBottomApply"] = function($player, $parts, $lastDecision) {
    $deck = &GetDeck($player);
    $tempZone = &GetTempZone($player);

    $piles = ["Top" => [], "Bottom" => []];
    foreach(explode(";", $lastDecision) as $pileStr) {
        $eqPos = strpos($pileStr, "=");
        if($eqPos === false) continue;
        $pileName = substr($pileStr, 0, $eqPos);
        $cardsStr = trim(substr($pileStr, $eqPos + 1));
        if(isset($piles[$pileName])) {
            $piles[$pileName] = ($cardsStr !== "") ? explode(",", $cardsStr) : [];
        }
    }

    foreach($tempZone as $obj) {
        if(!$obj->removed) $obj->Remove();
    }
    DecisionQueueController::CleanupRemovedCards();

    foreach(array_merge($piles["Bottom"], $piles["Top"]) as $cid) {
        $deck[] = new Deck($cid, 'Deck', $player);
    }
};

/**
 * After starcalling cost is paid, activate the card from hand.
 */
$customDQHandlers["StarcallingActivate"] = function($player, $parts, $lastDecision) {
    $mzCard = $parts[0];
    $chosenCardID = $parts[1];

    // Find the card in hand (index may have shifted due to reserve payments)
    $hand = GetZone("myHand");
    $actualMZ = null;
    for($i = 0; $i < count($hand); ++$i) {
        if(!$hand[$i]->removed && $hand[$i]->CardID === $chosenCardID) {
            $actualMZ = "myHand-" . $i;
            break;
        }
    }
    if($actualMZ === null) return;

    // Tag as starcalled so the card's ability code can check
    DecisionQueueController::StoreVariable("wasStarcalled", "YES");

    // Supernova Divination (qhBecpDUO9): [Arisanna Bonus] whenever you starcall a card, add divination counter.
    {
        global $playerID;
        $fieldZone = ($player == $playerID) ? "myField" : "theirField";
        $field = GetZone($fieldZone);
        for($sdi = 0; $sdi < count($field); ++$sdi) {
            if($field[$sdi]->removed || $field[$sdi]->CardID !== "qhBecpDUO9" || HasNoAbilities($field[$sdi])) continue;
            if(!IsArisannaBonusActive($player)) continue;
            $sdMZ = $fieldZone . "-" . $sdi;
            AddCounters($player, $sdMZ, "divination", 1);
            SupernovaDivinationCheck($player, $sdMZ);
            break;
        }
    }

    // Move to effect stack
    $obj = MZMove($player, $actualMZ, "EffectStack");
    $obj->Controller = $player;

    // Queue EffectStackOpportunity (opponent may respond)
    DecisionQueueController::AddDecision($player, "CUSTOM", "EffectStackOpportunity", 100);

    // Astrolabe: trigger Glimpse 5 after starcalling completes
    $astrolabeGlimpse = DecisionQueueController::GetVariable("astrolabeGlimpseAfterStarcall");
    if($astrolabeGlimpse === "1") {
        DecisionQueueController::StoreVariable("astrolabeGlimpseAfterStarcall", "0");
        // Queue glimpse 5 after the starcalled card resolves (high block)
        DecisionQueueController::AddDecision($player, "CUSTOM", "AstrolabeStarcallGlimpse", 201);
    }

    // Stargazer's Portent (btjuxztaug): copy the starcalled card's activation
    if(GlobalEffectCount($player, "btjuxztaug") > 0) {
        RemoveGlobalEffect($player, "btjuxztaug");
        DecisionQueueController::AddDecision($player, "CUSTOM", "StargazersPortentCopy|$chosenCardID", 201);
    }
};

function SupernovaDivinationCheck($player, $supernovaMZ) {
    $supernovaObj = GetZoneObject($supernovaMZ);
    if($supernovaObj === null || $supernovaObj->removed || $supernovaObj->CardID !== "qhBecpDUO9") return;
    if(GetCounterCount($supernovaObj, "divination") < 10) return;

    DoSacrificeFighter($player, $supernovaMZ);
    DecisionQueueController::CleanupRemovedCards();

    $opponent = ($player == 1) ? 2 : 1;
    global $playerID;
    $oppZone = ($opponent == $playerID) ? "myField" : "theirField";
    $oppField = GetZone($oppZone);
    for($i = 0; $i < count($oppField); ++$i) {
        if($oppField[$i]->removed || $oppField[$i]->Controller != $opponent) continue;
        if(!PropertyContains(EffectiveCardType($oppField[$i]), "ALLY") && !PropertyContains(EffectiveCardType($oppField[$i]), "CHAMPION")) continue;
        $targetMZ = $oppZone . "-" . $i;
        AddTurnEffect($targetMZ, "NO_ABILITIES");
        DealUnpreventableDamage($player, "qhBecpDUO9", $targetMZ, 25);
    }
}

/**
 * Aethercalling offer handler: player either chose a card to load into Aetherwing or passed.
 * If chosen, load the card into an Aetherwing weapon, then rearrange remaining glimpsed cards.
 * If passed, fall back to normal Glimpse rearrange.
 */
$customDQHandlers["AethercallingOffer"] = function($player, $parts, $lastDecision) {
    $n = intval(DecisionQueueController::GetVariable("glimpseCount"));
    $tempBaseIndex = intval(DecisionQueueController::GetVariable("glimpseTempBaseIndex"));
    $cardIDsStr = DecisionQueueController::GetVariable("glimpseCardIDs");
    $cardIDs = explode(",", $cardIDsStr);

    if($lastDecision === "-" || $lastDecision === "" || $lastDecision === "PASS") {
        // Declined â€” proceed to rearrange all tempzone cards
        $param = "Top=" . implode(",", $cardIDs) . ";Bottom=";
        DecisionQueueController::StoreVariable("glimpsedToTempZone", "1");
        DecisionQueueController::AddDecision($player, "MZREARRANGE", $param, 1, "Glimpse:_Top=return_to_top,_Bottom=put_on_bottom");
        DecisionQueueController::AddDecision($player, "CUSTOM", "GlimpseApply", 1);
        return;
    }

    // Accepted â€” load chosen card into Aetherwing
    $tmpParts = explode("-", $lastDecision);
    $chosenTempIndex = intval($tmpParts[1]); // absolute tempzone index
    $chosenRelativeIndex = $chosenTempIndex - $tempBaseIndex;
    if($chosenRelativeIndex < 0 || $chosenRelativeIndex >= count($cardIDs)) return;
    $chosenCardID = $cardIDs[$chosenRelativeIndex];

    // Remove chosen card from tempzone using direct zone ops so cross-player
    // glimpse flows do not hit perspective-flipped MZ lookups.
    $tempZoneRef = &GetTempZone($player);
    if($chosenTempIndex >= 0 && $chosenTempIndex < count($tempZoneRef)) {
        $tempObj = $tempZoneRef[$chosenTempIndex];
        if($tempObj !== null && !$tempObj->removed) $tempObj->Remove();
    }
    DecisionQueueController::CleanupRemovedCards();

    // Update cardIDs for rearrange (remove loaded card)
    array_splice($cardIDs, $chosenRelativeIndex, 1);
    $newN = $n - 1;
    DecisionQueueController::StoreVariable("glimpseCount", strval($newN));
    DecisionQueueController::StoreVariable("glimpseCardIDs", implode(",", $cardIDs));

    // Load into Aetherwing weapon
    $wings = GetAetherwingWeapons($player);
    if(!empty($wings)) {
        if(count($wings) === 1) {
            $wingObj = &GetZoneObject($wings[0]);
            if($wingObj !== null) {
                if(!is_array($wingObj->Subcards)) $wingObj->Subcards = [];
                $wingObj->Subcards[] = $chosenCardID;
            }
        } else {
            DecisionQueueController::StoreVariable("AethercallCardID", $chosenCardID);
            DecisionQueueController::AddDecision($player, "MZCHOOSE", implode("&", $wings), 1, "Choose_Aetherwing_weapon");
            DecisionQueueController::AddDecision($player, "CUSTOM", "AethercallingLoadSelect", 1);
        }
    }

    // Rearrange remaining cards
    if(!empty($cardIDs)) {
        $param = "Top=" . implode(",", $cardIDs) . ";Bottom=";
        DecisionQueueController::StoreVariable("glimpsedToTempZone", "1");
        DecisionQueueController::AddDecision($player, "MZREARRANGE", $param, 1, "Glimpse:_Top=return_to_top,_Bottom=put_on_bottom");
        DecisionQueueController::AddDecision($player, "CUSTOM", "GlimpseApply", 1);
    }
};

/**
 * Aethercalling weapon select handler: player chose which Aetherwing to load into.
 */
$customDQHandlers["AethercallingLoadSelect"] = function($player, $parts, $lastDecision) {
    $chosenCardID = DecisionQueueController::GetVariable("AethercallCardID");
    if($lastDecision !== "-" && $lastDecision !== "" && $lastDecision !== "PASS") {
        $wingObj = &GetZoneObject($lastDecision);
        if($wingObj !== null) {
            if(!is_array($wingObj->Subcards)) $wingObj->Subcards = [];
            $wingObj->Subcards[] = $chosenCardID;
        }
    }
};

function OnCardChosen($player, $lastResult) {
    $card = &GetZoneObject($lastResult);
}

function TraitContains($card, $trait) {
    // CardTraits() does not exist in SWUSim; traits are looked up via HasTrait (over $traitData).
    return HasTrait($card->CardID ?? '', $trait);
}

function CardHasAbility($obj) {
    global $debugMode;
    if(HasNoAbilities($obj)) return 0;
    $location = isset($obj->Location) ? $obj->Location : "";
    $supportsDynamic = ($location === "Field" || $location === "Intent");
    $hasDynamic = $supportsDynamic ? (GetDynamicAbilities($obj) !== "") : false;
    $isIntentObject = isset($obj->Location) && $obj->Location === "Intent";
    $controller = isset($obj->Controller) ? $obj->Controller : (isset($obj->PlayerID) ? intval($obj->PlayerID) : null);
    $isHandObject = ($location === "Hand");
    $staticCount = $isHandObject ? CardHandActivatedAbilityCount($obj->CardID) : CardActivateAbilityCount($obj->CardID);
    if($debugMode) {
        return ($staticCount > 0 || $hasDynamic) ? 1 : 0;
    }
    $turnPlayer = &GetTurnPlayer();
    $hasAbility = ($staticCount > 0 || $hasDynamic);
    if(!$hasAbility) return 0;
    if($controller === null || $turnPlayer != $controller) return 0;
    if(!$isIntentObject && isset($obj->Status) && $obj->Status != 2) return 0;

    // Cunning Broker (oy34bro89w): requires 2+ prep counters on champion
    if($obj->CardID === "oy34bro89w") {
        $pField = &GetField($obj->Controller);
        foreach($pField as $fCard) {
            if(!$fCard->removed && PropertyContains(EffectiveCardType($fCard), "CHAMPION")) {
                if(GetCounterCount($fCard, "preparation") < 2) return 0;
                break;
            }
        }
    }

    // Corhazi Arsonist (0ejcyuvuxn): requires 1+ prep counter on champion
    if($obj->CardID === "0ejcyuvuxn") {
        $pField = &GetField($obj->Controller);
        foreach($pField as $fCard) {
            if(!$fCard->removed && PropertyContains(EffectiveCardType($fCard), "CHAMPION")) {
                if(GetCounterCount($fCard, "preparation") < 1) return 0;
                break;
            }
        }
    }

    // Sigil of Budding Embers (g31dg6zl3j): requires Diao Chan Bonus + champion has glimmer
    if($obj->CardID === "g31dg6zl3j") {
        if(!IsDiaoChanBonus($obj->Controller)) return 0;
        $champObj = GetPlayerChampion($obj->Controller);
        if($champObj === null || GetCounterCount($champObj, "glimmer") <= 0) return 0;
    }

    // Duxal Proclamation (473gyf0w3v): activate only if each opponent controls no allies
    if($obj->CardID === "473gyf0w3v") {
        if(!empty(ZoneSearch("theirField", ["ALLY"]))) return 0;
    }

    // Scepter of Fascination (4864k12no2): [Diao Chan Bonus] banish
    if($obj->CardID === "4864k12no2") {
        if(!IsDiaoChanBonus($obj->Controller)) return 0;
    }

    // Staff of Blossoming Will (4moumzcx9z): [Diao Chan Bonus] (1), REST
    if($obj->CardID === "4moumzcx9z") {
        if(!IsDiaoChanBonus($obj->Controller)) return 0;
        if($obj->Status != 2) return 0;
        if(CountAvailableReservePayments($obj->Controller, $obj->GetMzID()) < 1) return 0;
    }

    // Mana Limiter (IC3OU6vCnF): requires champion has 6+ enlighten counters
    if($obj->CardID === "IC3OU6vCnF") {
        $champObj = GetPlayerChampion($obj->Controller);
        if($champObj === null || GetCounterCount($champObj, "enlighten") < 6) return 0;
    }

    // Ticket to the Afterlife (E09lX95cb9): [Alice Bonus] + Specter in graveyard + REST
    if($obj->CardID === "E09lX95cb9") {
        if(!IsAliceBonusActive($obj->Controller)) return 0;
        if($obj->Status != 2) return 0;
        global $playerID;
        $gyZone = ($obj->Controller == $playerID) ? "myGraveyard" : "theirGraveyard";
        if(empty(ZoneSearch($gyZone, cardSubtypes: ["SPECTER"]))) return 0;
    }

    return 1;
}

function GetActivateAbilityButtonStates($obj) {
    global $playerID;
    if(HasNoAbilities($obj)) return "";

    $location = isset($obj->Location) ? $obj->Location : "";
    $isHandObject = ($location === "Hand");
    $staticCount = $isHandObject ? CardHandActivatedAbilityCount($obj->CardID) : CardActivateAbilityCount($obj->CardID);
    if($staticCount <= 0) return "";

    $mzID = SelectionMetadataMzID($obj);
    if($mzID === null) return "";

    $actingPlayer = intval($playerID);
    $controller = isset($obj->Controller) ? $obj->Controller : (isset($obj->PlayerID) ? intval($obj->PlayerID) : null);
    $states = [];
    $existingFlash = GetFlashMessage();

    for($abilityIndex = 0; $abilityIndex < $staticCount; ++$abilityIndex) {
        $enabled = false;
        if($controller !== null && $actingPlayer == $controller) {
            if($isHandObject) {
                $enabled = function_exists("CanHandActivateAbility") ? CanHandActivateAbility($actingPlayer, $mzID, $abilityIndex) : true;
            } else {
                $enabled = function_exists("CanActivateAbility") ? CanActivateAbility($actingPlayer, $mzID, $abilityIndex) : true;
            }
            SetFlashMessage($existingFlash);
        }

        $states[] = [
            "index" => $abilityIndex,
            "enabled" => $enabled,
            "tooltip" => $enabled ? "" : "You do not meet the prerequisite to activate this ability."
        ];
    }

    SetFlashMessage($existingFlash);
    return json_encode($states);
}

function GetHandActivateAbilityCountForObject($obj) {
    if($obj == null || !isset($obj->CardID)) return 0;
    return function_exists("CardHandActivatedAbilityCount") ? CardHandActivatedAbilityCount($obj->CardID) : 0;
}

function GetHandActivateAbilityNamesForObject($obj) {
    if($obj == null || !isset($obj->CardID)) return "[]";
    if(function_exists("CardHandActivatedAbilityCountNames")) {
        return json_encode(CardHandActivatedAbilityCountNames($obj->CardID));
    }
    return "[]";
}

// Internal tracking effects that are backend-only and should never render in the UI
$backendOnlyTurnEffects = [
    "SHOOT_FIRST",   // implied "deals damage before defender" ordering — not a player-facing badge (always gone at attack end). Stays registered so SWUExpireTurnEffects('attack') still drops it; this only hides it from the Active Effects popup.
    "DEFENDER_FIRST", // LAW_086 — the reverse ordering; backend-only, attack-scoped (dropped by SWUExpireTurnEffects('attack')).
];

// SWU internal global-effect flags are SCOPED, unlike GA field-wide effects:
// a flag ending in `_<UniqueID>` (e.g. SWU_PLAYED_UNIT_42) belongs only to that one
// unit; a flag with no UniqueID suffix (e.g. SWU_HAN_DEFEAT_RESOURCE, SWU_PLAYED_VILLAINY)
// is player-scoped and belongs to NO unit. Non-SWU effects keep their existing behavior.
function SWUGlobalEffectAttachesToUnit(string $effectID, $obj): bool {
    if (strpos($effectID, 'SWU_') !== 0) return true;
    if (preg_match('/_(\d+)$/', $effectID, $m)) {
        return isset($obj->UniqueID) && intval($obj->UniqueID) === intval($m[1]);
    }
    return false; // player-scoped SWU flag — never attaches to a unit
}

function CardCurrentEffects($obj) {
    global $doesGlobalEffectApply, $effectAppliesToBoth,$playerID;
    //Start with this object's effects (all of them, unfiltered — used by game logic)
    $effects = (isset($obj->TurnEffects) && is_array($obj->TurnEffects)) ? $obj->TurnEffects : [];
    //Now add global effects
    $controller = isset($obj->Controller) ? $obj->Controller : -1;
    if($controller != -1) {
        $controllerEffects = $controller == $playerID ? GetZone("myGlobalEffects") : GetZone("theirGlobalEffects");
        foreach($controllerEffects as $index => $effectObj) {
            if(!SWUGlobalEffectAttachesToUnit($effectObj->CardID, $obj)) continue;
            if(!isset($doesGlobalEffectApply[$effectObj->CardID]) || $doesGlobalEffectApply[$effectObj->CardID]($obj)) {
                array_push($effects, $effectObj->CardID);
            }
        }
        $otherEffects = $controller != $playerID ? GetZone("myGlobalEffects") : GetZone("theirGlobalEffects");
        foreach($otherEffects as $index => $effectObj) {
            if(!SWUGlobalEffectAttachesToUnit($effectObj->CardID, $obj)) continue;
            if(isset($effectAppliesToBoth[$effectObj->CardID]) && (!isset($doesGlobalEffectApply[$effectObj->CardID]) || $doesGlobalEffectApply[$effectObj->CardID]($obj))) {
                array_push($effects, $effectObj->CardID);
            }
        }
    }
    return implode(",", $effects);
}

function CardDisplayEffects($obj) {
    global $backendOnlyTurnEffects;
    // Same as CardCurrentEffects but strips backend-only tracking effects before returning.
    // `SWU_`-prefixed flags are internal phase trackers (SWU_PLAYED_UNIT_*, SWU_HAN_*, etc.),
    // never player-facing badges. Player-facing turn effects use the registry token format
    // "CARDID-params@duration" (e.g. SOR_086, SOR_076-2-2) so the CardIDs-mode badge popup
    // (Core/CounterRendering.js) shows the source card's art — see SWUDescribeActiveEffects.
    $raw = CardCurrentEffects($obj);
    if($raw === "") return "";
    $out = [];
    foreach (explode(",", $raw) as $e) {
        if (in_array($e, $backendOnlyTurnEffects) || strpos($e, 'SWU_') === 0) continue;
        // Canonicalize an explicit "@duration" onto each registry-known turn-effect token so the
        // client Active Effects popup can render a duration chip without shipping the registry to
        // JS. Global-effect CardIDs and unregistered tokens pass through unchanged (no chip).
        if (strpos($e, '@') === false) {
            $p = SWUParseTurnEffect($e);
            if (SWUEffectKind($p['base']) !== null) $e .= '@' . $p['duration'];
        }
        $out[] = $e;
    }
    return implode(",", $out);
}

function SelectionMetadataMzID($obj) {
    global $playerID;
    if(!isset($obj->Location) || !isset($obj->PlayerID) || !isset($obj->mzIndex)) {
        return null;
    }
    $prefix = $playerID == $obj->PlayerID ? "my" : "their";
    return $prefix . $obj->Location . "-" . $obj->mzIndex;
}

function CanActivateCardForSelection($player, $obj, $strict = false) {
    if(!function_exists("CanActivateCard")) return true;
    $mzID = SelectionMetadataMzID($obj);
    if($mzID === null) return true;
    $existingFlash = GetFlashMessage();
    if(!CanActivateAttackCardNow($player, $obj->CardID, $strict)) {
        SetFlashMessage($existingFlash);
        return false;
    }
    if(!CanPlayerUseCardElement($player, $obj->CardID, $strict, $strict)) {
        SetFlashMessage($existingFlash);
        return false;
    }
    $canActivate = CanActivateCard($player, $mzID, false);
    SetFlashMessage($existingFlash);
    return $canActivate;
}

function SelectionMetadata($obj) {
    global $playerID;
    $currentPhase = GetCurrentPhase();
    $turnPlayer = &GetTurnPlayer();

    // During Opportunity windows, highlight only cards that are actually in the
    // fast-opportunity choice list for the active player perspective.
    if(function_exists("HasOpportunity") && HasOpportunity($playerID)
        && function_exists("GetPlayableOpportunityChoices")) {
        $mzID = SelectionMetadataMzID($obj);
        if($mzID === null) return json_encode(['highlight' => false]);
        $opportunityChoices = GetPlayableOpportunityChoices($playerID);
        if(!in_array($mzID, $opportunityChoices, true)) {
            return json_encode(['highlight' => false]);
        }
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Standard main phase check
    if ($currentPhase !== "MAIN") {
        return json_encode(['highlight' => false]);
    }

    // Check if decision queue is empty
    $decisionQueue = &GetDecisionQueue($turnPlayer);
    $theirDecisionQueue = &GetDecisionQueue($turnPlayer == 1 ? 2 : 1);
    if (count($decisionQueue) > 0 || count($theirDecisionQueue) > 0) {
        return json_encode(['highlight' => false]);
    }

    // Only highlight cards belonging to the turn player
    $owner = isset($obj->Controller) ? $obj->Controller : (isset($obj->PlayerID) ? $obj->PlayerID : null);
    if ($owner === null || intval($owner) !== intval($turnPlayer)) {
        return json_encode(['highlight' => false]);
    }

    if (isset($obj->Status) && $obj->Status != 2) { // Not ready
        if(!CanActExhausted($obj)) {
            return json_encode(['highlight' => false]);
        }
    }
    // Return red color if there's an activation restriction
    if(!CanActivateCardForSelection($turnPlayer, $obj)) {
        return json_encode(['color' => 'rgba(255, 64, 64, 0.95)']);
    }
    // Unaffordable hand cards get NO highlight — only cards you can actually pay for glow green.
    // (Affordability is advisory: rare cost branches can still make it playable, and the card stays
    // clickable either way — an unhighlighted card falls through to CardClick — so the server still
    // lets you attempt the play; we just don't draw an amber "can't afford" glow.)
    if(isset($obj->Location) && $obj->Location === "Hand" && !CanAffordActivationReserve($turnPlayer, $obj)) {
        return json_encode(['highlight' => false]);
    }
    // Return bright vibrant lime green highlight for valid selectable cards
    return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
}


function CombatTargetIndicator($obj) {
    if(!isset($obj->Location) || $obj->Location !== "Field") return "";
    if(!method_exists($obj, "GetMzID")) return "";

    $mzTarget = $obj->GetMzID();
    if($mzTarget === null || $mzTarget === "" || $mzTarget === "-") return "";

    if(IsUnitAttacking($mzTarget)) return "ATTACKER";
    if(IsUnitDefending($mzTarget)) return "TARGET";
    return "";
}

function CanActExhausted($obj) {

    return false;
}

// Virtual property: returns highlight metadata for a graveyard card that can be activated via Ephemerate.
// Returns a gold glow if the current player can pay the ephemerate cost for this card, false otherwise.
function EphemerateMeta($obj) {
    global $playerID;
    if (function_exists("HasOpportunity") && HasOpportunity($playerID)
        && function_exists("GetPlayableOpportunityChoices")) {
        $mzID = SelectionMetadataMzID($obj);
        if ($mzID !== null) {
            $opportunityChoices = GetPlayableOpportunityChoices($playerID);
            if (in_array($mzID, $opportunityChoices, true)) {
                return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
            }
        }
    }

    $currentPhase = GetCurrentPhase();
    if ($currentPhase !== "MAIN") {
        return json_encode(['highlight' => false]);
    }
    $turnPlayer = GetTurnPlayer();
    if ($playerID != $turnPlayer) {
        return json_encode(['highlight' => false]);
    }
    // Check if decision queue is empty
    $decisionQueue = &GetDecisionQueue($turnPlayer);
    if (count($decisionQueue) > 0) {
        return json_encode(['highlight' => false]);
    }

    // Three Visits (w7o3agvvnc): [Class Bonus] activate from graveyard while champion can be rested
    if ($obj->CardID === "w7o3agvvnc" && IsClassBonusActive($turnPlayer, ["CLERIC", "MAGE"]) && CanPayRestChampionCost($turnPlayer)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    global $ephemerateCards;
    if (!isset($ephemerateCards[$obj->CardID]) && !MordredFatedEphemerateApplies($playerID, $obj->CardID)) {
        return json_encode(['highlight' => false]);
    }
    if (!CanPayEphemerate($playerID, $obj->CardID)) {
        return json_encode(['highlight' => false]);
    }
    // Gold glow to distinguish Ephemerate from normal hand playability
    return json_encode(['color' => 'rgba(255, 200, 0, 0.95)']);
}

function MordredFatedEphemerateApplies($player, $cardID) {
    return ChampionHasInLineage($player, "KqBosnU7pU") && PropertyContains(CardType($cardID), "ATTACK");
}

// Virtual property: returns highlight metadata for material deck cards that can be activated via special conditions.
// Each check mirrors the exact FSM condition in the myMaterial case of ActionMap/FSM.
function MaterialSelectionMetadata($obj) {
    global $playerID;
    $currentPhase = GetCurrentPhase();
    if ($currentPhase !== "MAIN") {
        return json_encode(['highlight' => false]);
    }
    $turnPlayer = GetTurnPlayer();
    if ($playerID != $turnPlayer) {
        return json_encode(['highlight' => false]);
    }
    // Check if both decision queues are empty
    $decisionQueue = &GetDecisionQueue($turnPlayer);
    $theirDecisionQueue = &GetDecisionQueue($turnPlayer == 1 ? 2 : 1);
    if (count($decisionQueue) > 0 || count($theirDecisionQueue) > 0) {
        return json_encode(['highlight' => false]);
    }

    // Mantle of the Abyss (1ubrwubSQN): [Alice Bonus] sacrifice a Specter ally to activate from material deck
    if ($obj->CardID === "1ubrwubSQN" && IsAliceBonusActive($turnPlayer)) {
        $specterAllies = ZoneSearch("myField", ["ALLY"], cardSubtypes: ["SPECTER"]);
        if (!empty($specterAllies)) {
            return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
        }
    }

    // Bagua of Vital Demise (imdj3c7oh0): may activate from material deck when SC faces West
    if ($obj->CardID === "imdj3c7oh0" && GetShiftingCurrents($turnPlayer) === "WEST") {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Polaris, Twinkling Cauldron (41t71u4bzz): [Arisanna Bonus] may activate from material deck
    if ($obj->CardID === "41t71u4bzz" && IsArisannaBonusActive($turnPlayer)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Lost Providence (DNbIpzVgde): may activate from material deck when element requirements are met
    if ($obj->CardID === "DNbIpzVgde" && CanPlayerUseCardElement($turnPlayer, $obj->CardID, false, false)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Tome of Sacred Lightning (MyUTeqUJ0H): [Element Bonus] + you control a Book regalia
    if ($obj->CardID === "MyUTeqUJ0H" && IsElementBonusActive($turnPlayer, "MyUTeqUJ0H")) {
        $bookRegalia = ZoneSearch("myField", ["REGALIA"], cardSubtypes: ["BOOK"]);
        if (!empty($bookRegalia)) {
            return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
        }
    }

    // Gaia's Blessing (ymhDYTPfi1): [Element Bonus] 4+ Animal/Beast GY allies -> activate from material free
    if ($obj->CardID === "ymhDYTPfi1" && IsElementBonusActive($turnPlayer, "ymhDYTPfi1")) {
        $animalBeastGY = ZoneSearch("myGraveyard", ["ALLY"], cardSubtypes: ["ANIMAL", "BEAST"]);
        if (count($animalBeastGY) >= 4) {
            return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
        }
    }

    return json_encode(['highlight' => false]);
}

// Virtual property: returns highlight metadata for banish cards that can be activated via specific mechanics.
// Each check mirrors the exact FSM condition in the myBanish case of CardClick/FSM.
function BanishSelectionMetadata($obj) {
    global $playerID;
                //return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    if (HasOpportunity($playerID)) {
        $mzID = SelectionMetadataMzID($obj);
        if ($mzID !== null) {
            $opportunityChoices = GetPlayableOpportunityChoices($playerID);
            if (in_array($mzID, $opportunityChoices, true)) {
                return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
            }
        }
    }

    $turnPlayer = GetTurnPlayer();

    // Only highlight cards belonging to the turn player
    $owner = isset($obj->Controller) ? $obj->Controller : (isset($obj->PlayerID) ? $obj->PlayerID : null);
    if ($owner !== $turnPlayer) {
        return json_encode(['highlight' => false]);
    }

    // Check if both decision queues are empty
    $decisionQueue = &GetDecisionQueue($turnPlayer);
    $theirDecisionQueue = &GetDecisionQueue($turnPlayer == 1 ? 2 : 1);
    if (count($decisionQueue) > 0 || count($theirDecisionQueue) > 0) {
        return json_encode(['highlight' => false]);
    }

    $currentPhase = GetCurrentPhase();
    $turnEffects = $obj->TurnEffects ?? [];

    // Naia, Diviner of Fortunes (jdmthh88rx): spell tagged NAIA_BANISHED + Naia still on field
    if ($currentPhase === "MAIN" && in_array("NAIA_BANISHED", $turnEffects)) {
        foreach(GetZone("myField") as $fObj) {
            if (!$fObj->removed && $fObj->CardID === "jdmthh88rx" && !HasNoAbilities($fObj)) {
                return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
            }
        }
    }

    // Shattering Discharge (uutqo9hm33): self + has a charge counter
    if ($currentPhase === "MAIN" && $obj->CardID === "uutqo9hm33" && GetCounterCount($obj, "charge") > 0) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Three Visits (w7o3agvvnc): [Class Bonus] activate from banishment while champion can be rested.
    if ($currentPhase === "MAIN" && $obj->CardID === "w7o3agvvnc"
        && IsClassBonusActive($turnPlayer, ["CLERIC", "MAGE"]) && CanPayRestChampionCost($turnPlayer)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Seiryuu, Azure Dragon (tf5f2n38g0): generated Arcane Blast tagged for banish activation.
    if (GetCounterCount($obj, "_seiryuuBanished") > 0) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Kongming, Erudite Strategist (0i139x5eub): tagged KONGMING_<DIR> + SC faces that direction
    if ($currentPhase === "MAIN") {
        foreach(["NORTH", "EAST", "SOUTH", "WEST"] as $d) {
            if (in_array("KONGMING_" . $d, $turnEffects) && GetShiftingCurrents($turnPlayer) === $d) {
                return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
            }
        }
    }

    // Ignition Draw (RhSPMn8Lix): tagged _ignitionDraw turn effect
    if ($currentPhase === "MAIN" && in_array('_ignitionDraw', $turnEffects)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Mordred, Burnished Avenger (OWCdWq3mXY): tagged _mordredBurnished turn effect
    if ($currentPhase === "MAIN" && in_array('_mordredBurnished', $turnEffects)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Desperate Cavalier (slmer06rku): tagged _desperateCavalier turn effect
    if ($currentPhase === "MAIN" && in_array('_desperateCavalier', $turnEffects)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Seething Intercession (5Xfg69S1XX): tagged _seethingIntercession turn effect
    if ($currentPhase === "MAIN" && in_array('_seethingIntercession', $turnEffects)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Recursive Confidant (KfC8fwcF2T): tagged _recursiveConfidant turn effect
    if ($currentPhase === "MAIN" && in_array('_recursiveConfidant', $turnEffects)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Ashen Riffle (fjpimrl974): tagged _ashenRiffle turn effect
    if ($currentPhase === "MAIN" && in_array('_ashenRiffle', $turnEffects)) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    // Warrior of the Fae Realm (eRcqucBKhX): tagged _warriorFaeRealm turn effect + Warrior still on field
    if ($currentPhase === "MAIN" && in_array('_warriorFaeRealm', $turnEffects) && ZoneContainsCardID("myField", "eRcqucBKhX")) {
        return json_encode(['color' => 'rgba(0, 255, 0, 0.95)']);
    }

    return json_encode(['highlight' => false]);
}

function ZoneSearch($zoneName, $cardTypes=null, $floatingMemoryOnly=false, $cardElements=null, $cardSubtypes=null, $excludeSubtypes=null, $forPlayer=null, $cardClasses=null) {
    global $playerID;
    // $forPlayer: when specified and different from $playerID, flip the zone name so we
    // search the zone that corresponds to "my..." from $forPlayer's perspective. Results
    // are then flipped back to $forPlayer's coordinate space so they can be used directly
    // in MZChoose decisions (which are always resolved from the requesting player's view).
    $flip = ($forPlayer !== null && $forPlayer != $playerID);
    $searchZone = $zoneName;
    if ($flip) {
        if (substr($searchZone, 0, 2) === "my")        $searchZone = "their" . substr($searchZone, 2);
        elseif (substr($searchZone, 0, 5) === "their") $searchZone = "my"    . substr($searchZone, 5);
    }
    $results = [];
    $zoneArr = &GetZone($searchZone);
    foreach($zoneArr as $i => $obj) {
        $cardTypeStr = EffectiveCardType($obj);
        $cardTypes_arr = $cardTypeStr ? explode(",", $cardTypeStr) : [];
        // A deployed leader in an arena has CardType 'Leader', but it IS a leader unit and should
        // match the 'Leader Unit' filter token that effects use for "a unit" targeting (deal damage,
        // give -X/-Y, etc.). Without this, the ['Unit','Token Unit','Leader Unit'] pattern silently
        // skips deployed leaders everywhere.
        if (IsLeaderUnit($obj) && !in_array('Leader Unit', $cardTypes_arr, true)) $cardTypes_arr[] = 'Leader Unit';
        $cardSubtypesStr = EffectiveCardSubtypes($obj);
        $cardSubtypes_arr = $cardSubtypesStr ? explode(",", $cardSubtypesStr) : [];
        $cardClassesStr = EffectiveCardClasses($obj);
        $cardClasses_arr = $cardClassesStr ? explode(",", $cardClassesStr) : [];
        $effectiveElementStr = EffectiveCardElement($obj);
        $effectiveElements = $effectiveElementStr ? array_values(array_filter(array_map('trim', explode(",", $effectiveElementStr)), fn($part) => $part !== "")) : [];
        if(($cardTypes === null || count(array_intersect($cardTypes_arr, (array)$cardTypes)) > 0) &&
           ($cardElements === null || count(array_intersect($effectiveElements, (array)$cardElements)) > 0) &&
           ($cardSubtypes === null || count(array_intersect($cardSubtypes_arr, (array)$cardSubtypes)) > 0) &&
              ($cardClasses === null || count(array_intersect($cardClasses_arr, (array)$cardClasses)) > 0) &&
           ($excludeSubtypes === null || count(array_intersect($cardSubtypes_arr, (array)$excludeSubtypes)) === 0) &&
           (!$floatingMemoryOnly || HasFloatingMemory($obj))) {
            $mzID = $searchZone . "-" . $i;
            if ($flip) $mzID = FlipZonePerspective($mzID);
            array_push($results, $mzID);
        }
    }
    return $results;
}

function ZoneCardSearch($zoneName, $cardID) {
    $zoneName = explode("-", $zoneName)[0];
    $results = [];
    $zoneArr = &GetZone($zoneName);
    for($i = 0; $i < count($zoneArr); ++$i) {
        $obj = $zoneArr[$i];
        if($obj->CardID == $cardID) {
            array_push($results, $zoneName . "-" . $i);
        }
    }
    return $results;
}

