/**
 * Count distinct reserve costs among Suited objects a player controls on the field.
 * Used to compute Cardistry cost reduction: ability costs (1) less per distinct cost.
 * @param int $player The player whose field to check.
 * @return int Number of distinct reserve costs among their Suited objects.
 */
function GetCardistryDiscount($player) {
    global $playerID;
    $zone = $player == $playerID ? "myField" : "theirField";
    $field = GetZone($zone);
    $distinctCosts = [];
    foreach($field as $obj) {
        if($obj->removed) continue;
        if(!PropertyContains(EffectiveCardSubtypes($obj), "SUITED")) continue;
        $cost = CardCost_reserve($obj->CardID);
        if($cost !== null) $distinctCosts[$cost] = true;
    }
    return count($distinctCosts);
}

function CardistryThreeOfDiamonds($player, $mzID) {
    $deck = GetDeck($player);
    $n = min(3, count($deck));
    if($n <= 0) return;
    for($i = 0; $i < $n; ++$i) {
        MZMove($player, "myDeck-0", "myTempZone");
    }
    $choices = ZoneSearch("myTempZone");
    if(empty($choices)) return;
    DecisionQueueController::AddDecision($player, "MZCHOOSE", implode("&", $choices), 1, "Choose_card_to_put_into_graveyard");
    DecisionQueueController::AddDecision($player, "CUSTOM", "ThreeOfDiamondsGraveyard", 1);
}

function CountAliceChessmanDiscount($player) {
    if(!IsAliceBonusActive($player)) return 0;
    $seen = [];
    foreach(ZoneSearch("myField", ["ALLY", "CHAMPION"], cardSubtypes: ["CHESSMAN"]) as $mz) {
        $obj = GetZoneObject($mz);
        if($obj === null || $obj->removed) continue;
        $subtypes = EffectiveCardSubtypes($obj);
        foreach(["PAWN", "ROOK", "KNIGHT", "BISHOP", "QUEEN", "KING"] as $piece) {
            if(PropertyContains($subtypes, $piece)) $seen[$piece] = true;
        }
    }
    return 2 * count($seen);
}

function HasAgilityThisTurn($player) {
    for($amount = 1; $amount <= 10; ++$amount) {
        if(GlobalEffectCount($player, "AGILITY_" . $amount) > 0) return true;
    }
    return false;
}

/**
 * Check whether a field object currently has immortality.
 * Immortal objects can take damage, but can't be destroyed/sacrificed/sent to graveyard by death.
 * @param object|null $obj A field zone object.
 * @return bool
 */
function HasImmortality($obj) {
    if($obj === null || $obj->removed) return false;
    if(HasNoAbilities($obj)) return false;
    // Jin, Undying Resolve (c4yrrtv7o1): as long as it's not your end phase, Jin has immortality.
    if(PropertyContains(EffectiveCardType($obj), "CHAMPION")) {
        $controller = $obj->Controller ?? null;
        if($controller !== null) {
            $isJinUndying = ($obj->CardID === "c4yrrtv7o1")
                || ChampionHasInLineage($controller, "c4yrrtv7o1");
            if($isJinUndying) {
                $isJinEndPhase = (GetCurrentPhase() === "END" && GetTurnPlayer() == $controller);
                if(!$isJinEndPhase) return true;
            }
        }
    }
    // Wrathful Slime (wjaq7t8vbf): immortality while it has 6+ buff counters.
    if($obj->CardID === "wjaq7t8vbf" && GetCounterCount($obj, "buff") >= 6) return true;
    if(HasGrantedKeyword($obj, 'Immortality')) return true;
    if(in_array("IMMORTALITY_NEXT_TURN", $obj->TurnEffects ?? [])) return true;
    if(!PropertyContains(EffectiveCardSubtypes($obj), "SUITED")) return false;
    if(!PropertyContains(EffectiveCardType($obj), "ALLY")) return false;
    global $playerID;
    $zone = $obj->Controller == $playerID ? "myField" : "theirField";
    $field = GetZone($zone);
    foreach($field as $fObj) {
        if(!$fObj->removed && $fObj->CardID === "4qc47amgpp" && !HasNoAbilities($fObj)
            && $fObj !== $obj && $fObj->Controller == $obj->Controller) {
            return true;
        }
    }
    return false;
}

